/// First DIR_INDEX sequence number assigned in a fresh directory, matching the
/// kernel's `BTRFS_DIR_START_INDEX`. Sequences 0 and 1 are reserved for the
/// implicit "." and ".." entries.
const BTRFS_DIR_START_INDEX: u64 = 2;

/// Adler-32 checksum with a 32-bit seed, matching the e2compr convention.
///
/// The seed is split into `s1 = seed & 0xFFFF` and `s2 = seed >> 16`,
/// then updated byte-by-byte over `data`.
fn adler32_seeded(seed: u32, data: &[u8]) -> u32 {
    const MOD_ADLER: u32 = 65521;
    let mut s1 = seed & 0xFFFF;
    let mut s2 = seed >> 16;
    for &byte in data {
        s1 = (s1 + u32::from(byte)) % MOD_ADLER;
        s2 = (s2 + s1) % MOD_ADLER;
    }
    (s2 << 16) | s1
}

#[derive(Debug)]
struct Ext4CompressedClusterWrite {
    old_blocks: Vec<BlockNumber>,
    new_blocks: Vec<BlockNumber>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum E2ComprCodec {
    Lzv1,
    Lzrw3a,
    Gzip { level: u32 },
    Bzip2,
    Lzo1x1,
    None,
}

impl E2ComprCodec {
    fn from_method_index(method_idx: u8) -> Result<Self, FfsError> {
        match method_idx {
            0 => Ok(Self::Lzv1),
            1..=3 => Ok(Self::None),
            4 => Ok(Self::Bzip2),
            8 => Ok(Self::Lzrw3a),
            10 => Ok(Self::Lzo1x1),
            16 => Ok(Self::Gzip { level: 1 }),
            17 => Ok(Self::Gzip { level: 2 }),
            18 => Ok(Self::Gzip { level: 3 }),
            19 => Ok(Self::Gzip { level: 4 }),
            20 => Ok(Self::Gzip { level: 5 }),
            21 => Ok(Self::Gzip { level: 6 }),
            22 => Ok(Self::Gzip { level: 7 }),
            23 => Ok(Self::Gzip { level: 8 }),
            24 => Ok(Self::Gzip { level: 9 }),
            _ => Err(FfsError::UnsupportedFeature(format!(
                "e2compr: unsupported method index {method_idx}"
            ))),
        }
    }

    const fn name(self) -> &'static str {
        match self {
            Self::Lzv1 => "lzv1",
            Self::Lzrw3a => "lzrw3a",
            Self::Gzip { .. } => "gzip",
            Self::Bzip2 => "bzip2",
            Self::Lzo1x1 => "LZO",
            Self::None => "none",
        }
    }

    fn legacy_exclusion(self, method_idx: u8, operation: &str) -> FfsError {
        FfsError::UnsupportedFeature(format!(
            "e2compr: method {method_idx} selects legacy {} codec; FrankenFS V1 supports gzip, LZO, and passthrough none only for {operation}",
            self.name()
        ))
    }
}

/// Detected filesystem type with the parsed superblock embedded.
///
/// Returned by [`detect_filesystem`] and stored in [`OpenFs::flavor`].
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum FsFlavor {
    /// ext4 filesystem with its parsed superblock.
    Ext4(Box<Ext4Superblock>),
    /// btrfs filesystem with its parsed superblock.
    Btrfs(Box<BtrfsSuperblock>),
}

/// Error from filesystem detection (superblock probing).
#[derive(Debug, Error)]
pub enum DetectionError {
    /// The image does not contain a recognized ext4 or btrfs superblock.
    #[error("image does not decode as supported ext4/btrfs superblock")]
    UnsupportedImage,
    /// An I/O error occurred while reading the image.
    #[error("I/O error while probing image: {0}")]
    Io(#[from] FfsError),
}

/// Summary of ext4 free space from bitmap analysis.
///
/// Contains both the bitmap-derived counts and the group descriptor cached
/// values, allowing detection of inconsistencies.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct Ext4FreeSpaceSummary {
    /// Total free blocks derived from bitmap analysis.
    pub free_blocks_total: u64,
    /// Total free inodes derived from bitmap analysis.
    pub free_inodes_total: u64,
    /// Total free blocks from group descriptor cached values.
    pub gd_free_blocks_total: u64,
    /// Total free inodes from group descriptor cached values.
    pub gd_free_inodes_total: u64,
    /// True if bitmap count differs from group descriptor count.
    pub blocks_mismatch: bool,
    /// True if bitmap count differs from group descriptor count.
    pub inodes_mismatch: bool,
}

/// Safe traversal result for the ext4 orphan inode list.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct Ext4OrphanList {
    /// Raw orphan-list head from the ext4 superblock (`s_last_orphan`).
    pub head: u32,
    /// Traversed inode numbers in on-disk chain order.
    pub inodes: Vec<InodeNumber>,
}

impl Ext4OrphanList {
    /// Number of inodes in the orphan list.
    #[must_use]
    pub fn count(&self) -> usize {
        self.inodes.len()
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
struct Ext4OrphanRecoveryStats {
    scanned: u32,
    deleted: u32,
    truncated: u32,
    skipped: u32,
}

impl Ext4OrphanRecoveryStats {
    #[must_use]
    fn processed(self) -> u32 {
        self.deleted.saturating_add(self.truncated)
    }
}

/// Probe an in-memory image for ext4 or btrfs superblock magic.
///
/// Tries ext4 first, then btrfs. Returns the first successful parse.
pub fn detect_filesystem(image: &[u8]) -> Result<FsFlavor, DetectionError> {
    if let Ok(ext4) = Ext4Superblock::parse_from_image(image) {
        return Ok(FsFlavor::Ext4(Box::new(ext4)));
    }

    if let Ok(btrfs) = BtrfsSuperblock::parse_from_image(image) {
        return Ok(FsFlavor::Btrfs(Box::new(btrfs)));
    }

    Err(DetectionError::UnsupportedImage)
}

/// Probe a block device for ext4 or btrfs superblock magic.
///
/// Reads the superblock regions from the device and tries to parse them.
/// Useful when the full image is not memory-mapped.
pub fn detect_filesystem_on_device(
    cx: &Cx,
    dev: &dyn ByteDevice,
) -> Result<FsFlavor, DetectionError> {
    let len = dev.len_bytes();

    let ext4_end =
        u64::try_from(ffs_types::EXT4_SUPERBLOCK_OFFSET + ffs_types::EXT4_SUPERBLOCK_SIZE)
            .map_err(|_| FfsError::Format("ext4 superblock end offset overflows u64".to_owned()))?;
    if len >= ext4_end {
        let ext4_region = read_ext4_superblock_region(cx, dev)?;
        if let Ok(sb) = Ext4Superblock::parse_superblock_region(&ext4_region) {
            return Ok(FsFlavor::Ext4(Box::new(sb)));
        }
    }

    let btrfs_end =
        u64::try_from(ffs_types::BTRFS_SUPER_INFO_OFFSET + ffs_types::BTRFS_SUPER_INFO_SIZE)
            .map_err(|_| {
                FfsError::Format("btrfs superblock end offset overflows u64".to_owned())
            })?;
    if len >= btrfs_end {
        let btrfs_region = read_btrfs_superblock_region(cx, dev)?;
        if let Ok(sb) = BtrfsSuperblock::parse_superblock_region(&btrfs_region) {
            return Ok(FsFlavor::Btrfs(Box::new(sb)));
        }
    }

    Err(DetectionError::UnsupportedImage)
}

/// Probe a filesystem image file at `path` for ext4 or btrfs superblock magic.
///
/// Convenience wrapper around [`detect_filesystem_on_device`] that opens the file.
pub fn detect_filesystem_at_path(
    cx: &Cx,
    path: impl AsRef<Path>,
) -> Result<FsFlavor, DetectionError> {
    let dev = FileByteDevice::open(path)?;
    detect_filesystem_on_device(cx, &dev)
}

