        let sb = make_test_superblock();
        let inode = make_test_inode(S_IFREG | 0o644, 0, 0);
        let attr = inode_to_attr(&sb, InodeNumber(11), &inode);
        assert_eq!(attr.kind, FileType::RegularFile);
        assert_eq!(attr.rdev, 0);
