    #[test]
    fn inode_file_type_maps_symlink_fifo_socket_and_unknown() {
        use ffs_types::{S_IFIFO, S_IFLNK, S_IFSOCK};

        let with_mode = |mode: u16| make_test_inode(mode, 0, 0);
        assert_eq!(
            inode_file_type(&with_mode(S_IFLNK | 0o777)),
            FileType::Symlink
        );
        assert_eq!(inode_file_type(&with_mode(S_IFIFO | 0o644)), FileType::Fifo);
        assert_eq!(
            inode_file_type(&with_mode(S_IFSOCK | 0o644)),
            FileType::Socket
        );
        // An undefined S_IFMT value (0o030000) matches no predicate and falls
        // back to RegularFile.
        assert_eq!(
            inode_file_type(&with_mode(0o030_000 | 0o644)),
            FileType::RegularFile
        );
    }

    #[test]
    fn inode_file_type_maps_directory_regular_and_devices() {
        // Complements inode_file_type_maps_symlink_fifo_socket_and_unknown by
        // pinning the common formats directly (they were only hit indirectly).
        let with_mode = |mode: u16| make_test_inode(mode, 0, 0);
        assert_eq!(
            inode_file_type(&with_mode(ffs_types::S_IFREG | 0o644)),
            FileType::RegularFile
        );
        assert_eq!(
            inode_file_type(&with_mode(ffs_types::S_IFDIR | 0o755)),
            FileType::Directory
        );
        assert_eq!(
            inode_file_type(&with_mode(ffs_types::S_IFBLK | 0o644)),
            FileType::BlockDevice
        );
        assert_eq!(
            inode_file_type(&with_mode(ffs_types::S_IFCHR | 0o644)),
            FileType::CharDevice
        );
    }

    #[test]
    fn ext4_flags_to_xflags_projects_each_flag_exactly() {
        use ffs_types::{
            EXT4_APPEND_FL, EXT4_IMMUTABLE_FL, EXT4_NOATIME_FL, EXT4_NODUMP_FL,
            EXT4_PROJINHERIT_FL, EXT4_SYNC_FL,
        };

        // No flags -> 0, and in particular no HASATTR.
        assert_eq!(ext4_flags_to_xflags(0), 0);

        // Each flag projects to exactly its xflag plus HASATTR.
        let hasattr = xflags::FS_XFLAG_HASATTR;
        assert_eq!(
            ext4_flags_to_xflags(EXT4_IMMUTABLE_FL),
            xflags::FS_XFLAG_IMMUTABLE | hasattr
        );
        assert_eq!(
            ext4_flags_to_xflags(EXT4_APPEND_FL),
            xflags::FS_XFLAG_APPEND | hasattr
        );
        assert_eq!(
            ext4_flags_to_xflags(EXT4_SYNC_FL),
            xflags::FS_XFLAG_SYNC | hasattr
        );
        assert_eq!(
            ext4_flags_to_xflags(EXT4_NOATIME_FL),
            xflags::FS_XFLAG_NOATIME | hasattr
        );
        assert_eq!(
            ext4_flags_to_xflags(EXT4_NODUMP_FL),
            xflags::FS_XFLAG_NODUMP | hasattr
        );
        assert_eq!(
            ext4_flags_to_xflags(EXT4_PROJINHERIT_FL),
            xflags::FS_XFLAG_PROJINHERIT | hasattr
        );

        // All flags together project to the union plus HASATTR.
        let all = EXT4_IMMUTABLE_FL
            | EXT4_APPEND_FL
            | EXT4_SYNC_FL
            | EXT4_NOATIME_FL
            | EXT4_NODUMP_FL
            | EXT4_PROJINHERIT_FL;
        assert_eq!(
            ext4_flags_to_xflags(all),
            xflags::FS_XFLAG_IMMUTABLE
                | xflags::FS_XFLAG_APPEND
                | xflags::FS_XFLAG_SYNC
                | xflags::FS_XFLAG_NOATIME
                | xflags::FS_XFLAG_NODUMP
                | xflags::FS_XFLAG_PROJINHERIT
                | hasattr
        );

        // An ext4 flag with no xflag mapping projects to nothing.
        assert_eq!(ext4_flags_to_xflags(ffs_types::EXT4_EXTENTS_FL), 0);
    }

    #[test]
    fn xflags_to_ext4_flags_validates_preserves_and_clears() {
        use ffs_types::{EXT4_APPEND_FL, EXT4_EXTENTS_FL, EXT4_IMMUTABLE_FL};

        // The output-only HASATTR bit may not be set by userspace -> EINVAL.
        let err = xflags_to_ext4_flags(xflags::FS_XFLAG_HASATTR, 0).unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        // An xflag ext4 does not support (NODEFRAG) -> EOPNOTSUPP.
        let err = xflags_to_ext4_flags(xflags::FS_XFLAG_NODEFRAG, 0).unwrap_err();
        assert_eq!(err.to_errno(), libc::EOPNOTSUPP);

        // Non-user-settable current flags (EXTENTS) are preserved when applying
        // xflags — clobbering them would make the extent tree uninterpretable.
        let result = xflags_to_ext4_flags(xflags::FS_XFLAG_IMMUTABLE, EXT4_EXTENTS_FL).unwrap();
        assert_eq!(result, EXT4_EXTENTS_FL | EXT4_IMMUTABLE_FL);

        // A user-settable flag (APPEND) present in current_flags but absent from
        // the new xflags is cleared, while EXTENTS is still preserved.
        let result =
            xflags_to_ext4_flags(xflags::FS_XFLAG_IMMUTABLE, EXT4_EXTENTS_FL | EXT4_APPEND_FL)
                .unwrap();
        assert_eq!(result, EXT4_EXTENTS_FL | EXT4_IMMUTABLE_FL);
    }

