    // ── OpenFs tests ─────────────────────────────────────────────────────

    /// Byte device wrapping a fixed image that counts scalar `read_exact_at`
    /// calls versus ranged `read_vectored_exact_at` calls. Counters live behind
    /// an `Arc` so the test can read them after the device is moved into
    /// `OpenFs`.
    #[derive(Debug, Default)]
    struct ByteReadCounters {
        scalar: std::sync::atomic::AtomicUsize,
        vectored: std::sync::atomic::AtomicUsize,
    }

    #[derive(Debug)]
    struct CountingByteDevice {
        data: Vec<u8>,
        counters: Arc<ByteReadCounters>,
    }

    impl CountingByteDevice {
        fn new(data: Vec<u8>) -> (Self, Arc<ByteReadCounters>) {
            let counters = Arc::new(ByteReadCounters::default());
            (
                Self {
                    data,
                    counters: Arc::clone(&counters),
                },
                counters,
            )
        }
    }

    impl ByteDevice for CountingByteDevice {
        fn len_bytes(&self) -> u64 {
            self.data.len() as u64
        }
        fn supports_vectored_reads(&self) -> bool {
            true
        }
        fn read_exact_at(
            &self,
            _cx: &Cx,
            offset: ByteOffset,
            buf: &mut [u8],
        ) -> ffs_error::Result<()> {
            self.counters
                .scalar
                .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
            let off = usize::try_from(offset.0).expect("offset fits usize");
            buf.copy_from_slice(&self.data[off..off + buf.len()]);
            Ok(())
        }
        fn read_vectored_exact_at(
            &self,
            _cx: &Cx,
            offset: ByteOffset,
            bufs: &mut [IoSliceMut<'_>],
        ) -> ffs_error::Result<()> {
            self.counters
                .vectored
                .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
            let mut off = usize::try_from(offset.0).expect("offset fits usize");
            for buf in bufs {
                let len = buf.len();
                buf.copy_from_slice(&self.data[off..off + len]);
                off += len;
            }
            Ok(())
        }
        fn write_all_at(
            &self,
            _cx: &Cx,
            _offset: ByteOffset,
            _buf: &[u8],
        ) -> ffs_error::Result<()> {
            Ok(())
        }
        fn sync(&self, _cx: &Cx) -> ffs_error::Result<()> {
            Ok(())
        }
    }

    /// Isomorphism + Score proof for the scoped contiguous-read batching lever:
    /// when a transaction has staged only part of a contiguous range, the prior
    /// path read EVERY base block with a scalar device read; the single-pass
    /// path resolves staged blocks in memory and coalesces base-resident gap
    /// runs into ranged device reads, with byte-identical per-block results.
    #[test]
    fn scoped_contiguous_read_coalesces_base_gaps_score() {
        const BS: usize = 1024;
        const START: u64 = 40;
        const COUNT: usize = 64;
        const STAGED: u64 = 72; // single staged block splitting the range
        let cx = Cx::for_testing();

        let image = build_ext4_image(0); // 1024-byte blocks, 128 blocks
        let (dev, counters) = CountingByteDevice::new(image);
        let fs =
            OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).expect("open ext4");

        let mut txn = fs.begin_transaction();
        txn.stage_write(BlockNumber(STAGED), vec![0xEE_u8; BS]);
        let scope = RequestScope {
            snapshot: None,
            tx: Some(txn),
            commit_mode: RequestCommitMode::PerRequest,
            skip_readdir_prefetch: false,
        };

        // Reference (prior behavior): per-block read_block_with_scope. Reset
        // first so mount-time superblock/metadata reads are not counted.
        counters
            .scalar
            .store(0, std::sync::atomic::Ordering::SeqCst);
        counters
            .vectored
            .store(0, std::sync::atomic::Ordering::SeqCst);
        let reference: Vec<Vec<u8>> = (START..START + COUNT as u64)
            .map(|b| {
                fs.read_block_with_scope(&cx, &scope, BlockNumber(b))
                    .expect("ref read")
            })
            .collect();
        let ref_scalar = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);

        // New: single contiguous read.
        counters
            .scalar
            .store(0, std::sync::atomic::Ordering::SeqCst);
        counters
            .vectored
            .store(0, std::sync::atomic::Ordering::SeqCst);
        let coalesced = fs
            .read_contiguous_blocks_with_scope(&cx, &scope, BlockNumber(START), COUNT)
            .expect("contiguous read");
        let new_scalar = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);
        let new_vectored = counters.vectored.load(std::sync::atomic::Ordering::SeqCst);

        // ISOMORPHISM: byte-identical per block, incl. the staged overlay block.
        assert_eq!(coalesced.len(), COUNT);
        for (i, (a, b)) in reference.iter().zip(coalesced.iter()).enumerate() {
            assert_eq!(a, b, "block {} bytes diverged", START as usize + i);
        }
        assert_eq!(coalesced[(STAGED - START) as usize], vec![0xEE_u8; BS]);

        // GOLDEN: FNV-1a over the concatenated contiguous-read output.
        let mut digest: u64 = 0xcbf2_9ce4_8422_2325;
        for blk in &coalesced {
            for &byte in blk {
                digest ^= u64::from(byte);
                digest = digest.wrapping_mul(0x0000_0100_0000_01b3);
            }
        }
        assert_eq!(
            digest, 12_574_137_928_603_788_069,
            "golden scoped contiguous-read digest changed"
        );

        // SCORE: 63 scalar base reads (one per gap block) → 2 ranged reads.
        assert_eq!(
            ref_scalar, 63,
            "prior path: one scalar base read per gap block"
        );
        assert_eq!(
            new_vectored, 2,
            "two maximal gap runs around the staged block"
        );
        assert_eq!(new_scalar, 0, "no scalar base reads on the coalesced path");
        let read_op_ratio = ref_scalar as f64 / new_vectored as f64;
        assert!(
            read_op_ratio >= 2.0,
            "Score {read_op_ratio} must clear 2.0 ({ref_scalar} -> {new_vectored})"
        );
    }

    #[test]
    fn scoped_contiguous_read_into_coalesces_base_gaps_score_bd_xfdjk() {
        const BS: usize = 1024;
        const START: u64 = 40;
        const COUNT: usize = 64;
        const STAGED: u64 = 72;
        let cx = Cx::for_testing();

        let image = build_ext4_image(0);
        let (dev, counters) = CountingByteDevice::new(image);
        let fs =
            OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).expect("open ext4");

        let mut txn = fs.begin_transaction();
        txn.stage_write(BlockNumber(STAGED), vec![0xEE_u8; BS]);
        let scope = RequestScope {
            snapshot: None,
            tx: Some(txn),
            commit_mode: RequestCommitMode::PerRequest,
            skip_readdir_prefetch: false,
        };

        let reference: Vec<Vec<u8>> = (START..START + COUNT as u64)
            .map(|b| {
                fs.read_block_with_scope(&cx, &scope, BlockNumber(b))
                    .expect("reference read")
            })
            .collect();

        counters
            .scalar
            .store(0, std::sync::atomic::Ordering::SeqCst);
        counters
            .vectored
            .store(0, std::sync::atomic::Ordering::SeqCst);
        let mut direct = vec![0_u8; COUNT * BS];
        fs.read_contiguous_into_with_scope(&cx, &scope, BlockNumber(START), &mut direct)
            .expect("direct contiguous read");
        let new_scalar = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);
        let new_vectored = counters.vectored.load(std::sync::atomic::Ordering::SeqCst);

        for (idx, expected) in reference.iter().enumerate() {
            let actual = &direct[idx * BS..(idx + 1) * BS];
            assert_eq!(
                actual,
                expected,
                "block {} bytes diverged",
                START as usize + idx
            );
        }
        assert_eq!(
            &direct[(STAGED - START) as usize * BS..(STAGED - START + 1) as usize * BS],
            &[0xEE_u8; BS]
        );

        let mut digest: u64 = 0xcbf2_9ce4_8422_2325;
        for &byte in &direct {
            digest ^= u64::from(byte);
            digest = digest.wrapping_mul(0x0000_0100_0000_01b3);
        }
        assert_eq!(
            digest, 12_574_137_928_603_788_069,
            "golden direct-into scoped contiguous-read digest changed"
        );

        assert_eq!(
            new_vectored, 0,
            "direct-into path should not use vectored scatter reads"
        );
        assert_eq!(
            new_scalar, 2,
            "two maximal base-gap runs around the staged block"
        );
        let old_scalar_reads = COUNT - 1;
        let read_op_ratio = old_scalar_reads as f64 / new_scalar as f64;
        assert!(
            read_op_ratio >= 2.0,
            "Score {read_op_ratio} must clear 2.0 ({old_scalar_reads} -> {new_scalar})"
        );
    }

    /// Build a minimal synthetic ext4 image for OpenFs testing.
    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image(block_size_log: u32) -> Vec<u8> {
        let block_size = 1024_u32 << block_size_log;
        let image_size: u32 = 128 * 1024; // 128K
        let mut image = vec![0_u8; image_size as usize];
        let sb_off = EXT4_SUPERBLOCK_OFFSET;

        // magic
        image[sb_off + 0x38..sb_off + 0x3A].copy_from_slice(&EXT4_SUPER_MAGIC.to_le_bytes());
        // log_block_size
        image[sb_off + 0x18..sb_off + 0x1C].copy_from_slice(&block_size_log.to_le_bytes());
        // blocks_count_lo
        let blocks_count = image_size / block_size;
        image[sb_off + 0x04..sb_off + 0x08].copy_from_slice(&blocks_count.to_le_bytes());
        // inodes_count
        image[sb_off..sb_off + 0x04].copy_from_slice(&128_u32.to_le_bytes());
        // first_data_block
        let first_data = u32::from(block_size == 1024);
        image[sb_off + 0x14..sb_off + 0x18].copy_from_slice(&first_data.to_le_bytes());
        // blocks_per_group
        image[sb_off + 0x20..sb_off + 0x24].copy_from_slice(&blocks_count.to_le_bytes());
        // inodes_per_group
        image[sb_off + 0x28..sb_off + 0x2C].copy_from_slice(&128_u32.to_le_bytes());
        // inode_size = 256
        image[sb_off + 0x58..sb_off + 0x5A].copy_from_slice(&256_u16.to_le_bytes());
        // rev_level = 1 (dynamic)
        image[sb_off + 0x4C..sb_off + 0x50].copy_from_slice(&1_u32.to_le_bytes());
        // feature_incompat = FILETYPE | EXTENTS
        let filetype: u32 = 0x0002;
        let extents: u32 = 0x0040;
        image[sb_off + 0x60..sb_off + 0x64].copy_from_slice(&(filetype | extents).to_le_bytes());
        // first_ino
        image[sb_off + 0x54..sb_off + 0x58].copy_from_slice(&11_u32.to_le_bytes());

        image
    }

    fn build_ext4_image_with_mmp(seq: u32) -> Vec<u8> {
        let mut image = build_ext4_image(2);
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        image[sb_off + 0x3A..sb_off + 0x3C].copy_from_slice(&EXT4_VALID_FS.to_le_bytes());

        let mut incompat_bytes = [0_u8; 4];
        incompat_bytes.copy_from_slice(&image[sb_off + 0x60..sb_off + 0x64]);
        let incompat = u32::from_le_bytes(incompat_bytes) | ffs_ondisk::Ext4IncompatFeatures::MMP.0;
        image[sb_off + 0x60..sb_off + 0x64].copy_from_slice(&incompat.to_le_bytes());

        let mmp_block = 8_u64;
        image[sb_off + 0x166..sb_off + 0x168].copy_from_slice(&5_u16.to_le_bytes());
        image[sb_off + 0x168..sb_off + 0x170].copy_from_slice(&mmp_block.to_le_bytes());

        let mmp_offset = usize::try_from(mmp_block * 4096).expect("mmp offset should fit");
        image[mmp_offset..mmp_offset + 4]
            .copy_from_slice(&ffs_ondisk::ext4::EXT4_MMP_MAGIC.to_le_bytes());
        image[mmp_offset + 4..mmp_offset + 8].copy_from_slice(&seq.to_le_bytes());
        image[mmp_offset + 8..mmp_offset + 16].copy_from_slice(&1_700_000_123_u64.to_le_bytes());
        image[mmp_offset + 0x10..mmp_offset + 0x18].copy_from_slice(b"ffs-node");
        image[mmp_offset + 0x50..mmp_offset + 0x5B].copy_from_slice(b"/dev/testfs");
        image[mmp_offset + 0x70..mmp_offset + 0x72].copy_from_slice(&5_u16.to_le_bytes());

        image
    }

    fn find_log_entry<'a>(logs: &'a [Value], message: &str) -> &'a Value {
        let entry = logs
            .iter()
            .find(|entry| entry.get("message").and_then(Value::as_str) == Some(message));
        assert!(
            entry.is_some(),
            "missing log message `{message}` in logs: {logs:?}"
        );
        entry.expect("log entry should exist after assert")
    }

