        assert_eq!(fc.replay.last_tid, 1);
        assert_eq!(fc.replay.operations.len(), 1);
        assert_eq!(fc.replay.incomplete_transactions, 0);
        assert!(!fc.replay.fallback_required);
        assert_eq!(fc.replay.blocks_scanned, 1);
