        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();
        let inode = fs.read_inode(&cx, InodeNumber(2)).unwrap();

        assert!(inode.is_dir());
        assert_eq!(inode.size, 4096);
