    #[test]
    fn lseek_beyond_eof_returns_error() {
        let image = build_ext4_image_with_extents();
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();

        // Get file size.
        let mut scope = RequestScope::empty();
        let attr = fs.getattr(&cx, InodeNumber(11)).unwrap();

        // SEEK_DATA at/beyond EOF must return ENXIO (lseek(2)), not EINVAL.
        let err = fs
            .lseek(
                &cx,
                &mut scope,
                InodeNumber(11),
                attr.size,
                SeekWhence::Data,
            )
            .expect_err("SEEK_DATA at EOF must fail");
        assert_eq!(err.to_errno(), libc::ENXIO);

        // SEEK_HOLE at/beyond EOF must also return ENXIO.
        let err = fs
            .lseek(
                &cx,
                &mut scope,
                InodeNumber(11),
                attr.size,
                SeekWhence::Hole,
            )
            .expect_err("SEEK_HOLE at EOF must fail");
        assert_eq!(err.to_errno(), libc::ENXIO);
    }

    /// Isomorphism guard for bd-62s1d: SEEK_HOLE over a fragmented sparse file
    /// whose extent tree spans multiple leaves must report the exact known hole
    /// positions even though the bounded collection prunes the leaves before the
    /// query offset. Data lives at even blocks, a hole at every odd block.
    #[test]
    fn ext4_lseek_hole_bounded_finds_known_holes_bd_62s1d() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("sparse_holes.bin"), 0o644, 0, 0)
            .expect("create");
        let bs = 4096_u64;
        let block = vec![0xAA_u8; bs as usize];
        // Enough sparse extents to push the extent tree past a single leaf so the
        // from_block prune actually drops leaves for high offsets.
        let n = 400_u32;
        for i in 0..n {
            let off = u64::from(i) * 2 * bs;
            assert_eq!(
                fs.write(&cx, attr.ino, off, &block).expect("write"),
                bs as u32
            );
        }
        let file_size = fs.getattr(&cx, attr.ino).expect("getattr").size;
        let mut scope = RequestScope::empty();
        for i in 0..n {
            let data_byte = u64::from(i) * 2 * bs;
            // From inside data block 2i, the next hole is the odd block right
            // after it (or the virtual EOF hole for the final data block).
            let hole = fs
                .lseek(&cx, &mut scope, attr.ino, data_byte, SeekWhence::Hole)
                .expect("SEEK_HOLE from data");
            assert_eq!(
                hole,
                (data_byte + bs).min(file_size),
                "SEEK_HOLE from data block {i} (offset {data_byte}) must land on the hole after it"
            );
            // From inside the hole block itself, SEEK_HOLE returns the offset.
            let hole_byte = data_byte + bs;
            if hole_byte < file_size {
                let same = fs
                    .lseek(&cx, &mut scope, attr.ino, hole_byte, SeekWhence::Hole)
                    .expect("SEEK_HOLE from hole");
                assert_eq!(
                    same, hole_byte,
                    "SEEK_HOLE inside a hole returns the offset"
                );
            }
        }
    }

    /// Isomorphism guard for bd-v388x: count_extents (sum leaf eh_entries) must
    /// equal collect_extents().len() over a fragmented multi-leaf extent tree.
    #[test]
    fn ext4_count_extents_matches_collect_len_bd_v388x() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("frag_count.bin"), 0o644, 0, 0)
            .expect("create");
        let bs = 4096_u64;
        let block = vec![0xBB_u8; bs as usize];
        let n = 600_u32; // many sparse extents -> tree spans multiple leaves
        for i in 0..n {
            let off = u64::from(i) * 2 * bs;
            fs.write(&cx, attr.ino, off, &block).expect("write");
        }
        let scope = RequestScope::empty();
        let canonical = OpenFs::ext4_canonical_inode(attr.ino);
        let inode = fs
            .read_inode_with_scope(&cx, &scope, canonical)
            .expect("read inode");
        let collected = u32::try_from(fs.collect_extents(&cx, &inode).expect("collect").len())
            .expect("len fits u32");
        let counted = fs.count_extents(&cx, &scope, &inode).expect("count");
        assert_eq!(
            counted, collected,
            "count_extents must equal collect_extents().len()"
        );
        assert!(
            collected >= n,
            "expected at least {n} extents, got {collected}"
        );
    }

    /// Diagnostic A/B for bd-v388x: header-count vs materialize-and-len over a
    /// fragmented file (warm cache). Run with --ignored --nocapture.
    #[test]
    #[ignore = "perf A/B: ext4 count_extents (eh_entries) vs collect_extents().len() (bd-v388x)"]
    fn ext4_count_extents_vs_collect_ab_bd_v388x() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(128) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("frag_ab.bin"), 0o644, 0, 0)
            .expect("create");
        let bs = 4096_u64;
        let block = vec![0xCC_u8; bs as usize];
        let n = 2000_u32;
        for i in 0..n {
            fs.write(&cx, attr.ino, u64::from(i) * 2 * bs, &block)
                .expect("write");
        }
        let scope = RequestScope::empty();
        let canonical = OpenFs::ext4_canonical_inode(attr.ino);
        let inode = fs
            .read_inode_with_scope(&cx, &scope, canonical)
            .expect("read inode");
        // Warm the extent-tree block cache.
        let _ = fs.collect_extents(&cx, &inode).expect("warm");
        let iters = 200usize;
        let mut acc = 0u64;
        let t_count = std::time::Instant::now();
        for _ in 0..iters {
            acc = acc.wrapping_add(u64::from(fs.count_extents(&cx, &scope, &inode).unwrap()));
        }
        let count_ns = t_count.elapsed().as_nanos();
        let t_collect = std::time::Instant::now();
        for _ in 0..iters {
            acc = acc.wrapping_add(fs.collect_extents(&cx, &inode).unwrap().len() as u64);
        }
        let collect_ns = t_collect.elapsed().as_nanos();
        eprintln!(
            "BD_V388X n={n} iters={iters} count_ns={count_ns} collect_ns={collect_ns} score={:.2} (acc={acc})",
            collect_ns as f64 / count_ns.max(1) as f64
        );
    }

