    #[test]
    fn open_fs_fsops_statfs_ext4_aggregates_group_descriptor_counts() {
        let mut image = build_ext4_image_with_dir();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        image[sb_off + 0x08..sb_off + 0x0C].copy_from_slice(&3_u32.to_le_bytes());
        image[sb_off + 0x0C..sb_off + 0x10].copy_from_slice(&63_u32.to_le_bytes());
        image[sb_off + 0x10..sb_off + 0x14].copy_from_slice(&127_u32.to_le_bytes());
        set_group_desc_free_counts(&mut image, 42, 17);
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();
        let sb = fs.ext4_superblock().expect("ext4 superblock");

        let ops: &dyn FsOps = &fs;
        let stats = ops
            .statfs(&cx, &mut RequestScope::empty(), InodeNumber(2))
            .unwrap();
        assert_eq!(stats.block_size, sb.block_size);
        assert_eq!(stats.fragment_size, sb.block_size);
        assert_eq!(stats.blocks, sb.blocks_count);
        assert_eq!(stats.blocks_free, 42);
        assert_eq!(stats.blocks_available, 39);
        assert_eq!(stats.files, u64::from(sb.inodes_count));
        assert_eq!(stats.files_free, 17);
        assert_eq!(stats.name_max, 255);
    }

    #[test]
    fn open_fs_fsops_statfs_ext4_parallel_group_descriptor_sum_matches_serial_bd_xmh5g_196() {
        let mut image = build_ext4_image_with_dir();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        image[sb_off + 0x20..sb_off + 0x24].copy_from_slice(&32_u32.to_le_bytes());
        image[sb_off + 0x28..sb_off + 0x2C].copy_from_slice(&64_u32.to_le_bytes());
        set_group_desc_free_counts_at(&mut image, 0, 11, 7);
        set_group_desc_free_counts_at(&mut image, 1, 31, 13);

        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();
        let sb = fs.ext4_superblock().expect("ext4 superblock");
        let geo = FsGeometry::from_superblock(sb);
        assert_eq!(geo.group_count, 2);

        let serial = fs
            .with_latest_scope(|scope| {
                let mut blocks = 0_u64;
                let mut inodes = 0_u64;
                for g in 0..geo.group_count {
                    let gd = fs.read_group_desc_with_scope(&cx, scope, GroupNumber(g))?;
                    blocks = blocks.saturating_add(u64::from(gd.free_blocks_count));
                    inodes = inodes.saturating_add(u64::from(gd.free_inodes_count));
                }
                Ok((blocks, inodes))
            })
            .expect("serial group descriptor sum");
        let parallel = fs
            .with_latest_scope(|scope| fs.read_only_statfs_group_desc_totals(&cx, scope, sb, &geo))
            .expect("parallel group descriptor sum");
        assert_eq!(parallel, serial);
        assert_eq!(parallel, (42, 20));

        let stats = fs.statfs(&cx, InodeNumber(2)).expect("statfs");
        assert_eq!(stats.blocks_free, 42);
        assert_eq!(stats.files_free, 20);
        assert_eq!(stats.blocks_available, 42);
    }

    #[test]
    fn open_fs_fsops_statfs_btrfs_uses_capacity_fields() {
        let image = build_btrfs_fsops_image();
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();
        let sb = fs.btrfs_superblock().expect("btrfs superblock");
        let unit = sb.sectorsize.max(1);
        let unit_u64 = u64::from(unit);
        let free_bytes = sb.total_bytes.saturating_sub(sb.bytes_used);

        let ops: &dyn FsOps = &fs;
        let stats = ops
            .statfs(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();
        assert_eq!(stats.block_size, unit);
        assert_eq!(stats.fragment_size, unit);
        assert_eq!(stats.blocks, sb.total_bytes / unit_u64);
        assert_eq!(stats.blocks_free, free_bytes / unit_u64);
        assert_eq!(stats.blocks_available, free_bytes / unit_u64);
        assert_eq!(stats.files, 1_000_000_000);
        assert_eq!(stats.files_free, 1_000_000_000);
        assert_eq!(stats.name_max, 255);
    }

    #[test]
    fn open_fs_btrfs_fsops_getattr_lookup_readdir_read() {
        let image = build_btrfs_fsops_image();
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();

        let ops: &dyn FsOps = &fs;

        // Root inode alias: VFS inode 1 should map to btrfs root_dir_objectid.
        let root_attr = ops
            .getattr(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();
        assert_eq!(root_attr.kind, FileType::Directory);
        assert_eq!(root_attr.perm, 0o755);

        let child_attr = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("hello.txt"),
            )
            .unwrap();
        assert_eq!(child_attr.ino, InodeNumber(257));
        assert_eq!(child_attr.kind, FileType::RegularFile);
        assert_eq!(child_attr.size, 22);

        let entries = ops
            .readdir(&cx, &mut RequestScope::empty(), InodeNumber(1), 0)
            .unwrap();
        assert_eq!(entries.len(), 3);
        assert_eq!(entries[0].name, b".");
        assert_eq!(entries[1].name, b"..");
        assert_eq!(entries[2].name, b"hello.txt");

        // Offset pagination should skip "." and ".."
        let paged = ops
            .readdir(&cx, &mut RequestScope::empty(), InodeNumber(1), 2)
            .unwrap();
        assert_eq!(paged.len(), 1);
        assert_eq!(paged[0].name, b"hello.txt");

        let data = ops
            .read(&cx, &mut RequestScope::empty(), InodeNumber(257), 0, 128)
            .unwrap();
        assert_eq!(&data, b"hello from btrfs fsops");
    }

