    #[test]
    fn btrfs_read_beyond_eof_returns_truncated() {
        let image = build_btrfs_fsops_image();
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();

        let ops: &dyn FsOps = &fs;
        // File is 22 bytes. Read 4096 from offset 0 → should get exactly 22 bytes.
        let data = ops
            .read(&cx, &mut RequestScope::empty(), InodeNumber(257), 0, 4096)
            .unwrap();
        assert_eq!(data.len(), 22);
        assert_eq!(&data, b"hello from btrfs fsops");

        // Read from beyond EOF → empty.
        let data = ops
            .read(&cx, &mut RequestScope::empty(), InodeNumber(257), 100, 4096)
            .unwrap();
        assert!(data.is_empty());
    }

    fn btrfs_test_zlib_compress(data: &[u8]) -> Vec<u8> {
        use flate2::Compression;
        use flate2::write::ZlibEncoder;
        use std::io::Write;

        let mut encoder = ZlibEncoder::new(Vec::new(), Compression::default());
        encoder.write_all(data).expect("compress zlib fixture");
        encoder.finish().expect("finish zlib fixture")
    }

    fn btrfs_test_lzo_frame(data: &[u8]) -> Vec<u8> {
        let mut framed = vec![0_u8; 4];
        for chunk in data.chunks(4096) {
            let compressed = lzokay_native::compress(chunk).expect("compress lzo fixture");
            framed.extend_from_slice(
                &u32::try_from(compressed.len())
                    .expect("fixture segment length fits u32")
                    .to_le_bytes(),
            );
            framed.extend_from_slice(&compressed);
        }
        let total_len = u32::try_from(framed.len()).expect("fixture frame length fits u32");
        framed[0..4].copy_from_slice(&total_len.to_le_bytes());
        framed
    }

    #[test]
    fn btrfs_decompress_lzo_accepts_exact_frame_length() {
        let payload = b"btrfs lzo exact decoded length";
        let framed = btrfs_test_lzo_frame(payload);

        let decoded = OpenFs::btrfs_decompress(&framed, 2, payload.len())
            .expect("exact LZO frame should decode");
        assert_eq!(decoded, payload);
    }

    /// btrfs LZO segment headers may not cross a sector boundary: the writer
    /// pads up to LZO_LEN-1 zeros at a sector's end and the reader must skip
    /// them (kernel fs/btrfs/lzo.c). The previous reader packed segments
    /// contiguously and would misread the next header out of the padding —
    /// silently corrupting any multi-segment `compress=lzo` extent. Build a
    /// kernel-valid padded frame (small sector so the pad is exercised
    /// deterministically) and prove it round-trips, and that a contiguous
    /// (no-skip) read fails on the same frame.
    #[test]
    fn btrfs_decompress_lzo_skips_inter_segment_sector_padding() {
        const SECTOR: usize = 64;
        const LZO_LEN: usize = 4;

        // Find a full-sector payload whose LZO segment ends within LZO_LEN-1
        // bytes of the SECTOR boundary, so the writer must pad and the reader
        // must skip. Varying the leading run length (and a tail tweak) sweeps
        // the compressed length until the next header would straddle the
        // boundary. Deterministic — no RNG.
        let mut sector0: Option<Vec<u8>> = None;
        'search: for run in 0..SECTOR {
            for tweak in 0_u8..64 {
                let mut s0 = vec![0xAB_u8; run];
                for i in run..SECTOR {
                    let b = (i as u8).wrapping_mul(197)
                        ^ (i as u8).wrapping_mul(i as u8)
                        ^ tweak
                        ^ 0x5b;
                    s0.push(b);
                }
                let c0 = lzokay_native::compress(&s0).expect("compress lzo sector");
                let after = 4 + LZO_LEN + c0.len(); // total hdr + seg hdr + data
                let left = SECTOR - (after % SECTOR);
                if (1..LZO_LEN).contains(&left) {
                    sector0 = Some(s0);
                    break 'search;
                }
            }
        }
        let sector0 = sector0.expect("must find a pad-forcing sector-0 payload");
        let sector1: Vec<u8> = (0..40_u8).map(|i| i.wrapping_mul(37) ^ 0x91).collect();
        let original: Vec<u8> = sector0.iter().chain(sector1.iter()).copied().collect();

        // Build the kernel-valid frame with the forced inter-segment pad.
        let c0 = lzokay_native::compress(&sector0).expect("compress sector0");
        let c1 = lzokay_native::compress(&sector1).expect("compress sector1");
        let mut frame = vec![0_u8; 4];
        frame.extend_from_slice(&u32::try_from(c0.len()).unwrap().to_le_bytes());
        frame.extend_from_slice(&c0);
        let left = SECTOR - (frame.len() % SECTOR);
        assert!(
            (1..LZO_LEN).contains(&left),
            "fixture must place the next header in a pad zone (left={left})"
        );
        frame.extend(std::iter::repeat_n(0_u8, left)); // sector padding
        frame.extend_from_slice(&u32::try_from(c1.len()).unwrap().to_le_bytes());
        frame.extend_from_slice(&c1);
        let total = u32::try_from(frame.len()).expect("frame len fits u32");
        frame[0..4].copy_from_slice(&total.to_le_bytes());

        let decoded = OpenFs::btrfs_decompress_lzo(&frame, original.len(), SECTOR)
            .expect("padded multi-segment LZO frame decodes");
        assert_eq!(decoded, original, "padded LZO frame must round-trip");

        // A contiguous reader (no sector boundary -> never skips padding)
        // misreads the next header out of the padding zeros and must fail.
        let no_skip = OpenFs::btrfs_decompress_lzo(&frame, original.len(), usize::MAX);
        assert!(
            no_skip.is_err(),
            "a no-skip (contiguous) read must fail on a sector-padded frame"
        );
    }

    #[test]
    fn btrfs_decompress_rejects_oversized_target_before_allocation() {
        let err =
            OpenFs::btrfs_decompress(b"", 1, BTRFS_COMPRESSED_EXTENT_BYTE_LIMIT.saturating_add(1))
                .expect_err("oversized decompression target rejects before decoding");

        assert!(
            matches!(
                err,
                FfsError::Corruption { ref detail, .. }
                    if detail.contains("btrfs decompressed target")
                        && detail.contains("exceeds 128MB limit")
            ),
            "unexpected oversized decompression error: {err:?}"
        );
    }

    #[test]
    fn btrfs_decompress_zlib_short_frame_zero_fills_to_ram_bytes() {
        // Same tail-extent sector-rounding as zstd (bd-pokmq): a short zlib frame
        // zero-fills up to ram_bytes rather than being rejected, matching the kernel.
        let payload = b"short zlib payload";
        let compressed = btrfs_test_zlib_compress(payload);
        let out = OpenFs::btrfs_decompress(&compressed, 1, 4096)
            .expect("short zlib frame zero-fills to ram_bytes");
        assert_eq!(out.len(), 4096, "output padded to ram_bytes");
        assert_eq!(
            &out[..payload.len()],
            payload,
            "frame content preserved at the head"
        );
        assert!(
            out[payload.len()..].iter().all(|&b| b == 0),
            "the bytes past the frame are zero-filled"
        );
    }

    #[test]
    fn btrfs_decompress_zstd_short_frame_zero_fills_to_ram_bytes() {
        // btrfs sector-rounds a file's TAIL compressed extent, so its `ram_bytes`
        // can exceed the zstd frame's actual decompressed length; the kernel
        // decompresses into a zeroed page buffer and leaves the tail (which lies
        // beyond i_size and is never returned) zero. frankenfs must match this to
        // read kernel-written zstd files (bd-pokmq) — the old strict "decoded N but
        // expected M" rejection broke that. Integrity of the compressed bytes is
        // enforced by the csum tree, not by this length check.
        let payload = b"short zstd payload";
        let compressed = zstd::stream::encode_all(&payload[..], 0).expect("compress zstd fixture");
        let out = OpenFs::btrfs_decompress(&compressed, 3, 4096)
            .expect("short zstd frame zero-fills to ram_bytes");
        assert_eq!(out.len(), 4096, "output is padded to ram_bytes");
        assert_eq!(
            &out[..payload.len()],
            payload,
            "frame content preserved at the head"
        );
        assert!(
            out[payload.len()..].iter().all(|&b| b == 0),
            "the bytes past the frame are zero-filled"
        );
    }

    #[test]
    fn btrfs_decompress_zstd_rejects_oversized_frame() {
        // A frame that decodes to MORE than ram_bytes is still rejected: the one-shot
        // decoder writes into a fixed ram_bytes buffer and errors on overflow.
        let payload = vec![0xABu8; 8192];
        let compressed = zstd::stream::encode_all(&payload[..], 0).expect("compress zstd fixture");
        let err = OpenFs::btrfs_decompress(&compressed, 3, 4096)
            .expect_err("oversized zstd output rejects");
        assert!(
            matches!(err, FfsError::Corruption { .. }),
            "unexpected oversized-frame error: {err:?}"
        );
    }

    #[test]
    fn btrfs_decompress_lzo_rejects_truncated_frame() {
        let payload = b"btrfs lzo truncated frame payload";
        let mut framed = btrfs_test_lzo_frame(payload);
        framed.pop();

        let err = OpenFs::btrfs_decompress(&framed, 2, payload.len())
            .expect_err("truncated LZO frame rejects");
        assert!(
            matches!(
                err,
                FfsError::Corruption { ref detail, .. }
                    if detail.contains("btrfs LZO total_len")
            ),
            "unexpected LZO framing error: {err:?}"
        );
    }

