    /// Helper: open the ext4_small test fixture and enable writes.
    ///
    /// Returns None if the fixture doesn't exist (e.g. in minimal CI).
    fn open_writable_ext4() -> Option<OpenFs> {
        let path = std::path::Path::new("tests/fixtures/images/ext4_small.img");
        // Also check from the workspace root
        let path = if path.exists() {
            path.to_path_buf()
        } else {
            let ws = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
                .parent()
                .unwrap()
                .parent()
                .unwrap()
                .join("tests/fixtures/images/ext4_small.img");
            if ws.exists() {
                ws
            } else {
                // No committed fixture (CI / remote-build workers): generate an
                // in-memory ext4 image so the write-path tests that gate on this
                // helper actually run instead of silently skipping (bd-cc6ua).
                // If the format tooling is unavailable the helper still skips.
                return open_writable_ext4_mkfs(64).map(|(fs, _tmp)| fs);
            }
        };
        let cx = Cx::for_testing();
        // Copy the image so we don't mutate the fixture.
        let data = std::fs::read(&path).expect("read fixture");
        let dev = TestDevice::from_vec(data);
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Skip,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some(fs)
    }

    /// Create a fresh ext4 image via `mkfs.ext4` and open it writable.
    ///
    /// Returns `None` if `mkfs.ext4` is not available.
    #[test]
    fn dir_block_checksum_stays_valid_after_create_metadata_csum_bd_gauub() {
        // Latent correctness check: after a directory modification on a
        // metadata_csum filesystem, the modified directory block's CRC32C tail
        // must still verify, or e2fsck flags it (bd-fwph3 class).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (has_csum, seed) = {
            let sb = fs.ext4_superblock().expect("sb");
            (sb.has_metadata_csum(), sb.csum_seed())
        };
        assert!(has_csum, "generated image expected to have metadata_csum");

        fs.create(&cx, root, OsStr::new("file_a.txt"), 0o644, 0, 0)
            .expect("create");

        let root_inode = fs.read_inode(&cx, root).expect("root inode");
        let extents = fs.collect_extents(&cx, &root_inode).expect("root extents");
        let phys = extents
            .iter()
            .find(|e| e.logical_block == 0)
            .expect("root logical block 0")
            .physical_start;
        let block = fs
            .read_block_vec(&cx, BlockNumber(phys))
            .expect("read root dir block");
        ffs_ondisk::verify_dir_block_checksum(&block, seed, 2, root_inode.generation)
            .expect("root dir block checksum must be valid after a create");

        // unlink must also leave the directory block checksum valid.
        fs.unlink(&cx, root, OsStr::new("file_a.txt"))
            .expect("unlink");
        let root_inode2 = fs.read_inode(&cx, root).expect("root inode");
        let extents2 = fs.collect_extents(&cx, &root_inode2).expect("root extents");
        let phys2 = extents2
            .iter()
            .find(|e| e.logical_block == 0)
            .expect("root logical block 0")
            .physical_start;
        let block2 = fs
            .read_block_vec(&cx, BlockNumber(phys2))
            .expect("read root dir block");
        ffs_ondisk::verify_dir_block_checksum(&block2, seed, 2, root_inode2.generation)
            .expect("root dir block checksum must be valid after an unlink");
    }

    #[test]
    fn rename_keeps_dir_block_checksums_valid_bd_x4icj() {
        // Cross-parent directory rename must keep the source parent, target
        // parent, and moved directory's ('..'-updated) dir-block checksums valid
        // on a metadata_csum filesystem (bd-x4icj rename path).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (has_csum, seed) = {
            let sb = fs.ext4_superblock().expect("sb");
            (sb.has_metadata_csum(), sb.csum_seed())
        };
        assert!(has_csum, "generated image expected to have metadata_csum");

        let a = fs
            .mkdir(&cx, root, OsStr::new("a"), 0o755, 0, 0)
            .expect("mkdir a");
        let b = fs
            .mkdir(&cx, root, OsStr::new("b"), 0o755, 0, 0)
            .expect("mkdir b");
        let sub = fs
            .mkdir(&cx, a.ino, OsStr::new("sub"), 0o755, 0, 0)
            .expect("mkdir a/sub");

        fs.rename(&cx, a.ino, OsStr::new("sub"), b.ino, OsStr::new("sub"))
            .expect("cross-parent rename of a directory");

        let check = |ino: InodeNumber| {
            let inode = fs.read_inode(&cx, ino).expect("inode");
            let extents = fs.collect_extents(&cx, &inode).expect("extents");
            let phys = extents
                .iter()
                .find(|e| e.logical_block == 0)
                .expect("logical block 0")
                .physical_start;
            let block = fs
                .read_block_vec(&cx, BlockNumber(phys))
                .expect("read dir block");
            let ino_u32 = u32::try_from(ino.0).unwrap();
            ffs_ondisk::verify_dir_block_checksum(&block, seed, ino_u32, inode.generation)
        };
        check(a.ino).expect("source parent dir block checksum valid after rename");
        check(b.ino).expect("target parent dir block checksum valid after rename");
        check(sub.ino).expect("moved dir '..' block checksum valid after rename");
    }

    #[test]
    fn external_extent_blocks_carry_valid_crc32c_bd_o3wif() {
        // A file whose extent tree spills out of the inode (>4 discontiguous
        // extents -> depth >= 1) writes external index/leaf blocks. On a
        // metadata_csum image each external block must carry a valid CRC32C
        // tail keyed on the owning inode's number + generation, or e2fsck
        // reports the extent block as corrupt (bd-o3wif).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (has_csum, seed, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.has_metadata_csum(),
                sb.csum_seed(),
                u64::from(sb.block_size),
            )
        };
        assert!(has_csum, "generated image expected to have metadata_csum");

        let attr = fs
            .create(&cx, root, OsStr::new("frag.bin"), 0o644, 0, 0)
            .expect("create");
        let file_ino = attr.ino;
        let block = vec![0xAB_u8; usize::try_from(block_size).expect("bs fits usize")];
        // Write 24 single blocks each separated by a one-block hole, forcing 24
        // discontiguous extents — far past the inline root capacity of 4, so the
        // extent tree must grow to depth >= 1 and allocate external blocks.
        for i in 0..24_u64 {
            fs.write(&cx, file_ino, i * 2 * block_size, &block)
                .expect("discontiguous block write");
        }

        let inode = fs.read_inode(&cx, file_ino).expect("read inode");
        let root_bytes = OpenFs::extent_root(&inode);
        let root_depth = u16::from_le_bytes([root_bytes[6], root_bytes[7]]);
        assert!(
            root_depth >= 1,
            "test must exercise an external (depth>=1) extent tree, got depth {root_depth}"
        );

        // Collect the physical block numbers of every external node reachable
        // from the inline root, walking index nodes recursively.
        let child_block = |node: &[u8], i: usize| -> u64 {
            let off = 12 + i * 12;
            let lo =
                u32::from_le_bytes([node[off + 4], node[off + 5], node[off + 6], node[off + 7]]);
            let hi = u16::from_le_bytes([node[off + 8], node[off + 9]]);
            u64::from(lo) | (u64::from(hi) << 32)
        };
        let entries_of =
            |node: &[u8]| -> usize { usize::from(u16::from_le_bytes([node[2], node[3]])) };

        let mut stack: Vec<u64> = (0..entries_of(&root_bytes))
            .map(|i| child_block(&root_bytes, i))
            .collect();
        let mut external = Vec::new();
        while let Some(blk) = stack.pop() {
            external.push(blk);
            let bytes = fs
                .read_block_vec(&cx, BlockNumber(blk))
                .expect("read external block");
            let depth = u16::from_le_bytes([bytes[6], bytes[7]]);
            if depth >= 1 {
                for i in 0..entries_of(&bytes) {
                    stack.push(child_block(&bytes, i));
                }
            }
        }
        assert!(
            !external.is_empty(),
            "depth>=1 tree must reference at least one external block"
        );

        let file_ino_u32 = u32::try_from(file_ino.0).expect("ino fits u32");
        for blk in external {
            let bytes = fs
                .read_block_vec(&cx, BlockNumber(blk))
                .expect("read external block");
            ffs_ondisk::verify_extent_block_checksum(&bytes, seed, file_ino_u32, inode.generation)
                .unwrap_or_else(|e| {
                    panic!("external extent block {blk} has invalid CRC32C tail: {e:?}")
                });
        }
    }

    /// Splice a fabricated htree (dx-indexed) directory onto `dir_ino`, replacing
    /// its linear blocks with `htree_blocks` (block 0 = dx_root, 1.. = leaves) and
    /// setting `EXT4_INDEX_FL`. FrankenFS cannot yet *build* htree directories
    /// (bd-rzq1y), so end-to-end htree-write tests fabricate one with
    /// `ffs_ondisk::build_htree_directory_stamped` and install it here.
    #[allow(clippy::significant_drop_tightening)]
    fn install_htree_dir(fs: &OpenFs, cx: &Cx, dir_ino: InodeNumber, htree_blocks: &[Vec<u8>]) {
        let mut inode = fs.read_inode(cx, dir_ino).expect("read dir inode");
        let extents = fs.collect_extents(cx, &inode).expect("collect dir extents");
        let block0_phys = extents
            .iter()
            .find(|e| e.logical_block == 0)
            .expect("dir logical block 0")
            .physical_start;
        let block_size = u64::from(fs.ext4_superblock().expect("sb").block_size);

        let block_dev = fs.block_device_adapter();
        block_dev
            .write_block(cx, BlockNumber(block0_phys), &htree_blocks[0])
            .expect("write dx_root over block 0");

        let dir_ino_u32 = u32::try_from(dir_ino.0).expect("ino fits u32");
        let generation = inode.generation;
        let mut root_bytes = OpenFs::extent_root(&inode);
        {
            let alloc_mutex = fs.require_alloc_state().expect("alloc state");
            let mut alloc = alloc_mutex.write();
            for (i, blk) in htree_blocks.iter().enumerate().skip(1) {
                let Ext4AllocState {
                    geo,
                    groups,
                    persist_ctx,
                } = &mut *alloc;
                let ba = ffs_alloc::alloc_blocks_persist(
                    cx,
                    &block_dev,
                    geo,
                    groups,
                    1,
                    &AllocHint::default(),
                    persist_ctx,
                )
                .expect("alloc leaf block");
                block_dev
                    .write_block(cx, ba.start, blk)
                    .expect("write leaf block");
                let extent = Ext4Extent {
                    logical_block: u32::try_from(i).expect("logical fits u32"),
                    raw_len: 1,
                    physical_start: ba.start.0,
                };
                let mut tree_alloc = ffs_extent::GroupBlockAllocator {
                    cx,
                    dev: &block_dev,
                    geo,
                    groups,
                    hint: AllocHint::default(),
                    pctx: persist_ctx,
                    ino: dir_ino_u32,
                    generation,
                };
                ffs_btree::insert(cx, &block_dev, &mut root_bytes, extent, &mut tree_alloc)
                    .expect("insert leaf extent");
            }
        }
        OpenFs::set_extent_root(&mut inode, &root_bytes);
        inode.flags |= ffs_types::EXT4_INDEX_FL;
        inode.size = u64::try_from(htree_blocks.len()).unwrap() * block_size;
        fs.persist_ext4_inode_for_testing(cx, dir_ino, &inode)
            .expect("persist htree dir inode");
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn create_in_htree_dir_preserves_index_and_finds_new_entry_bd_wb4cd() {
        // End-to-end proof of the bd-wb4cd routing fix: creating a file in a real
        // htree directory must (a) leave the dx_root index intact (not the prior
        // dx-root-overwriting corruption) and (b) place the new entry in its
        // hash-correct leaf so htree_find_entry reaches it via the index.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, has_large_dir, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.has_large_dir(),
                // Build with the effective (signed/unsigned-resolved) version so
                // the fabricated hashes match what the fs computes on lookup; the
                // effective versions are fixed points of effective_dirhash_version.
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let dir = fs
            .mkdir(&cx, root, OsStr::new("bigdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;

        // Fabricate a real dx_root + multi-leaf htree (300 entries).
        let names: Vec<Vec<u8>> = (0..300)
            .map(|i| format!("file_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    1000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(
            blocks.len() >= 3,
            "need dx_root + multiple leaves, got {}",
            blocks.len()
        );
        install_htree_dir(&fs, &cx, dir_ino, &blocks);

        let find = |name: &[u8]| -> ffs_ondisk::HtreeFindResult {
            ffs_ondisk::htree_find_entry(
                u32::try_from(block_size).unwrap(),
                &hash_seed,
                has_large_dir,
                name,
                |v| v,
                |lb| {
                    let inode = fs.read_inode(&cx, dir_ino).ok()?;
                    let exts = fs.collect_extents(&cx, &inode).ok()?;
                    let phys = exts.iter().find_map(|e| {
                        let len = u32::from(e.actual_len());
                        if lb >= e.logical_block && lb < e.logical_block + len {
                            Some(e.physical_start + u64::from(lb - e.logical_block))
                        } else {
                            None
                        }
                    })?;
                    fs.read_block_vec(&cx, BlockNumber(phys)).ok()
                },
            )
        };

        assert!(
            fs.read_inode(&cx, dir_ino).unwrap().has_htree_index(),
            "installed dir must be htree-indexed"
        );
        assert!(
            matches!(
                find(b"file_0100.txt"),
                ffs_ondisk::HtreeFindResult::Found(_)
            ),
            "pre-existing entry must be index-reachable before the create"
        );

        // Operation under test: create a NEW file in the htree directory.
        let created = fs
            .create(&cx, dir_ino, OsStr::new("zzz_new_entry.bin"), 0o644, 0, 0)
            .expect("create in htree dir must succeed without corrupting the index");

        // (a) dx_root (block 0) still parses as a valid index — NOT overwritten.
        let block0_phys = {
            let di = fs.read_inode(&cx, dir_ino).unwrap();
            fs.collect_extents(&cx, &di)
                .unwrap()
                .iter()
                .find(|e| e.logical_block == 0)
                .unwrap()
                .physical_start
        };
        let dxr = fs.read_block_vec(&cx, BlockNumber(block0_phys)).unwrap();
        let parsed = ffs_ondisk::parse_dx_root(&dxr)
            .expect("dx_root must still parse after the create (no corruption)");
        assert!(
            !parsed.entries.is_empty(),
            "dx_root index entries must survive the create"
        );

        // (b) the new entry is reachable VIA THE INDEX (hash-correct leaf).
        match find(b"zzz_new_entry.bin") {
            ffs_ondisk::HtreeFindResult::Found(e) => {
                assert_eq!(e.inode, u32::try_from(created.ino.0).unwrap());
            }
            other => panic!("new htree entry must be index-reachable, got {other:?}"),
        }
        // (c) a pre-existing entry remains index-reachable.
        assert!(
            matches!(
                find(b"file_0100.txt"),
                ffs_ondisk::HtreeFindResult::Found(_)
            ),
            "pre-existing entry must remain index-reachable after the create"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn fast_commit_create_apply_into_htree_dir_bd_w6fxn() {
        // bd-w6fxn: a fast-committed create whose parent is an htree (large)
        // directory. CREAT recovery must descend the DX index and splice the new
        // entry into the hash-correct leaf — reaching realistic directories the
        // linear path skips — keeping the index consistent (no dx surgery).
        //
        // The apply is a recovery (from_device) operation: it reads the device
        // directly, not the MVCC overlay. So we build the htree dir on a writable
        // fs, flush it to the device, then REOPEN from_device and run the apply
        // there (mirroring a real post-crash mount).
        let Some((fs, dev, _tmp)) = open_writable_ext4_mkfs_with_device(16) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, has_large_dir, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.has_large_dir(),
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let dir = fs
            .mkdir(&cx, root, OsStr::new("bigdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;

        // A real target inode the recovered entry will point at (CREAT reads its
        // mode for the dir-entry file type).
        let target = fs
            .create(&cx, root, OsStr::new("target.bin"), 0o644, 0, 0)
            .expect("create target file");
        let target_ino_u32 = u32::try_from(target.ino.0).unwrap();

        // Fabricate the htree blocks now (needs the dir generation). Keep the
        // entry count small so the leaf the name hashes to always has ample room
        // — mkfs picks a RANDOM hash seed each run, so a near-full multi-leaf
        // layout would make the (no-split) recovery apply flakily hit a full
        // leaf. A small dir is still genuinely htree-indexed (dx_root + leaf).
        let names: Vec<Vec<u8>> = (0..20)
            .map(|i| format!("file_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    1000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(blocks.len() >= 2, "need dx_root + at least one leaf");

        // Land the MVCC writes (mkdir/create) on the device FIRST, then install
        // the htree blocks directly (so the direct dir-inode write is not later
        // clobbered by a flush of the pre-htree MVCC dir inode).
        fs.flush_mvcc_to_device(&cx).expect("flush mvcc");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);

        // Reopen from the device so reads ARE the device (not the MVCC overlay).
        // Skip journal replay: install_htree_dir's direct, non-journaled writes
        // would otherwise be clobbered by replaying the pre-htree committed
        // journal transactions (a flaky-under-parallelism failure depending on
        // whether the flush left a pending transaction).
        let reopen_opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Skip,
            ..OpenOptions::default()
        };
        let fs2 = OpenFs::from_device(
            &cx,
            Box::new(TestDevice::from_vec(dev.snapshot_bytes())),
            &reopen_opts,
        )
        .expect("reopen ext4 from device");
        let find = |name: &[u8]| -> ffs_ondisk::HtreeFindResult {
            ffs_ondisk::htree_find_entry(
                u32::try_from(block_size).unwrap(),
                &hash_seed,
                has_large_dir,
                name,
                |v| v,
                |lb| {
                    let inode = fs2.read_inode(&cx, dir_ino).ok()?;
                    let exts = fs2.collect_extents(&cx, &inode).ok()?;
                    let phys = exts.iter().find_map(|e| {
                        let len = u32::from(e.actual_len());
                        if lb >= e.logical_block && lb < e.logical_block + len {
                            Some(e.physical_start + u64::from(lb - e.logical_block))
                        } else {
                            None
                        }
                    })?;
                    fs2.read_block_vec(&cx, BlockNumber(phys)).ok()
                },
            )
        };

        assert!(
            fs2.read_inode(&cx, dir_ino).unwrap().has_htree_index(),
            "installed dir must be htree-indexed on the device"
        );
        assert!(
            matches!(
                find(b"file_0005.txt"),
                ffs_ondisk::HtreeFindResult::Found(_)
            ),
            "pre-existing entry must be index-reachable before recovery"
        );
        assert!(
            matches!(
                find(b"zzz_recovered.bin"),
                ffs_ondisk::HtreeFindResult::NotFoundInIndex
            ),
            "the recovered name must be absent before recovery"
        );

        // Operation under test: recover the fast-committed CREAT.
        let dentry = ffs_journal::FcDentry {
            parent_ino: dir_ino_u32,
            ino: target_ino_u32,
            name: b"zzz_recovered.bin".to_vec(),
        };
        let applied = fs2
            .apply_fast_commit_add_dentry(&cx, &dentry)
            .expect("apply htree create");
        assert!(applied, "entry should splice into the hash-correct leaf");

        // (a) the recovered entry is reachable VIA THE INDEX (hash-correct leaf).
        match find(b"zzz_recovered.bin") {
            ffs_ondisk::HtreeFindResult::Found(e) => assert_eq!(e.inode, target_ino_u32),
            other => panic!("recovered htree entry must be index-reachable, got {other:?}"),
        }
        // (b) dx_root still parses (the index was not corrupted).
        let block0_phys = {
            let di = fs2.read_inode(&cx, dir_ino).unwrap();
            fs2.collect_extents(&cx, &di)
                .unwrap()
                .iter()
                .find(|e| e.logical_block == 0)
                .unwrap()
                .physical_start
        };
        let dxr = fs2.read_block_vec(&cx, BlockNumber(block0_phys)).unwrap();
        let parsed = ffs_ondisk::parse_dx_root(&dxr).expect("dx_root must still parse");
        assert!(!parsed.entries.is_empty(), "dx_root index must survive");
        // (c) a pre-existing entry remains index-reachable.
        assert!(
            matches!(
                find(b"file_0005.txt"),
                ffs_ondisk::HtreeFindResult::Found(_)
            ),
            "pre-existing entry must remain index-reachable after recovery"
        );
    }

    /// Corruption-critical gate (bd-owt2r / bd-vsuni): inserting a NON-ASCII name
    /// into a CASEFOLD htree directory must be REFUSED, never silently inserted.
    /// FrankenFS's non-ASCII fold diverges from the kernel's NFD-normalized
    /// casefold, so it cannot compute the fold-correct dx leaf — writing the entry
    /// anyway would place it in the WRONG leaf, where the kernel's own (correct-
    /// fold) descent would never find it (silent data loss). This pins the refusal
    /// on every insertion entry point — create / link / rename, all of which route
    /// through ext4_add_dir_entry — and that a refused op leaves NO partial entry.
    /// Previously only the ASCII-create success path was covered. Remove these
    /// asserts when byte-exact UTF-8 normalization lands (bd-vsuni).
    #[test]
    fn casefold_htree_rejects_non_ascii_insert_bd_owt2r() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return; // mkfs.ext4 unavailable
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        // Build an htree-indexed directory and mark it casefold.
        let dir = fs
            .mkdir(&cx, root, OsStr::new("casedir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;
        let names: Vec<Vec<u8>> = (0..30)
            .map(|i| format!("file_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    1000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);
        {
            let mut inode = fs.read_inode(&cx, dir_ino).expect("read dir inode");
            inode.flags |= ffs_types::EXT4_CASEFOLD_FL;
            fs.persist_ext4_inode_for_testing(&cx, dir_ino, &inode)
                .expect("set casefold flag");
        }
        assert!(
            fs.read_inode(&cx, dir_ino)
                .expect("re-read")
                .has_htree_index(),
            "the casefold test dir must be htree-indexed for the gate to apply"
        );

        // café.txt — the 'é' (U+00E9) makes this non-ASCII.
        let non_ascii = OsStr::new("café.txt");

        // create: refused, with no partial entry left behind.
        let create_res = fs.create(&cx, dir_ino, non_ascii, 0o644, 0, 0);
        assert!(
            create_res.is_err(),
            "non-ASCII create in a casefold htree dir must be refused, got {create_res:?}"
        );
        assert!(
            fs.lookup(&cx, dir_ino, non_ascii).is_err(),
            "a refused non-ASCII create must not leave a partial dir entry (silent corruption)"
        );

        // link: same gate.
        let target = fs
            .create(&cx, root, OsStr::new("linktgt.txt"), 0o644, 0, 0)
            .expect("create link target");
        let link_res = fs.link(&cx, target.ino, dir_ino, OsStr::new("résumé"));
        assert!(
            link_res.is_err(),
            "non-ASCII link into a casefold htree dir must be refused, got {link_res:?}"
        );

        // rename: move an ASCII file in root to a non-ASCII name in the casefold dir.
        fs.create(&cx, root, OsStr::new("mover.txt"), 0o644, 0, 0)
            .expect("create mover");
        let rename_res = fs.rename(
            &cx,
            root,
            OsStr::new("mover.txt"),
            dir_ino,
            OsStr::new("naïve.txt"),
        );
        assert!(
            rename_res.is_err(),
            "non-ASCII rename into a casefold htree dir must be refused, got {rename_res:?}"
        );
        // The source name must survive a refused rename (no half-applied move).
        assert!(
            fs.lookup(&cx, root, OsStr::new("mover.txt")).is_ok(),
            "a refused rename must leave the source entry intact"
        );

        // SAME-PARENT rename to a non-ASCII name (within the casefold dir itself):
        // an ASCII file already living in the casefold dir, renamed to a non-ASCII
        // name in place, must also refuse atomically — the gate lives in the shared
        // preflight, so it fires regardless of whether the parents differ.
        fs.create(&cx, dir_ino, OsStr::new("inplace.txt"), 0o644, 0, 0)
            .expect("create ascii file inside casefold dir");
        let same_parent_res = fs.rename(
            &cx,
            dir_ino,
            OsStr::new("inplace.txt"),
            dir_ino,
            OsStr::new("élan.txt"),
        );
        assert!(
            same_parent_res.is_err(),
            "non-ASCII same-parent rename in a casefold htree dir must be refused, got {same_parent_res:?}"
        );
        assert!(
            fs.lookup(&cx, dir_ino, OsStr::new("inplace.txt")).is_ok(),
            "a refused same-parent rename must leave the source entry intact"
        );
    }

    /// A non-ASCII create/mkdir into a casefold htree dir is refused by the gate
    /// INSIDE ext4_add_dir_entry — i.e. AFTER the new inode is already allocated.
    /// The op must then roll back that allocation (ext4_create/ext4_mkdir call
    /// delete_inode on the add failure) or it leaks an inode. The existing
    /// rollback test triggers failure via an invalid name, which fails in
    /// validate_single_path_component BEFORE any allocation, so it never exercises
    /// this post-allocation rollback path. This pins it: the free-inode count must
    /// be identical before and after the refused create AND the refused mkdir
    /// (16 MiB image == one block group, so the group-0 count is the whole fs).
    #[test]
    fn casefold_htree_refused_insert_rolls_back_inode_alloc_bd_owt2r() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return; // mkfs.ext4 unavailable
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };
        let dir = fs
            .mkdir(&cx, root, OsStr::new("casedir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;
        let names: Vec<Vec<u8>> = (0..30)
            .map(|i| format!("file_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    1000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);
        {
            let mut inode = fs.read_inode(&cx, dir_ino).expect("read dir inode");
            inode.flags |= ffs_types::EXT4_CASEFOLD_FL;
            fs.persist_ext4_inode_for_testing(&cx, dir_ino, &inode)
                .expect("set casefold flag");
        }

        let free_before = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count");

        // Refused non-ASCII create — the gate fires after create_inode allocated
        // the inode, so the create must delete_inode to roll it back.
        let create_res = fs.create(&cx, dir_ino, OsStr::new("café.txt"), 0o644, 0, 0);
        assert!(create_res.is_err(), "non-ASCII create must be refused");
        let free_after_create = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count");
        assert_eq!(
            free_after_create, free_before,
            "a refused casefold create must roll back (free) its allocated inode, not leak it"
        );

        // Refused non-ASCII mkdir — same post-allocation rollback (a directory
        // inode also charges used_dirs, which delete_inode must release).
        let mkdir_res = fs.mkdir(&cx, dir_ino, OsStr::new("ÜberDir"), 0o755, 0, 0);
        assert!(mkdir_res.is_err(), "non-ASCII mkdir must be refused");
        let free_after_mkdir = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count");
        assert_eq!(
            free_after_mkdir, free_before,
            "a refused casefold mkdir must roll back (free) its allocated inode, not leak it"
        );
    }

    /// bd-owt2r (insert side, end-to-end): creating an ASCII-named file in a
    /// CASEFOLD htree directory now succeeds (was UnsupportedFeature) and places
    /// the entry in the fold-correct leaf, so a case-insensitive lookup finds it.
    #[test]
    #[allow(clippy::too_many_lines)]
    fn create_in_casefold_htree_dir_finds_new_entry_via_fold_bd_owt2r() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, has_large_dir, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.has_large_dir(),
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let dir = fs
            .mkdir(&cx, root, OsStr::new("casedir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;

        // A casefold dir hashes by the folded name. Build the index from LOWERCASE
        // names so the stored hashes equal the kernel's casefold (ASCII) hashes.
        // Keep the count modest so leaves retain free space — this exercises the
        // common non-full-leaf insert (the leaf-full casefold rebuild is deferred).
        let names: Vec<Vec<u8>> = (0..30)
            .map(|i| format!("file_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    1000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(blocks.len() >= 2, "need dx_root + at least one leaf");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);

        // Mark the directory casefold.
        {
            let mut inode = fs.read_inode(&cx, dir_ino).expect("read dir inode");
            inode.flags |= ffs_types::EXT4_CASEFOLD_FL;
            fs.persist_ext4_inode_for_testing(&cx, dir_ino, &inode)
                .expect("set casefold flag");
        }

        let find_casefold = |name: &[u8]| -> ffs_ondisk::HtreeFindResult {
            ffs_ondisk::htree_find_entry_casefold(
                u32::try_from(block_size).unwrap(),
                &hash_seed,
                has_large_dir,
                name,
                |v| v,
                |lb| {
                    let inode = fs.read_inode(&cx, dir_ino).ok()?;
                    let exts = fs.collect_extents(&cx, &inode).ok()?;
                    let phys = exts.iter().find_map(|e| {
                        let len = u32::from(e.actual_len());
                        if lb >= e.logical_block && lb < e.logical_block + len {
                            Some(e.physical_start + u64::from(lb - e.logical_block))
                        } else {
                            None
                        }
                    })?;
                    fs.read_block_vec(&cx, BlockNumber(phys)).ok()
                },
            )
        };

        // A pre-existing entry is reachable via a CASE-VARIANT (uppercase) query.
        assert!(
            matches!(
                find_casefold(b"FILE_0010.TXT"),
                ffs_ondisk::HtreeFindResult::Found(_)
            ),
            "case-variant lookup of a pre-existing casefold entry must hit the index"
        );

        // Operation under test: create a file with an UPPERCASE name in the
        // casefold dir (previously returned UnsupportedFeature).
        let created = fs
            .create(&cx, dir_ino, OsStr::new("ZZZ_NEW_ENTRY.BIN"), 0o644, 0, 0)
            .expect("create in casefold htree dir must now succeed");

        // The new entry is reachable via the folded (lowercase) query through the
        // index — i.e. it was placed in the fold-correct leaf.
        match find_casefold(b"zzz_new_entry.bin") {
            ffs_ondisk::HtreeFindResult::Found(e) => {
                assert_eq!(e.inode, u32::try_from(created.ino.0).unwrap());
                assert_eq!(e.name, b"ZZZ_NEW_ENTRY.BIN", "original case is stored");
            }
            other => panic!("new casefold entry must be index-reachable, got {other:?}"),
        }

        // dx_root still parses (index not corrupted).
        let block0_phys = {
            let di = fs.read_inode(&cx, dir_ino).unwrap();
            fs.collect_extents(&cx, &di)
                .unwrap()
                .iter()
                .find(|e| e.logical_block == 0)
                .unwrap()
                .physical_start
        };
        let dxr = fs.read_block_vec(&cx, BlockNumber(block0_phys)).unwrap();
        assert!(
            !ffs_ondisk::parse_dx_root(&dxr)
                .expect("dx_root parses")
                .entries
                .is_empty(),
            "dx_root index must survive the casefold create"
        );
    }

    /// bd-4y9ca regression guard: ext4 inline-data DIRECTORY operations must fail
    /// loudly (UnsupportedFeature / Err), never silently see an empty/block-mapped
    /// directory. FrankenFS has no inline-directory parser; a silent empty readdir
    /// would let rmdir drop a non-empty inline dir, and a silent insert would
    /// overwrite the inline entries with a fresh extent root — both data loss. This
    /// pins the comprehensive guard coverage across readdir/lookup/create/unlink/rmdir
    /// so a future dir-op path cannot regress it.
    #[test]
    fn inline_data_directory_ops_fail_loudly_not_silently_bd_4y9ca() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let dir = fs
            .mkdir(&cx, root, OsStr::new("inlinedir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        // A real child so that a "silently empty" view would be an observable
        // data-loss bug (rmdir would think the dir is empty and drop it).
        fs.create(&cx, dir_ino, OsStr::new("child.txt"), 0o644, 0, 0)
            .expect("create child");

        // Mark the directory inline-data, as a kernel-created inline dir would be.
        {
            let mut inode = fs.read_inode(&cx, dir_ino).expect("read dir inode");
            inode.flags |= ffs_types::EXT4_INLINE_DATA_FL;
            inode.flags &= !ffs_types::EXT4_COMPR_FL;
            fs.persist_ext4_inode_for_testing(&cx, dir_ino, &inode)
                .expect("mark inline-data");
        }
        let inline_inode = fs.read_inode(&cx, dir_ino).expect("reread dir inode");

        // readdir / lookup must reject rather than return an empty / not-found view.
        assert!(
            matches!(
                fs.read_dir(&cx, &inline_inode),
                Err(FfsError::UnsupportedFeature(_))
            ),
            "inline-dir readdir must fail loudly, not return an empty listing"
        );
        assert!(
            matches!(
                fs.lookup_name(&cx, &inline_inode, b"child.txt"),
                Err(FfsError::UnsupportedFeature(_))
            ),
            "inline-dir lookup must fail loudly"
        );
        // create / unlink / rmdir must all error, never silently mutate a block view.
        assert!(
            fs.create(&cx, dir_ino, OsStr::new("new.txt"), 0o644, 0, 0)
                .is_err(),
            "create into an inline dir must fail, not overwrite the inline entries"
        );
        assert!(
            fs.unlink(&cx, dir_ino, OsStr::new("child.txt")).is_err(),
            "unlink from an inline dir must fail"
        );
        assert!(
            fs.rmdir(&cx, root, OsStr::new("inlinedir")).is_err(),
            "rmdir of a (non-empty) inline dir must fail, not silently drop it"
        );
    }

    /// The readdir snapshot must never serve a stale listing after a rename moves
    /// an entry OUT of the directory — even if the rename does not bump the source
    /// directory's timestamps (which the snapshot's self-validation keys on).
    #[test]
    fn readdir_snapshot_reflects_rename_out_of_source_dir() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let a = fs
            .mkdir(&cx, root, OsStr::new("A"), 0o755, 0, 0)
            .unwrap()
            .ino;
        let b = fs
            .mkdir(&cx, root, OsStr::new("B"), 0o755, 0, 0)
            .unwrap()
            .ino;
        fs.create(&cx, a, OsStr::new("x.txt"), 0o644, 0, 0).unwrap();

        // Populate A's readdir snapshot.
        let before = fs.readdir(&cx, a, 0).unwrap();
        assert!(
            before.iter().any(|e| e.name == b"x.txt"),
            "x.txt must be listed before the rename"
        );

        // Move x.txt out of A into B.
        fs.rename(&cx, a, OsStr::new("x.txt"), b, OsStr::new("x.txt"))
            .unwrap();

        // A must no longer list x.txt (no stale snapshot).
        let after = fs.readdir(&cx, a, 0).unwrap();
        assert!(
            !after.iter().any(|e| e.name == b"x.txt"),
            "readdir of the source dir must not show an entry renamed out of it"
        );
        // And B must now list it.
        let blist = fs.readdir(&cx, b, 0).unwrap();
        assert!(
            blist.iter().any(|e| e.name == b"x.txt"),
            "renamed entry must appear in the destination dir"
        );
    }

    /// Paginated readdir must read+parse the directory ONCE and serve later pages
    /// from the snapshot, not re-parse the whole dir per page (O(N) vs O(N^2)),
    /// while producing byte-identical entries; a mutation invalidates the snapshot.
    #[test]
    fn readdir_pagination_serves_pages_from_one_parse_not_quadratic() {
        use std::sync::atomic::Ordering::SeqCst;
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let dir = fs
            .mkdir(&cx, root, OsStr::new("bigdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let n = 50usize;
        for i in 0..n {
            fs.create(&cx, dir_ino, OsStr::new(&format!("f{i:04}")), 0o644, 0, 0)
                .expect("create entry");
        }

        // One full read builds the snapshot; every paginated page is then served
        // from it (the prior behaviour re-parsed the whole dir on each page).
        fs.readdir_full_reads.store(0, SeqCst);
        let full = fs.readdir(&cx, dir_ino, 0).expect("readdir full");
        assert!(
            full.len() >= n,
            "directory must list all {n} entries (+ '.' '..')"
        );

        let page = 7usize;
        let mut collected: Vec<DirEntry> = Vec::new();
        let mut off = 0u64;
        loop {
            let chunk = fs.readdir(&cx, dir_ino, off).expect("readdir page");
            if chunk.is_empty() {
                break;
            }
            let take: Vec<DirEntry> = chunk.iter().take(page).cloned().collect();
            off = take.last().expect("non-empty page").offset;
            collected.extend(take);
            if collected.len() >= full.len() {
                break;
            }
        }

        // ISOMORPHISM: the paginated listing equals the single full listing.
        assert_eq!(
            collected, full,
            "paginated readdir must equal the full listing"
        );

        // SCORE: one full parse served the full read + all paginated pages; the
        // prior per-call rescan would have parsed once per call.
        let pages = (full.len()).div_ceil(page);
        assert!(
            pages >= 3,
            "need several pages for a meaningful score (got {pages})"
        );
        assert_eq!(
            fs.readdir_full_reads.load(SeqCst),
            1,
            "snapshot must serve {pages}+ pages from a single directory parse"
        );

        // A mutation invalidates the snapshot (forces a fresh parse) and the new
        // entry is visible.
        fs.create(&cx, dir_ino, OsStr::new("zzz_new"), 0o644, 0, 0)
            .expect("create after listing");
        fs.readdir_full_reads.store(0, SeqCst);
        let after = fs.readdir(&cx, dir_ino, 0).expect("readdir after mutation");
        assert_eq!(
            fs.readdir_full_reads.load(SeqCst),
            1,
            "a directory mutation must invalidate the snapshot"
        );
        assert!(
            after.iter().any(|e| e.name == b"zzz_new"),
            "newly created entry must appear after snapshot invalidation"
        );
    }

    /// A FrankenFS-created (initially linear) directory must auto-convert to an
    /// htree once it outgrows linear blocks (when the fs has dir_index, like the
    /// kernel), so mass-create is O(N) (htree + doubling rebuilds) and lookups are
    /// O(log N) — not O(blocks). Every entry stays findable across the conversion.
    #[test]
    #[allow(clippy::too_many_lines)]
    fn fresh_linear_dir_auto_converts_to_htree_on_overflow() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(32) else {
            return;
        };
        let cx = Cx::for_testing();
        // The conversion only applies when the filesystem supports hash indexing.
        let has_dir_index = fs
            .ext4_superblock()
            .is_some_and(|sb| sb.has_compat(ffs_ondisk::ext4::Ext4CompatFeatures::DIR_INDEX));
        if !has_dir_index {
            return;
        }
        let root = InodeNumber(2);
        let dir = fs
            .mkdir(&cx, root, OsStr::new("growdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        assert!(
            !fs.read_inode(&cx, dir_ino).unwrap().has_htree_index(),
            "a freshly created directory must start linear (no htree index)"
        );

        // Create enough files to overflow the initial linear block(s) and trigger
        // the linear -> htree conversion.
        let n = 400usize;
        for i in 0..n {
            let nm = format!("f{i:05}.dat");
            fs.create(&cx, dir_ino, OsStr::new(&nm), 0o644, 0, 0)
                .unwrap_or_else(|e| panic!("create {nm} must succeed: {e:?}"));
        }

        // The directory must now be hash-indexed (auto-converted), with a valid
        // dx_root, and every entry must remain findable.
        assert!(
            fs.read_inode(&cx, dir_ino).unwrap().has_htree_index(),
            "directory must auto-convert to htree once it overflows linear blocks"
        );
        let block0_phys = {
            let di = fs.read_inode(&cx, dir_ino).unwrap();
            fs.collect_extents(&cx, &di)
                .unwrap()
                .iter()
                .find(|e| e.logical_block == 0)
                .unwrap()
                .physical_start
        };
        let dxr = fs.read_block_vec(&cx, BlockNumber(block0_phys)).unwrap();
        assert!(
            !ffs_ondisk::parse_dx_root(&dxr)
                .expect("converted block 0 must parse as a dx_root")
                .entries
                .is_empty(),
            "converted dx_root must index at least one leaf"
        );

        let listing = fs.readdir(&cx, dir_ino, 0).expect("readdir");
        let names: std::collections::HashSet<Vec<u8>> =
            listing.iter().map(|e| e.name.clone()).collect();
        for i in 0..n {
            let nm = format!("f{i:05}.dat").into_bytes();
            assert!(
                names.contains(&nm),
                "entry {i} missing from converted htree dir"
            );
        }
        // A direct lookup must also resolve through the new index.
        assert!(
            fs.lookup(&cx, dir_ino, OsStr::new("f00200.dat")).is_ok(),
            "lookup must resolve via the converted htree index"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn many_creates_in_htree_dir_trigger_rebuild_and_keep_all_findable_bd_rzq1y() {
        // Filling a hash-target leaf forces ext4_rebuild_htree_dir (bd-rzq1y).
        // After many creates the directory must have grown new blocks (only the
        // rebuild path allocates for an htree dir) and EVERY entry — original and
        // newly created — must remain reachable via the index in its hash-correct
        // leaf, with the dx_root still valid.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(32) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, has_large_dir, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.has_large_dir(),
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let dir = fs
            .mkdir(&cx, root, OsStr::new("growdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;

        let orig_names: Vec<Vec<u8>> = (0..200)
            .map(|i| format!("orig_{i:04}.txt").into_bytes())
            .collect();
        let orig_entries: Vec<(u32, u8, &[u8])> = orig_names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    5000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &orig_entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(blocks.len() >= 2, "need a dx_root + at least one leaf");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);
        let initial_size = fs.read_inode(&cx, dir_ino).unwrap().size;

        // Create enough new files to overflow leaves. With the bd-gauub
        // incremental leaf-split fast path each overflow now splits ONE full leaf
        // (O(log N)) instead of rebuilding the whole index, so the overflow is
        // serviced by `htree_leaf_splits`, not `htree_rebuilds`.
        fs.htree_rebuilds
            .store(0, std::sync::atomic::Ordering::SeqCst);
        fs.htree_leaf_splits
            .store(0, std::sync::atomic::Ordering::SeqCst);
        let mut new_names: Vec<Vec<u8>> = Vec::new();
        for i in 0..600 {
            let nm = format!("created_{i:04}.dat");
            fs.create(&cx, dir_ino, OsStr::new(&nm), 0o644, 0, 0)
                .unwrap_or_else(|e| panic!("create {nm} must succeed: {e:?}"));
            new_names.push(nm.into_bytes());
        }

        // The directory must have grown — both the split and the rebuild paths
        // allocate blocks for an htree dir, so growth proves the overflow path ran.
        let final_size = fs.read_inode(&cx, dir_ino).unwrap().size;
        assert!(
            final_size > initial_size,
            "htree dir must have grown via leaf split: {initial_size} -> {final_size}"
        );

        // SCORE (bd-gauub): the overflow is serviced by INCREMENTAL leaf splits,
        // not full rebuilds. The single-level fast path handles every overflow
        // here (the dx_root has ample room for ~50 leaves at this block size), so
        // the rebuild path must NOT run, and the split path must run repeatedly —
        // each split is O(log N), making the whole create burst O(N log N) rather
        // than the O(N^2) the per-create full rebuild would cost.
        let rebuilds = fs.htree_rebuilds.load(std::sync::atomic::Ordering::SeqCst);
        let leaf_splits = fs
            .htree_leaf_splits
            .load(std::sync::atomic::Ordering::SeqCst);
        assert!(
            leaf_splits > 0,
            "the incremental leaf-split fast path must have run at least once"
        );
        assert_eq!(
            rebuilds, 0,
            "single-level overflow must split incrementally, not rebuild (got {rebuilds} rebuilds, {leaf_splits} splits)"
        );

        let find = |name: &[u8]| -> ffs_ondisk::HtreeFindResult {
            ffs_ondisk::htree_find_entry(
                u32::try_from(block_size).unwrap(),
                &hash_seed,
                has_large_dir,
                name,
                |v| v,
                |lb| {
                    let inode = fs.read_inode(&cx, dir_ino).ok()?;
                    let exts = fs.collect_extents(&cx, &inode).ok()?;
                    let phys = exts.iter().find_map(|e| {
                        let len = u32::from(e.actual_len());
                        if lb >= e.logical_block && lb < e.logical_block + len {
                            Some(e.physical_start + u64::from(lb - e.logical_block))
                        } else {
                            None
                        }
                    })?;
                    fs.read_block_vec(&cx, BlockNumber(phys)).ok()
                },
            )
        };

        // Every created entry is reachable via the index in its hash-correct leaf.
        for nm in &new_names {
            assert!(
                matches!(find(nm), ffs_ondisk::HtreeFindResult::Found(_)),
                "created entry {:?} must be index-reachable after rebuild",
                String::from_utf8_lossy(nm)
            );
        }
        // A sample of the original entries survived the rebuild(s).
        for i in (0..200).step_by(17) {
            let nm = format!("orig_{i:04}.txt").into_bytes();
            assert!(
                matches!(find(&nm), ffs_ondisk::HtreeFindResult::Found(_)),
                "original entry {:?} must survive the rebuild(s)",
                String::from_utf8_lossy(&nm)
            );
        }
        // dx_root (block 0) is still a valid index.
        let block0_phys = {
            let di = fs.read_inode(&cx, dir_ino).unwrap();
            fs.collect_extents(&cx, &di)
                .unwrap()
                .iter()
                .find(|e| e.logical_block == 0)
                .unwrap()
                .physical_start
        };
        let dxr = fs.read_block_vec(&cx, BlockNumber(block0_phys)).unwrap();
        let parsed =
            ffs_ondisk::parse_dx_root(&dxr).expect("dx_root must still parse after rebuilds");
        assert!(
            !parsed.entries.is_empty(),
            "dx_root index must be populated"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn cross_parent_rename_of_htree_dir_keeps_dx_root_valid_bd_0h5jy() {
        // Moving an htree directory to a new parent updates its '..'. That entry
        // lives in the dx_root (logical block 0); the update must repoint '..' in
        // place and re-stamp the DX-root checksum — not rewrite it as a linear
        // block with the regular dir-block checksum (which left it e2fsck-dirty).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(32) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, has_large_dir, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.has_large_dir(),
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let src = fs
            .mkdir(&cx, root, OsStr::new("src"), 0o755, 0, 0)
            .expect("mkdir src");
        let dst = fs
            .mkdir(&cx, root, OsStr::new("dst"), 0o755, 0, 0)
            .expect("mkdir dst");
        let big = fs
            .mkdir(&cx, src.ino, OsStr::new("big"), 0o755, 0, 0)
            .expect("mkdir src/big");
        let big_ino = big.ino;
        let big_ino_u32 = u32::try_from(big_ino.0).unwrap();
        let generation = fs.read_inode(&cx, big_ino).expect("read big").generation;

        // Fabricate a real htree directory for `big`.
        let names: Vec<Vec<u8>> = (0..250)
            .map(|i| format!("kid_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    9000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            big_ino_u32,
            u32::try_from(src.ino.0).unwrap(),
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            big_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(blocks.len() >= 3, "need dx_root + multiple leaves");
        install_htree_dir(&fs, &cx, big_ino, &blocks);
        assert!(
            fs.read_inode(&cx, big_ino).unwrap().has_htree_index(),
            "big must be htree-indexed"
        );

        // Cross-parent rename: src/big -> dst/big.
        fs.rename(&cx, src.ino, OsStr::new("big"), dst.ino, OsStr::new("big"))
            .expect("cross-parent rename of an htree directory");

        // The moved dir's block 0 is still a valid dx_root with a valid DX
        // checksum, and '..' now points to dst.
        let inode = fs.read_inode(&cx, big_ino).expect("reread big");
        let exts = fs.collect_extents(&cx, &inode).expect("extents");
        let block0_phys = exts
            .iter()
            .find(|e| e.logical_block == 0)
            .expect("logical 0")
            .physical_start;
        let dxr = fs
            .read_block_vec(&cx, BlockNumber(block0_phys))
            .expect("read dx_root");
        assert!(
            ffs_ondisk::verify_dx_block_checksum(
                &dxr,
                csum_seed,
                big_ino_u32,
                generation,
                ffs_ondisk::DX_ROOT_COUNT_OFFSET,
            ),
            "moved htree dir's dx_root checksum must be valid after rename"
        );
        let dotdot = u32::from_le_bytes([dxr[12], dxr[13], dxr[14], dxr[15]]);
        assert_eq!(
            u64::from(dotdot),
            dst.ino.0,
            "moved dir '..' must point to the new parent"
        );

        // The index still navigates: a sample child remains reachable.
        let find = ffs_ondisk::htree_find_entry(
            u32::try_from(block_size).unwrap(),
            &hash_seed,
            has_large_dir,
            b"kid_0100.txt",
            |v| v,
            |lb| {
                let exts = fs.collect_extents(&cx, &inode).ok()?;
                let phys = exts.iter().find_map(|e| {
                    let len = u32::from(e.actual_len());
                    if lb >= e.logical_block && lb < e.logical_block + len {
                        Some(e.physical_start + u64::from(lb - e.logical_block))
                    } else {
                        None
                    }
                })?;
                fs.read_block_vec(&cx, BlockNumber(phys)).ok()
            },
        );
        assert!(
            matches!(find, ffs_ondisk::HtreeFindResult::Found(_)),
            "moved htree dir must remain index-navigable"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn create_then_unlink_in_htree_dir_keeps_index_consistent() {
        // Unlink from an htree directory must remove the entry from its leaf
        // (restamping that leaf) without touching or invalidating the dx_root,
        // and the removed name must no longer resolve via the index while
        // siblings still do.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(32) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, has_large_dir, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.has_large_dir(),
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let dir = fs
            .mkdir(&cx, root, OsStr::new("htdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;

        let names: Vec<Vec<u8>> = (0..250)
            .map(|i| format!("seed_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    7000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(blocks.len() >= 3, "need dx_root + multiple leaves");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);

        let find = |name: &[u8]| -> ffs_ondisk::HtreeFindResult {
            ffs_ondisk::htree_find_entry(
                u32::try_from(block_size).unwrap(),
                &hash_seed,
                has_large_dir,
                name,
                |v| v,
                |lb| {
                    let inode = fs.read_inode(&cx, dir_ino).ok()?;
                    let exts = fs.collect_extents(&cx, &inode).ok()?;
                    let phys = exts.iter().find_map(|e| {
                        let len = u32::from(e.actual_len());
                        if lb >= e.logical_block && lb < e.logical_block + len {
                            Some(e.physical_start + u64::from(lb - e.logical_block))
                        } else {
                            None
                        }
                    })?;
                    fs.read_block_vec(&cx, BlockNumber(phys)).ok()
                },
            )
        };

        // Create a real file (real inode so unlink can decrement its link count).
        let created = fs
            .create(&cx, dir_ino, OsStr::new("victim.bin"), 0o644, 0, 0)
            .expect("create victim");
        assert!(
            matches!(find(b"victim.bin"), ffs_ondisk::HtreeFindResult::Found(_)),
            "victim must be index-reachable after create"
        );

        // Unlink it.
        fs.unlink(&cx, dir_ino, OsStr::new("victim.bin"))
            .expect("unlink victim from htree dir");

        // The victim no longer resolves via the index; a seed sibling still does.
        assert!(
            !matches!(find(b"victim.bin"), ffs_ondisk::HtreeFindResult::Found(_)),
            "victim must not resolve via the index after unlink (it was {:?})",
            created.ino
        );
        assert!(
            matches!(
                find(b"seed_0100.txt"),
                ffs_ondisk::HtreeFindResult::Found(_)
            ),
            "sibling entries must remain index-reachable after the unlink"
        );

        // The dx_root (block 0) is untouched and still valid.
        let block0_phys = {
            let di = fs.read_inode(&cx, dir_ino).unwrap();
            fs.collect_extents(&cx, &di)
                .unwrap()
                .iter()
                .find(|e| e.logical_block == 0)
                .unwrap()
                .physical_start
        };
        let dxr = fs.read_block_vec(&cx, BlockNumber(block0_phys)).unwrap();
        assert!(
            ffs_ondisk::verify_dx_block_checksum(
                &dxr,
                csum_seed,
                dir_ino_u32,
                generation,
                ffs_ondisk::DX_ROOT_COUNT_OFFSET,
            ),
            "dx_root checksum must remain valid across an unlink"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn link_and_rename_into_htree_dir_place_entries_in_index() {
        // Hard-linking and renaming a file INTO an htree directory both route
        // through ext4_add_dir_entry, so the new names must land in their
        // hash-correct leaf (index-reachable) and the dx_root must stay valid.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(32) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, has_large_dir, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.has_large_dir(),
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let dir = fs
            .mkdir(&cx, root, OsStr::new("htdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;

        let names: Vec<Vec<u8>> = (0..250)
            .map(|i| format!("base_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    8000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(blocks.len() >= 3, "need dx_root + multiple leaves");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);

        let find = |name: &[u8]| -> ffs_ondisk::HtreeFindResult {
            ffs_ondisk::htree_find_entry(
                u32::try_from(block_size).unwrap(),
                &hash_seed,
                has_large_dir,
                name,
                |v| v,
                |lb| {
                    let inode = fs.read_inode(&cx, dir_ino).ok()?;
                    let exts = fs.collect_extents(&cx, &inode).ok()?;
                    let phys = exts.iter().find_map(|e| {
                        let len = u32::from(e.actual_len());
                        if lb >= e.logical_block && lb < e.logical_block + len {
                            Some(e.physical_start + u64::from(lb - e.logical_block))
                        } else {
                            None
                        }
                    })?;
                    fs.read_block_vec(&cx, BlockNumber(phys)).ok()
                },
            )
        };

        // Hard-link an existing file into the htree dir.
        let src = fs
            .create(&cx, root, OsStr::new("orig.bin"), 0o644, 0, 0)
            .expect("create source file");
        fs.link(&cx, src.ino, dir_ino, OsStr::new("hardlink.bin"))
            .expect("hard-link into htree dir");
        assert!(
            matches!(find(b"hardlink.bin"), ffs_ondisk::HtreeFindResult::Found(_)),
            "hard-linked name must be index-reachable in the htree dir"
        );

        // Rename a file from root into the htree dir.
        let mover = fs
            .create(&cx, root, OsStr::new("mover.bin"), 0o644, 0, 0)
            .expect("create mover");
        fs.rename(
            &cx,
            root,
            OsStr::new("mover.bin"),
            dir_ino,
            OsStr::new("moved.bin"),
        )
        .expect("rename into htree dir");
        match find(b"moved.bin") {
            ffs_ondisk::HtreeFindResult::Found(e) => {
                assert_eq!(e.inode, u32::try_from(mover.ino.0).unwrap());
            }
            other => panic!("renamed-in name must be index-reachable, got {other:?}"),
        }

        // dx_root remains valid after both index insertions.
        let block0_phys = {
            let di = fs.read_inode(&cx, dir_ino).unwrap();
            fs.collect_extents(&cx, &di)
                .unwrap()
                .iter()
                .find(|e| e.logical_block == 0)
                .unwrap()
                .physical_start
        };
        let dxr = fs.read_block_vec(&cx, BlockNumber(block0_phys)).unwrap();
        assert!(
            ffs_ondisk::verify_dx_block_checksum(
                &dxr,
                csum_seed,
                dir_ino_u32,
                generation,
                ffs_ondisk::DX_ROOT_COUNT_OFFSET,
            ),
            "dx_root checksum must stay valid across link + rename-in"
        );
    }

    #[test]
    fn readdir_and_lookup_work_on_htree_dir() {
        // The read paths must traverse an htree directory: read_dir parses every
        // block (including the dx_root at block 0) and lookup falls back to a
        // linear scan over block 0 — neither may choke on the dx_root's
        // index-spanning '..' the way the write-path add_entry did.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(32) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (csum_seed, hash_seed, hash_version, block_size) = {
            let sb = fs.ext4_superblock().expect("sb");
            (
                sb.csum_seed(),
                sb.hash_seed,
                sb.effective_dirhash_version(sb.def_hash_version),
                usize::try_from(sb.block_size).unwrap(),
            )
        };

        let dir = fs
            .mkdir(&cx, root, OsStr::new("htdir"), 0o755, 0, 0)
            .expect("mkdir");
        let dir_ino = dir.ino;
        let dir_ino_u32 = u32::try_from(dir_ino.0).unwrap();
        let generation = fs.read_inode(&cx, dir_ino).expect("read dir").generation;

        let names: Vec<Vec<u8>> = (0..250)
            .map(|i| format!("entry_{i:04}.txt").into_bytes())
            .collect();
        let entries: Vec<(u32, u8, &[u8])> = names
            .iter()
            .enumerate()
            .map(|(i, n)| {
                (
                    6000 + u32::try_from(i).unwrap(),
                    ffs_ondisk::ext4::EXT4_FT_REG_FILE,
                    n.as_slice(),
                )
            })
            .collect();
        let blocks = ffs_ondisk::build_htree_directory_stamped(
            dir_ino_u32,
            2,
            &entries,
            block_size,
            hash_version,
            &hash_seed,
            csum_seed,
            dir_ino_u32,
            generation,
        )
        .expect("build htree");
        assert!(blocks.len() >= 3, "need dx_root + multiple leaves");
        install_htree_dir(&fs, &cx, dir_ino, &blocks);

        // read_dir must enumerate every entry (plus '.'/'..') without choking on
        // the dx_root.
        let inode = fs.read_inode(&cx, dir_ino).expect("reread");
        let listed = fs.read_dir(&cx, &inode).expect("read_dir on htree dir");
        let real: std::collections::BTreeSet<Vec<u8>> = listed
            .iter()
            .map(|e| e.name.clone())
            .filter(|n| n != b"." && n != b"..")
            .collect();
        assert_eq!(
            real.len(),
            names.len(),
            "read_dir must enumerate every htree entry exactly once"
        );
        for n in &names {
            assert!(
                real.contains(n),
                "read_dir missing {:?}",
                String::from_utf8_lossy(n)
            );
        }

        // lookup_name must resolve a sample entry (via index or linear fallback).
        let hit = fs
            .lookup_name(&cx, &inode, b"entry_0137.txt")
            .expect("lookup_name on htree dir must not error");
        assert!(
            hit.is_some(),
            "lookup_name must find an existing htree entry"
        );
        let miss = fs
            .lookup_name(&cx, &inode, b"does_not_exist.txt")
            .expect("lookup_name miss must not error");
        assert!(
            miss.is_none(),
            "lookup_name must report a real miss as None"
        );
    }

    #[test]
    fn inline_data_directory_operations_fail_loudly_bd_4y9ca() {
        // FrankenFS has no inline-directory parser, so directory ops on an
        // EXT4_INLINE_DATA_FL inode must return a clean UnsupportedFeature error
        // rather than silently reading an empty dir (which would let rmdir drop a
        // non-empty dir) or overwriting the inline entries on insert (data loss).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let dir = fs
            .mkdir(&cx, root, OsStr::new("inlinedir"), 0o755, 0, 0)
            .expect("mkdir");

        // Flag the directory inode as inline_data (mirrors an inline_data image).
        let mut inode = fs.read_inode(&cx, dir.ino).expect("read inode");
        inode.flags |= ffs_types::EXT4_INLINE_DATA_FL;
        inode.flags &= !ffs_types::EXT4_COMPR_FL;
        fs.persist_ext4_inode_for_testing(&cx, dir.ino, &inode)
            .expect("persist inline flag");

        let reread = fs.read_inode(&cx, dir.ino).expect("reread");
        assert!(
            matches!(
                fs.read_dir(&cx, &reread),
                Err(FfsError::UnsupportedFeature(_))
            ),
            "read_dir on an inline_data dir must fail loudly, not return empty"
        );
        assert!(
            matches!(
                fs.lookup_name(&cx, &reread, b"anything"),
                Err(FfsError::UnsupportedFeature(_))
            ),
            "lookup on an inline_data dir must fail loudly"
        );
        assert!(
            fs.create(&cx, dir.ino, OsStr::new("newfile.txt"), 0o644, 0, 0)
                .is_err(),
            "create in an inline_data dir must fail, not lose the inline entries"
        );
    }

    #[test]
    fn encrypted_file_content_io_fails_loudly_bd_4sfty() {
        // FrankenFS has no fscrypt support, so read/write/fallocate on an
        // encrypted file must fail loudly rather than return raw ciphertext
        // (read) or store plaintext into the encrypted blocks (write/corruption).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("secret.bin"), 0o644, 0, 0)
            .expect("create");
        // Give the file an extent root + a small write before flagging it
        // encrypted, so the guard (not some other path) is what rejects.
        fs.write(&cx, attr.ino, 0, b"plaintext")
            .expect("seed write");

        // Flag the inode encrypted (EXT4_ENCRYPT_INODE_FL = 0x0000_0800).
        let mut inode = fs.read_inode(&cx, attr.ino).expect("read inode");
        inode.flags |= 0x0000_0800;
        fs.persist_ext4_inode_for_testing(&cx, attr.ino, &inode)
            .expect("persist encrypt flag");
        assert!(
            fs.read_inode(&cx, attr.ino).unwrap().is_encrypted(),
            "inode must now be flagged encrypted"
        );

        assert!(
            matches!(
                fs.read(&cx, attr.ino, 0, 16),
                Err(FfsError::UnsupportedFeature(_))
            ),
            "reading an encrypted file must fail, not return ciphertext as plaintext"
        );
        assert!(
            matches!(
                fs.write(&cx, attr.ino, 0, b"newdata"),
                Err(FfsError::UnsupportedFeature(_))
            ),
            "writing an encrypted file must fail, not store plaintext into encrypted blocks"
        );
        assert!(
            fs.fallocate(&cx, attr.ino, 0, 4096, 0).is_err(),
            "fallocate on an encrypted file must fail"
        );
    }

    #[test]
    fn verity_file_content_mutation_rejected_bd_yz6c6() {
        // FrankenFS has no fs-verity support; mutating a verity file's content
        // would break its Merkle tree, so write/fallocate/truncate must be
        // rejected. Reads stay allowed (FrankenFS returns the raw data).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("sealed.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, b"sealed contents")
            .expect("seed write before sealing");

        // Flag the inode fs-verity (EXT4_VERITY_FL).
        let mut inode = fs.read_inode(&cx, attr.ino).expect("read inode");
        inode.flags |= ffs_types::EXT4_VERITY_FL;
        fs.persist_ext4_inode_for_testing(&cx, attr.ino, &inode)
            .expect("persist verity flag");

        assert!(
            fs.write(&cx, attr.ino, 0, b"tamper").is_err(),
            "writing a verity file must be rejected"
        );
        assert!(
            fs.fallocate(&cx, attr.ino, 0, 4096, 0).is_err(),
            "fallocate on a verity file must be rejected"
        );
        let trunc = SetAttrRequest {
            size: Some(0),
            ..SetAttrRequest::default()
        };
        assert!(
            fs.setattr(&cx, attr.ino, &trunc).is_err(),
            "truncating a verity file must be rejected"
        );
        // Reads remain allowed.
        assert!(
            fs.read(&cx, attr.ino, 0, 8).is_ok(),
            "reading a verity file must still succeed"
        );
    }

    #[test]
    fn ext4_checked_inode_blocks_after_cluster_rewrite_scales_by_huge_flag() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let ino = InodeNumber(2); // root
        let mut inode = fs.read_inode(&cx, ino).expect("read root inode");
        inode.blocks = 100;

        // added_data=3 + added_meta=1 = 4 total added, freed=1 -> net 3 blocks.
        // Non-HUGE: i_blocks is in 512-byte sectors, so scale by block_size/512.
        inode.flags &= !ffs_types::EXT4_HUGE_FILE_FL;
        let spb = u64::from(fs.block_size() / 512);
        let result = fs
            .ext4_checked_inode_blocks_after_cluster_rewrite(&inode, ino, 3, 1, 1, "test")
            .expect("non-huge delta");
        assert_eq!(result, 100 + 3 * spb);

        // HUGE_FILE: i_blocks is in filesystem blocks, so the net delta applies
        // directly without sector scaling.
        inode.flags |= ffs_types::EXT4_HUGE_FILE_FL;
        let result = fs
            .ext4_checked_inode_blocks_after_cluster_rewrite(&inode, ino, 3, 1, 1, "test")
            .expect("huge delta");
        assert_eq!(result, 100 + 3);
    }

    #[test]
    fn immutable_and_append_attributes_enforced_on_writes_bd_hbld5() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let set_flag = |ino: InodeNumber, flag: u32| {
            let mut inode = fs.read_inode(&cx, ino).expect("read inode");
            inode.flags &= !(ffs_types::EXT4_IMMUTABLE_FL | ffs_types::EXT4_APPEND_FL);
            inode.flags |= flag;
            fs.persist_ext4_inode_for_testing(&cx, ino, &inode)
                .expect("persist flag");
        };

        // ── Immutable: every content mutation must be rejected. ──
        let imm = fs
            .create(&cx, root, OsStr::new("imm.bin"), 0o644, 0, 0)
            .expect("create imm");
        fs.write(&cx, imm.ino, 0, b"hello world")
            .expect("seed write");
        set_flag(imm.ino, ffs_types::EXT4_IMMUTABLE_FL);
        assert!(
            fs.write(&cx, imm.ino, 0, b"nope").is_err(),
            "write to an immutable file must be rejected"
        );
        assert!(
            fs.fallocate(&cx, imm.ino, 0, 4096, 0).is_err(),
            "fallocate on an immutable file must be rejected"
        );
        let trunc = SetAttrRequest {
            size: Some(0),
            ..SetAttrRequest::default()
        };
        assert!(
            fs.setattr(&cx, imm.ino, &trunc).is_err(),
            "truncate of an immutable file must be rejected"
        );

        // ── Append-only: appends at EOF allowed; overwrite/shrink rejected. ──
        let app = fs
            .create(&cx, root, OsStr::new("app.bin"), 0o644, 0, 0)
            .expect("create app");
        fs.write(&cx, app.ino, 0, b"0123456789")
            .expect("seed write");
        let size = fs.read_inode(&cx, app.ino).unwrap().size;
        set_flag(app.ino, ffs_types::EXT4_APPEND_FL);
        assert!(
            fs.write(&cx, app.ino, 0, b"x").is_err(),
            "non-append (offset < EOF) write to an append-only file must be rejected"
        );
        fs.write(&cx, app.ino, size, b"appended")
            .expect("append at EOF must succeed on an append-only file");
        let shrink = SetAttrRequest {
            size: Some(1),
            ..SetAttrRequest::default()
        };
        assert!(
            fs.setattr(&cx, app.ino, &shrink).is_err(),
            "shrinking an append-only file must be rejected"
        );
    }

    #[test]
    fn immutable_and_append_attributes_enforced_on_metadata_ops_bd_hbld5() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let set_flag = |ino: InodeNumber, flag: u32| {
            let mut inode = fs.read_inode(&cx, ino).expect("read inode");
            inode.flags &= !(ffs_types::EXT4_IMMUTABLE_FL | ffs_types::EXT4_APPEND_FL);
            inode.flags |= flag;
            fs.persist_ext4_inode_for_testing(&cx, ino, &inode)
                .expect("persist flag");
        };

        // Immutable: delete, rename, link, and xattr-set all rejected.
        let imm = fs
            .create(&cx, root, OsStr::new("imm.bin"), 0o644, 0, 0)
            .expect("create imm");
        set_flag(imm.ino, ffs_types::EXT4_IMMUTABLE_FL);
        assert!(
            fs.unlink(&cx, root, OsStr::new("imm.bin")).is_err(),
            "deleting an immutable file must be rejected"
        );
        assert!(
            fs.rename(
                &cx,
                root,
                OsStr::new("imm.bin"),
                root,
                OsStr::new("imm2.bin")
            )
            .is_err(),
            "renaming an immutable file must be rejected"
        );
        assert!(
            fs.link(&cx, imm.ino, root, OsStr::new("imm_link.bin"))
                .is_err(),
            "hard-linking an immutable file must be rejected"
        );
        assert!(
            fs.setxattr(&cx, imm.ino, "user.x", b"v", XattrSetMode::Set)
                .is_err(),
            "setting an xattr on an immutable file must be rejected"
        );
        let chmod = SetAttrRequest {
            mode: Some(0o600),
            ..SetAttrRequest::default()
        };
        assert!(
            fs.setattr(&cx, imm.ino, &chmod).is_err(),
            "chmod of an immutable file must be rejected"
        );
        let chown = SetAttrRequest {
            uid: Some(1234),
            ..SetAttrRequest::default()
        };
        assert!(
            fs.setattr(&cx, imm.ino, &chown).is_err(),
            "chown of an immutable file must be rejected"
        );

        // Append-only: delete, rename, and hard-link rejected. The kernel's
        // vfs_link forbids a link to an append-only file too (bd-69ich).
        let app = fs
            .create(&cx, root, OsStr::new("app.bin"), 0o644, 0, 0)
            .expect("create app");
        set_flag(app.ino, ffs_types::EXT4_APPEND_FL);
        assert!(
            fs.unlink(&cx, root, OsStr::new("app.bin")).is_err(),
            "deleting an append-only file must be rejected"
        );
        assert!(
            fs.rename(
                &cx,
                root,
                OsStr::new("app.bin"),
                root,
                OsStr::new("app2.bin")
            )
            .is_err(),
            "renaming an append-only file must be rejected"
        );
        assert_eq!(
            fs.link(&cx, app.ino, root, OsStr::new("app_link.bin"))
                .unwrap_err()
                .to_errno(),
            libc::EPERM,
            "hard-linking an append-only file must be EPERM (vfs_link)"
        );
        assert_eq!(
            fs.setxattr(&cx, app.ino, "user.x", b"v", XattrSetMode::Set)
                .unwrap_err()
                .to_errno(),
            libc::EPERM,
            "setxattr on an append-only file must be EPERM (xattr_permission, bd-kf7uw)"
        );
    }

    #[test]
    fn ext4_rename_onto_immutable_target_is_eperm_bd_85rav() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        fs.create(&cx, root, OsStr::new("rsrc.bin"), 0o644, 0, 0)
            .expect("create src");
        let dst = fs
            .create(&cx, root, OsStr::new("rdst.bin"), 0o644, 0, 0)
            .expect("create dst");
        // Make the rename victim immutable.
        let mut di = fs.read_inode(&cx, dst.ino).expect("read dst inode");
        di.flags |= ffs_types::EXT4_IMMUTABLE_FL;
        persist_ext4_test_inode(&fs, &cx, dst.ino, &di);

        // vfs_rename's may_delete(victim) forbids clobbering an immutable target.
        assert_eq!(
            fs.rename(
                &cx,
                root,
                OsStr::new("rsrc.bin"),
                root,
                OsStr::new("rdst.bin")
            )
            .unwrap_err()
            .to_errno(),
            libc::EPERM,
            "renaming onto an immutable target must be EPERM (bd-85rav)"
        );
        // No partial mutation: both names still resolve.
        assert!(
            fs.lookup(&cx, root, OsStr::new("rsrc.bin")).is_ok(),
            "source must survive a rejected rename"
        );
        assert!(
            fs.lookup(&cx, root, OsStr::new("rdst.bin")).is_ok(),
            "immutable target must survive a rejected rename"
        );
    }

    fn open_writable_ext4_mkfs(size_mb: u64) -> Option<(OpenFs, tempfile::TempDir)> {
        let tmp = tempfile::TempDir::new().expect("tmpdir");
        let image = tmp.path().join("test.ext4");
        let f = std::fs::File::create(&image).expect("create image");
        f.set_len(size_mb * 1024 * 1024).expect("set image size");
        drop(f);

        let out = std::process::Command::new("mkfs.ext4")
            .args(["-F", "-b", "4096", image.to_str().unwrap()])
            .output();
        let out = match out {
            Ok(o) if o.status.success() => o,
            _ => return None,
        };
        let _ = out; // suppress unused warning

        // Make root writable.
        let _ = std::process::Command::new("debugfs")
            .args([
                "-w",
                "-R",
                "set_inode_field / mode 040777",
                image.to_str().unwrap(),
            ])
            .output();

        let cx = Cx::for_testing();
        let data = std::fs::read(&image).expect("read image");
        let dev = TestDevice::from_vec(data);
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Apply,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some((fs, tmp))
    }

    /// Run `e2fsck -fn` (force, read-only) on an image; returns (clean, output).
    fn run_e2fsck(image: &std::path::Path) -> Option<(bool, String)> {
        let out = std::process::Command::new("e2fsck")
            .args(["-fn", image.to_str().unwrap()])
            .output()
            .ok()?;
        let mut combined = String::from_utf8_lossy(&out.stdout).into_owned();
        combined.push_str(&String::from_utf8_lossy(&out.stderr));
        // Exit 0 = clean. With -n, non-zero means errors were found (not fixed).
        Some((out.status.success(), combined))
    }

    /// Validate FrankenFS's ext4 write path against real `e2fsck` (the ext4
    /// analog of the btrfs-check harness): create a file, write data, persist,
    /// and require e2fsck to report the image clean.
    ///
    /// Regression guard for bd-0ta4z: allocation on a fresh (lazy-init) image
    /// formerly left the group flagged INODE_UNINIT/BLOCK_UNINIT with a stale
    /// `bg_itable_unused`, so e2fsck recomputed the bitmaps/free counts as
    /// all-free and reported them wrong. Fixed by clearing the UNINIT flags +
    /// shrinking `itable_unused` when a group's bitmap is persisted.
    #[test]
    fn ext4_created_file_passes_e2fsck_bd_0ta4z() {
        let Some((fs, dev, tmp)) = open_writable_ext4_mkfs_with_device(64) else {
            return; // format tool unavailable
        };
        let image = tmp.path().join("test.ext4");
        let cx = Cx::for_testing();

        let attr = fs
            .create(
                &cx,
                InodeNumber(2),
                OsStr::new("e2fsck_probe.txt"),
                0o644,
                0,
                0,
            )
            .expect("create on real ext4 image");
        fs.write(&cx, attr.ino, 0, &[0xAB_u8; 8192])
            .expect("write file data");

        // Persist the MVCC buffer to the device, then write the modified image
        // back to disk for e2fsck.
        fs.flush_mvcc_to_device(&cx).expect("flush mvcc to device");
        let bytes = dev.snapshot_bytes();
        std::fs::write(&image, &bytes).expect("write modified image");

        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            clean,
            "e2fsck must accept a FrankenFS-created+written ext4 image:\n{output}"
        );
    }

    /// Special-file inodes — a character device node, a block device node, and a
    /// FIFO — must leave an ext4 image e2fsck-clean. Existing mknod tests only
    /// round-trip the rdev back through FrankenFS's own getattr (internal
    /// consistency); this is the only check that the ON-DISK device inode is
    /// kernel-valid: a device/FIFO inode carries no data (i_size 0, i_blocks 0,
    /// no EXTENTS_FL), and the rdev lives in i_block[0] (old encoding) or
    /// i_block[1] (new), with the rest of i_block zero. A stray EXTENTS flag,
    /// allocated block, or non-zero size on these inodes would surface here.
    #[test]
    fn ext4_special_files_pass_e2fsck() {
        let Some((fs, dev, tmp)) = open_writable_ext4_mkfs_with_device(64) else {
            return; // format tool unavailable
        };
        let image = tmp.path().join("test.ext4");
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        fs.mknod(
            &cx,
            root,
            OsStr::new("cdev"),
            (libc::S_IFCHR as u16) | 0o644,
            259, // makedev(1, 3), e.g. /dev/null
            0,
            0,
        )
        .expect("mknod character device");
        fs.mknod(
            &cx,
            root,
            OsStr::new("bdev"),
            (libc::S_IFBLK as u16) | 0o644,
            2048, // makedev(8, 0), e.g. /dev/sda
            0,
            0,
        )
        .expect("mknod block device");
        fs.mknod(
            &cx,
            root,
            OsStr::new("fifo"),
            (libc::S_IFIFO as u16) | 0o644,
            0,
            0,
            0,
        )
        .expect("mknod FIFO");
        // A large device number (minor >= 256, so it does not fit the 16-bit old
        // encoding) exercises the NEW rdev encoding stored in i_block[1] with
        // i_block[0] zero — a separate code path from the three nodes above.
        fs.mknod(
            &cx,
            root,
            OsStr::new("bigdev"),
            (libc::S_IFCHR as u16) | 0o644,
            1_050_668, // makedev(8, 300): minor 300 forces the new (i_block[1]) form
            0,
            0,
        )
        .expect("mknod large-rdev character device");

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc to device");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write modified image");

        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            clean,
            "e2fsck must accept FrankenFS-written ext4 device nodes (old + new rdev encoding) and a FIFO:\n{output}"
        );
    }

    /// Both ext4 symlink forms must leave the image e2fsck-clean. A FAST symlink
    /// (< 60-byte target) stores the target inline in i_block with no data block
    /// (i_size = target length, i_blocks = 0). A SLOW symlink (longer target)
    /// allocates a data block holding the target (i_size = target length,
    /// i_blocks accounting for that block, an extent mapping it). The existing
    /// symlink tests only round-trip the target back through readlink — internal
    /// consistency — and never validate the on-disk i_size/i_blocks/extent
    /// encoding, where a wrong block count or stray inline byte would surface
    /// only under e2fsck.
    #[test]
    fn ext4_symlinks_pass_e2fsck() {
        let Some((fs, dev, tmp)) = open_writable_ext4_mkfs_with_device(64) else {
            return; // format tool unavailable
        };
        let image = tmp.path().join("test.ext4");
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let fast_target = "short/target.txt";
        assert!(fast_target.len() < ffs_types::EXT4_FAST_SYMLINK_MAX);
        fs.symlink(
            &cx,
            root,
            OsStr::new("fastlink"),
            Path::new(fast_target),
            0,
            0,
        )
        .expect("create fast symlink");

        let slow_target = "/var/lib/frankenfs/some/really/long/path/exceeding/sixty/bytes/for/the/slow/symlink-target.txt";
        assert!(slow_target.len() > ffs_types::EXT4_FAST_SYMLINK_MAX);
        let slow = fs
            .symlink(
                &cx,
                root,
                OsStr::new("slowlink"),
                Path::new(slow_target),
                0,
                0,
            )
            .expect("create slow symlink");
        assert!(
            !fs.read_inode(&cx, slow.ino)
                .expect("read slow symlink inode")
                .is_fast_symlink(),
            "the long target must be a slow (block-mapped) symlink"
        );

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc to device");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write modified image");

        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            clean,
            "e2fsck must accept FrankenFS-written fast and slow ext4 symlinks:\n{output}"
        );
    }

    /// bd-zpe9s: when a file's extent tree grows past its inline 4-extent root
    /// (depth >= 1), ffs_btree::insert allocates on-disk index/leaf metadata
    /// blocks that must be charged to i_blocks alongside the data blocks, or
    /// e2fsck reports "i_blocks is X, should be Y". The fix snapshots the
    /// extent-tree metadata-block count at the start of each write/fallocate and
    /// applies the signed delta at the end, so it stays correct under both growth
    /// and the tree later shrinking via coalescing. Writes many discontiguous
    /// single-block extents (holes defeat coalescing) to force growth, then
    /// requires e2fsck clean.
    #[test]
    fn ext4_extent_tree_growth_counts_metadata_in_iblocks_bd_zpe9s() {
        let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(16, false) else {
            return; // e2fsprogs unavailable
        };
        let cx = Cx::for_testing();
        let bs = u64::from(fs.ext4_superblock().expect("sb").block_size);
        let attr = fs
            .create(&cx, InodeNumber(2), OsStr::new("grow.bin"), 0o644, 0, 0)
            .expect("create");

        // 16 single blocks at even logical offsets: the holes between them defeat
        // extent coalescing, so the 16 discontiguous extents overflow the inline
        // 4-extent root and grow the tree to depth >= 1, allocating extent-tree
        // metadata blocks that must land in i_blocks.
        for k in 0..16u64 {
            fs.write(&cx, attr.ino, k * 2 * bs, &vec![0xCD_u8; bs as usize])
                .expect("discontiguous write");
        }

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        // The pre-fix bug surfaces specifically as an i_blocks mismatch; assert
        // on that directly (and on overall cleanliness) so the regression is
        // unambiguous even if e2fsck emits unrelated optimization notices.
        assert!(
            !output.contains("i_blocks"),
            "e2fsck must not report an i_blocks mismatch after extent-tree growth:\n{output}"
        );
        assert!(
            clean,
            "e2fsck must accept a file whose extent tree grew to depth >= 1:\n{output}"
        );
    }

    /// metadata_csum companion to bd-zpe9s: when a file's extent tree grows past
    /// the inline 4-extent root, the newly allocated external leaf/index blocks
    /// each carry an `ext4_extent_tail` CRC32C keyed on the fs csum seed + the
    /// owning inode's number + generation. That tail is stamped via the block
    /// allocator's `finalize_node` hook (GroupBlockAllocator), which `write_node`
    /// invokes on every grow/rewrite. bd-zpe9s exercises growth only on a
    /// `^metadata_csum` image (isolating the i_blocks accounting), so it would not
    /// catch a missing or mis-keyed extent-block checksum — the extent-tree analog
    /// of the empty-directory tail gap (bd-bribi). This pins the end-to-end
    /// stamping: grow the tree on a metadata_csum image and require real e2fsck to
    /// find no extent-checksum damage.
    #[test]
    fn ext4_extent_tree_growth_stamps_block_csum_passes_e2fsck() {
        let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(16, true) else {
            return; // e2fsprogs unavailable
        };
        let cx = Cx::for_testing();
        let bs = u64::from(fs.ext4_superblock().expect("sb").block_size);
        let attr = fs
            .create(
                &cx,
                InodeNumber(2),
                OsStr::new("grow_csum.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");

        // 16 discontiguous single-block writes (holes defeat coalescing) overflow
        // the inline 4-extent root and grow the tree to depth >= 1, allocating
        // external extent blocks that must be checksum-stamped on metadata_csum.
        for k in 0..16u64 {
            fs.write(&cx, attr.ino, k * 2 * bs, &vec![0xCD_u8; bs as usize])
                .expect("discontiguous write");
        }

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            clean,
            "e2fsck must accept a metadata_csum file whose extent tree grew to depth >= 1 \
             (an unstamped/mis-keyed ext4_extent_tail would surface here):\n{output}"
        );
    }

    /// bd-kyp2q: the directory-mapping paths (`ext4_add_dir_entry` linear growth
    /// and `ext4_rebuild_htree_dir`) insert into a directory's extent tree via
    /// direct `ffs_btree::insert` calls. Once that tree grows past its inline
    /// 4-extent root the allocated index/leaf metadata blocks must be charged to
    /// the directory `i_blocks`, or e2fsck reports "i_blocks is X, should be Y"
    /// — the directory analog of the file-write gap (bd-zpe9s).
    ///
    /// Uses a `^dir_index` image so the directory stays LINEAR and grows one
    /// block at a time through the `ext4_add_dir_entry` insert (an htree rebuild
    /// would re-pack the directory into fresh, possibly-contiguous blocks and
    /// hide the fragmentation). A 4 KiB file write per entry occupies the block
    /// the directory's contiguity hint would otherwise reuse, so the directory
    /// blocks fragment across the disk: >4 discontiguous extents overflow the
    /// inline root and force the extent tree to depth >= 1.
    #[test]
    fn ext4_dir_extent_tree_growth_counts_metadata_in_iblocks_bd_kyp2q() {
        let Some((fs, dev, _tmp, image)) =
            open_ext4_mke2fs_features(16, "extent,fast_commit,^metadata_csum,^dir_index")
        else {
            return; // e2fsprogs unavailable
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        // At a 1 KiB block size a linear directory needs many blocks for 300
        // entries; the 4 KiB file write between each create occupies the blocks
        // the directory's contiguity hint would reuse, so the directory blocks
        // scatter. The resulting >4 discontiguous extents overflow the inline
        // root and grow the extent tree to depth >= 1, allocating index/leaf
        // metadata blocks that must land in the directory i_blocks.
        for i in 0..300u32 {
            let name = format!("entry_{i:04}.dat");
            let attr = fs
                .create(&cx, root, OsStr::new(&name), 0o644, 0, 0)
                .expect("create entry");
            fs.write(&cx, attr.ino, 0, &[0xAB_u8; 4096])
                .expect("write file data");
        }

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        // The pre-fix bug surfaces as an i_blocks mismatch on the directory
        // inode; assert on that directly (and on overall cleanliness).
        assert!(
            !output.contains("i_blocks"),
            "e2fsck must not report an i_blocks mismatch after directory extent-tree growth:\n{output}"
        );
        assert!(
            clean,
            "e2fsck must accept a directory whose extent tree grew to depth >= 1:\n{output}"
        );
    }

    /// Broader e2fsck stress (bd-0ta4z follow-on): exercise many ext4 write-path
    /// mutations — multi-block file writes, a subdirectory, an unlink (free
    /// path), a rename, and a fallocate — then require the image to be
    /// e2fsck-clean. Catches accounting regressions the single-create test
    /// cannot (free paths, used_dirs, multi-group allocation).
    #[test]
    fn ext4_many_mutations_pass_e2fsck_bd_0ta4z() {
        let Some((fs, dev, tmp)) = open_writable_ext4_mkfs_with_device(64) else {
            return; // format tool unavailable
        };
        let image = tmp.path().join("test.ext4");
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        // 20 files, 4 blocks (16 KiB) each — exercises inode + block allocation.
        for i in 0..20 {
            let name = format!("file_{i:02}.dat");
            let attr = fs
                .create(&cx, root, OsStr::new(&name), 0o644, 0, 0)
                .expect("create");
            fs.write(&cx, attr.ino, 0, &[0xCD_u8; 16384])
                .expect("write");
        }
        // A subdirectory with a file inside (exercises used_dirs + nested dirs).
        let dir = fs
            .mkdir(&cx, root, OsStr::new("subdir"), 0o755, 0, 0)
            .expect("mkdir");
        let inner = fs
            .create(&cx, dir.ino, OsStr::new("inner.txt"), 0o644, 0, 0)
            .expect("create inner");
        fs.write(&cx, inner.ino, 0, &[0xEE_u8; 4096])
            .expect("write inner");
        // Unlink (inode + block free path) and rename.
        fs.unlink(&cx, root, OsStr::new("file_05.dat"))
            .expect("unlink");
        fs.rename(
            &cx,
            root,
            OsStr::new("file_06.dat"),
            root,
            OsStr::new("renamed.dat"),
        )
        .expect("rename");
        // Preallocate beyond the file's data.
        fs.fallocate(&cx, inner.ino, 0, 8192, libc::FALLOC_FL_KEEP_SIZE)
            .expect("fallocate");

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc to device");
        let bytes = dev.snapshot_bytes();
        std::fs::write(&image, &bytes).expect("write modified image");

        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            clean,
            "e2fsck must accept a multi-mutation FrankenFS ext4 image:\n{output}"
        );
    }

    /// bd-bribi: an EMPTY directory created on a metadata_csum filesystem must
    /// leave its data block's CRC32C tail correctly stamped. The mkdir path
    /// initialized the new dir block (`.`/`..` + a zeroed checksum tail) and wrote
    /// it WITHOUT stamping — only the add_entry paths restamp — so a directory
    /// that never receives an entry reached disk with a zero checksum and e2fsck
    /// pass 2 reported "directory passes checks but fails checksum". (A subdir
    /// that later gets a file appeared clean because the add restamps the block,
    /// which is why the single-subdir bd-0ta4z stress did not catch it.) Minimal
    /// repro from the namespace-churn proptest: two empty sibling subdirs (pa, pb)
    /// plus a single create in root.
    #[test]
    fn ext4_empty_dir_block_csum_stamped_passes_e2fsck_bd_bribi() {
        let Some((fs, dev, tmp)) = open_writable_ext4_mkfs_with_device(64) else {
            return; // format tool unavailable
        };
        let image = tmp.path().join("test.ext4");
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        // Two empty sibling subdirectories — neither ever receives an entry, so
        // their blocks are never restamped by an add_entry on the writable path.
        fs.mkdir(&cx, root, OsStr::new("pa"), 0o755, 0, 0)
            .expect("mkdir pa");
        fs.mkdir(&cx, root, OsStr::new("pb"), 0o755, 0, 0)
            .expect("mkdir pb");
        // A single create in root (the minimal churn op from the proptest).
        fs.create(&cx, root, OsStr::new("f0"), 0o644, 0, 0)
            .expect("create f0");

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc to device");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write modified image");

        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            !output.contains("fails checksum"),
            "empty-directory data block must carry a correct metadata_csum tail (bd-bribi):\n{output}"
        );
        assert!(
            clean,
            "e2fsck must accept empty sibling subdirectories on a metadata_csum image (bd-bribi):\n{output}"
        );
    }

    /// Renaming a directory into a DIFFERENT parent on a metadata_csum image
    /// exercises two paths no other e2fsck test covers: (1) the in-place `..`
    /// repoint of the moved directory's block 0 and its subsequent re-stamp
    /// (lib.rs ~16790: dx_root vs linear keyed on the moved dir's own inode +
    /// generation), and (2) the parent link-count deltas (old parent loses the
    /// child's `..` backlink, new parent gains one). A wrong `..` checksum would
    /// surface as "directory passes checks but fails checksum" (the bd-bribi
    /// failure mode) and a wrong link count as "Inode N ref count is M, should be
    /// K". The namespace-churn proptest renames among parents but defers e2fsck;
    /// bd-0ta4z renames a plain file, not a directory. This pins the directory
    /// cross-parent rename deterministically.
    #[test]
    fn ext4_dir_rename_across_parents_passes_e2fsck() {
        let Some((fs, dev, tmp)) = open_writable_ext4_mkfs_with_device(64) else {
            return; // format tool unavailable
        };
        let image = tmp.path().join("test.ext4");
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let a = fs
            .mkdir(&cx, root, OsStr::new("a"), 0o755, 0, 0)
            .expect("mkdir a");
        let b = fs
            .mkdir(&cx, root, OsStr::new("b"), 0o755, 0, 0)
            .expect("mkdir b");
        // A subdirectory inside `a`, itself holding a file, so the move shifts a
        // non-trivial subtree and its `..` backlink between parents.
        let sub = fs
            .mkdir(&cx, a.ino, OsStr::new("sub"), 0o755, 0, 0)
            .expect("mkdir a/sub");
        let inner = fs
            .create(&cx, sub.ino, OsStr::new("inner.txt"), 0o644, 0, 0)
            .expect("create a/sub/inner.txt");
        fs.write(&cx, inner.ino, 0, &[0x5A_u8; 1024])
            .expect("write inner");

        // Move the directory `a/sub` -> `b/sub`: repoints sub's `..` from a to b
        // and adjusts both parents' link counts.
        fs.rename(&cx, a.ino, OsStr::new("sub"), b.ino, OsStr::new("sub"))
            .expect("rename a/sub -> b/sub");

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc to device");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write modified image");

        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            !output.contains("fails checksum"),
            "moved directory's '..' block must carry a correct metadata_csum tail:\n{output}"
        );
        assert!(
            clean,
            "e2fsck must accept a directory renamed across parents on a metadata_csum image:\n{output}"
        );
    }

    /// bd-0y7jp: a block group's `bg_used_dirs_count` must stay correct as
    /// directory inodes are created and freed, or e2fsck reports "Directories
    /// count wrong for group #N". On the writable path the count was previously
    /// never maintained — `alloc_inode_persist` used the `is_directory` hint only
    /// for Orlov target-group selection and `free_inode_persist` ignored it — so
    /// the persisted descriptor drifted from the actual directory count. The fix
    /// increments the owning group's `used_dirs` on directory-inode allocation
    /// and decrements it on free, in the same group-descriptor write.
    ///
    /// Uses a `^metadata_csum` image so the assertion isolates the directory-count
    /// accounting from the separate writable-path directory-block-checksum gap
    /// (bd-bribi). Creates many directories (Orlov spreads them across both 1 KiB
    /// block groups), removes half, and creates/unlinks a plain file (which must
    /// NOT touch `used_dirs`), then requires e2fsck to find no directory-count
    /// mismatch.
    #[test]
    fn ext4_dir_count_maintained_passes_e2fsck_bd_0y7jp() {
        let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(16, false) else {
            return; // e2fsprogs unavailable
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        // 24 directories: Orlov dir-spreading places them across both block
        // groups, exercising the per-group used_dirs increment in each.
        for i in 0..24u32 {
            fs.mkdir(&cx, root, OsStr::new(&format!("d{i:02}")), 0o755, 0, 0)
                .expect("mkdir");
        }
        // Remove half (exercises the used_dirs decrement on the free path).
        for i in (0..24u32).step_by(2) {
            fs.rmdir(&cx, root, OsStr::new(&format!("d{i:02}")))
                .expect("rmdir");
        }
        // A plain file create+unlink must NOT change any group's used_dirs.
        let f = fs
            .create(&cx, root, OsStr::new("plain.txt"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, f.ino, 0, &[0xAB_u8; 2048]).expect("write");
        fs.unlink(&cx, root, OsStr::new("plain.txt"))
            .expect("unlink");

        fs.flush_mvcc_to_device(&cx).expect("flush mvcc");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        let Some((clean, output)) = run_e2fsck(&image) else {
            return; // e2fsck unavailable
        };
        assert!(
            !output.contains("Directories count wrong"),
            "e2fsck must not report a directory-count mismatch after dir create/rmdir churn (bd-0y7jp):\n{output}"
        );
        assert!(
            clean,
            "e2fsck must accept the image after directory create/rmdir churn:\n{output}"
        );
    }

    fn open_writable_ext4_mkfs_with_incompat_features(
        size_mb: u64,
        incompat_bits: u32,
    ) -> Option<(OpenFs, tempfile::TempDir)> {
        let tmp = tempfile::TempDir::new().expect("tmpdir");
        let image = tmp.path().join("test.ext4");
        let f = std::fs::File::create(&image).expect("create image");
        f.set_len(size_mb * 1024 * 1024).expect("set image size");
        drop(f);

        let out = std::process::Command::new("mkfs.ext4")
            .args(["-F", "-b", "4096", image.to_str().unwrap()])
            .output();
        let out = match out {
            Ok(o) if o.status.success() => o,
            _ => return None,
        };
        let _ = out;

        let _ = std::process::Command::new("debugfs")
            .args([
                "-w",
                "-R",
                "set_inode_field / mode 040777",
                image.to_str().unwrap(),
            ])
            .output();

        let mut data = std::fs::read(&image).expect("read image");
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        let incompat_off = sb_off + 0x60;
        let checksum_off = sb_off + EXT4_SB_CHECKSUM_OFFSET;
        let mut feature_incompat = u32::from_le_bytes(
            data[incompat_off..incompat_off + 4]
                .try_into()
                .expect("feature_incompat bytes"),
        );
        feature_incompat |= incompat_bits;
        data[incompat_off..incompat_off + 4].copy_from_slice(&feature_incompat.to_le_bytes());
        let checksum =
            ffs_ondisk::ext4::ext4_chksum(!0u32, &data[sb_off..sb_off + EXT4_SB_CHECKSUM_OFFSET]);
        data[checksum_off..checksum_off + 4].copy_from_slice(&checksum.to_le_bytes());

        let cx = Cx::for_testing();
        let dev = TestDevice::from_vec(data);
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Apply,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some((fs, tmp))
    }

    /// Create a fresh ext4 image via `mkfs.ext4`, returning a clonable device
    /// handle so crash tests can snapshot in-memory bytes before reopening.
    fn open_writable_ext4_mkfs_with_device(
        size_mb: u64,
    ) -> Option<(OpenFs, TestDevice, tempfile::TempDir)> {
        let tmp = tempfile::TempDir::new().expect("tmpdir");
        let image = tmp.path().join("test.ext4");
        let f = std::fs::File::create(&image).expect("create image");
        f.set_len(size_mb * 1024 * 1024).expect("set image size");
        drop(f);

        let out = std::process::Command::new("mkfs.ext4")
            .args(["-F", "-b", "4096", image.to_str().unwrap()])
            .output();
        let out = match out {
            Ok(o) if o.status.success() => o,
            _ => return None,
        };
        let _ = out;

        let _ = std::process::Command::new("debugfs")
            .args([
                "-w",
                "-R",
                "set_inode_field / mode 040777",
                image.to_str().unwrap(),
            ])
            .output();

        let cx = Cx::for_testing();
        let data = std::fs::read(&image).expect("read image");
        let dev = TestDevice::from_vec(data);
        let snapshot = dev.clone();
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Apply,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some((fs, snapshot, tmp))
    }

    fn reopen_ext4_after_crash(dev: &TestDevice) -> OpenFs {
        let cx = Cx::for_testing();
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Apply,
            ..OpenOptions::default()
        };
        OpenFs::from_device(
            &cx,
            Box::new(TestDevice::from_vec(dev.snapshot_bytes())),
            &opts,
        )
        .expect("reopen ext4 after crash")
    }

    fn ext4_lookup_optional(fs: &OpenFs, cx: &Cx, name: &str) -> Option<InodeAttr> {
        fs.lookup(cx, InodeNumber(2), OsStr::new(name)).ok()
    }

    fn ext4_read_exact(fs: &OpenFs, cx: &Cx, ino: InodeNumber, size: u64) -> Vec<u8> {
        fs.read(cx, ino, 0, u32::try_from(size).expect("small test file"))
            .expect("read exact bytes")
    }

    fn ext4_block_mapping(
        fs: &OpenFs,
        cx: &Cx,
        ino: InodeNumber,
        logical_block: u32,
    ) -> ffs_extent::ExtentMapping {
        let inode = fs
            .read_inode(cx, ino)
            .expect("read inode for extent mapping");
        let root_bytes = OpenFs::extent_root(&inode);
        let block_dev = fs.block_device_adapter();
        let mut mappings =
            ffs_extent::map_logical_to_physical(cx, &block_dev, &root_bytes, logical_block, 1)
                .expect("map logical block");
        mappings.pop().expect("single logical block mapping")
    }

    fn ext4_move_ext_request(
        fs: &OpenFs,
        cx: &Cx,
        ino: InodeNumber,
        donor_fd: u32,
        orig_start: u64,
        donor_start: u64,
        len: u64,
    ) -> ffs_error::Result<u64> {
        let mut scope = fs
            .begin_request_scope(cx, RequestOp::IoctlWrite)
            .expect("begin ioctl write scope");
        let result = fs.move_ext(cx, &mut scope, ino, donor_fd, orig_start, donor_start, len);
        if result.is_ok() {
            fs.commit_request_scope(&mut scope)
                .expect("commit ioctl write scope");
        }
        fs.end_request_scope(cx, RequestOp::IoctlWrite, scope)
            .expect("end ioctl write scope");
        result
    }

    fn assert_ext4_crash_event(
        logs: &[Value],
        scenario_id: &str,
        crash_point: &str,
        outcome: &str,
    ) {
        let event = logs.iter().find(|entry| {
            entry.get("message").and_then(Value::as_str) == Some("CRASH_MATRIX_EVENT")
                && entry.get("scenario_id").and_then(Value::as_str) == Some(scenario_id)
        });
        assert!(
            event.is_some(),
            "missing crash-matrix event for {scenario_id}: {logs:?}"
        );
        let event = event.expect("crash-matrix event must be present after assert");

        assert_eq!(
            event.get("crash_point").and_then(Value::as_str),
            Some(crash_point)
        );
        assert_eq!(event.get("outcome").and_then(Value::as_str), Some(outcome));
    }

    fn enable_e2compr_for_inode(
        fs: &OpenFs,
        cx: &Cx,
        ino: InodeNumber,
        cluster_shift: u32,
        method_idx: u8,
    ) {
        let mut inode = fs.read_inode(cx, ino).expect("read inode for e2compr");
        inode.flags |= ffs_types::EXT4_COMPR_FL;
        inode.flags &= !ffs_types::EXT4_INLINE_DATA_FL;
        inode.flags &= !ffs_types::EXT4_EXTENTS_FL;
        inode.flags &= !((0x7_u32 << 23) | (0x1F_u32 << 26));
        inode.flags |= (cluster_shift & 0x7) << 23;
        inode.flags |= u32::from(method_idx & 0x1F) << 26;
        inode.extent_bytes.fill(0);
        fs.persist_ext4_inode_for_testing(cx, ino, &inode)
            .expect("persist e2compr inode flags");
    }

    fn persist_ext4_test_inode(fs: &OpenFs, cx: &Cx, ino: InodeNumber, inode: &Ext4Inode) {
        let sb = fs.ext4_superblock().expect("ext4 superblock");
        let csum_seed = sb.csum_seed();
        let block_dev = fs.block_device_adapter();
        let alloc_mutex = fs.require_alloc_state().expect("alloc state");
        let alloc = alloc_mutex.read();
        ffs_inode::write_inode(
            cx,
            &block_dev,
            &alloc.geo,
            &alloc.groups,
            ino,
            inode,
            csum_seed,
        )
        .expect("persist test inode");
    }

    #[test]
    fn write_create_and_read_roundtrip() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2); // ext4 root inode

        // Create a new file
        let attr = fs
            .create(&cx, root, OsStr::new("test_rw.txt"), 0o644, 1000, 1000)
            .expect("create");
        assert_eq!(attr.kind, FileType::RegularFile);
        assert_eq!(attr.perm, 0o644);
        assert_eq!(attr.uid, 1000);
        let ino = attr.ino;

        // Write data
        let payload = b"FrankenFS write test!";
        let written = fs.write(&cx, ino, 0, payload).expect("write");
        assert_eq!(written as usize, payload.len());

        // Read back
        let readback = fs.read(&cx, ino, 0, 4096).expect("read");
        assert_eq!(&readback[..payload.len()], payload);

        // Lookup should find it
        let looked_up = fs
            .lookup(&cx, root, OsStr::new("test_rw.txt"))
            .expect("lookup");
        assert_eq!(looked_up.ino, ino);
    }

    #[test]
    fn write_cross_block_boundary_preserves_data() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("cross_block.bin"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        // Write 6KB of distinct data starting at offset 0 to span two 4KB blocks.
        let mut payload = vec![0u8; 6144];
        for (idx, byte) in payload.iter_mut().enumerate() {
            *byte = u8::try_from(idx % 251).unwrap(); // prime modulus for pattern uniqueness
        }
        let written = fs.write(&cx, ino, 0, &payload).expect("write 6KB");
        assert_eq!(written as usize, 6144);

        // Now overwrite 2KB starting at offset 3072 (spanning the 4KB block boundary).
        let patch = vec![0xFF_u8; 2048];
        let written2 = fs.write(&cx, ino, 3072, &patch).expect("cross-block write");
        assert_eq!(written2 as usize, 2048);

        // Read back all 6KB and verify:
        // - [0..3072] should be original pattern
        // - [3072..5120] should be 0xFF
        // - [5120..6144] should be original pattern
        let readback = fs.read(&cx, ino, 0, 6144).expect("read");
        assert_eq!(readback.len(), 6144);
        assert_eq!(&readback[..3072], &payload[..3072], "prefix corrupted");
        assert!(
            readback[3072..5120].iter().all(|&b| b == 0xFF),
            "cross-block patch not applied correctly"
        );
        assert_eq!(&readback[5120..], &payload[5120..], "suffix corrupted");
    }

    #[test]
    fn write_create_invalid_name_rolls_back_inode_allocation() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let free_before = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count before create");

        let err = fs
            .create(&cx, root, OsStr::from_bytes(b"bad/name"), 0o644, 1000, 1000)
            .unwrap_err();
        assert!(matches!(err, FfsError::Format(_)));

        let free_after = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count after create");
        assert_eq!(
            free_after, free_before,
            "failed create should not leak inode"
        );
    }

    #[test]
    #[ignore = "bd-cc6ua: inode.blocks overflow injection (u64::MAX) does not round-trip through the generated image's inode encoding; defensive guard for an unreachable state"]
    fn write_data_block_inode_blocks_overflow_reports_corruption() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let ino = fs
            .create(
                &cx,
                root,
                OsStr::new("blocks_overflow_write.txt"),
                0o644,
                0,
                0,
            )
            .expect("create file")
            .ino;
        let free_before = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count before write");

        let mut inode = fs.read_inode(&cx, ino).expect("read inode before write");
        inode.blocks = u64::MAX;
        persist_ext4_test_inode(&fs, &cx, ino, &inode);

        let err = fs
            .write(&cx, ino, 0, b"x")
            .expect_err("write should fail on inode.blocks overflow");
        assert!(matches!(err, FfsError::Corruption { .. }));

        let free_after = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count after failed write");
        assert_eq!(
            free_after, free_before,
            "failed write should not leak a newly allocated data block"
        );

        let inode_after = fs
            .read_inode(&cx, ino)
            .expect("read inode after failed write");
        assert_eq!(
            inode_after.size, 0,
            "failed write must not extend file size"
        );
        let readback = fs.read(&cx, ino, 0, 16).expect("read after failed write");
        assert!(
            readback.is_empty(),
            "failed write must not publish any file data"
        );
    }

    #[test]
    fn write_create_and_read_roundtrip_via_vfs_root_alias() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(1); // VFS/FUSE root alias for ext4 inode 2

        let root_attr = fs.getattr(&cx, root).expect("getattr root");
        assert_eq!(root_attr.ino, root);
        assert_eq!(root_attr.kind, FileType::Directory);

        let root_entries = fs.readdir(&cx, root, 0).expect("readdir root");
        let dot = root_entries
            .iter()
            .find(|entry| entry.name_str() == ".")
            .expect("dot entry");
        let dotdot = root_entries
            .iter()
            .find(|entry| entry.name_str() == "..")
            .expect("dotdot entry");
        assert_eq!(dot.ino, root);
        assert_eq!(dotdot.ino, root);

        let attr = fs
            .create(
                &cx,
                root,
                OsStr::new("test_rw_alias.txt"),
                0o644,
                1000,
                1000,
            )
            .expect("create");
        assert_eq!(attr.kind, FileType::RegularFile);

        let payload = b"FrankenFS root-alias write test!";
        let written = fs.write(&cx, attr.ino, 0, payload).expect("write");
        assert_eq!(written as usize, payload.len());

        let readback = fs.read(&cx, attr.ino, 0, 4096).expect("read");
        assert_eq!(&readback[..payload.len()], payload);

        let looked_up = fs
            .lookup(&cx, root, OsStr::new("test_rw_alias.txt"))
            .expect("lookup");
        assert_eq!(looked_up.ino, attr.ino);
    }

    #[test]
    fn ext4_fallocate_collapse_range_rejects_misaligned_and_eof_reaching() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("collapse-bad.bin"), 0o644, 0, 0)
            .expect("create");
        // 4 blocks of 4096 bytes.
        fs.write(&cx, attr.ino, 0, &[0xAB_u8; 16384])
            .expect("write");

        let collapse = libc::FALLOC_FL_COLLAPSE_RANGE;
        // Misaligned offset -> EINVAL.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 100, 4096, collapse)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
        // Misaligned length -> EINVAL.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 4096, 100, collapse)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
        // A range that reaches EOF (whole file) -> EINVAL.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 0, 16384, collapse)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
    }

    #[test]
    fn ext4_fallocate_insert_range_rejects_misaligned_and_past_eof() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("insert-bad.bin"), 0o644, 0, 0)
            .expect("create");
        // 4 blocks of 4096 bytes.
        fs.write(&cx, attr.ino, 0, &[0xAB_u8; 16384])
            .expect("write");

        let insert = libc::FALLOC_FL_INSERT_RANGE;
        // Misaligned offset -> EINVAL.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 100, 4096, insert)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
        // Misaligned length -> EINVAL.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 4096, 100, insert)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
        // Offset at/past EOF -> EINVAL (a hole cannot be inserted past the end).
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 16384, 4096, insert)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
    }

    #[test]
    fn ext4_collapse_range_preserves_preallocated_zeros_and_data() {
        // collapse_range over a preallocated region must (a) shift written data
        // correctly and (b) leave the preallocated (unwritten) blocks reading
        // zeros — never exposing stale physical block contents. (FrankenFS
        // fallocate initializes preallocation as written-zeroed extents rather
        // than lazy uninitialized extents, so this exercises the zeroed-prealloc
        // path; tracked separately as a parity/perf gap.) Runs on remote workers
        // via the generated image.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let block = 4096_u64;
        let blen = usize::try_from(block).unwrap();
        let attr = fs
            .create(&cx, root, OsStr::new("collapse_prealloc.bin"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        // Preallocate 6 blocks (mode 0 extends size).
        fs.fallocate(&cx, ino, 0, 6 * block, 0)
            .expect("preallocate 6 blocks");
        let z = fs.read(&cx, ino, 0, 4096).expect("read b0");
        assert!(z.iter().all(|&b| b == 0), "preallocated block reads zeros");

        // Write a marker into block 4.
        let marker = vec![0xCC_u8; blen];
        fs.write(&cx, ino, 4 * block, &marker)
            .expect("write marker");

        // Collapse block 1: tail [2,6) shifts left to [1,5); the marker block
        // 4 -> 3. FALLOC_FL_COLLAPSE_RANGE = 0x08.
        fs.fallocate(&cx, ino, block, block, 0x08)
            .expect("collapse_range over preallocated block");
        assert_eq!(
            fs.getattr(&cx, ino).expect("ga").size,
            5 * block,
            "file shrinks by the collapsed block"
        );

        // Written data shifted correctly.
        let m = fs
            .read(&cx, ino, 3 * block, 4096)
            .expect("read marker after");
        assert_eq!(m, marker, "written block shifted left across collapse");

        // Remaining preallocated blocks still read zeros (no stale exposure).
        for b in [0_u64, 1, 2, 4] {
            let d = fs
                .read(&cx, ino, b * block, 4096)
                .expect("read prealloc after");
            assert!(
                d.iter().all(|&x| x == 0),
                "block {b} must still read zeros after collapse"
            );
        }
    }

    #[test]
    fn ext4_insert_range_preserves_preallocated_zeros_and_data() {
        // Mirror of the collapse test for insert_range: inserting a hole into a
        // preallocated region must shift written data right and leave the
        // inserted hole and the surrounding preallocated blocks reading zeros
        // (no stale physical exposure).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let block = 4096_u64;
        let blen = usize::try_from(block).unwrap();
        let attr = fs
            .create(&cx, root, OsStr::new("insert_prealloc.bin"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        fs.fallocate(&cx, ino, 0, 5 * block, 0)
            .expect("preallocate 5 blocks");

        // Write a marker into block 3.
        let marker = vec![0x5A_u8; blen];
        fs.write(&cx, ino, 3 * block, &marker)
            .expect("write marker");

        // Insert a hole at block 1: tail [1,5) shifts right to [2,6); marker
        // block 3 -> 4. FALLOC_FL_INSERT_RANGE = 0x20.
        fs.fallocate(&cx, ino, block, block, 0x20)
            .expect("insert_range into preallocated region");
        assert_eq!(
            fs.getattr(&cx, ino).expect("ga").size,
            6 * block,
            "file grows by the inserted block"
        );

        let m = fs
            .read(&cx, ino, 4 * block, 4096)
            .expect("read marker after");
        assert_eq!(m, marker, "written block shifted right across insert");

        // Inserted hole (block 1) + surrounding preallocated blocks read zeros.
        for b in [0_u64, 1, 2, 3, 5] {
            let d = fs.read(&cx, ino, b * block, 4096).expect("read zero after");
            assert!(
                d.iter().all(|&x| x == 0),
                "block {b} must read zeros after insert"
            );
        }
    }

    #[test]
    #[ignore = "profiling tool for bd-gauub: measures the linear-directory O(n^2) population / \
                O(n) lookup scaling (no htree). Run via `cargo test -- --ignored --nocapture \
                profile_linear_directory_scaling_bd_gauub`."]
    fn profile_linear_directory_scaling_bd_gauub() {
        // Quantifies the bd-gauub gap: directory create/lookup are linear scans
        // (no htree), so populating a directory of N entries is O(N^2) and a
        // lookup is O(N). Doubling-ish steps (4x) make the scaling visible:
        // O(N^2) populate -> ~16x per step; O(N) per-create / lookup -> ~4x.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(256) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        for &n in &[200_u32, 800, 3200] {
            let dir = fs
                .mkdir(&cx, root, OsStr::new(&format!("dir_{n}")), 0o755, 0, 0)
                .expect("mkdir");
            let t0 = std::time::Instant::now();
            for i in 0..n {
                fs.create(&cx, dir.ino, OsStr::new(&format!("f{i:05}")), 0o644, 0, 0)
                    .expect("create");
            }
            let populate = t0.elapsed();

            let reps = 50_u32;
            let last = format!("f{:05}", n - 1);
            let t1 = std::time::Instant::now();
            for _ in 0..reps {
                let _ = fs.lookup(&cx, dir.ino, OsStr::new(&last)).expect("lookup");
            }
            let per_lookup = t1.elapsed() / reps;

            eprintln!(
                "bd-gauub N={n}: populate={populate:?} (per_create={:?}), per_lookup_last={per_lookup:?}",
                populate / n
            );
        }
    }

    const DIR_INDEX_RUNTIME_TEST_FILE_COUNT: usize = 256;
    const DIR_INDEX_RUNTIME_TEST_CONTENT: &[u8] = b"hello from FrankenFS runtime htree test\n";
    const DIR_INDEX_RUNTIME_TEST_HASH_SEED: &str = "11111111-2222-3333-4444-555555555555";

    fn ext4_dir_index_golden_path() -> Option<std::path::PathBuf> {
        let path = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .parent()
            .expect("crate has workspace parent")
            .parent()
            .expect("workspace parent exists")
            .join("conformance/golden/ext4_dir_index_reference.ext4");
        path.exists().then_some(path)
    }

    fn run_dir_index_debugfs(image: &std::path::Path, cmd: &str) -> bool {
        std::process::Command::new("debugfs")
            .args(["-w", "-R", cmd])
            .arg(image)
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .status()
            .is_ok_and(|status| status.success())
    }

    fn run_dir_index_e2fsck(image: &std::path::Path) -> bool {
        let Ok(status) = std::process::Command::new("e2fsck")
            .args(["-fyD"])
            .arg(image)
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .status()
        else {
            return false;
        };
        matches!(status.code().unwrap_or(-1), 0 | 1)
    }

    fn generated_ext4_dir_index_image_bytes() -> Option<Vec<u8>> {
        let tmp = tempfile::TempDir::new().expect("tmpdir");
        let image = tmp.path().join("dir_index.ext4");
        let file = std::fs::File::create(&image).expect("create dir_index image");
        file.set_len(64 * 1024 * 1024)
            .expect("set dir_index image size");
        drop(file);

        let Ok(status) = std::process::Command::new("mkfs.ext4")
            .args([
                "-F",
                "-L",
                "ffs-runtime-dx",
                "-b",
                "4096",
                "-q",
                "-O",
                "dir_index",
            ])
            .arg(&image)
            .stderr(std::process::Stdio::null())
            .status()
        else {
            return None;
        };
        if !status.success() {
            return None;
        }

        if !run_dir_index_debugfs(
            &image,
            &format!("set_super_value hash_seed {DIR_INDEX_RUNTIME_TEST_HASH_SEED}"),
        ) {
            return None;
        }
        if !run_dir_index_debugfs(&image, "mkdir /htree") {
            return None;
        }

        let content = tmp.path().join("content.txt");
        std::fs::write(&content, DIR_INDEX_RUNTIME_TEST_CONTENT).expect("write content file");
        for idx in 0..DIR_INDEX_RUNTIME_TEST_FILE_COUNT {
            if !run_dir_index_debugfs(
                &image,
                &format!("write {} /htree/file_{idx:03}.txt", content.display()),
            ) {
                return None;
            }
        }
        if !run_dir_index_debugfs(
            &image,
            &format!("write {} /readme-dx.txt", content.display()),
        ) {
            return None;
        }
        if !run_dir_index_e2fsck(&image) {
            return None;
        }

        Some(std::fs::read(&image).expect("read generated dir_index image"))
    }

    fn ext4_dir_index_image_bytes() -> Option<Vec<u8>> {
        if let Some(path) = ext4_dir_index_golden_path() {
            return Some(std::fs::read(path).expect("read dir_index golden image"));
        }

        let generated = generated_ext4_dir_index_image_bytes();
        if generated.is_none() {
            eprintln!(
                "SKIPPED: ext4_dir_index_reference.ext4 fixture not present and ext4 tools unavailable"
            );
        }
        generated
    }

    fn open_ext4_dir_index_golden() -> Option<(OpenFs, Cx, Ext4Inode)> {
        let data = ext4_dir_index_image_bytes()?;
        let cx = Cx::for_testing();
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Skip,
            ..OpenOptions::default()
        };
        let fs = OpenFs::from_device(&cx, Box::new(TestDevice::from_vec(data)), &opts)
            .expect("open dir_index image");
        let htree_attr = fs
            .lookup(&cx, InodeNumber(2), OsStr::new("htree"))
            .expect("lookup /htree");
        let htree_inode = fs
            .read_inode(&cx, htree_attr.ino)
            .expect("read /htree inode");
        assert!(
            htree_inode.has_htree_index(),
            "/htree must be backed by a real ext4 htree index"
        );
        Some((fs, cx, htree_inode))
    }

    fn linear_lookup_name_reference(
        fs: &OpenFs,
        cx: &Cx,
        scope: &RequestScope,
        dir_inode: &Ext4Inode,
        name: &[u8],
    ) -> Result<Option<Ext4DirEntry>, FfsError> {
        let bs = u64::from(fs.block_size());
        let num_blocks = dir_logical_block_count(dir_inode.size, bs)?;

        for lb in 0..num_blocks {
            if let Some((phys, unwritten)) = fs.resolve_extent(cx, scope, dir_inode, lb)? {
                if unwritten {
                    continue;
                }
                let block_data = fs.read_block_with_scope(cx, scope, BlockNumber(phys))?;
                let found = lookup_in_dir_block(&block_data, fs.block_size(), name)
                    .map_err(|e| parse_to_ffs_error(&e))?;
                if let Some(entry) = found {
                    return Ok(Some(entry));
                }
            }
        }

        Ok(None)
    }

    fn linear_read_dir_reference(
        fs: &OpenFs,
        cx: &Cx,
        scope: &RequestScope,
        dir_inode: &Ext4Inode,
    ) -> Result<Vec<Ext4DirEntry>, FfsError> {
        let bs = u64::from(fs.block_size());
        let block_size = fs.block_size();
        let num_blocks = dir_logical_block_count(dir_inode.size, bs)?;
        let mut entries = Vec::new();

        for lb in 0..num_blocks {
            let Some((phys, unwritten)) = fs.resolve_extent(cx, scope, dir_inode, lb)? else {
                continue;
            };
            if unwritten {
                continue;
            }
            let block_data = fs.read_block_with_scope(cx, scope, BlockNumber(phys))?;
            let (block_entries, _tail) =
                parse_dir_block(&block_data, block_size).map_err(|e| parse_to_ffs_error(&e))?;
            entries.extend(block_entries);
        }

        Ok(entries)
    }

    #[test]
    fn ext4_runtime_htree_lookup_matches_linear_scan_reference() {
        let Some((fs, cx, htree_inode)) = open_ext4_dir_index_golden() else {
            return;
        };
        let scope = RequestScope::empty();

        for name in ["file_000.txt", "file_090.txt", "file_179.txt"] {
            let fast = fs
                .lookup_name_with_scope(&cx, &scope, &htree_inode, name.as_bytes())
                .unwrap_or_else(|err| panic!("htree runtime lookup {name}: {err}"));
            let linear =
                linear_lookup_name_reference(&fs, &cx, &scope, &htree_inode, name.as_bytes())
                    .unwrap_or_else(|err| panic!("linear reference lookup {name}: {err}"));
            assert_eq!(
                fast, linear,
                "htree lookup must match linear reference for {name}"
            );
            // Prove the htree index path is actually exercised (not silently
            // always falling back to the linear scan, which would make the
            // equality above vacuous): the index alone must locate the entry.
            let via_index =
                fs.htree_lookup_name_with_scope(&cx, &scope, &htree_inode, name.as_bytes());
            assert!(
                via_index.is_some(),
                "htree index must locate {name} directly, not via the linear fallback"
            );
            assert_eq!(
                via_index, fast,
                "htree index entry must equal the full lookup"
            );
        }

        let missing = fs
            .lookup_name_with_scope(&cx, &scope, &htree_inode, b"missing.txt")
            .expect("missing htree lookup should fall back safely");
        let linear_missing =
            linear_lookup_name_reference(&fs, &cx, &scope, &htree_inode, b"missing.txt")
                .expect("missing linear lookup");
        assert_eq!(missing, linear_missing);
    }

    /// A non-htree (no `dir_index`) directory large enough to span several
    /// directory blocks forces EVERY lookup through the parallel linear scan in
    /// `lookup_name_with_scope` (bd-xmh5g.194), including positive matches in
    /// blocks past the first. The htree golden test never exercises that case
    /// because present names resolve via the index, not the linear fallback.
    /// Each present and absent name must agree byte-for-byte with the
    /// independent serial `linear_lookup_name_reference` oracle (bd-xmh5g.200).
    #[test]
    fn ext4_parallel_linear_lookup_matches_serial_multiblock_bd_xmh5g_200() {
        let Some((fs, _dev, _tmp, _image)) =
            open_ext4_mke2fs_features(16, "extent,fast_commit,^metadata_csum,^dir_index")
        else {
            return; // e2fsprogs unavailable; skip.
        };
        let cx = Cx::for_testing();
        let scope = RequestScope::empty();

        // Enough entries to span several 1 KiB directory blocks.
        let names: Vec<String> = (0..180).map(|i| format!("entry_{i:04}.dat")).collect();
        for name in &names {
            fs.create(&cx, InodeNumber(2), OsStr::new(name), 0o644, 0, 0)
                .unwrap_or_else(|err| panic!("create {name}: {err}"));
        }

        // Re-read the grown root inode and prove the path under test: a
        // multi-block, non-htree directory (every lookup is a linear scan).
        let dir_inode = fs.read_inode(&cx, InodeNumber(2)).expect("read root inode");
        assert!(
            !dir_inode.has_htree_index(),
            "test needs a linear (non-htree) directory to exercise the parallel scan"
        );
        let bs = u64::from(fs.block_size());
        let num_blocks = dir_logical_block_count(dir_inode.size, bs).expect("dir block count");
        assert!(
            num_blocks > 1,
            "directory must span multiple blocks (got {num_blocks})"
        );

        // Every present name must be found by the parallel scan and agree with
        // the serial reference; matches land in blocks past the first.
        for name in &names {
            let parallel = fs
                .lookup_name_with_scope(&cx, &scope, &dir_inode, name.as_bytes())
                .unwrap_or_else(|err| panic!("parallel lookup {name}: {err}"));
            let serial =
                linear_lookup_name_reference(&fs, &cx, &scope, &dir_inode, name.as_bytes())
                    .unwrap_or_else(|err| panic!("serial lookup {name}: {err}"));
            assert!(parallel.is_some(), "present name {name} must be found");
            assert_eq!(parallel, serial, "parallel vs serial mismatch for {name}");
        }

        // Absent names: the parallel scan reads every block (negative lookup)
        // and must return None, matching the serial reference.
        for absent in ["entry_9999.dat", "nope", "entry_0001.daX"] {
            let parallel = fs
                .lookup_name_with_scope(&cx, &scope, &dir_inode, absent.as_bytes())
                .unwrap_or_else(|err| panic!("parallel absent lookup {absent}: {err}"));
            let serial =
                linear_lookup_name_reference(&fs, &cx, &scope, &dir_inode, absent.as_bytes())
                    .unwrap_or_else(|err| panic!("serial absent lookup {absent}: {err}"));
            assert_eq!(parallel, None, "absent name {absent} must not be found");
            assert_eq!(
                parallel, serial,
                "parallel vs serial mismatch for absent {absent}"
            );
        }
    }

    /// A multi-block non-htree directory exercises the parallel cold-run reader
    /// inside `read_dir_with_scope`. Compare it with a serial block-by-block
    /// oracle so ordering, record lengths, and hole/unwritten skipping stay
    /// byte-for-byte equivalent (bd-ygvfs).
    #[test]
    fn ext4_parallel_read_dir_matches_serial_multiblock_bd_ygvfs() {
        let Some((fs, _dev, _tmp, _image)) =
            open_ext4_mke2fs_features(16, "extent,fast_commit,^metadata_csum,^dir_index")
        else {
            return; // e2fsprogs unavailable; skip.
        };
        let cx = Cx::for_testing();
        let scope = RequestScope::empty();

        let names: Vec<String> = (0..180).map(|i| format!("entry_{i:04}.dat")).collect();
        for name in &names {
            fs.create(&cx, InodeNumber(2), OsStr::new(name), 0o644, 0, 0)
                .unwrap_or_else(|err| panic!("create {name}: {err}"));
        }

        let dir_inode = fs.read_inode(&cx, InodeNumber(2)).expect("read root inode");
        assert!(
            !dir_inode.has_htree_index(),
            "test needs a linear (non-htree) directory to exercise parallel read_dir"
        );
        let bs = u64::from(fs.block_size());
        let num_blocks = dir_logical_block_count(dir_inode.size, bs).expect("dir block count");
        assert!(
            num_blocks > 1,
            "directory must span multiple blocks (got {num_blocks})"
        );

        let parallel = fs
            .read_dir_with_scope(&cx, &scope, &dir_inode)
            .expect("parallel read_dir");
        let serial =
            linear_read_dir_reference(&fs, &cx, &scope, &dir_inode).expect("serial read_dir");
        assert_eq!(
            parallel, serial,
            "parallel read_dir must match serial block order and parsed entries"
        );

        for name in &names {
            assert!(
                parallel.iter().any(|entry| entry.name == name.as_bytes()),
                "read_dir output must contain {name}"
            );
        }
    }

    #[test]
    #[ignore = "profiling tool for bd-gauub: same-binary htree lookup vs old linear scan on the committed dir_index golden."]
    fn profile_htree_lookup_bd_gauub_ab() {
        let Some((fs, cx, htree_inode)) = open_ext4_dir_index_golden() else {
            return;
        };
        let scope = RequestScope::empty();
        let target = b"file_179.txt";
        let reps = 5_000_u32;

        let linear_start = std::time::Instant::now();
        for _ in 0..reps {
            let entry = linear_lookup_name_reference(&fs, &cx, &scope, &htree_inode, target)
                .expect("linear lookup")
                .expect("linear target");
            std::hint::black_box(entry);
        }
        let linear = linear_start.elapsed() / reps;

        let htree_start = std::time::Instant::now();
        for _ in 0..reps {
            let entry = fs
                .lookup_name_with_scope(&cx, &scope, &htree_inode, target)
                .expect("htree lookup")
                .expect("htree target");
            std::hint::black_box(entry);
        }
        let htree = htree_start.elapsed() / reps;

        eprintln!(
            "bd-gauub htree_ab target=file_179.txt reps={reps}: linear={linear:?}, htree={htree:?}"
        );
    }

