    #[test]
    fn write_mkdir_at_dir_link_max_returns_emlink_bd_j12g7() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let free_inodes_before = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count before mkdir");
        let free_blocks_before = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count before mkdir");

        // A NON-htree directory at the EXT4_LINK_MAX cap must reject a new
        // subdirectory with EMLINK (kernel EXT4_DIR_LINK_MAX), before allocating
        // anything — previously FrankenFS let the parent's link count climb to a
        // u16 overflow and surfaced a generic Corruption instead (bd-j12g7).
        let mut root_inode = fs.read_inode(&cx, root).expect("read root inode");
        assert_eq!(
            root_inode.flags & ffs_types::EXT4_INDEX_FL,
            0,
            "root must be non-htree for the EMLINK path"
        );
        root_inode.links_count = 65_000;
        persist_ext4_test_inode(&fs, &cx, root, &root_inode);

        let err = fs
            .mkdir(&cx, root, OsStr::new("overflow_dir"), 0o755, 0, 0)
            .expect_err("mkdir at the directory link cap must fail");
        assert_eq!(err.to_errno(), libc::EMLINK);

        let lookup_err = fs
            .lookup(&cx, root, OsStr::new("overflow_dir"))
            .expect_err("failed mkdir must not publish directory entry");
        assert_eq!(lookup_err.to_errno(), libc::ENOENT);

        let free_inodes_after = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count after mkdir");
        let free_blocks_after = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count after mkdir");
        assert_eq!(
            free_inodes_after, free_inodes_before,
            "failed mkdir should not leak inode allocation"
        );
        assert_eq!(
            free_blocks_after, free_blocks_before,
            "failed mkdir should not leak directory block allocation"
        );
    }

    #[test]
    fn ext4_dir_link_inc_models_kernel_inc_count_bd_j12g7() {
        let ino = InodeNumber(2);
        // Non-htree: a plain increment (ext4_mkdir's EMLINK guard keeps it below
        // the cap, so the overflow edge is unreachable here).
        assert_eq!(OpenFs::ext4_dir_link_inc(2, ino, false).unwrap(), 3);
        assert_eq!(
            OpenFs::ext4_dir_link_inc(64_999, ino, false).unwrap(),
            65_000
        );
        // htree below the cap: still a plain increment (parity unchanged).
        assert_eq!(OpenFs::ext4_dir_link_inc(7, ino, true).unwrap(), 8);
        assert_eq!(
            OpenFs::ext4_dir_link_inc(64_999, ino, true).unwrap(),
            65_000
        );
        // htree crossing EXT4_LINK_MAX (65000): pinned to the sentinel 1.
        assert_eq!(OpenFs::ext4_dir_link_inc(65_000, ino, true).unwrap(), 1);
        assert_eq!(OpenFs::ext4_dir_link_inc(65_001, ino, true).unwrap(), 1);
        // htree already at the sentinel (1): the bump lands on 2 -> stays 1.
        assert_eq!(OpenFs::ext4_dir_link_inc(1, ino, true).unwrap(), 1);
    }

    #[test]
    fn ext4_dir_link_dec_models_kernel_dec_count_bd_j12g7() {
        let ino = InodeNumber(2);
        // Real count > 2: a plain decrement.
        assert_eq!(OpenFs::ext4_dir_link_dec(7, ino).unwrap(), 6);
        assert_eq!(OpenFs::ext4_dir_link_dec(3, ino).unwrap(), 2);
        // Never drop a directory below 2: a base dir stays 2, an htree directory
        // pinned at the sentinel stays 1.
        assert_eq!(OpenFs::ext4_dir_link_dec(2, ino).unwrap(), 2);
        assert_eq!(OpenFs::ext4_dir_link_dec(1, ino).unwrap(), 1);
    }

