    #[test]
    fn write_rename_directory_within_same_parent_preserves_parent_link_count() {
        // `mv P/child P/child2` (same parent): the moved directory's '..' still
        // points to P, so P's link count must be UNCHANGED. ext4_add_dir_entry
        // increments the parent's link count for the inserted directory entry
        // (treating it as a fresh subdirectory); the same-parent rename path
        // must undo that, or the parent leaks a link and e2fsck reports
        // "inode <P> ref count is N, should be N-1".
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let parent = fs
            .mkdir(&cx, root, OsStr::new("same_rename_parent"), 0o755, 0, 0)
            .expect("create parent dir");
        fs.mkdir(&cx, parent.ino, OsStr::new("child"), 0o755, 0, 0)
            .expect("create child dir");

        let before = fs
            .read_inode(&cx, parent.ino)
            .expect("read parent before")
            .links_count;

        fs.rename(
            &cx,
            parent.ino,
            OsStr::new("child"),
            parent.ino,
            OsStr::new("child2"),
        )
        .expect("same-parent directory rename");

        let after = fs
            .read_inode(&cx, parent.ino)
            .expect("read parent after")
            .links_count;
        assert_eq!(
            after, before,
            "same-parent directory rename must not change the parent link count \
             (before={before}, after={after})"
        );

        // The directory is reachable only under the new name.
        fs.lookup(&cx, parent.ino, OsStr::new("child2"))
            .expect("child reachable under new name");
        assert!(fs.lookup(&cx, parent.ino, OsStr::new("child")).is_err());
    }

    #[test]
    fn write_rename_directory_clamps_corrupt_parent_nlink_bd_j12g7() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let src = fs
            .mkdir(&cx, root, OsStr::new("rename_corrupt_src"), 0o755, 0, 0)
            .expect("create source dir");
        fs.mkdir(&cx, root, OsStr::new("rename_corrupt_dst"), 0o755, 0, 0)
            .expect("create destination dir");

        // Inject a corrupt parent link count (a real directory with subdirs never
        // has 0). The kernel's ext4_dec_count never drops a directory below 2, so
        // the '..'-backref decrements during this dir-over-dir rename CLAMP at the
        // floor instead of underflowing — the rename completes rather than failing
        // as a generic Corruption. Before bd-j12g7 FrankenFS surfaced the underflow
        // as a hard error (non-kernel-faithful), which this test used to pin.
        let mut root_inode = fs.read_inode(&cx, root).expect("read root inode");
        root_inode.links_count = 0;
        persist_ext4_test_inode(&fs, &cx, root, &root_inode);

        fs.rename(
            &cx,
            root,
            OsStr::new("rename_corrupt_src"),
            root,
            OsStr::new("rename_corrupt_dst"),
        )
        .expect("rename clamps the corrupt parent link count instead of erroring");

        // The source name is gone; the destination name now resolves to the moved
        // directory (the empty target was clobbered).
        assert!(
            fs.lookup(&cx, root, OsStr::new("rename_corrupt_src"))
                .is_err(),
            "source name must be removed after a successful rename"
        );
        let dst_lookup = fs
            .lookup(&cx, root, OsStr::new("rename_corrupt_dst"))
            .expect("destination name resolves to the moved directory");
        assert_eq!(dst_lookup.ino, src.ino);

        // The corrupt parent link count is clamped at the directory floor, never
        // underflowed past it.
        let after = fs
            .read_inode(&cx, root)
            .expect("read root after rename")
            .links_count;
        assert!(
            after <= 2,
            "corrupt parent nlink must be clamped at the dir floor, not underflowed (got {after})"
        );
    }

    #[test]
    fn write_rename_over_existing_file_replaces_target() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let src = fs
            .create(&cx, root, OsStr::new("rename_src.txt"), 0o644, 0, 0)
            .expect("create source");
        let src_payload = b"source payload";
        fs.write(&cx, src.ino, 0, src_payload)
            .expect("write source");

        let dst = fs
            .create(&cx, root, OsStr::new("rename_dst.txt"), 0o644, 0, 0)
            .expect("create destination");
        fs.write(&cx, dst.ino, 0, b"destination payload")
            .expect("write destination");

        fs.rename(
            &cx,
            root,
            OsStr::new("rename_src.txt"),
            root,
            OsStr::new("rename_dst.txt"),
        )
        .expect("rename over existing file");

        let err = fs
            .lookup(&cx, root, OsStr::new("rename_src.txt"))
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::ENOENT);

        let renamed = fs
            .lookup(&cx, root, OsStr::new("rename_dst.txt"))
            .expect("lookup renamed destination");
        assert_eq!(renamed.ino, src.ino);
        assert_ne!(renamed.ino, dst.ino);

        let read_len = u32::try_from(src_payload.len()).expect("payload length fits in u32");
        let readback = fs
            .read(&cx, renamed.ino, 0, read_len)
            .expect("read renamed file");
        assert_eq!(&readback, src_payload);
    }

    #[test]
    fn write_rename_over_existing_file_reclaims_target_inode_and_blocks() {
        // Regression for bd-vdi91: the replaced target's inode (nlink -> 0) and
        // its data blocks must be freed by rename — not leaked — and the group
        // block-bitmap CRC32C must stay valid on a metadata_csum image. Before
        // the read-your-writes fix to the no-tx MvccBlockDevice adapter, the
        // free that runs inside rename's MVCC-txn op read a stale GDT/bitmap and
        // re-stamped a stale block_bitmap_csum, so count_free_blocks_in_group
        // here errored. Runs on remote workers via the generated image
        // (open_writable_ext4 skips — bd-cc6ua).
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let src = fs
            .create(&cx, root, OsStr::new("rn_src.txt"), 0o644, 0, 0)
            .expect("create source");
        fs.write(&cx, src.ino, 0, b"source payload")
            .expect("write source");
        let dst = fs
            .create(&cx, root, OsStr::new("rn_dst.txt"), 0o644, 0, 0)
            .expect("create destination");
        // Give the target a full data block so block reclamation is observable.
        fs.write(&cx, dst.ino, 0, &vec![0xDD_u8; 4096])
            .expect("write destination");
        let dst_group = GroupNumber(0);

        let free_inodes_before = fs
            .count_free_inodes_in_group(&cx, dst_group)
            .expect("free inodes before");
        let free_blocks_before = fs
            .count_free_blocks_in_group(&cx, dst_group)
            .expect("free blocks before");

        fs.rename(
            &cx,
            root,
            OsStr::new("rn_src.txt"),
            root,
            OsStr::new("rn_dst.txt"),
        )
        .expect("rename over existing file");

        // src.ino now lives under the dst name; the OLD dst inode must be freed.
        let renamed = fs
            .lookup(&cx, root, OsStr::new("rn_dst.txt"))
            .expect("lookup renamed");
        assert_eq!(
            renamed.ino, src.ino,
            "dst name now resolves to source inode"
        );

        let free_inodes_after = fs
            .count_free_inodes_in_group(&cx, dst_group)
            .expect("free inodes after");
        let free_blocks_after = fs
            .count_free_blocks_in_group(&cx, dst_group)
            .expect("free blocks after");
        assert_eq!(
            free_inodes_after,
            free_inodes_before + 1,
            "replaced target inode must be reclaimed (not leaked)"
        );
        assert_eq!(
            free_blocks_after,
            free_blocks_before + 1,
            "replaced target's data block must be reclaimed (not leaked)"
        );
    }

