    #[test]
    fn write_symlink_rejects_target_exceeding_path_max() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        // Linux PATH_MAX includes the trailing NUL, so a 4096-byte target is too long.
        let too_long = "x".repeat(usize::try_from(LINUX_PATH_MAX).unwrap());
        let err = fs
            .symlink(
                &cx,
                root,
                OsStr::new("too_long_link"),
                Path::new(&too_long),
                1000,
                1000,
            )
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::ENAMETOOLONG);

        // Empty target is also rejected.
        let err = fs
            .symlink(
                &cx,
                root,
                OsStr::new("empty_link"),
                Path::new(""),
                1000,
                1000,
            )
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::ENAMETOOLONG);

        // Target of exactly PATH_MAX-1 bytes is accepted.
        let at_limit = "y".repeat(usize::try_from(LINUX_SYMLINK_TARGET_MAX).unwrap());
        let attr = fs
            .symlink(
                &cx,
                root,
                OsStr::new("max_link"),
                Path::new(&at_limit),
                1000,
                1000,
            )
            .expect("symlink at PATH_MAX-1 should succeed");
        assert_eq!(attr.kind, FileType::Symlink);
    }

    #[test]
    #[ignore = "bd-cc6ua: needs a near-full filesystem to trigger ENOSPC; the generated 64 MiB image is too large, so the symlink succeeds. Passes against a small committed fixture"]
    fn write_symlink_slow_target_enospc_rolls_back_inode_and_name() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let free_before = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count before slow symlink failure");
        let summary = fs.free_space_summary(&cx).expect("free space summary");
        let block_size = usize::try_from(fs.ext4_superblock().expect("ext4 superblock").block_size)
            .expect("block size fits usize");
        let target_len = usize::try_from(summary.free_blocks_total)
            .expect("free block total fits usize")
            .saturating_mul(block_size)
            .saturating_add(1);
        let huge_target = "x".repeat(target_len);

        let err = fs
            .symlink(
                &cx,
                root,
                OsStr::new("slow_link_enospc"),
                Path::new(&huge_target),
                1000,
                1000,
            )
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::ENOSPC);

        let lookup_err = fs
            .lookup(&cx, root, OsStr::new("slow_link_enospc"))
            .unwrap_err();
        assert_eq!(lookup_err.to_errno(), libc::ENOENT);

        let free_after = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count after slow symlink failure");
        assert_eq!(
            free_after, free_before,
            "failed slow symlink should not leak inode"
        );
    }

