    fn write_symlink_slow_target_corrupt_parent_rolls_back_inode_and_blocks() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let free_inodes_before = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count before slow symlink corruption");
        let free_blocks_before = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count before slow symlink corruption");
        let long_target =
            "/var/lib/frankenfs/corrupt-parent/slow/symlink/target/path/that/exceeds/fast-storage";

        let root_inode = fs.read_inode(&cx, root).expect("read root inode");
        let root_extents = fs.collect_extents(&cx, &root_inode).expect("root extents");
        let first_ext = root_extents.first().expect("root directory extent");
        let dir_block_no = BlockNumber(first_ext.physical_start);
        let mut dir_block = fs
            .read_block_vec(&cx, dir_block_no)
            .expect("read root directory block");
        dir_block[4..6].copy_from_slice(&0_u16.to_le_bytes());
        fs.block_device_adapter()
            .write_block(&cx, dir_block_no, &dir_block)
            .expect("persist corrupted root directory block");

        let err = fs
            .symlink(
                &cx,
                root,
                OsStr::new("slow_link_corrupt_parent"),
                Path::new(long_target),
                1000,
                1000,
            )
            .unwrap_err();
        assert!(
            matches!(err, FfsError::Corruption { .. } | FfsError::Format(_)),
            "expected corruption-style failure, got {err:?}"
        );

        let lookup_err = fs
            .lookup(&cx, root, OsStr::new("slow_link_corrupt_parent"))
            .unwrap_err();
        assert_eq!(lookup_err.to_errno(), libc::ENOENT);

        let free_inodes_after = fs
            .count_free_inodes_in_group(&cx, GroupNumber(0))
            .expect("free inode count after slow symlink corruption");
        let free_blocks_after = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count after slow symlink corruption");
        assert_eq!(
            free_inodes_after, free_inodes_before,
            "failed slow symlink should not leak inode allocation"
        );
        assert_eq!(
            free_blocks_after, free_blocks_before,
            "failed slow symlink should not leak target block allocation"
        );
    }

    #[test]
    fn write_fallocate_preallocate_keep_size_and_punch_hole() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("falloc.bin"), 0o644, 0, 0)
            .expect("create");

        fs.fallocate(&cx, attr.ino, 0, 8192, 0).expect("fallocate");
        let after_alloc = fs.getattr(&cx, attr.ino).expect("getattr");
        assert_eq!(after_alloc.size, 8192);
        assert!(after_alloc.blocks >= 16);

        let zero_data = fs.read(&cx, attr.ino, 0, 8192).expect("read prealloc");
        assert_eq!(zero_data.len(), 8192);
        assert!(zero_data.iter().all(|&b| b == 0));

        fs.fallocate(&cx, attr.ino, 12288, 4096, libc::FALLOC_FL_KEEP_SIZE)
            .expect("fallocate keep_size");
        let after_keep = fs.getattr(&cx, attr.ino).expect("getattr keep_size");
        assert_eq!(after_keep.size, 8192);

        let payload = vec![0xAB_u8; 8192];
        fs.write(&cx, attr.ino, 0, &payload).expect("write payload");

        fs.fallocate(
            &cx,
            attr.ino,
            4096,
            4096,
            libc::FALLOC_FL_KEEP_SIZE | libc::FALLOC_FL_PUNCH_HOLE,
        )
        .expect("punch hole");

        let after_punch = fs.getattr(&cx, attr.ino).expect("getattr after punch");
        assert_eq!(after_punch.size, 8192);
        let readback = fs.read(&cx, attr.ino, 0, 8192).expect("read after punch");
        assert!(readback[..4096].iter().all(|&b| b == 0xAB));
        assert!(readback[4096..8192].iter().all(|&b| b == 0));
    }

    #[test]
    fn write_many_blocks_into_preallocated_unwritten_extent_bd_e4uwb() {
        // Regression for bd-e4uwb: ext4_write reuses its extent cache across the
        // per-block loop and deliberately does NOT invalidate it after
        // mark_written. Writing many consecutive blocks into one preallocated
        // (unwritten) extent splits that extent per block; every block must still
        // land its own distinct data at the right physical offset despite the
        // cache still holding the pre-split single extent. A stale-resolution bug
        // would corrupt later blocks, so verify EACH block reads back its byte.
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("falloc_write.bin"), 0o644, 0, 0)
            .expect("create");

        const BLOCKS: usize = 8;
        const BS: usize = 4096;
        fs.fallocate(&cx, attr.ino, 0, (BLOCKS * BS) as u64, 0)
            .expect("fallocate");
        let pre = fs
            .read(&cx, attr.ino, 0, (BLOCKS * BS) as u32)
            .expect("read prealloc");
        assert!(
            pre.iter().all(|&b| b == 0),
            "preallocated region must read zero before write"
        );

        // Distinct data per block, written in ONE multi-block call so each block
        // flows through the unwritten->written (mark_written) loop branch.
        let mut payload = vec![0u8; BLOCKS * BS];
        for (i, chunk) in payload.chunks_mut(BS).enumerate() {
            chunk.fill(0x10 + u8::try_from(i).expect("block index fits u8"));
        }
        fs.write(&cx, attr.ino, 0, &payload)
            .expect("write into unwritten");

        let back = fs
            .read(&cx, attr.ino, 0, (BLOCKS * BS) as u32)
            .expect("readback");
        for i in 0..BLOCKS {
            let expect = 0x10 + u8::try_from(i).expect("block index fits u8");
            assert!(
                back[i * BS..(i + 1) * BS].iter().all(|&b| b == expect),
                "block {i} mismatched: expected {expect:#x}"
            );
        }
    }

    #[test]
    fn ext4_write_cross_call_extent_snapshot_golden_bd_pqzev() {
        use sha2::{Digest, Sha256};

        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("pqzev_frag.bin"), 0o644, 0, 0)
            .expect("create");

        const BLOCKS: usize = 16;
        const BS: usize = 4096;
        let mut model = vec![0_u8; (BLOCKS * 2 - 1) * BS];

        for i in 0..BLOCKS {
            let logical = i * 2;
            let payload = vec![0x30 + u8::try_from(i).expect("block index fits u8"); BS];
            let offset = (logical * BS) as u64;
            fs.write(&cx, attr.ino, offset, &payload)
                .expect("sparse write");
            model[logical * BS..(logical + 1) * BS].copy_from_slice(&payload);
        }

        for i in 0..BLOCKS {
            let logical = i * 2;
            let payload = vec![0x80 + u8::try_from(i).expect("block index fits u8"); BS];
            let offset = (logical * BS) as u64;
            fs.write(&cx, attr.ino, offset, &payload)
                .expect("cross-call overwrite");
            model[logical * BS..(logical + 1) * BS].copy_from_slice(&payload);
        }

        let inode_after_overwrite = fs.read_inode(&cx, attr.ino).expect("read inode");
        let ns = extent_cache_namespace(&inode_after_overwrite);
        assert!(
            fs.ext4_write_extent_snapshot
                .lock()
                .as_ref()
                .is_some_and(|snapshot| snapshot.namespace == ns),
            "pure cross-call overwrites should retain the write extent snapshot"
        );

        let readback = fs
            .read(
                &cx,
                attr.ino,
                0,
                u32::try_from(model.len()).expect("model length fits u32"),
            )
            .expect("read fragmented file");
        assert_eq!(readback, model);

        let extents = fs
            .collect_extents(&cx, &inode_after_overwrite)
            .expect("collect extents");
        let mut hasher = Sha256::new();
        hasher.update(&readback);
        for extent in &extents {
            hasher.update(extent.logical_block.to_le_bytes());
            hasher.update(extent.actual_len().to_le_bytes());
            hasher.update(extent.physical_start.to_le_bytes());
            hasher.update([u8::from(extent.is_unwritten())]);
        }
        let digest = hasher
            .finalize()
            .iter()
            .map(|byte| format!("{byte:02x}"))
            .collect::<String>();
        println!("bd_pqzev_ext4_write_cross_call_golden_sha256={digest}");
        assert_eq!(
            digest,
            "791b273880e57a4958d5ebb2d0ed53cb5944cddcadc143e6b1dd99442a62bf18"
        );

        fs.setattr(
            &cx,
            attr.ino,
            &SetAttrRequest {
                size: Some(BS as u64),
                ..SetAttrRequest::default()
            },
        )
        .expect("truncate");
        assert!(
            fs.ext4_write_extent_snapshot.lock().is_none(),
            "truncate must invalidate the write extent snapshot"
        );

        let tail_payload = vec![0xEE_u8; BS];
        fs.write(&cx, attr.ino, (BS * 4) as u64, &tail_payload)
            .expect("write after truncate");
        let tail = fs
            .read(&cx, attr.ino, (BS * 4) as u64, BS as u32)
            .expect("read tail after truncate");
        assert_eq!(tail, tail_payload);
    }

    #[test]
    fn write_fallocate_punch_hole_in_middle_of_extent_splits_and_frees() {
        // The existing punch test removes the trailing block (extent
        // truncation). Punching the MIDDLE of a larger contiguous region forces
        // the extent to be split into a head and a tail with a hole between —
        // the subtle case. The surrounding data must survive, the hole must
        // read as zeros, size must be preserved, and the punched blocks freed.
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("punch-mid.bin"), 0o644, 0, 0)
            .expect("create");

        // 16 KiB of non-zero data (so the punched hole's zeros are unambiguous).
        let payload: Vec<u8> = (0_usize..16 * 1024)
            .map(|i| u8::try_from((i % 250) + 1).expect("pattern byte fits u8"))
            .collect();
        fs.write(&cx, attr.ino, 0, &payload).expect("write 16K");
        let before = fs.getattr(&cx, attr.ino).expect("getattr before punch");

        // Punch the middle two blocks: [4K, 12K).
        fs.fallocate(
            &cx,
            attr.ino,
            4096,
            8192,
            libc::FALLOC_FL_KEEP_SIZE | libc::FALLOC_FL_PUNCH_HOLE,
        )
        .expect("punch middle hole");

        let after = fs.getattr(&cx, attr.ino).expect("getattr after punch");
        assert_eq!(
            after.size,
            payload.len() as u64,
            "punch_hole keeps file size"
        );
        assert!(
            after.blocks < before.blocks,
            "punching the middle must free the punched blocks (before={}, after={})",
            before.blocks,
            after.blocks
        );

        let readback = fs
            .read(
                &cx,
                attr.ino,
                0,
                u32::try_from(payload.len()).expect("test read length fits u32"),
            )
            .expect("read after punch");
        assert_eq!(readback.len(), payload.len());
        assert_eq!(
            &readback[..4096],
            &payload[..4096],
            "head before hole intact"
        );
        assert!(
            readback[4096..12288].iter().all(|&b| b == 0),
            "punched middle reads as zeros"
        );
        assert_eq!(
            &readback[12288..],
            &payload[12288..],
            "tail after hole intact (extent split preserved)"
        );
    }

    #[test]
    fn write_setattr_truncate() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("truncate_me.txt"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        // Write 100 bytes
        let data = vec![0x42_u8; 100];
        fs.write(&cx, ino, 0, &data).expect("write");

        // Verify size
        let attr = fs.getattr(&cx, ino).expect("getattr");
        assert_eq!(attr.size, 100);

        // Truncate to 50 bytes
        let attrs = SetAttrRequest {
            size: Some(50),
            ..SetAttrRequest::default()
        };
        let new_attr = fs.setattr(&cx, ino, &attrs).expect("setattr truncate");
        assert_eq!(new_attr.size, 50);

        // Read should return 50 bytes
        let readback = fs.read(&cx, ino, 0, 4096).expect("read after truncate");
        assert_eq!(readback.len(), 50);
        assert!(readback.iter().all(|&b| b == 0x42));
    }

    #[test]
    fn ext4_xattr_survives_data_overwrite() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("f.dat"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, b"original").expect("write data");
        fs.setxattr(&cx, attr.ino, "user.tag", b"KEEPME", XattrSetMode::Set)
            .expect("setxattr");

        // Overwrite the data; the inode-body/external xattr must survive the
        // inode rewrite that the data write performs.
        fs.write(&cx, attr.ino, 0, b"OVERWRITTEN")
            .expect("overwrite data");

        let val = fs.getxattr(&cx, attr.ino, "user.tag").expect("getxattr");
        assert_eq!(
            val,
            Some(b"KEEPME".to_vec()),
            "xattr must survive a data overwrite"
        );
        // The overwrite itself took effect (test is not vacuous).
        let data = fs.read(&cx, attr.ino, 0, 11).expect("read data");
        assert_eq!(&data, b"OVERWRITTEN");
    }

