        let bad = FsxattrInfo {
            xflags: 0,
            extsize: 0,
            nextents: 0,
            projid: 0,
            cowextsize: 4096,
        };
        let err = <OpenFs as FsOps>::set_inode_fsxattr(&fs, &cx, &mut scope, attr.ino, bad)
            .expect_err("non-zero cowextsize must fail");
