    #[test]
    fn write_sparse_file_write_at_offset() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("sparse.bin"), 0o644, 0, 0)
            .expect("create");

        // Write at offset 8192 (two blocks in), leaving a hole at the start.
        let payload = b"sparse data";
        let written = fs
            .write(&cx, attr.ino, 8192, payload)
            .expect("write at offset");
        assert_eq!(written as usize, payload.len());

        // Read the hole — should return zeros.
        let hole = fs.read(&cx, attr.ino, 0, 4096).expect("read hole");
        assert!(hole.iter().all(|&b| b == 0), "hole should be zero-filled");

        // Read the written region.
        let data = fs
            .read(
                &cx,
                attr.ino,
                8192,
                u32::try_from(payload.len()).expect("len fits u32"),
            )
            .expect("read at offset");
        assert_eq!(&data[..payload.len()], payload);
    }

    #[test]
    fn write_overwrite_preserves_surrounding_data() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("overwrite.bin"), 0o644, 0, 0)
            .expect("create");

        // Write initial data: "AAAA....AAAA" (100 bytes of 'A')
        let initial = vec![b'A'; 100];
        fs.write(&cx, attr.ino, 0, &initial).expect("initial write");

        // Overwrite bytes 10..20 with 'B'
        let patch = vec![b'B'; 10];
        fs.write(&cx, attr.ino, 10, &patch).expect("patch write");

        // Read back and verify
        let readback = fs.read(&cx, attr.ino, 0, 200).expect("read");
        assert!(readback.len() >= 100);
        assert!(
            readback[..10].iter().all(|&b| b == b'A'),
            "prefix preserved"
        );
        assert!(readback[10..20].iter().all(|&b| b == b'B'), "patch applied");
        assert!(
            readback[20..100].iter().all(|&b| b == b'A'),
            "suffix preserved"
        );
    }

    #[test]
    fn write_compressed_overwrite_reuses_blocks_and_preserves_i_blocks() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("e2compr_rewrite.bin"), 0o644, 0, 0)
            .expect("create");
        enable_e2compr_for_inode(&fs, &cx, attr.ino, 2, 20);
        let inode = fs
            .read_inode(&cx, attr.ino)
            .expect("inode after e2compr enable");
        assert!(
            !OpenFs::ext4_inode_uses_inline_data(&inode),
            "e2compr helper must not leave the inode logically classified as inline-data",
        );

        let baseline = fs.free_space_summary(&cx).expect("baseline free space");

        let first = vec![b'A'; 4096];
        fs.write(&cx, attr.ino, 0, &first)
            .expect("first compressed write");

        let after_first_summary = fs.free_space_summary(&cx).expect("after first write");
        let inode_after_first = fs
            .read_inode(&cx, attr.ino)
            .expect("inode after first write");
        assert!(
            inode_after_first.flags & ffs_types::EXT4_COMPRBLK_FL != 0,
            "compressed write should mark COMPRBLK"
        );
        assert!(
            after_first_summary.free_blocks_total < baseline.free_blocks_total,
            "first compressed write should consume at least one block"
        );
        assert!(
            inode_after_first.blocks > 0,
            "compressed write should update i_blocks"
        );

        let second = vec![b'B'; 4096];
        fs.write(&cx, attr.ino, 0, &second)
            .expect("second compressed write");

        let after_second_summary = fs.free_space_summary(&cx).expect("after rewrite");
        let inode_after_second = fs
            .read_inode(&cx, attr.ino)
            .expect("inode after second write");
        let readback = fs.read(&cx, attr.ino, 0, 4096).expect("readback");

        assert_eq!(
            after_second_summary.free_blocks_total,
            after_first_summary.free_blocks_total
        );
        assert_eq!(
            after_second_summary.gd_free_blocks_total,
            after_first_summary.gd_free_blocks_total
        );
        assert_eq!(inode_after_second.blocks, inode_after_first.blocks);
        assert_eq!(&readback[..second.len()], second.as_slice());
    }

    #[test]
    fn write_compressed_uncompressed_fallback_preserves_sparse_tail() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(
                &cx,
                root,
                OsStr::new("e2compr_sparse_tail.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");
        enable_e2compr_for_inode(&fs, &cx, attr.ino, 2, 20);

        let baseline = fs.free_space_summary(&cx).expect("baseline free space");
        let mut payload = vec![0_u8; 4096];
        let mut state = 0x1234_5678_u32;
        for byte in &mut payload {
            state ^= state << 13;
            state ^= state >> 17;
            state ^= state << 5;
            *byte = state.to_le_bytes()[0];
        }

        fs.write(&cx, attr.ino, 0, &payload)
            .expect("fallback compressed write");

        let after_write = fs.free_space_summary(&cx).expect("after fallback write");
        let inode = fs
            .read_inode(&cx, attr.ino)
            .expect("inode after fallback write");
        let readback = fs.read(&cx, attr.ino, 0, 4096).expect("readback");

        assert_eq!(
            baseline.free_blocks_total - after_write.free_blocks_total,
            1,
            "uncompressed fallback should allocate only the live 4 KiB block and keep the rest of the cluster sparse",
        );
        assert_eq!(
            baseline.gd_free_blocks_total - after_write.gd_free_blocks_total,
            1,
            "group descriptor free block accounting should match the sparse-tail allocation",
        );
        assert_eq!(
            inode.blocks,
            u64::from(4096 / EXT4_SECTOR_SIZE),
            "i_blocks should reflect a single allocated block for the sparse-tail fallback",
        );
        assert_eq!(readback, payload);
    }

    #[test]
    #[ignore = "bd-cc6ua: inode.blocks overflow injection (near-u64::MAX) does not round-trip through the generated image's inode encoding; defensive guard for an unreachable state"]
    fn write_compressed_inode_blocks_overflow_reports_corruption() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(
                &cx,
                root,
                OsStr::new("e2compr_blocks_overflow.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");
        enable_e2compr_for_inode(&fs, &cx, attr.ino, 2, 20);

        let free_before = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count before compressed write");
        let mut inode = fs
            .read_inode(&cx, attr.ino)
            .expect("read inode before compressed write");
        inode.blocks = u64::MAX;
        persist_ext4_test_inode(&fs, &cx, attr.ino, &inode);

        let payload = vec![b'Z'; 4096];
        let err = fs
            .write(&cx, attr.ino, 0, &payload)
            .expect_err("compressed write should fail on inode.blocks overflow");
        assert!(matches!(err, FfsError::Corruption { .. }));

        let free_after = fs
            .count_free_blocks_in_group(&cx, GroupNumber(0))
            .expect("free block count after compressed write failure");
        assert_eq!(
            free_after, free_before,
            "failed compressed write should not leak cluster allocations"
        );

        let inode_after = fs
            .read_inode(&cx, attr.ino)
            .expect("read inode after compressed write failure");
        assert_eq!(
            inode_after.size, 0,
            "failed compressed write must not extend file"
        );
        let readback = fs
            .read(&cx, attr.ino, 0, 32)
            .expect("read after failed write");
        assert!(
            readback.is_empty(),
            "failed compressed write must not publish file data"
        );
    }

    #[test]
    fn write_compressed_indirect_rewrite_reuses_blocks() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(
                &cx,
                root,
                OsStr::new("e2compr_indirect_rewrite.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");
        enable_e2compr_for_inode(&fs, &cx, attr.ino, 2, 20);

        let block_size = u64::from(fs.ext4_superblock().expect("ext4 superblock").block_size);
        let sectors_per_block = block_size / u64::from(EXT4_SECTOR_SIZE);
        let indirect_cluster_offset = 12 * block_size;
        let baseline = fs.free_space_summary(&cx).expect("baseline free space");

        let first = vec![b'A'; 4096];
        fs.write(&cx, attr.ino, indirect_cluster_offset, &first)
            .expect("first indirect compressed write");

        let after_first_summary = fs.free_space_summary(&cx).expect("after first write");
        let inode_after_first = fs
            .read_inode(&cx, attr.ino)
            .expect("inode after first write");
        assert!(
            after_first_summary.free_blocks_total < baseline.free_blocks_total,
            "indirect compressed write should consume blocks"
        );
        let consumed_blocks = baseline.free_blocks_total - after_first_summary.free_blocks_total;
        assert_eq!(
            inode_after_first.blocks,
            consumed_blocks * sectors_per_block,
            "i_blocks must include indirect metadata blocks as well as cluster payload blocks"
        );

        let second = vec![b'B'; 4096];
        fs.write(&cx, attr.ino, indirect_cluster_offset, &second)
            .expect("second indirect compressed write");

        let after_second_summary = fs.free_space_summary(&cx).expect("after rewrite");
        let inode_after_second = fs
            .read_inode(&cx, attr.ino)
            .expect("inode after second write");
        let readback = fs
            .read(&cx, attr.ino, indirect_cluster_offset, 4096)
            .expect("readback");

        assert_eq!(
            after_second_summary.free_blocks_total, after_first_summary.free_blocks_total,
            "rewriting an indirect compressed cluster should not leak old data blocks"
        );
        assert_eq!(
            after_second_summary.gd_free_blocks_total,
            after_first_summary.gd_free_blocks_total
        );
        assert_eq!(inode_after_second.blocks, inode_after_first.blocks);
        assert_eq!(&readback[..second.len()], second.as_slice());
    }

    #[test]
    #[ignore = "bd-cc6ua: inode.blocks overflow injection (near-u64::MAX) does not round-trip through the generated image's inode encoding; defensive guard for an unreachable state"]
    fn write_compressed_multicluster_failure_rolls_back_allocations() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(
                &cx,
                root,
                OsStr::new("e2compr_multicluster_rollback.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");
        enable_e2compr_for_inode(&fs, &cx, attr.ino, 2, 20);

        let block_size = u64::from(fs.ext4_superblock().expect("ext4 superblock").block_size);
        let sectors_per_block = block_size / u64::from(EXT4_SECTOR_SIZE);
        let indirect_cluster_offset = 12 * block_size;
        let free_before = fs.free_space_summary(&cx).expect("free space before write");

        let mut inode = fs
            .read_inode(&cx, attr.ino)
            .expect("read inode before compressed write");
        inode.blocks = u64::MAX - (2 * sectors_per_block);
        persist_ext4_test_inode(&fs, &cx, attr.ino, &inode);

        let payload = vec![b'Q'; 8192];
        let err = fs
            .write(&cx, attr.ino, indirect_cluster_offset, &payload)
            .expect_err("second compressed cluster should overflow inode.blocks");
        assert!(matches!(err, FfsError::Corruption { .. }));

        let free_after = fs
            .free_space_summary(&cx)
            .expect("free space after failed write");
        assert_eq!(
            free_after.free_blocks_total, free_before.free_blocks_total,
            "failed multicluster compressed write should free newly allocated data and metadata blocks"
        );
        assert_eq!(
            free_after.gd_free_blocks_total, free_before.gd_free_blocks_total,
            "group descriptor free block count should roll back after failed multicluster compressed write"
        );

        let inode_after = fs
            .read_inode(&cx, attr.ino)
            .expect("read inode after failed compressed write");
        assert_eq!(inode_after.size, 0, "failed write must not extend the file");
        let readback = fs
            .read(&cx, attr.ino, indirect_cluster_offset, 32)
            .expect("read after failed write");
        assert!(
            readback.is_empty(),
            "failed write must not publish compressed data"
        );
    }

    #[test]
    #[ignore = "bd-cc6ua: truncate of indirect-mapped compressed (e2compr) files is unimplemented (UnsupportedFeature); aspirational test"]
    fn write_compressed_truncate_to_zero_frees_blocks() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(
                &cx,
                root,
                OsStr::new("e2compr_truncate_zero.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");
        enable_e2compr_for_inode(&fs, &cx, attr.ino, 2, 20);

        let baseline = fs.free_space_summary(&cx).expect("baseline free space");
        let payload = vec![b'T'; 4096];
        fs.write(&cx, attr.ino, 0, &payload)
            .expect("compressed write before truncate");

        let after_write = fs.free_space_summary(&cx).expect("free space after write");
        assert!(
            after_write.free_blocks_total < baseline.free_blocks_total,
            "compressed write should consume blocks before truncate"
        );

        let trunc = SetAttrRequest {
            size: Some(0),
            ..SetAttrRequest::default()
        };
        fs.setattr(&cx, attr.ino, &trunc)
            .expect("truncate compressed inode to zero");

        let after_truncate = fs
            .free_space_summary(&cx)
            .expect("free space after truncate");
        let inode_after = fs
            .read_inode(&cx, attr.ino)
            .expect("read inode after truncate");
        let readback = fs.read(&cx, attr.ino, 0, 64).expect("read after truncate");

        assert_eq!(
            after_truncate.free_blocks_total, baseline.free_blocks_total,
            "truncate should free all compressed data/metadata blocks"
        );
        assert_eq!(
            after_truncate.gd_free_blocks_total, baseline.gd_free_blocks_total,
            "group descriptor free block count should return to baseline after truncate"
        );
        assert_eq!(inode_after.size, 0, "truncate should reset file size");
        assert_eq!(inode_after.blocks, 0, "truncate should clear i_blocks");
        assert!(
            readback.is_empty(),
            "truncate should remove compressed file contents"
        );
    }

