    /// ext4 mirror of btrfs_truncate_updates_mtime: a size-changing truncate
    /// must update mtime, not just ctime (bd-pssza). Deterministic via
    /// mtime == ctime after the op (both from the same op timestamp).
    #[test]
    fn ext4_truncate_updates_mtime_bd_pssza() {
        let Some(fs) = open_writable_ext4() else {
            return; // no ext4 fixture / mkfs available
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("trunc_mtime.bin"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;
        fs.write(&cx, ino, 0, b"0123456789").expect("write");

        let after = fs
            .setattr(
                &cx,
                ino,
                &SetAttrRequest {
                    size: Some(4),
                    ..SetAttrRequest::default()
                },
            )
            .expect("truncate");
        assert_eq!(after.size, 4);
        assert_eq!(
            after.mtime, after.ctime,
            "an ext4 size-changing truncate must update mtime, not just ctime"
        );
    }

    #[test]
    fn write_setattr_extend_file_via_size() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("extend_me.txt"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        fs.write(&cx, ino, 0, b"hello").expect("write");
        assert_eq!(fs.getattr(&cx, ino).expect("getattr").size, 5);

        // Extend to 100 bytes
        let new_attr = fs
            .setattr(
                &cx,
                ino,
                &SetAttrRequest {
                    size: Some(100),
                    ..SetAttrRequest::default()
                },
            )
            .expect("extend via setattr");
        assert_eq!(new_attr.size, 100);

        // Read back: first 5 bytes should be "hello", rest should be zeroed
        let data = fs.read(&cx, ino, 0, 4096).expect("read");
        assert_eq!(data.len(), 100);
        assert_eq!(&data[..5], b"hello");
        assert!(data[5..].iter().all(|&b| b == 0));
    }

    #[test]
    fn btrfs_align_up_and_down_boundaries() {
        // align_up: already-aligned passes through; otherwise rounds up.
        assert_eq!(OpenFs::btrfs_align_up(96, 16).unwrap(), 96);
        assert_eq!(OpenFs::btrfs_align_up(100, 16).unwrap(), 112);
        assert_eq!(OpenFs::btrfs_align_up(0, 16).unwrap(), 0);
        // Rounding up past u64::MAX is rejected, not wrapped.
        let err = OpenFs::btrfs_align_up(u64::MAX, 16).unwrap_err();
        assert!(matches!(err, FfsError::InvalidGeometry(_)), "got {err:?}");

        // align_down: already-aligned passes through; otherwise rounds down.
        assert_eq!(OpenFs::btrfs_align_down(96, 16), 96);
        assert_eq!(OpenFs::btrfs_align_down(100, 16), 96);
        assert_eq!(OpenFs::btrfs_align_down(15, 16), 0);
        assert_eq!(OpenFs::btrfs_align_down(0, 16), 0);
    }

    #[test]
    fn btrfs_checked_physical_offset_and_span_reject_overflow() {
        // Normal add.
        assert_eq!(
            OpenFs::btrfs_checked_physical_offset(1000, 24).unwrap(),
            1024
        );
        // base + pos overflowing u64 is rejected, not wrapped.
        let err = OpenFs::btrfs_checked_physical_offset(u64::MAX, 1).unwrap_err();
        assert!(matches!(err, FfsError::Corruption { .. }), "got {err:?}");

        // span: a zero-length span is always fine.
        assert!(OpenFs::btrfs_checked_physical_span(1000, 0).is_ok());
        assert!(OpenFs::btrfs_checked_physical_span(1000, 24).is_ok());
        // A span whose last byte overflows u64 is rejected.
        let err = OpenFs::btrfs_checked_physical_span(u64::MAX, 2).unwrap_err();
        assert!(matches!(err, FfsError::Corruption { .. }), "got {err:?}");
    }

    #[test]
    fn validate_single_path_component_rejects_special_names() {
        // A normal component and the maximum 255-byte component are accepted.
        assert!(OpenFs::validate_single_path_component(b"normal").is_ok());
        assert!(OpenFs::validate_single_path_component(&[b'x'; 255]).is_ok());
        // Empty, the special "." / ".." names, a NUL-bearing name, and a
        // 256-byte name are all rejected.
        assert!(OpenFs::validate_single_path_component(b"").is_err());
        assert!(OpenFs::validate_single_path_component(b".").is_err());
        assert!(OpenFs::validate_single_path_component(b"..").is_err());
        assert!(OpenFs::validate_single_path_component(b"a\0b").is_err());
        assert!(OpenFs::validate_single_path_component(&[b'x'; 256]).is_err());
        // A component containing the path separator '/' is rejected — the guard
        // that stops a single component from spanning directories (path traversal),
        // whether the slash is embedded, leading, or trailing.
        assert!(OpenFs::validate_single_path_component(b"a/b").is_err());
        assert!(OpenFs::validate_single_path_component(b"/etc").is_err());
        assert!(OpenFs::validate_single_path_component(b"sub/").is_err());
    }

    #[test]
    fn nlink_delta_guards_reject_overflow_and_underflow() {
        let ino = InodeNumber(42);
        // ── ext4 links_count (u16) ──
        assert_eq!(
            OpenFs::ext4_checked_links_count_delta(5, ino, 2).unwrap(),
            7
        );
        assert_eq!(
            OpenFs::ext4_checked_links_count_delta(5, ino, -2).unwrap(),
            3
        );
        assert_eq!(
            OpenFs::ext4_checked_links_count_delta(5, ino, 0).unwrap(),
            5
        );
        // Overflow past u16::MAX would wrap small and free a still-linked inode.
        assert!(OpenFs::ext4_checked_links_count_delta(u16::MAX, ino, 1).is_err());
        // Decrement below zero would wrap huge and leak the inode forever.
        assert!(OpenFs::ext4_checked_links_count_delta(0, ino, -1).is_err());
        assert!(OpenFs::ext4_checked_links_count_delta(1, ino, -2).is_err());

        // ── btrfs nlink (u32) ──
        assert_eq!(OpenFs::btrfs_checked_nlink_delta(5, 42, 2).unwrap(), 7);
        assert_eq!(OpenFs::btrfs_checked_nlink_delta(5, 42, -2).unwrap(), 3);
        assert!(OpenFs::btrfs_checked_nlink_delta(u32::MAX, 42, 1).is_err());
        assert!(OpenFs::btrfs_checked_nlink_delta(0, 42, -1).is_err());
    }

    #[test]
    fn ext4_checked_inode_blocks_delta_bounds() {
        let ino = InodeNumber(7);
        // Normal increment/decrement (i_blocks counts 512-byte sectors).
        assert_eq!(
            OpenFs::ext4_checked_inode_blocks_delta(100, ino, 8).unwrap(),
            108
        );
        assert_eq!(
            OpenFs::ext4_checked_inode_blocks_delta(100, ino, -8).unwrap(),
            92
        );
        assert_eq!(
            OpenFs::ext4_checked_inode_blocks_delta(100, ino, 0).unwrap(),
            100
        );
        // Overflow past u64::MAX.
        assert!(OpenFs::ext4_checked_inode_blocks_delta(u64::MAX, ino, 1).is_err());
        // Releasing more sectors than the inode holds would wrap i_blocks huge.
        assert!(OpenFs::ext4_checked_inode_blocks_delta(0, ino, -1).is_err());
        assert!(OpenFs::ext4_checked_inode_blocks_delta(8, ino, -16).is_err());
        // A delta that does not fit u64 is rejected.
        assert!(OpenFs::ext4_checked_inode_blocks_delta(0, ino, i128::from(u64::MAX) + 1).is_err());
    }

    #[test]
    fn btrfs_nbytes_delta_guards_reject_overflow_and_underflow() {
        // apply: normal increment / decrement / zero.
        assert_eq!(OpenFs::btrfs_apply_nbytes_delta(1000, 24).unwrap(), 1024);
        assert_eq!(OpenFs::btrfs_apply_nbytes_delta(1000, -24).unwrap(), 976);
        assert_eq!(OpenFs::btrfs_apply_nbytes_delta(1000, 0).unwrap(), 1000);
        // Overflow past u64::MAX.
        assert!(OpenFs::btrfs_apply_nbytes_delta(u64::MAX, 1).is_err());
        // Releasing more bytes than the inode holds would wrap nbytes huge.
        assert!(OpenFs::btrfs_apply_nbytes_delta(0, -1).is_err());
        assert!(OpenFs::btrfs_apply_nbytes_delta(8, -16).is_err());
        // A delta whose magnitude exceeds u64 is rejected (both signs).
        assert!(OpenFs::btrfs_apply_nbytes_delta(0, i128::from(u64::MAX) + 1).is_err());
        assert!(OpenFs::btrfs_apply_nbytes_delta(0, -(i128::from(u64::MAX) + 1)).is_err());
        // i128::MIN cannot be negated -> rejected, not panicked.
        assert!(OpenFs::btrfs_apply_nbytes_delta(0, i128::MIN).is_err());

        // accumulate: sums deltas; rejects i128 overflow.
        let mut acc: i128 = 0;
        OpenFs::btrfs_accumulate_nbytes_delta(&mut acc, 100).unwrap();
        OpenFs::btrfs_accumulate_nbytes_delta(&mut acc, -30).unwrap();
        assert_eq!(acc, 70);
        let mut at_max = i128::MAX;
        assert!(OpenFs::btrfs_accumulate_nbytes_delta(&mut at_max, 1).is_err());
    }

    #[test]
    fn btrfs_checked_chunk_available_and_logical_advance_guards() {
        // chunk_available: bytes from `logical` up to `chunk_end`.
        assert_eq!(
            OpenFs::btrfs_checked_chunk_available(2000, 1000).unwrap(),
            1000
        );
        // A logical bytenr past the chunk end would map to the wrong chunk.
        assert!(OpenFs::btrfs_checked_chunk_available(1000, 2000).is_err());
        // A logical bytenr exactly at chunk_end leaves no bytes available.
        assert!(OpenFs::btrfs_checked_chunk_available(1000, 1000).is_err());

        // logical_advance: logical + amount, rejecting a u64 overflow.
        assert_eq!(
            OpenFs::btrfs_checked_logical_advance(1000, 24).unwrap(),
            1024
        );
        assert!(OpenFs::btrfs_checked_logical_advance(u64::MAX, 1).is_err());
    }

    #[test]
    fn ext4_max_file_size_scales_with_block_size_and_rejects_above() {
        // The extent tree addresses 2^32 logical blocks, so the max file size
        // is 2^32 * block_size: 4 TiB / 8 TiB / 16 TiB for 1K / 2K / 4K blocks.
        assert_eq!(OpenFs::ext4_max_file_size(1024), 1_u64 << 42);
        assert_eq!(OpenFs::ext4_max_file_size(2048), 1_u64 << 43);
        assert_eq!(OpenFs::ext4_max_file_size(4096), 1_u64 << 44);

        // A file ending exactly at the max is allowed; one byte over is EFBIG.
        let max = OpenFs::ext4_max_file_size(4096);
        assert!(OpenFs::ext4_reject_oversized_file(max, 4096).is_ok());
        let err = OpenFs::ext4_reject_oversized_file(max + 1, 4096).unwrap_err();
        assert_eq!(err.to_errno(), libc::EFBIG);
    }

    #[test]
    fn write_setattr_extend_past_max_file_size_returns_efbig() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let ino = fs
            .create(&cx, root, OsStr::new("toobig.txt"), 0o644, 0, 0)
            .expect("create")
            .ino;

        // ext4 max file size is 2^32 * block_size (>= 4 TiB even at 1 KiB
        // blocks). ftruncate(2) past it must be EFBIG, not a silently-accepted
        // i_size. 1 PiB exceeds the cap for any supported block size.
        let one_pib: u64 = 1 << 50;
        let err = fs
            .setattr(
                &cx,
                ino,
                &SetAttrRequest {
                    size: Some(one_pib),
                    ..SetAttrRequest::default()
                },
            )
            .expect_err("extend past the ext4 max file size must fail");
        assert_eq!(err.to_errno(), libc::EFBIG);

        // The rejected truncate left the file untouched (still empty).
        assert_eq!(fs.getattr(&cx, ino).expect("getattr").size, 0);

        // A modest extend still works.
        let ok = fs
            .setattr(
                &cx,
                ino,
                &SetAttrRequest {
                    size: Some(1 << 20),
                    ..SetAttrRequest::default()
                },
            )
            .expect("a within-limit extend still succeeds");
        assert_eq!(ok.size, 1 << 20);
    }

    #[test]
    fn write_past_max_file_size_returns_efbig() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let ino = fs
            .create(&cx, root, OsStr::new("bigwrite.txt"), 0o644, 0, 0)
            .expect("create")
            .ino;

        // A write whose end offset exceeds the ext4 max file size is EFBIG.
        let err = fs
            .write(&cx, ino, 1 << 50, b"x")
            .expect_err("write past the ext4 max file size must fail");
        assert_eq!(err.to_errno(), libc::EFBIG);
    }

    #[test]
    fn ext4_fallocate_insert_range_past_max_file_size_returns_efbig_bd_a3fh8() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let ino = fs
            .create(&cx, root, OsStr::new("insbig.bin"), 0o644, 0, 0)
            .expect("create")
            .ino;

        let bs = u64::from(fs.ext4_superblock().expect("ext4 sb").block_size);
        let max = (1_u64 << 32) * bs; // ext4 max file size (2^32 * block_size)

        // Sparse-extend to just under the max (sets i_size only, no blocks).
        let near_max = max - bs;
        fs.setattr(
            &cx,
            ino,
            &SetAttrRequest {
                size: Some(near_max),
                ..SetAttrRequest::default()
            },
        )
        .expect("sparse extend to near the max must succeed");

        // INSERT_RANGE of 2 blocks at offset `bs` would grow i_size to max + bs,
        // exceeding the ext4 maximum -> EFBIG. The request's own offset+length is
        // tiny, so only the post-insert size check catches it (bd-a3fh8).
        const INSERT_RANGE: i32 = 0x20;
        let ops: &dyn FsOps = &fs;
        let err = ops
            .fallocate(
                &cx,
                &mut RequestScope::empty(),
                ino,
                bs,
                2 * bs,
                INSERT_RANGE,
            )
            .expect_err("insert_range past the ext4 max file size must be EFBIG");
        assert_eq!(err.to_errno(), libc::EFBIG);

        // The rejected insert left i_size unchanged.
        assert_eq!(fs.getattr(&cx, ino).expect("getattr").size, near_max);
    }

    #[test]
    fn btrfs_setattr_extend_past_max_file_size_returns_efbig() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(u64::from(BTRFS_FIRST_FREE_OBJECTID));
        let ino = fs
            .create(&cx, root, OsStr::new("toobig.txt"), 0o644, 0, 0)
            .expect("create")
            .ino;

        // btrfs max file size is MAX_LFS_FILESIZE = i64::MAX (2^63 - 1).
        // ftruncate(2) past it must be EFBIG, not a silently-accepted i_size.
        let past_max: u64 = 1 << 63; // 2^63 > i64::MAX
        let err = fs
            .setattr(
                &cx,
                ino,
                &SetAttrRequest {
                    size: Some(past_max),
                    ..SetAttrRequest::default()
                },
            )
            .expect_err("extend past the btrfs max file size must fail");
        assert_eq!(err.to_errno(), libc::EFBIG);

        // The rejected truncate left the file untouched (still empty).
        assert_eq!(fs.getattr(&cx, ino).expect("getattr").size, 0);

        // A within-limit extend still works.
        let ok = fs
            .setattr(
                &cx,
                ino,
                &SetAttrRequest {
                    size: Some(1 << 20),
                    ..SetAttrRequest::default()
                },
            )
            .expect("a within-limit extend still succeeds");
        assert_eq!(ok.size, 1 << 20);
    }

