    #[test]
    fn write_create_long_name_succeeds_or_rejects() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        // 255 chars is the ext4 max name length — should succeed
        let name_255 = "a".repeat(255);
        let result = fs.create(&cx, root, OsStr::new(&name_255), 0o644, 0, 0);
        // Might succeed or fail due to directory block space, but shouldn't panic
        match result {
            Ok(attr) => assert_eq!(attr.kind, FileType::RegularFile),
            Err(e) => {
                // ENOSPC or ENAMETOOLONG are acceptable
                assert!(
                    e.to_errno() == libc::ENOSPC || e.to_errno() == libc::ENAMETOOLONG,
                    "unexpected error for 255-char name: {e}"
                );
            }
        }

        // 256 chars exceeds ext4 limit — should fail
        let name_256 = "b".repeat(256);
        let err = fs
            .create(&cx, root, OsStr::new(&name_256), 0o644, 0, 0)
            .unwrap_err();
        assert!(
            err.to_errno() == libc::ENAMETOOLONG
                || err.to_errno() == libc::EINVAL
                || err.to_errno() == libc::ENOSPC,
            "expected name-too-long error for 256-char name, got errno {}",
            err.to_errno()
        );
    }

    #[test]
    fn write_ext4_rejects_empty_and_slash_names_early() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        // Empty name must be rejected.
        let err = fs
            .create(&cx, root, OsStr::new(""), 0o644, 0, 0)
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        // Name containing '/' must be rejected.
        let err = fs
            .create(&cx, root, OsStr::new("bad/name"), 0o644, 0, 0)
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        let err = fs
            .create(&cx, root, OsStr::from_bytes(b"bad\0name"), 0o644, 0, 0)
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        for name in [b".".as_slice(), b"..".as_slice()] {
            let err = fs
                .create(&cx, root, OsStr::from_bytes(name), 0o644, 0, 0)
                .unwrap_err();
            assert_eq!(err.to_errno(), libc::EINVAL);
        }

        // Same for mkdir.
        let err = fs
            .mkdir(&cx, root, OsStr::new(""), 0o755, 0, 0)
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        let err = fs
            .mkdir(&cx, root, OsStr::new("a/b"), 0o755, 0, 0)
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        let err = fs
            .mkdir(&cx, root, OsStr::from_bytes(b"a\0b"), 0o755, 0, 0)
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        for name in [b".".as_slice(), b"..".as_slice()] {
            let err = fs
                .mkdir(&cx, root, OsStr::from_bytes(name), 0o755, 0, 0)
                .unwrap_err();
            assert_eq!(err.to_errno(), libc::EINVAL);
        }
    }

