    #[test]
    fn ext4_fallocate_rejects_invalid_mode_combinations() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("falloc-mode.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &[0xAB_u8; 8192]).expect("write");

        // PUNCH_HOLE and ZERO_RANGE are mutually exclusive -> EINVAL.
        let punch_zero =
            libc::FALLOC_FL_PUNCH_HOLE | libc::FALLOC_FL_ZERO_RANGE | libc::FALLOC_FL_KEEP_SIZE;
        let err = fs
            .fallocate(&cx, attr.ino, 0, 4096, punch_zero)
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        // PUNCH_HOLE requires KEEP_SIZE -> EINVAL without it.
        let err2 = fs
            .fallocate(&cx, attr.ino, 0, 4096, libc::FALLOC_FL_PUNCH_HOLE)
            .unwrap_err();
        assert_eq!(err2.to_errno(), libc::EINVAL);

        // An unknown / unsupported mode bit is rejected.
        assert!(fs.fallocate(&cx, attr.ino, 0, 4096, 0x4000).is_err());
    }

    #[test]
    fn write_fallocate_punch_hole_zeroes_data() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("punch.txt"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        // Fill file with non-zero data (3 blocks = 12288 bytes)
        let fill = vec![0xAB_u8; 12288];
        fs.write(&cx, ino, 0, &fill).expect("fill");

        // Punch a hole in the middle block (offset 4096, length 4096 — block-aligned)
        fs.fallocate(
            &cx,
            ino,
            4096,
            4096,
            libc::FALLOC_FL_PUNCH_HOLE | libc::FALLOC_FL_KEEP_SIZE,
        )
        .expect("punch hole");

        // Size should be preserved
        assert_eq!(fs.getattr(&cx, ino).expect("ga").size, 12288);

        // Read the punched region — should be zeros
        let data = fs.read(&cx, ino, 0, 12288).expect("read");
        assert!(
            data[4096..8192].iter().all(|&b| b == 0),
            "punched region should be zeroed"
        );
        // Data outside the hole should be intact
        assert!(
            data[..4096].iter().all(|&b| b == 0xAB),
            "data before hole should be intact"
        );
        assert!(
            data[8192..12288].iter().all(|&b| b == 0xAB),
            "data after hole should be intact"
        );
    }

