    // ── bd-ezmts: FALLOC_FL_COLLAPSE_RANGE ─────────────────────────────────
    //
    // collapse_range removes [offset, offset+length) from the file and
    // shifts everything past the cut left by length. Both must be
    // block-aligned and the range must lie strictly inside the file.

    #[test]
    fn write_fallocate_collapse_range_shifts_tail_and_shrinks_file() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("collapse_basic.bin"), 0o644, 0, 0)
            .expect("create");

        // Layout: 4 file-aligned 4 KiB chunks A B C D.
        let block = 4096_u64;
        let block_len = usize::try_from(block).expect("test block size fits usize");
        let block_read_len = u32::try_from(block).expect("test block size fits u32");
        let chunk_a = vec![0xAA_u8; block_len];
        let chunk_b = vec![0xBB_u8; block_len];
        let chunk_c = vec![0xCC_u8; block_len];
        let chunk_d = vec![0xDD_u8; block_len];
        fs.write(&cx, attr.ino, 0, &chunk_a).expect("write A");
        fs.write(&cx, attr.ino, block, &chunk_b).expect("write B");
        fs.write(&cx, attr.ino, 2 * block, &chunk_c)
            .expect("write C");
        fs.write(&cx, attr.ino, 3 * block, &chunk_d)
            .expect("write D");

        let before = fs.getattr(&cx, attr.ino).expect("getattr before");
        assert_eq!(before.size, 4 * block, "file is 16 KiB before collapse");

        // Collapse the second 4 KiB chunk (B). Tail (C, D) shifts left.
        // FALLOC_FL_COLLAPSE_RANGE = 0x08, with no other mode bits.
        fs.fallocate(&cx, attr.ino, block, block, 0x08)
            .expect("collapse_range over chunk B");

        let after = fs.getattr(&cx, attr.ino).expect("getattr after");
        assert_eq!(
            after.size,
            3 * block,
            "file size shrinks by exactly the collapsed length"
        );

        // Read back every chunk and verify the tail moved.
        let read_a = fs.read(&cx, attr.ino, 0, block_read_len).expect("read A");
        let read_c_now_at_b = fs
            .read(&cx, attr.ino, block, block_read_len)
            .expect("read former-C");
        let read_d_now_at_c = fs
            .read(&cx, attr.ino, 2 * block, block_read_len)
            .expect("read former-D");
        assert_eq!(read_a, chunk_a, "A unchanged");
        assert_eq!(read_c_now_at_b, chunk_c, "C shifted left into B's slot");
        assert_eq!(read_d_now_at_c, chunk_d, "D shifted left into C's slot");
    }

    #[test]
    fn ext4_write_fallocate_interleave_matches_reference_model() {
        // Metamorphic coverage for the ext4 mutation surface, driven on a real
        // mkfs.ext4 image so it actually runs on rch (the existing single-op
        // collapse/insert tests use open_writable_ext4(), which skips there).
        // Interleaves writes, truncates, KEEP_SIZE punch-hole, zero-range, and
        // the data-SHIFTING modes collapse_range / insert_range against a
        // byte-exact in-memory model. The shifting modes splice the extent tree;
        // an off-by-one in the logical-block shift would diverge from the model.
        #[derive(Clone, Copy)]
        enum Op {
            Write(usize, usize, u8),
            Trunc(usize),
            Punch(usize, usize),
            Zero(usize, usize),
            Collapse(usize, usize),
            Insert(usize, usize),
        }
        use Op::{Collapse, Insert, Punch, Trunc, Write, Zero};

        let Some((fs, dev, tmp)) = open_writable_ext4_mkfs_with_device(64) else {
            eprintln!("mkfs.ext4 unavailable, skipping");
            return;
        };
        let cx = Cx::for_testing();
        let attr = fs
            .create(
                &cx,
                InodeNumber(2),
                OsStr::new("ext4-meta.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");

        // Block size is 4096; collapse/insert offsets and lengths are 4 KiB
        // aligned and strictly inside the file, as the kernel requires. Sizes in
        // the trailing comments track the model after each op.
        let program = [
            Write(0, 40960, 0x11),    // ten-block extent [0,40K)
            Collapse(8192, 8192),     // drop blocks 2-3, tail shifts down -> 32768
            Insert(4096, 8192),       // insert two zero blocks, tail shifts up -> 40960
            Write(0, 50000, 0x22),    // overwrite + extend (unaligned len)
            Punch(8192, 4096),        // KEEP_SIZE hole
            Zero(20480, 8192),        // zero a fragmented region
            Collapse(16384, 4096),    // drop one interior block -> 45904
            Insert(0, 4096),          // insert a leading block -> 50000
            Trunc(30000),             // shrink
            Trunc(45056),             // extend to an aligned size (implicit hole)
            Collapse(4096, 8192),     // drop [4096,12288) -> 36864
            Write(36000, 4000, 0x33), // overwrite crossing EOF -> 40000
        ];

        let mut model: Vec<u8> = Vec::new();
        for (step, op) in program.iter().enumerate() {
            match *op {
                Write(off, len, val) => {
                    let buf = vec![val; len];
                    fs.write(&cx, attr.ino, off as u64, &buf).expect("write");
                    if off + len > model.len() {
                        model.resize(off + len, 0);
                    }
                    model[off..off + len].copy_from_slice(&buf);
                }
                Trunc(size) => {
                    fs.setattr(
                        &cx,
                        attr.ino,
                        &SetAttrRequest {
                            size: Some(size as u64),
                            ..Default::default()
                        },
                    )
                    .expect("truncate");
                    model.resize(size, 0);
                }
                Punch(off, len) => {
                    fs.fallocate(
                        &cx,
                        attr.ino,
                        off as u64,
                        len as u64,
                        libc::FALLOC_FL_KEEP_SIZE | libc::FALLOC_FL_PUNCH_HOLE,
                    )
                    .expect("punch hole");
                    model[off..off + len].fill(0);
                }
                Zero(off, len) => {
                    fs.fallocate(
                        &cx,
                        attr.ino,
                        off as u64,
                        len as u64,
                        libc::FALLOC_FL_ZERO_RANGE,
                    )
                    .expect("zero range");
                    model[off..off + len].fill(0);
                }
                Collapse(off, len) => {
                    fs.fallocate(
                        &cx,
                        attr.ino,
                        off as u64,
                        len as u64,
                        libc::FALLOC_FL_COLLAPSE_RANGE,
                    )
                    .expect("collapse range");
                    model.drain(off..off + len);
                }
                Insert(off, len) => {
                    fs.fallocate(
                        &cx,
                        attr.ino,
                        off as u64,
                        len as u64,
                        libc::FALLOC_FL_INSERT_RANGE,
                    )
                    .expect("insert range");
                    model.splice(off..off, std::iter::repeat_n(0_u8, len));
                }
            }

            let attr_now = fs.getattr(&cx, attr.ino).expect("getattr");
            assert_eq!(
                attr_now.size,
                model.len() as u64,
                "inode size mismatch after step {step}"
            );
            if model.is_empty() {
                continue;
            }
            let got = fs
                .read(
                    &cx,
                    attr.ino,
                    0,
                    u32::try_from(model.len()).expect("model size fits u32"),
                )
                .expect("read");
            let ndiff = (0..model.len().min(got.len()))
                .filter(|&i| got[i] != model[i])
                .count();
            assert!(
                got.len() == model.len() && ndiff == 0,
                "content diverged from model after step {step}: got {} bytes, model {} bytes, \
                 {ndiff} differ (first at {})",
                got.len(),
                model.len(),
                (0..model.len().min(got.len()))
                    .find(|&i| got[i] != model[i])
                    .unwrap_or(0),
            );
        }

        // The whole collapse/insert/punch/zero churn must also leave the on-disk
        // accounting consistent (i_blocks / free totals after the extent-tree
        // splices) — validated now that file-op snapshots are e2fsck-clean
        // (bd-nd61w sb-total sync + bd-bdro7 coalescing).
        fs.flush_mvcc_to_device(&cx).expect("flush mvcc");
        let image = tmp.path().join("falloc_interleave_check.ext4");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        if let Some((clean, output)) = run_e2fsck(&image) {
            assert!(clean, "e2fsck after fallocate interleave churn:\n{output}");
        }
    }

    // Randomized differential gauntlet for the full ext4 mutation surface
    // (write / truncate / punch-hole / zero-range / collapse-range /
    // insert-range) against a byte-exact in-memory model, on a real mkfs.ext4
    // image. The curated `ext4_write_fallocate_interleave_matches_reference_model`
    // exercises ONE fixed 12-step program; this explores random interleavings so
    // the extent-tree-splicing modes (collapse/insert) meet states the fixed
    // sequence never reaches. Each fallocate op is attempted and an EINVAL (an
    // alignment/bounds combination that is invalid for the current file state) is
    // skipped identically in fs and model — keeping them in lockstep — while any
    // content/size divergence or unexpected error fails the case.
    proptest::proptest! {
        #![proptest_config(proptest::prelude::ProptestConfig::with_cases(16))]

        /// The O(N) HashSet dedup must produce exactly the same result as the
        /// prior O(N^2) keep-first-by-name all-pairs scan, for any row sequence.
        #[test]
        fn btrfs_dedup_dir_rows_matches_linear_dedup(
            names in proptest::collection::vec(
                proptest::collection::vec(proptest::prelude::any::<u8>(), 0..=6),
                0..=80,
            ),
        ) {
            let rows: Vec<(u64, DirEntry)> = names
                .iter()
                .enumerate()
                .map(|(i, name)| {
                    let key = u64::try_from(i).expect("index fits u64");
                    (
                        key,
                        DirEntry {
                            ino: InodeNumber(key + 2),
                            offset: 0,
                            kind: FileType::RegularFile,
                            name: name.clone(),
                        },
                    )
                })
                .collect();
            let mut expected: Vec<(u64, DirEntry)> = Vec::new();
            for row in rows.clone() {
                if expected.iter().any(|(_, e)| e.name == row.1.name) {
                    continue;
                }
                expected.push(row);
            }
            let got = OpenFs::btrfs_dedup_dir_rows(rows);
            proptest::prop_assert_eq!(got, expected);
        }

        #[test]
        fn ext4_write_fallocate_random_matches_reference_model(
            ops in proptest::collection::vec(
                (0u8..6, 0usize..200_000, 1usize..40_000, proptest::prelude::any::<u8>()),
                1..40,
            ),
        ) {
            let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
                return Ok(()); // mkfs.ext4 unavailable — skip.
            };
            let cx = Cx::for_testing();
            let attr = fs
                .create(&cx, InodeNumber(2), OsStr::new("rand-meta.bin"), 0o644, 0, 0)
                .expect("create");
            let mut model: Vec<u8> = Vec::new();
            const BS: usize = 4096;
            const CAP: usize = 512 * 1024;
            let align_down = |x: usize| x & !(BS - 1);

            for (step, (kind, a, b, val)) in ops.into_iter().enumerate() {
                let size = model.len();
                // Attempt a fallocate op: update the model only when the fs
                // accepts it; tolerate EINVAL (invalid for the current state) by
                // skipping both; fail on any other error.
                let do_falloc = |fs: &OpenFs,
                                     model: &mut Vec<u8>,
                                     off: usize,
                                     len: usize,
                                     mode: i32,
                                     apply: &dyn Fn(&mut Vec<u8>)|
                 -> Result<(), String> {
                    match fs.fallocate(&cx, attr.ino, off as u64, len as u64, mode) {
                        Ok(()) => {
                            apply(model);
                            Ok(())
                        }
                        // EINVAL (args invalid for the current state) or
                        // EOPNOTSUPP (FrankenFS does not yet support this exact
                        // shape, e.g. unaligned punch — tracked separately) are
                        // skipped identically in fs and model. Anything else is a
                        // real failure.
                        Err(e)
                            if e.to_errno() == libc::EINVAL
                                || e.to_errno() == libc::EOPNOTSUPP =>
                        {
                            Ok(())
                        }
                        Err(e) => Err(format!("unexpected fallocate error at step {step}: {e}")),
                    }
                };

                match kind {
                    0 => {
                        // Write.
                        let off = a.min(CAP - 1);
                        let len = b.min(CAP - off).max(1);
                        let buf = vec![val; len];
                        fs.write(&cx, attr.ino, off as u64, &buf).expect("write");
                        if off + len > model.len() {
                            model.resize(off + len, 0);
                        }
                        model[off..off + len].copy_from_slice(&buf);
                    }
                    1 => {
                        // Truncate.
                        let size_new = a % (CAP + 1);
                        fs.setattr(
                            &cx,
                            attr.ino,
                            &SetAttrRequest {
                                size: Some(size_new as u64),
                                ..Default::default()
                            },
                        )
                        .expect("truncate");
                        model.resize(size_new, 0);
                    }
                    2 if size > 0 => {
                        // Punch hole (KEEP_SIZE) — unaligned offsets/lengths
                        // included (bd-xnel9): the in-range bytes must read back
                        // zero while the file size is unchanged.
                        let off = a % size;
                        let len = (b % (size - off)).max(1);
                        let res = do_falloc(
                            &fs,
                            &mut model,
                            off,
                            len,
                            libc::FALLOC_FL_KEEP_SIZE | libc::FALLOC_FL_PUNCH_HOLE,
                            &|m| m[off..off + len].fill(0),
                        );
                        proptest::prop_assert!(res.is_ok(), "{}", res.unwrap_err());
                    }
                    3 if size > 0 => {
                        // Zero range — unaligned included (partial-block zeroing).
                        let off = a % size;
                        let len = (b % (size - off)).max(1);
                        let res = do_falloc(
                            &fs,
                            &mut model,
                            off,
                            len,
                            libc::FALLOC_FL_ZERO_RANGE,
                            &|m| m[off..off + len].fill(0),
                        );
                        proptest::prop_assert!(res.is_ok(), "{}", res.unwrap_err());
                    }
                    4 if size >= 2 * BS => {
                        // Collapse range (block-aligned, strictly inside file).
                        let off = align_down(a % (size - BS));
                        let len = BS * (1 + (b % 8));
                        if off + len < size {
                            let res = do_falloc(
                                &fs,
                                &mut model,
                                off,
                                len,
                                libc::FALLOC_FL_COLLAPSE_RANGE,
                                &|m| {
                                    m.drain(off..off + len);
                                },
                            );
                            proptest::prop_assert!(res.is_ok(), "{}", res.unwrap_err());
                        }
                    }
                    5 if size >= BS => {
                        // Insert range (block-aligned, offset inside file).
                        let off = align_down(a % size);
                        let len = BS * (1 + (b % 8));
                        if off + len <= CAP {
                            let res = do_falloc(
                                &fs,
                                &mut model,
                                off,
                                len,
                                libc::FALLOC_FL_INSERT_RANGE,
                                &|m| {
                                    m.splice(off..off, std::iter::repeat_n(0_u8, len));
                                },
                            );
                            proptest::prop_assert!(res.is_ok(), "{}", res.unwrap_err());
                        }
                    }
                    _ => {}
                }

                // Verify size + full content against the model after every op.
                let attr_now = fs.getattr(&cx, attr.ino).expect("getattr");
                proptest::prop_assert_eq!(
                    attr_now.size,
                    model.len() as u64,
                    "size mismatch after step {}",
                    step
                );
                if model.is_empty() {
                    continue;
                }
                let got = fs
                    .read(&cx, attr.ino, 0, u32::try_from(model.len()).expect("fits u32"))
                    .expect("read");
                proptest::prop_assert_eq!(got.len(), model.len(), "read length mismatch");
                let ndiff = (0..model.len()).filter(|&i| got[i] != model[i]).count();
                proptest::prop_assert!(
                    ndiff == 0,
                    "content diverged after step {}: {} bytes differ (first at {})",
                    step,
                    ndiff,
                    (0..model.len()).find(|&i| got[i] != model[i]).unwrap_or(0)
                );
            }
        }
    }

    // Randomized differential gauntlet for the ext4 XATTR surface (set / remove
    // across small in-inode values, ~external-block values, and >block-size
    // values that spill to an EA_INODE). Random op streams on one file are run
    // against a byte-exact name->value model: each op is applied to the model
    // only on success (so out-of-room sets / absent removes skip in lockstep),
    // and after every op getxattr (incl. an absent name) + listxattr must match
    // the model. A final e2fsck validates the external-xattr-block + EA_INODE
    // accounting (i_blocks / free totals) that a value model can't see — now that
    // file-op snapshots are e2fsck-clean (bd-nd61w sb-total sync + bd-bdro7).
    proptest::proptest! {
        #![proptest_config(proptest::prelude::ProptestConfig::with_cases(16))]
        #[test]
        fn ext4_xattr_churn_matches_reference_model_and_e2fsck(
            ops in proptest::collection::vec(
                (0u8..3, 0usize..5, 1usize..1500, proptest::prelude::any::<u8>()),
                1..25,
            ),
        ) {
            let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(8, false) else {
                return Ok(()); // e2fsprogs unavailable — skip.
            };
            let cx = Cx::for_testing();
            let attr = fs
                .create(&cx, InodeNumber(2), OsStr::new("xattr.bin"), 0o644, 0, 0)
                .expect("create");
            let ino = attr.ino;
            let names = ["user.a", "user.b", "user.c", "user.d", "user.eee"];
            let absent = "user.zzz_absent";

            let mut model: std::collections::BTreeMap<&'static str, Vec<u8>> =
                std::collections::BTreeMap::new();

            for (step, (kind, nidx, vlen, vbyte)) in ops.into_iter().enumerate() {
                let name = names[nidx];
                if kind < 2 {
                    // set (create-or-replace). Skip the model update if the fs
                    // rejects it (e.g. no room for an external block / EA_INODE).
                    let value = vec![vbyte; vlen];
                    if fs.setxattr(&cx, ino, name, &value, XattrSetMode::Set).is_ok() {
                        model.insert(name, value);
                    }
                } else if fs.removexattr(&cx, ino, name).unwrap_or(false) {
                    model.remove(name);
                }

                // listxattr lists exactly the modelled names.
                let mut got_names: Vec<String> =
                    fs.listxattr(&cx, ino).expect("listxattr");
                got_names.sort();
                let mut want_names: Vec<String> =
                    model.keys().map(|s| (*s).to_owned()).collect();
                want_names.sort();
                proptest::prop_assert_eq!(got_names, want_names, "listxattr mismatch step {}", step);

                // getxattr of each modelled name returns its value; an absent name
                // returns None.
                for (n, v) in &model {
                    let got = fs.getxattr(&cx, ino, n).expect("getxattr");
                    proptest::prop_assert_eq!(
                        got.as_deref(),
                        Some(v.as_slice()),
                        "getxattr value mismatch for {} step {}",
                        n,
                        step
                    );
                }
                proptest::prop_assert!(
                    fs.getxattr(&cx, ino, absent).expect("getxattr absent").is_none(),
                    "absent xattr must read None step {}",
                    step
                );
            }

            // e2fsck: validates external-xattr-block / EA_INODE accounting.
            fs.flush_mvcc_to_device(&cx).expect("flush");
            std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
            if let Some((clean, output)) = run_e2fsck(&image) {
                proptest::prop_assert!(clean, "e2fsck after xattr churn:\n{}", output);
            }
        }
    }

    // Randomized differential gauntlet for the ext4 NAMESPACE mutation surface
    // (create / mkdir / unlink / rmdir / cross-directory rename incl. directory
    // rename with `..` reparenting). ext4 had no directory-churn fuzz (btrfs did:
    // btrfs_directory_mutation_churn_matches_reference_model). Random op streams
    // across a small fixed set of parent dirs run against a byte-exact path->inode
    // model: each fs op is attempted, applied to the model only on success (so
    // invalid ops — ENOTEMPTY, EEXIST, loops — are skipped in lockstep), and after
    // every op readdir + lookup must match the model. A final real e2fsck
    // validates the cross-cutting invariants a model can't easily check: directory
    // link counts (one extra per child subdir for `..`), `..` targets, and the
    // absence of orphans/loops after the rename churn.
    proptest::proptest! {
        #![proptest_config(proptest::prelude::ProptestConfig::with_cases(16))]
        #[test]
        fn ext4_namespace_churn_matches_reference_model_and_e2fsck(
            ops in proptest::collection::vec(
                (0u8..5, 0usize..3, 0usize..4, 0usize..3, 0usize..4),
                1..30,
            ),
        ) {
            let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
                return Ok(()); // mkfs.ext4 unavailable — skip.
            };
            let cx = Cx::for_testing();
            let root = InodeNumber(2);
            // Three stable parent directories: root + two created subdirs. Ops
            // only ever target the name pool below (never "pa"/"pb"), so these
            // parents are never moved — bounding the model and ruling out
            // rename-into-own-descendant loops among them.
            let pa = fs.mkdir(&cx, root, OsStr::new("pa"), 0o755, 0, 0).expect("mkdir pa");
            let pb = fs.mkdir(&cx, root, OsStr::new("pb"), 0o755, 0, 0).expect("mkdir pb");
            let parents = [root, pa.ino, pb.ino];
            let names = ["f0", "f1", "f2", "f3"];

            // model: (parent_ino, name) -> (ino, is_dir)
            let mut model: std::collections::BTreeMap<(u64, &'static str), (u64, bool)> =
                std::collections::BTreeMap::new();

            let verify = |fs: &OpenFs,
                          model: &std::collections::BTreeMap<(u64, &'static str), (u64, bool)>,
                          step: usize|
             -> Result<(), proptest::test_runner::TestCaseError> {
                // lookup every modelled entry resolves to its inode.
                for ((pino, name), (ino, _)) in model {
                    let attr = fs
                        .lookup(&cx, InodeNumber(*pino), OsStr::new(name))
                        .map_err(|e| {
                            proptest::test_runner::TestCaseError::fail(format!(
                                "lookup {name} in {pino} after step {step}: {e}"
                            ))
                        })?;
                    proptest::prop_assert_eq!(attr.ino.0, *ino, "lookup ino mismatch step {}", step);
                }
                // readdir of each parent lists exactly the modelled children.
                for (pidx, pino) in [root.0, pa.ino.0, pb.ino.0].into_iter().enumerate() {
                    let _ = pidx;
                    let mut got: std::collections::BTreeMap<String, u64> =
                        std::collections::BTreeMap::new();
                    for e in fs.readdir(&cx, InodeNumber(pino), 0).expect("readdir") {
                        if e.name != b"." && e.name != b".." {
                            if let Ok(s) = std::str::from_utf8(&e.name) {
                                // Only track the name pool (ignore pa/pb in root).
                                if names.contains(&s) {
                                    got.insert(s.to_owned(), e.ino.0);
                                }
                            }
                        }
                    }
                    let want: std::collections::BTreeMap<String, u64> = model
                        .iter()
                        .filter(|((p, _), _)| *p == pino)
                        .map(|((_, n), (ino, _))| ((*n).to_owned(), *ino))
                        .collect();
                    proptest::prop_assert_eq!(got, want, "readdir mismatch in {} step {}", pino, step);
                }
                Ok(())
            };

            for (step, (kind, p, n, dp, dn)) in ops.into_iter().enumerate() {
                let (pino, name) = (parents[p].0, names[n]);
                match kind {
                    0 => {
                        if fs.create(&cx, parents[p], OsStr::new(name), 0o644, 0, 0).is_ok() {
                            let ino = fs.lookup(&cx, parents[p], OsStr::new(name)).unwrap().ino.0;
                            model.insert((pino, name), (ino, false));
                        }
                    }
                    1 => {
                        if fs.mkdir(&cx, parents[p], OsStr::new(name), 0o755, 0, 0).is_ok() {
                            let ino = fs.lookup(&cx, parents[p], OsStr::new(name)).unwrap().ino.0;
                            model.insert((pino, name), (ino, true));
                        }
                    }
                    2 => {
                        if fs.unlink(&cx, parents[p], OsStr::new(name)).is_ok() {
                            model.remove(&(pino, name));
                        }
                    }
                    3 => {
                        if fs.rmdir(&cx, parents[p], OsStr::new(name)).is_ok() {
                            model.remove(&(pino, name));
                        }
                    }
                    _ => {
                        let (dpino, dname) = (parents[dp].0, names[dn]);
                        if fs
                            .rename(&cx, parents[p], OsStr::new(name), parents[dp], OsStr::new(dname))
                            .is_ok()
                        {
                            if let Some(moved) = model.remove(&(pino, name)) {
                                model.insert((dpino, dname), moved);
                            }
                        }
                    }
                }
                verify(&fs, &model, step)?;
            }
            // NOTE: wiring a full e2fsck pass into this proptest loop is left as
            // optional future hardening (it would run e2fsck on a metadata_csum
            // device snapshot per generated case). The previously-blocking gaps
            // are now all closed and each has a dedicated deterministic e2fsck
            // test: superblock free totals (bd-nd61w,
            // flush_syncs_superblock_free_totals_e2fsck_clean_bd_nd61w), group
            // bg_used_dirs_count (bd-0y7jp,
            // ext4_dir_count_maintained_passes_e2fsck_bd_0y7jp), and the empty-
            // directory metadata_csum tail that enabling e2fsck here first
            // surfaced (bd-bribi,
            // ext4_empty_dir_block_csum_stamped_passes_e2fsck_bd_bribi — the
            // mkdir path now stamps the new dir block). The per-step readdir +
            // lookup model match above already validates namespace correctness
            // under the rename churn.
        }
    }

    /// bd-nd61w: flush_mvcc_to_device must sync the superblock free-block/inode
    /// TOTALS so a device snapshot is e2fsck-clean. Before the fix a bare
    /// create+write+flush left s_free_blocks_count / s_free_inodes_count at their
    /// mkfs values ("Free blocks/inodes count wrong"). Validated on BOTH
    /// metadata_csum modes (the csum path re-stamps the superblock checksum) plus
    /// a from_device reopen (proves the superblock still parses + csum-verifies).
    /// (File ops only — no directories — so the separate worker-owned
    /// gd-used-dirs gap is not exercised.)
    #[test]
    fn flush_syncs_superblock_free_totals_e2fsck_clean_bd_nd61w() {
        for with_csum in [false, true] {
            let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(8, with_csum) else {
                continue; // e2fsprogs unavailable — skip.
            };
            let cx = Cx::for_testing();
            // A file + several blocks of data: allocates an inode and data blocks,
            // moving the free totals off their mkfs values.
            let attr = fs
                .create(&cx, InodeNumber(2), OsStr::new("nd61w.bin"), 0o644, 0, 0)
                .expect("create");
            fs.write(&cx, attr.ino, 0, &[0xAB_u8; 6 * 1024])
                .expect("write");
            fs.flush_mvcc_to_device(&cx).expect("flush");

            // Reopen must succeed — proves the superblock still parses and (with
            // metadata_csum) its checksum verifies after the free-total rewrite.
            OpenFs::from_device(
                &cx,
                Box::new(TestDevice::from_vec(dev.snapshot_bytes())),
                &OpenOptions::default(),
            )
            .unwrap_or_else(|e| panic!("reopen after sb free-total sync (csum={with_csum}): {e}"));

            std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
            let Some((clean, output)) = run_e2fsck(&image) else {
                continue;
            };
            assert!(
                clean,
                "e2fsck must accept after sb free-total sync (with_csum={with_csum}):\n{output}"
            );
        }
    }

    /// A COMPOUND ext4 data-op churn — extent growth, a sparse gap, in-place
    /// overwrite, unwritten preallocation, punch-hole, truncate-down and -up,
    /// and a write into the extended region — must keep the on-disk image
    /// e2fsck-clean AND byte-exact. The xattr/namespace churn proptests cover
    /// those surfaces; the data path (extent tree split/merge/free, i_blocks
    /// accounting, block bitmap, unwritten extents) had only piecemeal e2fsck
    /// coverage and the write/truncate/fallocate random proptests are in-memory
    /// only (no e2fsck). Skips when e2fsprogs is unavailable (bd-8w6xh).
    #[test]
    fn ext4_data_op_churn_passes_e2fsck_bd_8w6xh() {
        let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(8, false) else {
            return; // e2fsprogs unavailable — skip.
        };
        let cx = Cx::for_testing();
        let ino = fs
            .create(&cx, InodeNumber(2), OsStr::new("data.bin"), 0o644, 0, 0)
            .expect("create")
            .ino;

        // Mirror every op into a Vec<u8> content model (unwritten/holes read as
        // zeros), applying the same ops to both fs and model.
        let mut model: Vec<u8> = Vec::new();
        let do_write = |model: &mut Vec<u8>, off: usize, byte: u8, len: usize| {
            fs.write(&cx, ino, off as u64, &vec![byte; len])
                .expect("write");
            if off + len > model.len() {
                model.resize(off + len, 0);
            }
            for b in &mut model[off..off + len] {
                *b = byte;
            }
        };
        do_write(&mut model, 0, b'A', 8192); // two-block extent
        do_write(&mut model, 16384, b'B', 4096); // sparse gap [8192,16384) + new extent
        do_write(&mut model, 4096, b'C', 4096); // in-place overwrite of the 2nd block

        const KEEP_SIZE: i32 = 0x01;
        const PUNCH_HOLE: i32 = 0x02;
        // Preallocate part of the hole as unwritten (reads zero; model no-op).
        fs.fallocate(&cx, ino, 8192, 4096, KEEP_SIZE)
            .expect("fallocate preallocate");
        // Punch the first block (frees it; reads zero).
        fs.fallocate(&cx, ino, 0, 4096, PUNCH_HOLE | KEEP_SIZE)
            .expect("fallocate punch hole");
        for b in &mut model[0..4096] {
            *b = 0;
        }

        let do_truncate = |model: &mut Vec<u8>, size: usize| {
            fs.setattr(
                &cx,
                ino,
                &SetAttrRequest {
                    size: Some(size as u64),
                    ..SetAttrRequest::default()
                },
            )
            .expect("truncate");
            model.resize(size, 0);
        };
        do_truncate(&mut model, 18000); // truncate down mid-extent (frees tail blocks)
        do_truncate(&mut model, 24000); // sparse extend
        do_write(&mut model, 22000, b'D', 2000); // write into the extended region

        // Content must match the model exactly.
        let got = fs
            .read(&cx, ino, 0, u32::try_from(model.len()).unwrap())
            .expect("read");
        assert_eq!(
            got, model,
            "ext4 data-op churn content must match the model"
        );

        // e2fsck: validates extent-tree / i_blocks / block-bitmap accounting.
        fs.flush_mvcc_to_device(&cx).expect("flush");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        if let Some((clean, output)) = run_e2fsck(&image) {
            eprintln!("BD_8W6XH_E2FSCK_RAN clean={clean}");
            assert!(clean, "e2fsck after ext4 data-op churn:\n{output}");
        }
    }

    /// bd-bdro7: a contiguous sequential write must coalesce into ONE extent.
    /// The write path allocated one block at a time; without run allocation each
    /// became its own extent, so a >4-block write overflowed the inline extent
    /// root and grew the tree into a metadata leaf block the writer did not count
    /// in i_blocks — making the snapshot e2fsck-dirty. Allocating the contiguous
    /// run as one extent keeps it inline: no growth, correct i_blocks, clean.
    #[test]
    fn ext4_contiguous_write_coalesces_to_one_extent_bd_bdro7() {
        let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(8, false) else {
            return;
        };
        let cx = Cx::for_testing();
        let attr = fs
            .create(&cx, InodeNumber(2), OsStr::new("seq.bin"), 0o644, 0, 0)
            .expect("create");
        // 8 contiguous blocks — 8 single-block extents pre-fix (exceeds the
        // 4-entry inline root, forcing tree growth).
        fs.write(&cx, attr.ino, 0, &[0xAB_u8; 8 * 1024])
            .expect("write");

        let inode = fs.read_inode(&cx, attr.ino).expect("read inode");
        let exts = fs.collect_extents(&cx, &inode).expect("collect extents");
        assert_eq!(
            exts.len(),
            1,
            "a contiguous write must coalesce into one extent, got {exts:?}"
        );
        assert_eq!(exts[0].logical_block, 0);
        assert_eq!(u32::from(exts[0].actual_len()), 8);

        // Read-back is byte-exact (run allocation must not corrupt the mapping).
        let got = fs.read(&cx, attr.ino, 0, 8 * 1024).expect("read back");
        assert!(got.iter().all(|&b| b == 0xAB) && got.len() == 8 * 1024);

        // e2fsck-clean: one inline extent, no metadata leaf, i_blocks correct.
        fs.flush_mvcc_to_device(&cx).expect("flush");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        if let Some((clean, output)) = run_e2fsck(&image) {
            assert!(clean, "e2fsck after coalesced sequential write:\n{output}");
        }
    }

    /// bd-xnel9: an UNALIGNED ext4 PUNCH_HOLE must zero exactly the in-range
    /// bytes (deallocating the aligned interior, zeroing the partial edge bytes
    /// of written edge blocks) while preserving the bytes just outside the range
    /// and keeping the file size — matching the kernel. Validated byte-exact plus
    /// real e2fsck.
    #[test]
    fn fallocate_punch_hole_unaligned_preserves_neighbors_bd_xnel9() {
        let Some((fs, dev, _tmp, image)) = open_ext4_mke2fs(8, false) else {
            return;
        };
        let cx = Cx::for_testing();
        let bs = u64::from(fs.ext4_superblock().expect("sb").block_size);
        let attr = fs
            .create(
                &cx,
                InodeNumber(2),
                OsStr::new("punch_unaligned.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");
        let total = usize::try_from(bs * 5).unwrap();
        fs.write(&cx, attr.ino, 0, &vec![0xAB_u8; total])
            .expect("write pattern");

        // Punch [bs/2, bs/2 + 3*bs): partial head block, two full interior
        // blocks (deallocated), partial tail block.
        let off = bs / 2;
        let len = bs * 3;
        fs.fallocate(
            &cx,
            attr.ino,
            off,
            len,
            libc::FALLOC_FL_KEEP_SIZE | libc::FALLOC_FL_PUNCH_HOLE,
        )
        .expect("unaligned punch_hole must be supported");

        // Size unchanged; in-range bytes zero; neighbors preserved.
        assert_eq!(
            fs.getattr(&cx, attr.ino).expect("getattr").size,
            total as u64,
            "punch_hole keeps the file size"
        );
        let got = fs
            .read(&cx, attr.ino, 0, u32::try_from(total).unwrap())
            .expect("read");
        for (i, &byte) in got.iter().enumerate() {
            let in_hole = (i as u64) >= off && (i as u64) < off + len;
            let expected = if in_hole { 0x00 } else { 0xAB };
            assert_eq!(byte, expected, "byte {i} (in_hole={in_hole}) wrong");
        }
        // Real e2fsck now runs: the superblock free-total sync (bd-nd61w) makes
        // a file-op snapshot e2fsck-clean, so this validates the unaligned punch
        // leaves no leaked blocks / wrong i_blocks beyond byte-exactness.
        fs.flush_mvcc_to_device(&cx).expect("flush mvcc");
        std::fs::write(&image, dev.snapshot_bytes()).expect("write image");
        if let Some((clean, output)) = run_e2fsck(&image) {
            assert!(clean, "e2fsck after unaligned punch_hole:\n{output}");
        }
    }

    /// bd-xnel9 (indirect path): unaligned PUNCH_HOLE on a legacy
    /// indirect-block-mapped file must zero the partial in-range bytes of the
    /// written edge blocks and deallocate only the fully-covered aligned
    /// interior, leaving neighbors intact and the size unchanged — the same
    /// semantics the extent path got in f8f28d07. Builds the indirect file via
    /// the established re-stamp pattern (write an extent file, then clear the
    /// extent flag and point the direct pointers at the allocated blocks).
    #[test]
    fn fallocate_punch_hole_unaligned_indirect_preserves_neighbors_bd_xnel9() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(16) else {
            return; // mkfs.ext4 unavailable
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let bs = fs.block_size() as u64;
        let sectors_per_block = bs / u64::from(EXT4_SECTOR_SIZE);

        // Write a 5-block extent file (one contiguous extent), then re-stamp it
        // as a legacy indirect file mapping logical 0..5 via i_block[0..5].
        let ino = fs
            .create(&cx, root, OsStr::new("punch_indirect.bin"), 0o644, 0, 0)
            .expect("create")
            .ino;
        let total = usize::try_from(bs * 5).unwrap();
        fs.write(&cx, ino, 0, &vec![0xAB_u8; total])
            .expect("write pattern");

        let inode = fs.read_inode(&cx, ino).expect("read inode");
        let extents = fs.collect_extents(&cx, &inode).expect("extents");
        let mut ptrs = vec![0_u8; 15 * 4];
        for lb in 0..5u32 {
            let phys = extents
                .iter()
                .find(|e| e.logical_block <= lb && lb < e.logical_block + u32::from(e.actual_len()))
                .map(|e| e.physical_start + u64::from(lb - e.logical_block))
                .expect("logical block mapped");
            let off = usize::try_from(lb).unwrap() * 4;
            ptrs[off..off + 4]
                .copy_from_slice(&u32::try_from(phys).expect("phys fits u32").to_le_bytes());
        }
        let mut indirect = inode.clone();
        indirect.flags &= !ffs_types::EXT4_EXTENTS_FL;
        indirect.extent_bytes = ptrs.into();
        indirect.size = total as u64;
        fs.persist_ext4_inode_for_testing(&cx, ino, &indirect)
            .expect("persist indirect inode");

        // Sanity: the indirect read path returns the original pattern.
        assert_eq!(
            fs.read(&cx, ino, 0, u32::try_from(total).unwrap())
                .expect("indirect read"),
            vec![0xAB_u8; total],
            "indirect read of the mapped blocks"
        );
        let blocks_before = fs.read_inode(&cx, ino).expect("inode pre-punch").blocks;

        // Punch [bs/2, bs/2 + 3*bs): partial head (block 0), two full interior
        // blocks (1,2 — freed), partial tail (block 3). Block 4 untouched.
        let off = bs / 2;
        let len = bs * 3;
        fs.fallocate(
            &cx,
            ino,
            off,
            len,
            libc::FALLOC_FL_KEEP_SIZE | libc::FALLOC_FL_PUNCH_HOLE,
        )
        .expect("unaligned indirect punch_hole must be supported");

        // Size unchanged; in-range bytes zero; neighbors preserved.
        assert_eq!(
            fs.getattr(&cx, ino).expect("getattr").size,
            total as u64,
            "punch_hole keeps the file size"
        );
        let got = fs
            .read(&cx, ino, 0, u32::try_from(total).unwrap())
            .expect("read");
        for (i, &byte) in got.iter().enumerate() {
            let in_hole = (i as u64) >= off && (i as u64) < off + len;
            let expected = if in_hole { 0x00 } else { 0xAB };
            assert_eq!(byte, expected, "byte {i} (in_hole={in_hole}) wrong");
        }

        // Exactly the two fully-covered interior blocks were deallocated.
        let blocks_after = fs.read_inode(&cx, ino).expect("inode post-punch").blocks;
        assert_eq!(
            blocks_before - blocks_after,
            2 * sectors_per_block,
            "only the 2 aligned interior blocks are freed (edges stay allocated)"
        );
    }

    #[test]
    fn write_fallocate_collapse_range_unaligned_returns_einval() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("collapse_unaligned.bin"), 0o644, 0, 0)
            .expect("create");
        fs.fallocate(&cx, attr.ino, 0, 4096 * 4, 0)
            .expect("preallocate 16 KiB");

        // Misaligned offset: must fail with EINVAL, not UnsupportedFeature.
        let err = fs
            .fallocate(&cx, attr.ino, 100, 4096, 0x08)
            .expect_err("unaligned offset must fail");
        assert_eq!(err.to_errno(), libc::EINVAL);

        // Misaligned length: same.
        let err = fs
            .fallocate(&cx, attr.ino, 4096, 200, 0x08)
            .expect_err("unaligned length must fail");
        assert_eq!(err.to_errno(), libc::EINVAL);
    }

    #[test]
    fn write_fallocate_collapse_range_past_eof_returns_einval() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("collapse_past_eof.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &vec![0_u8; 8192])
            .expect("write 8 KiB");

        // Range reaching EOF must fail per fallocate(2); use truncate to
        // remove a tail range instead.
        let err = fs
            .fallocate(&cx, attr.ino, 4096, 4096, 0x08)
            .expect_err("collapse reaching EOF must fail");
        assert_eq!(err.to_errno(), libc::EINVAL);

        // Range extending past file size must fail per ext4_collapse_range.
        let err = fs
            .fallocate(&cx, attr.ino, 4096, 8192, 0x08)
            .expect_err("collapse past EOF must fail");
        assert_eq!(err.to_errno(), libc::EINVAL);
    }

    #[test]
    fn write_fallocate_collapse_range_with_other_flags_returns_einval() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("collapse_combo.bin"), 0o644, 0, 0)
            .expect("create");
        fs.fallocate(&cx, attr.ino, 0, 4096 * 4, 0)
            .expect("preallocate");

        // ext4 rejects COLLAPSE_RANGE | KEEP_SIZE.
        let err = fs
            .fallocate(&cx, attr.ino, 0, 4096, 0x08 | 0x01)
            .expect_err("collapse + keep_size must fail");
        assert_eq!(err.to_errno(), libc::EINVAL);
    }

    #[test]
    fn write_fallocate_punch_hole_without_keep_size_returns_einval() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("falloc_ph_noks.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &[0xAB; 8192]).expect("write");
        // PUNCH_HOLE (0x02) without KEEP_SIZE (0x01) is invalid per POSIX
        let err = fs
            .fallocate(&cx, attr.ino, 0, 4096, libc::FALLOC_FL_PUNCH_HOLE)
            .expect_err("punch without keep_size");
        assert!(
            matches!(err, FfsError::Io(_)),
            "expected Io(EINVAL), got {err:?}"
        );
    }

    #[test]
    fn write_fallocate_punch_hole_with_zero_range_returns_einval_without_mutation() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("falloc_ph_zr.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &[0xAB; 8192]).expect("write");
        // PUNCH_HOLE and ZERO_RANGE are mutually exclusive (kernel vfs_fallocate
        // returns EINVAL). Without the guard, the punch_hole-first branch would
        // silently punch a hole and ignore the zeroing request. KEEP_SIZE is set
        // so the independent punch-without-keep-size check does not fire first —
        // this isolates the mutual-exclusion guard.
        let err = fs
            .fallocate(
                &cx,
                attr.ino,
                0,
                4096,
                libc::FALLOC_FL_PUNCH_HOLE | libc::FALLOC_FL_ZERO_RANGE | libc::FALLOC_FL_KEEP_SIZE,
            )
            .expect_err("PUNCH_HOLE | ZERO_RANGE must be rejected");
        assert_eq!(err.to_errno(), libc::EINVAL);
        // No partial mutation: the file is untouched (no punch occurred).
        let data = fs.read(&cx, attr.ino, 0, 8192).expect("read after reject");
        assert!(
            data.iter().all(|&b| b == 0xAB),
            "rejected fallocate must not have punched or zeroed any bytes"
        );
    }

    #[test]
    fn write_fallocate_non_block_aligned_punch_hole_zeroes_in_range_bytes() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("falloc_unalign.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &[0xAB; 8192]).expect("write");
        // Unaligned punch [100, 300) is now supported (bd-xnel9): it zeroes
        // exactly the in-range bytes (partial-block read-modify-write),
        // preserving the neighbors and the file size — matching the kernel.
        fs.fallocate(
            &cx,
            attr.ino,
            100,
            200,
            libc::FALLOC_FL_PUNCH_HOLE | libc::FALLOC_FL_KEEP_SIZE,
        )
        .expect("unaligned punch is now supported");
        assert_eq!(fs.getattr(&cx, attr.ino).expect("getattr").size, 8192);
        let got = fs.read(&cx, attr.ino, 0, 8192).expect("read");
        for (i, &byte) in got.iter().enumerate() {
            let in_hole = (100..300).contains(&i);
            assert_eq!(
                byte,
                if in_hole { 0x00 } else { 0xAB },
                "byte {i} (in_hole={in_hole})"
            );
        }
    }

    #[test]
    fn write_fallocate_prealloc_without_keep_size_extends_file() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("falloc_extend.bin"), 0o644, 0, 0)
            .expect("create");
        // File starts empty (size 0)
        assert_eq!(fs.getattr(&cx, attr.ino).expect("ga0").size, 0);

        // fallocate without KEEP_SIZE should extend the file size
        fs.fallocate(&cx, attr.ino, 0, 16384, 0)
            .expect("fallocate extend");
        let after = fs.getattr(&cx, attr.ino).expect("ga1");
        assert_eq!(after.size, 16384, "size should be extended to 16K");
        assert!(after.blocks > 0, "should have allocated blocks");

        // The preallocated region should read as zeros
        let data = fs.read(&cx, attr.ino, 0, 16384).expect("read");
        assert!(data.iter().all(|&b| b == 0), "prealloc should be zeroed");
    }

    #[test]
    fn write_fallocate_keep_size_does_not_extend_size() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("falloc_ks.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, b"small").expect("write");
        let before = fs.getattr(&cx, attr.ino).expect("ga before");

        // KEEP_SIZE fallocate beyond EOF should not change reported size
        fs.fallocate(&cx, attr.ino, 0, 16384, libc::FALLOC_FL_KEEP_SIZE)
            .expect("fallocate keep_size");
        let after = fs.getattr(&cx, attr.ino).expect("ga after");
        assert_eq!(after.size, before.size, "size should be unchanged");
        assert!(
            after.blocks >= before.blocks,
            "blocks should not decrease: {} >= {}",
            after.blocks,
            before.blocks
        );
    }

    #[test]
    fn write_fallocate_prealloc_creates_unwritten_extents_and_reads_zero() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let block = 4096_u64;
        let attr = fs
            .create(&cx, root, OsStr::new("falloc_unwritten.bin"), 0o644, 0, 0)
            .expect("create");

        fs.fallocate(&cx, attr.ino, 0, 2 * block, 0)
            .expect("fallocate");

        let inode = fs.read_inode(&cx, attr.ino).expect("read inode");
        let extents = fs.collect_extents(&cx, &inode).expect("collect extents");
        assert!(
            extents.iter().any(|extent| extent.is_unwritten()),
            "fallocate preallocation should use unwritten extents: {extents:?}"
        );

        let data = fs
            .read(&cx, attr.ino, 0, u32::try_from(2 * block).unwrap())
            .expect("read preallocated range");
        assert_eq!(data.len(), usize::try_from(2 * block).unwrap());
        assert!(
            data.iter().all(|&b| b == 0),
            "unwritten preallocation must read as zeros"
        );
    }

    #[test]
    fn write_into_unwritten_prealloc_zero_fills_and_marks_written_block() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let block = 4096_u64;
        let attr = fs
            .create(
                &cx,
                root,
                OsStr::new("falloc_unwritten_partial.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");

        fs.fallocate(&cx, attr.ino, 0, 3 * block, 0)
            .expect("fallocate");
        let write_offset = block + 17;
        fs.write(&cx, attr.ino, write_offset, b"abc")
            .expect("partial write into unwritten block");

        let data = fs
            .read(&cx, attr.ino, 0, u32::try_from(3 * block).unwrap())
            .expect("read after partial write");
        let write_start = usize::try_from(write_offset).unwrap();
        assert!(
            data[..write_start].iter().all(|&b| b == 0),
            "bytes before partial write must remain zero-filled"
        );
        assert_eq!(&data[write_start..write_start + 3], b"abc");
        assert!(
            data[write_start + 3..].iter().all(|&b| b == 0),
            "bytes after partial write must remain zero-filled"
        );

        let inode = fs.read_inode(&cx, attr.ino).expect("read inode");
        let extents = fs.collect_extents(&cx, &inode).expect("collect extents");
        let extent_for = |logical: u32| {
            extents
                .iter()
                .find(|extent| {
                    logical >= extent.logical_block
                        && logical < extent.logical_block + u32::from(extent.actual_len())
                })
                .expect("logical block remains allocated")
        };
        assert!(
            extent_for(0).is_unwritten(),
            "unwritten prefix block should remain unwritten: {extents:?}"
        );
        assert!(
            !extent_for(1).is_unwritten(),
            "partially written block should be marked written: {extents:?}"
        );
        assert!(
            extent_for(2).is_unwritten(),
            "unwritten suffix block should remain unwritten: {extents:?}"
        );
    }

    #[test]
    fn write_into_reused_unwritten_block_does_not_expose_recycled_data() {
        // Gold-standard exposure guard for bd-y6h03 (avoids zero-masking): write
        // NON-ZERO data to a block, free it, then fallocate — which reuses the
        // freed, still-dirty physical block as an UNWRITTEN extent — and partial
        // -write into it. The non-written bytes must read as ZERO, never the
        // recycled 0xAB content, proving the unwritten RMW zero-fills instead of
        // reading stale physical.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let block = 4096_u64;
        let blen = usize::try_from(block).unwrap();

        let phys_of_lb0 = |ino: InodeNumber| -> Option<u64> {
            let inode = fs.read_inode(&cx, ino).ok()?;
            fs.collect_extents(&cx, &inode)
                .ok()?
                .iter()
                .find(|e| e.logical_block == 0)
                .map(|e| e.physical_start)
        };

        // A: a file whose first block is full of 0xAB.
        let a = fs
            .create(&cx, root, OsStr::new("dirty_a.bin"), 0o644, 0, 0)
            .expect("create A");
        fs.write(&cx, a.ino, 0, &vec![0xAB_u8; blen])
            .expect("write A");
        let a_phys = phys_of_lb0(a.ino);
        fs.unlink(&cx, root, OsStr::new("dirty_a.bin"))
            .expect("unlink A frees its dirty block");

        // B: fallocate one block — the allocator should reuse A's freed block.
        let b = fs
            .create(&cx, root, OsStr::new("reuse_b.bin"), 0o644, 0, 0)
            .expect("create B");
        fs.fallocate(&cx, b.ino, 0, block, 0).expect("fallocate B");
        let b_phys = phys_of_lb0(b.ino);
        let reused = a_phys.is_some() && a_phys == b_phys;
        eprintln!("bd-y6h03 recycled test: a_phys={a_phys:?} b_phys={b_phys:?} reused={reused}");

        // Partial write into B's (unwritten, possibly recycled-0xAB) block.
        let off = 100_u64;
        fs.write(&cx, b.ino, off, b"xyz")
            .expect("partial write into reused unwritten block");
        let data = fs
            .read(&cx, b.ino, 0, u32::try_from(block).unwrap())
            .expect("read B");
        let o = usize::try_from(off).unwrap();
        assert!(
            data[..o].iter().all(|&x| x == 0),
            "bytes before the partial write must be zero, never recycled 0xAB"
        );
        assert_eq!(&data[o..o + 3], b"xyz");
        assert!(
            data[o + 3..].iter().all(|&x| x == 0),
            "bytes after the partial write must be zero, never recycled 0xAB"
        );
    }

    #[test]
    fn fallocate_over_mixed_written_and_hole_preserves_written_data() {
        // bd-y6h03 edge: a fallocate range that spans an already-WRITTEN block
        // plus following holes must leave the written block's data intact (never
        // re-mark it unwritten or clobber it) while turning only the holes into
        // unwritten/zero extents.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(64) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let block = 4096_u64;
        let blen = usize::try_from(block).unwrap();

        let f = fs
            .create(&cx, root, OsStr::new("mixed_falloc.bin"), 0o644, 0, 0)
            .expect("create");
        // Block 0 becomes WRITTEN (full block of 0xCC).
        fs.write(&cx, f.ino, 0, &vec![0xCC_u8; blen])
            .expect("write block 0");

        // fallocate the first three blocks: block 0 already written, 1+2 holes.
        fs.fallocate(&cx, f.ino, 0, block * 3, 0)
            .expect("fallocate");

        // Block 0's data must survive untouched.
        let b0 = fs
            .read(&cx, f.ino, 0, u32::try_from(block).unwrap())
            .expect("read block 0");
        assert!(
            b0.iter().all(|&x| x == 0xCC),
            "already-written block must keep its 0xCC data after fallocate"
        );
        // Blocks 1 and 2 (newly preallocated holes) must read as zeros.
        let b12 = fs
            .read(&cx, f.ino, block, u32::try_from(block * 2).unwrap())
            .expect("read blocks 1+2");
        assert!(
            b12.iter().all(|&x| x == 0),
            "preallocated holes must read as zeros"
        );

        let inode = fs.read_inode(&cx, f.ino).expect("read inode");
        let extents = fs.collect_extents(&cx, &inode).expect("collect extents");
        let extent_for = |logical: u32| {
            extents
                .iter()
                .find(|extent| {
                    logical >= extent.logical_block
                        && logical < extent.logical_block + u32::from(extent.actual_len())
                })
                .expect("logical block remains allocated")
        };
        assert!(
            !extent_for(0).is_unwritten(),
            "block 0 must stay a WRITTEN extent across fallocate: {extents:?}"
        );
        assert!(
            extent_for(1).is_unwritten(),
            "preallocated hole block 1 must become unwritten: {extents:?}"
        );
        assert!(
            extent_for(2).is_unwritten(),
            "preallocated hole block 2 must become unwritten: {extents:?}"
        );
    }

    #[test]
    fn setxattr_external_block_is_metadata_csum_clean_bd_fwph3() {
        // bd-fwph3: a setxattr that spills into an EXTERNAL xattr block must
        // leave that block with a valid ext4 h_checksum on a metadata_csum
        // filesystem, or e2fsck reports corruption. Pairs with the ffs-ondisk
        // oracle test (formula == e2fsprogs) to prove e2fsck-cleanliness.
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(8) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let (has_csum, seed) = {
            let sb = fs.ext4_superblock().expect("ext4 superblock");
            (sb.has_metadata_csum(), sb.csum_seed())
        };
        assert!(
            has_csum,
            "the generated test image is expected to enable metadata_csum"
        );

        let f = fs
            .create(&cx, root, OsStr::new("xattr_csum.bin"), 0o644, 0, 0)
            .expect("create");
        // A large value forces the xattr out of the inode ibody into an
        // external block (file_acl != 0).
        let big = vec![0x5A_u8; 2000];
        fs.setxattr(&cx, f.ino, "user.big", &big, XattrSetMode::Set)
            .expect("setxattr");

        let inode = fs.read_inode(&cx, f.ino).expect("read inode");
        assert_ne!(
            inode.file_acl, 0,
            "large value should have spilled to an external xattr block"
        );
        let block = fs
            .read_block_vec(&cx, BlockNumber(inode.file_acl))
            .expect("read external xattr block");
        let stored = u32::from_le_bytes([block[16], block[17], block[18], block[19]]);
        assert_ne!(
            stored, 0,
            "h_checksum must be stamped (was always 0 before bd-fwph3)"
        );
        assert!(
            ffs_ondisk::verify_xattr_block_checksum(&block, seed, inode.file_acl),
            "external xattr block must carry a valid metadata_csum h_checksum"
        );

        // Removing one of several entries rewrites the block in place — its
        // checksum must stay valid too.
        fs.setxattr(&cx, f.ino, "user.second", b"x", XattrSetMode::Set)
            .expect("second setxattr");
        let removed = fs
            .removexattr(&cx, f.ino, "user.second")
            .expect("removexattr");
        assert!(removed);
        let inode2 = fs.read_inode(&cx, f.ino).expect("re-read inode");
        let block2 = fs
            .read_block_vec(&cx, BlockNumber(inode2.file_acl))
            .expect("re-read external xattr block");
        assert!(
            ffs_ondisk::verify_xattr_block_checksum(&block2, seed, inode2.file_acl),
            "external xattr block must stay metadata_csum-clean after removexattr"
        );
    }

    #[test]
    fn ext4_ea_inode_value_parallel_read_matches_serial_bd_xmh5g_197() {
        let Some((fs, _dev, _tmp, _image)) = open_ext4_mke2fs(8, false) else {
            return;
        };
        let cx = Cx::for_testing();
        let attr = fs
            .create(
                &cx,
                InodeNumber(2),
                OsStr::new("ea_inode_value.bin"),
                0o644,
                0,
                0,
            )
            .expect("create file used as EA-inode payload");
        let value: Vec<u8> = (0..17_317)
            .map(|i| u8::try_from((i * 37 + 11) % 251).expect("modulo fits u8"))
            .collect();
        fs.write(&cx, attr.ino, 0, &value)
            .expect("write multi-block payload");
        let value_inum = u32::try_from(attr.ino.0).expect("test inode fits u32");

        let serial = fs
            .ext4_read_ea_inode_value_serial_for_test(&cx, value_inum)
            .expect("serial EA-inode read");
        let parallel = fs
            .ext4_read_ea_inode_value(&cx, value_inum)
            .expect("parallel EA-inode read");

        assert_eq!(serial, value, "serial oracle must match file payload");
        assert_eq!(
            parallel, serial,
            "parallel EA-inode read must preserve the serial byte image"
        );
    }

    #[test]
    fn ext4_read_ea_inode_value_rejects_oversized_value() {
        let Some((fs, _dev, _tmp, _image)) = open_ext4_mke2fs(8, false) else {
            return;
        };
        let cx = Cx::for_testing();
        let attr = fs
            .create(
                &cx,
                InodeNumber(2),
                OsStr::new("oversized_ea.bin"),
                0o644,
                0,
                0,
            )
            .expect("create EA-inode payload");
        // A value larger than XATTR_SIZE_MAX (64 KiB) cannot be a valid xattr
        // value, so the EA-inode reader must reject it (bd-xmh5g.287) rather than
        // allocating an unbounded buffer on a corrupt EA-inode size.
        let value = vec![0xab_u8; 65_536 + 1];
        fs.write(&cx, attr.ino, 0, &value)
            .expect("write oversized payload");
        let value_inum = u32::try_from(attr.ino.0).expect("test inode fits u32");
        let err = fs
            .ext4_read_ea_inode_value(&cx, value_inum)
            .expect_err("oversized EA-inode value must be rejected");
        assert!(matches!(err, FfsError::Corruption { .. }), "got {err:?}");
    }

    #[test]
    #[ignore = "profiling tool for bd-y6h03: current ext4 preallocate cost and unwritten extent state"]
    fn profile_ext4_fallocate_prealloc_bd_y6h03() {
        let Some((fs, _tmp)) = open_writable_ext4_mkfs(256) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let block = 4096_u64;

        for blocks in [128_u64, 512, 2048] {
            let name = format!("falloc_profile_{blocks}.bin");
            let attr = fs
                .create(&cx, root, OsStr::new(&name), 0o644, 0, 0)
                .expect("create profile file");
            let length = blocks.checked_mul(block).expect("profile length fits");

            let start = std::time::Instant::now();
            fs.fallocate(&cx, attr.ino, 0, length, libc::FALLOC_FL_KEEP_SIZE)
                .expect("profile fallocate");
            let elapsed = start.elapsed();

            let inode = fs.read_inode(&cx, attr.ino).expect("read profile inode");
            let extents = fs
                .collect_extents(&cx, &inode)
                .expect("collect profile extents");
            let unwritten_extents = extents
                .iter()
                .filter(|extent| extent.is_unwritten())
                .count();
            std::hint::black_box(&extents);

            let per_block_ns = elapsed.as_nanos() / u128::from(blocks);
            eprintln!(
                "bd-y6h03 ext4_fallocate_prealloc blocks={blocks} elapsed={elapsed:?} \
                 per_block_ns={per_block_ns} extents={} unwritten_extents={} inode_blocks={}",
                extents.len(),
                unwritten_extents,
                inode.blocks
            );
        }
    }

