    #[test]
    fn write_statfs_returns_valid_values() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let stat = fs.statfs(&cx, root).expect("statfs");
        assert!(stat.blocks > 0, "should have blocks");
        assert!(stat.blocks_free <= stat.blocks, "free <= total");
        assert!(stat.blocks_available <= stat.blocks_free, "avail <= free");
        assert!(stat.files > 0, "should have inodes");
        assert!(stat.files_free <= stat.files, "free inodes <= total");
        assert!(stat.block_size > 0, "block size > 0");
    }

    #[test]
    fn write_statfs_consistent_after_mutations() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let before = fs.statfs(&cx, root).expect("statfs before");

        // Create a file and write data
        let attr = fs
            .create(&cx, root, OsStr::new("statfs_alloc.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &[0xCC; 8192]).expect("write");

        let after = fs.statfs(&cx, root).expect("statfs after");
        assert!(after.blocks > 0, "should have blocks");
        assert!(after.blocks_free <= after.blocks, "free <= total");
        assert!(after.blocks_available <= after.blocks_free, "avail <= free");
        assert!(after.files > 0, "should have inodes");
        assert!(after.files_free <= after.files, "free inodes <= total");
        assert!(
            after.blocks_free < before.blocks_free,
            "ext4 statfs should reflect allocated data blocks: before={}, after={}",
            before.blocks_free,
            after.blocks_free
        );
        assert!(
            after.files_free < before.files_free,
            "ext4 statfs should reflect allocated inode: before={}, after={}",
            before.files_free,
            after.files_free
        );
    }

    /// Isomorphism for bd-qsmav: statfs now sums the in-memory group stats, but
    /// after a real write that must equal what the old code computed by reading
    /// + summing every on-disk group descriptor. This pins the invariant the
    /// change rests on — the writable path keeps the device descriptors and the
    /// in-memory group stats consistent.
    #[test]
    fn write_statfs_group_stats_match_device_descriptors_bd_qsmav() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);
        let attr = fs
            .create(&cx, root, OsStr::new("qsmav.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &[0xCC; 16384]).expect("write");

        // Under GDT-persistence deferral (bd-cc-gdt-defer) the on-disk group
        // descriptors are updated only at a durability boundary, so flush before
        // sampling them — statfs reads the authoritative in-memory GroupStats,
        // which the descriptor sum matches exactly once persisted (no-op in eager
        // mode).
        fs.flush_mvcc_to_device(&cx).expect("flush");

        // Replicate the OLD aggregation: sum the on-disk group descriptors,
        // applying statfs's clamps.
        let (group_count, blocks_count, inodes_count, reserved) = {
            let sb = fs.ext4_superblock().expect("ext4 sb");
            let geo = FsGeometry::from_superblock(sb);
            (
                geo.group_count,
                sb.blocks_count,
                u64::from(sb.inodes_count),
                sb.reserved_blocks_count,
            )
        };
        let (gd_blocks, gd_inodes) = fs
            .with_latest_scope(|scope| {
                let mut blocks = 0_u64;
                let mut inodes = 0_u64;
                for g in 0..group_count {
                    let gd = fs.read_group_desc_with_scope(&cx, scope, GroupNumber(g))?;
                    blocks = blocks.saturating_add(u64::from(gd.free_blocks_count));
                    inodes = inodes.saturating_add(u64::from(gd.free_inodes_count));
                }
                Ok((blocks, inodes))
            })
            .expect("sum group descriptors");
        let exp_blocks = gd_blocks.min(blocks_count);
        let exp_inodes = gd_inodes.min(inodes_count);
        let exp_available = exp_blocks.saturating_sub(reserved);

        let st = fs.statfs(&cx, root).expect("statfs");
        assert_eq!(
            st.blocks_free, exp_blocks,
            "statfs blocks_free must equal the device group-descriptor sum"
        );
        assert_eq!(
            st.files_free, exp_inodes,
            "statfs files_free must equal the device group-descriptor sum"
        );
        assert_eq!(st.blocks_available, exp_available);
    }

