    /// Build an ext4 image with a specific superblock `state` value.
    fn build_ext4_image_with_state(state: u16) -> Vec<u8> {
        let mut image = build_ext4_image(2); // 4K blocks
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        // state field is at superblock offset 0x3A
        image[sb_off + 0x3A..sb_off + 0x3C].copy_from_slice(&state.to_le_bytes());
        image
    }

    #[test]
    fn request_scope_registers_and_releases_snapshot() {
        let image = build_ext4_image_with_state(EXT4_VALID_FS);
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();

        assert_eq!(fs.mvcc_active_snapshot_count(), 0);

        let scope = fs
            .begin_request_scope(&cx, RequestOp::Read)
            .expect("begin request scope");
        let pinned = scope
            .snapshot
            .expect("request scope should carry pinned snapshot");
        assert!(scope.tx.is_none(), "request scope should not allocate txn");
        assert_eq!(fs.mvcc_active_snapshot_count(), 1);

        fs.end_request_scope(
            &cx,
            RequestOp::Read,
            RequestScope {
                snapshot: Some(pinned),
                tx: None,
                commit_mode: RequestCommitMode::PerRequest,
                skip_readdir_prefetch: false,
            },
        )
        .expect("end request scope");
        assert_eq!(fs.mvcc_active_snapshot_count(), 0);
    }

    #[test]
    fn read_block_with_empty_scope_matches_current_adapter_view() {
        let image = build_ext4_image_with_state(EXT4_VALID_FS);
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();
        // The test writes through `block_device_adapter().write_block`, which only
        // yields a writable (snapshot-registered) adapter on a writable fs — a
        // read-only fs returns an unregistered RO adapter (bd-... new_unregistered)
        // whose write_block is correctly rejected. Enable writes so the
        // write→empty-scope-read overlay round-trip this test asserts can run.
        fs.enable_writes(&cx).expect("enable writes");
        let block = BlockNumber(8);

        let base = fs
            .block_device_adapter()
            .read_block(&cx, block)
            .expect("read adapter base block")
            .as_slice()
            .to_vec();
        assert_eq!(
            fs.read_block_with_scope(&cx, &RequestScope::empty(), block)
                .expect("read empty-scope base block"),
            base
        );

        let overlay = vec![0x5E_u8; usize::try_from(fs.block_size()).expect("block size fits")];
        fs.block_device_adapter()
            .write_block(&cx, block, &overlay)
            .expect("write through current adapter");

        assert_eq!(
            fs.read_block_with_scope(&cx, &RequestScope::empty(), block)
                .expect("read empty-scope current MVCC block"),
            overlay
        );
    }

    #[test]
    fn writable_current_adapter_does_not_pin_gc_watermark_bd_mvccgc() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let block = BlockNumber(8);
        let bytes = vec![0xC7_u8; usize::try_from(fs.block_size()).expect("block size fits")];

        assert_eq!(fs.mvcc_active_snapshot_count(), 0);
        {
            let block_dev = fs.block_device_adapter();
            assert_eq!(
                fs.mvcc_active_snapshot_count(),
                0,
                "read-your-writes adapters resolve at the live snapshot and must not pin one"
            );
            block_dev
                .write_block(&cx, block, &bytes)
                .expect("write through current adapter");
            assert_eq!(
                block_dev
                    .read_block(&cx, block)
                    .expect("read own committed write")
                    .as_slice(),
                bytes.as_slice()
            );
            assert_eq!(fs.mvcc_active_snapshot_count(), 0);
        }
        assert_eq!(fs.mvcc_active_snapshot_count(), 0);
    }

    #[test]
    fn open_fs_commit_prunes_unpinned_hot_block_versions_bd_mvccgc() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let block = BlockNumber(9);
        let bs = usize::try_from(fs.block_size()).expect("block size fits");
        let _current_adapter = fs.block_device_adapter();

        assert_eq!(fs.mvcc_active_snapshot_count(), 0);
        for seq in 0..512_u64 {
            let mut txn = fs.begin_transaction();
            let byte = u8::try_from(seq % 251).expect("modulo fits u8");
            fs.stage_block_write(&mut txn, block, vec![byte; bs]);
            fs.commit_transaction(txn)
                .expect("commit hot-block overwrite");
        }

        assert_eq!(fs.mvcc_active_snapshot_count(), 0);
        assert_eq!(fs.mvcc_oldest_active_snapshot(), None);
        assert!(
            fs.mvcc_version_count() <= 1,
            "periodic prune should retain only the current hot-block version, got {}",
            fs.mvcc_version_count()
        );
    }

    #[test]
    fn ext4_base_block_cache_reuses_reads_and_invalidates_direct_writes() {
        let image = build_ext4_image_with_state(EXT4_VALID_FS);
        let (dev, counters) = CountingByteDevice::new(image);
        let cx = Cx::for_testing();
        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();
        let block = BlockNumber(8);

        let before = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);
        let first = fs.read_block_vec(&cx, block).expect("first base read");
        let after_first = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);
        let second = fs.read_block_vec(&cx, block).expect("cached base read");
        let after_second = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);

        assert_eq!(first, second, "cached base block changed bytes");
        assert_eq!(after_first, before + 1, "first read must touch device");
        assert_eq!(
            after_second, after_first,
            "second read must come from ext4 base-block cache"
        );

        let replacement = vec![0xA5; usize::try_from(fs.block_size()).expect("block size fits")];
        fs.direct_block_device_adapter()
            .write_block(&cx, block, &replacement)
            .expect("direct write invalidates cache");
        let after_write = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);
        fs.read_block_vec(&cx, block)
            .expect("post-invalidation read");
        let after_invalidated_read = counters.scalar.load(std::sync::atomic::Ordering::SeqCst);

        assert_eq!(
            after_invalidated_read,
            after_write + 1,
            "direct write must evict the cached base block"
        );
    }

