    #[test]
    fn btrfs_write_create_invalid_name_rejected() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let err = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::from_bytes(b"bad/name"),
                0o644,
                0,
                0,
            )
            .expect_err("create with slash should fail");
        assert!(matches!(err, FfsError::Format(_)));

        let err = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::from_bytes(b"bad\0name"),
                0o644,
                0,
                0,
            )
            .expect_err("create with NUL should fail");
        assert!(matches!(err, FfsError::Format(_)));

        for name in [b".".as_slice(), b"..".as_slice()] {
            let err = ops
                .create(
                    &cx,
                    &mut RequestScope::empty(),
                    InodeNumber(1),
                    OsStr::from_bytes(name),
                    0o644,
                    0,
                    0,
                )
                .expect_err("create with reserved dot component should fail");
            assert!(matches!(err, FfsError::Format(_)));
        }

        let lookup_err = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::from_bytes(b"bad/name"),
            )
            .expect_err("invalid name must not be created");
        assert_eq!(lookup_err.to_errno(), libc::ENOENT);
    }

