    #[test]
    fn btrfs_write_rename() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("old.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("old.txt"),
            InodeNumber(1),
            OsStr::new("new.txt"),
        )
        .unwrap();

        // Old name gone.
        assert!(
            ops.lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("old.txt")
            )
            .is_err()
        );
        // New name resolves to same inode.
        let found = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("new.txt"),
            )
            .unwrap();
        assert_eq!(found.ino, attr.ino);
    }

    #[test]
    fn btrfs_rename2_exchange_swaps_two_entries_in_same_parent() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let root = InodeNumber(1);

        let x = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new("ex_x"),
                0o644,
                0,
                0,
            )
            .expect("create x");
        let y = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new("ex_y"),
                0o644,
                0,
                0,
            )
            .expect("create y");
        assert_ne!(x.ino, y.ino, "distinct inodes or the swap is a no-op");

        ops.write(&cx, &mut RequestScope::empty(), x.ino, 0, b"X-original")
            .expect("write x");
        ops.write(&cx, &mut RequestScope::empty(), y.ino, 0, b"Y-original")
            .expect("write y");

        ops.rename2(
            &cx,
            &mut RequestScope::empty(),
            root,
            OsStr::new("ex_x"),
            root,
            OsStr::new("ex_y"),
            libc::RENAME_EXCHANGE,
        )
        .expect("RENAME_EXCHANGE same-parent swap must succeed");

        let after_x = ops
            .lookup(&cx, &mut RequestScope::empty(), root, OsStr::new("ex_x"))
            .expect("lookup ex_x");
        let after_y = ops
            .lookup(&cx, &mut RequestScope::empty(), root, OsStr::new("ex_y"))
            .expect("lookup ex_y");
        assert_eq!(after_x.ino, y.ino, "ex_x now points at old y inode");
        assert_eq!(after_y.ino, x.ino, "ex_y now points at old x inode");

        let by_x = ops
            .read(&cx, &mut RequestScope::empty(), after_x.ino, 0, 64)
            .expect("read ex_x");
        let by_y = ops
            .read(&cx, &mut RequestScope::empty(), after_y.ino, 0, 64)
            .expect("read ex_y");
        assert!(by_x.starts_with(b"Y-original"), "ex_x reads y's data");
        assert!(by_y.starts_with(b"X-original"), "ex_y reads x's data");
    }

    #[test]
    fn btrfs_rename2_exchange_missing_target_returns_enoent() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let root = InodeNumber(1);

        ops.create(
            &cx,
            &mut RequestScope::empty(),
            root,
            OsStr::new("present"),
            0o644,
            0,
            0,
        )
        .expect("create present");

        let err = ops
            .rename2(
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new("present"),
                root,
                OsStr::new("absent"),
                libc::RENAME_EXCHANGE,
            )
            .expect_err("RENAME_EXCHANGE with a missing target must fail");
        assert_eq!(err.to_errno(), libc::ENOENT);

        // The source survives the failed, side-effect-free exchange.
        assert!(
            ops.lookup(&cx, &mut RequestScope::empty(), root, OsStr::new("present"))
                .is_ok(),
            "source entry must be untouched after a failed exchange"
        );
    }

    #[test]
    fn btrfs_rename2_exchange_swaps_across_distinct_parents() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let root = InodeNumber(1);

        let da = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new("da"),
                0o755,
                0,
                0,
            )
            .expect("mkdir da");
        let db = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new("db"),
                0o755,
                0,
                0,
            )
            .expect("mkdir db");

        let fa = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                da.ino,
                OsStr::new("fa"),
                0o644,
                0,
                0,
            )
            .expect("create da/fa");
        let fb = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                db.ino,
                OsStr::new("fb"),
                0o644,
                0,
                0,
            )
            .expect("create db/fb");

        ops.rename2(
            &cx,
            &mut RequestScope::empty(),
            da.ino,
            OsStr::new("fa"),
            db.ino,
            OsStr::new("fb"),
            libc::RENAME_EXCHANGE,
        )
        .expect("cross-parent RENAME_EXCHANGE must succeed");

        let after_a = ops
            .lookup(&cx, &mut RequestScope::empty(), da.ino, OsStr::new("fa"))
            .expect("lookup da/fa");
        let after_b = ops
            .lookup(&cx, &mut RequestScope::empty(), db.ino, OsStr::new("fb"))
            .expect("lookup db/fb");
        assert_eq!(after_a.ino, fb.ino, "da/fa now references old db/fb inode");
        assert_eq!(after_b.ino, fa.ino, "db/fb now references old da/fa inode");
    }

    #[test]
    fn btrfs_directory_is_descendant_of_walks_multiple_levels() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let root = InodeNumber(1);
        let mk = |parent: InodeNumber, name: &str| {
            ops.mkdir(
                &cx,
                &mut RequestScope::empty(),
                parent,
                OsStr::new(name),
                0o755,
                0,
                0,
            )
            .expect("mkdir")
        };
        let a = mk(root, "a");
        let mid = mk(a.ino, "mid");
        let deep = mk(mid.ino, "deep");
        let other = mk(root, "other");

        let alloc = fs.btrfs_alloc_state.as_ref().unwrap().read();
        // deep -> mid -> a: a descendant across multiple parent levels.
        assert!(OpenFs::btrfs_directory_is_descendant_of(&alloc, deep.ino.0, a.ino.0).unwrap());
        // mid -> a: one level.
        assert!(OpenFs::btrfs_directory_is_descendant_of(&alloc, mid.ino.0, a.ino.0).unwrap());
        // The inverse direction is false: a is not under deep.
        assert!(!OpenFs::btrfs_directory_is_descendant_of(&alloc, a.ino.0, deep.ino.0).unwrap());
        // A sibling subtree is not a descendant.
        assert!(!OpenFs::btrfs_directory_is_descendant_of(&alloc, other.ino.0, a.ino.0).unwrap());
        // A directory is reported as a descendant of itself (rename rejects mv a a).
        assert!(OpenFs::btrfs_directory_is_descendant_of(&alloc, a.ino.0, a.ino.0).unwrap());
    }

    #[test]
    fn btrfs_rename_directory_into_own_descendant_returns_einval() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(1);
        let a = fs
            .mkdir(&cx, root, OsStr::new("a"), 0o755, 0, 0)
            .expect("mkdir a");
        let b = fs
            .mkdir(&cx, a.ino, OsStr::new("b"), 0o755, 0, 0)
            .expect("mkdir a/b");

        // Moving "a" to be a child of "a/b" (its own descendant) would create a
        // cycle and must be rejected with EINVAL.
        let err = fs
            .rename(&cx, root, OsStr::new("a"), b.ino, OsStr::new("a"))
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::EINVAL);

        // The tree is unchanged: a still under root, b still under a.
        assert!(fs.lookup(&cx, root, OsStr::new("a")).is_ok());
        assert!(fs.lookup(&cx, a.ino, OsStr::new("b")).is_ok());
    }

    #[test]
    fn btrfs_rename2_exchange_directory_under_its_own_descendant_returns_einval() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let root = InodeNumber(1);

        // /a (dir), /a/sub (dir), /a/sub/b (file).
        let a = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new("a"),
                0o755,
                0,
                0,
            )
            .expect("mkdir a");
        let sub = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                a.ino,
                OsStr::new("sub"),
                0o755,
                0,
                0,
            )
            .expect("mkdir a/sub");
        ops.create(
            &cx,
            &mut RequestScope::empty(),
            sub.ino,
            OsStr::new("b"),
            0o644,
            0,
            0,
        )
        .expect("create a/sub/b");

        // Exchanging /a with /a/sub/b would move directory "a" under its own
        // descendant "a/sub" — a cycle the kernel rejects with EINVAL.
        let err = ops
            .rename2(
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new("a"),
                sub.ino,
                OsStr::new("b"),
                libc::RENAME_EXCHANGE,
            )
            .expect_err("exchanging a directory under its own descendant must fail");
        assert_eq!(err.to_errno(), libc::EINVAL);

        // Nothing moved: both entries remain where they were.
        assert!(
            ops.lookup(&cx, &mut RequestScope::empty(), root, OsStr::new("a"))
                .is_ok(),
            "directory a must remain under root"
        );
        assert!(
            ops.lookup(&cx, &mut RequestScope::empty(), sub.ino, OsStr::new("b"))
                .is_ok(),
            "file b must remain under a/sub"
        );
    }

