    #[test]
    fn btrfs_write_rename_directory_into_own_child_returns_einval() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let dir = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("cycle-dir"),
                0o755,
                0,
                0,
            )
            .expect("mkdir source dir");
        let child = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                dir.ino,
                OsStr::new("child"),
                0o755,
                0,
                0,
            )
            .expect("mkdir child dir");

        let err = ops
            .rename(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("cycle-dir"),
                child.ino,
                OsStr::new("moved"),
            )
            .expect_err("btrfs must reject moving a directory below itself");
        assert_eq!(err.to_errno(), libc::EINVAL);

        let dir_after = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("cycle-dir"),
            )
            .expect("source dir remains in root");
        assert_eq!(dir_after.ino, dir.ino);
        let child_after = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                dir.ino,
                OsStr::new("child"),
            )
            .expect("child remains under source dir");
        assert_eq!(child_after.ino, child.ino);
        assert!(
            ops.lookup(
                &cx,
                &mut RequestScope::empty(),
                child.ino,
                OsStr::new("moved"),
            )
            .is_err(),
            "failed descendant rename must not create destination entry"
        );
    }

    #[test]
    fn btrfs_write_rename_invalid_new_name_preserves_source() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("rename_src.txt"),
                0o644,
                0,
                0,
            )
            .expect("create source");

        let err = ops
            .rename(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("rename_src.txt"),
                InodeNumber(1),
                OsStr::from_bytes(b"bad/name"),
            )
            .expect_err("rename with slash should fail");
        assert!(matches!(err, FfsError::Format(_)));

        let looked_up = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("rename_src.txt"),
            )
            .expect("source should remain after failed rename");
        assert_eq!(looked_up.ino, attr.ino);

        let err = ops
            .rename(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("rename_src.txt"),
                InodeNumber(1),
                OsStr::from_bytes(b"bad\0name"),
            )
            .expect_err("rename with NUL should fail");
        assert!(matches!(err, FfsError::Format(_)));

        let looked_up = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("rename_src.txt"),
            )
            .expect("source should remain after failed NUL-name rename");
        assert_eq!(looked_up.ino, attr.ino);

        let err = ops
            .rename(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::from_bytes(b"rename\0src.txt"),
                InodeNumber(1),
                OsStr::new("rename_dst.txt"),
            )
            .expect_err("rename with NUL source should fail");
        assert!(matches!(err, FfsError::Format(_)));

        let looked_up = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("rename_src.txt"),
            )
            .expect("source should remain after failed NUL-source rename");
        assert_eq!(looked_up.ino, attr.ino);

        for name in [b".".as_slice(), b"..".as_slice()] {
            let err = ops
                .rename(
                    &cx,
                    &mut RequestScope::empty(),
                    InodeNumber(1),
                    OsStr::new("rename_src.txt"),
                    InodeNumber(1),
                    OsStr::from_bytes(name),
                )
                .expect_err("rename with reserved dot component should fail");
            assert!(matches!(err, FfsError::Format(_)));

            let looked_up = ops
                .lookup(
                    &cx,
                    &mut RequestScope::empty(),
                    InodeNumber(1),
                    OsStr::new("rename_src.txt"),
                )
                .expect("source should remain after failed reserved-name rename");
            assert_eq!(looked_up.ino, attr.ino);
        }
    }

