    #[test]
    fn btrfs_write_link_rejects_malformed_existing_inode_ref_without_partial_mutation() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.link(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            InodeNumber(1),
            OsStr::new("link_a.txt"),
        )
        .unwrap();

        // DIR_INDEX is now keyed by a monotonic sequence (bd-yqoni), so a new
        // link never reads a sibling DIR_INDEX item. The pre-mutation parse the
        // link path still performs is the target's INODE_REF (preflight). Corrupt
        // it and the next link must fail closed before any mutation.
        let alloc_mutex = fs.require_btrfs_alloc_state().unwrap();
        let mut alloc = alloc_mutex.write();
        let inode_ref_key = BtrfsKey {
            objectid: attr.ino.0,
            item_type: BTRFS_ITEM_INODE_REF,
            offset: 256,
        };
        alloc.fs_tree.update(&inode_ref_key, &[0xAA, 0xBB]).unwrap();
        drop(alloc);

        let err = ops
            .link(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                InodeNumber(1),
                OsStr::new("link_b.txt"),
            )
            .expect_err("malformed existing dir_index should fail closed");
        assert!(matches!(
            err,
            FfsError::Corruption { .. } | FfsError::Format(_)
        ));

        let attr_after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("source inode should remain readable");
        assert_eq!(attr_after.nlink, 2, "failed link must not bump nlink");

        let original = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original.txt"),
            )
            .expect("original name should remain");
        assert_eq!(original.ino, attr.ino);

        let link_a = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("link_a.txt"),
            )
            .expect("existing hard link should remain");
        assert_eq!(link_a.ino, attr.ino);

        let missing = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("link_b.txt"),
            )
            .expect_err("new hard link name must not appear after failed link");
        assert_eq!(missing.to_errno(), libc::ENOENT);
    }

    #[test]
    fn btrfs_setattr_atime_mtime_round_trip_without_swap() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(1);
        let attr = fs
            .create(&cx, root, OsStr::new("t.bin"), 0o644, 0, 0)
            .expect("create");

        // Distinct values so a swap or one-field drop is detectable.
        let atime = std::time::UNIX_EPOCH + std::time::Duration::from_secs(1_000_000);
        let mtime = std::time::UNIX_EPOCH + std::time::Duration::from_secs(2_000_000);
        let req = SetAttrRequest {
            mode: None,
            uid: None,
            gid: None,
            size: None,
            atime: Some(atime),
            mtime: Some(mtime),
        };
        fs.setattr(&cx, attr.ino, &req).expect("setattr times");

        let ga = fs.getattr(&cx, attr.ino).expect("getattr");
        assert_eq!(
            ga.atime, atime,
            "atime must round-trip (not swapped/dropped)"
        );
        assert_eq!(
            ga.mtime, mtime,
            "mtime must round-trip (not swapped/dropped)"
        );
    }

    #[test]
    fn btrfs_setattr_chown_uid_gid_round_trip_without_swap() {
        let (fs, cx) = open_writable_btrfs();
        let attr = fs
            .create(
                &cx,
                InodeNumber(1),
                OsStr::new("chown.bin"),
                0o644,
                1000,
                1000,
            )
            .expect("create");

        // Distinct uid != gid so a swap or one-field drop is detectable.
        let new_attr = fs
            .setattr(
                &cx,
                attr.ino,
                &SetAttrRequest {
                    uid: Some(2000),
                    gid: Some(3000),
                    ..SetAttrRequest::default()
                },
            )
            .expect("chown");
        assert_eq!(new_attr.uid, 2000);
        assert_eq!(new_attr.gid, 3000);

        let ga = fs.getattr(&cx, attr.ino).expect("getattr");
        assert_eq!(ga.uid, 2000, "uid must round-trip (not swapped/dropped)");
        assert_eq!(ga.gid, 3000, "gid must round-trip (not swapped/dropped)");
    }

