    #[test]
    fn btrfs_write_xattr_respects_create_and_replace_modes() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("xattr_modes.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            "user.color",
            b"blue",
            XattrSetMode::Create,
        )
        .expect("initial create");

        let err = ops
            .setxattr(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                "user.color",
                b"green",
                XattrSetMode::Create,
            )
            .expect_err("create on existing xattr should fail");
        assert_eq!(err.to_errno(), libc::EEXIST);
        assert_eq!(
            ops.getxattr(&cx, attr.ino, "user.color").unwrap(),
            Some(b"blue".to_vec()),
            "failed create path must not mutate existing xattr value"
        );

        let err = ops
            .setxattr(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                "user.missing",
                b"x",
                XattrSetMode::Replace,
            )
            .expect_err("replace on missing xattr should fail");
        // setxattr(2): XATTR_REPLACE on a missing attribute is ENODATA, not
        // ENOENT (matches getxattr/removexattr's missing-attribute errno; bd-dssi7).
        assert_eq!(err.to_errno(), libc::ENODATA);
        assert_eq!(ops.getxattr(&cx, attr.ino, "user.missing").unwrap(), None);
    }

    fn wait_until_wall_clock_after(previous: SystemTime) {
        let deadline = Instant::now() + Duration::from_millis(250);
        while SystemTime::now() <= previous {
            assert!(
                Instant::now() < deadline,
                "wall clock did not advance past {previous:?} before ctime-sensitive assertion"
            );
            std::thread::yield_now();
        }
    }

    #[test]
    fn btrfs_write_xattr_rejects_invalid_names_without_poisoning_payload() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("xattr_invalid_name.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            "user.good",
            b"kept",
            XattrSetMode::Set,
        )
        .unwrap();
        let before_invalid = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap()
            .ctime;
        wait_until_wall_clock_after(before_invalid);

        for invalid_name in ["", "user.", "naked", "unknown.name"] {
            let err = ops
                .setxattr(
                    &cx,
                    &mut RequestScope::empty(),
                    attr.ino,
                    invalid_name,
                    b"bad",
                    XattrSetMode::Set,
                )
                .expect_err("invalid btrfs xattr name must be rejected before serialization");
            assert_eq!(
                err.to_errno(),
                libc::EINVAL,
                "invalid name {invalid_name:?}"
            );

            let err = ops
                .getxattr(&cx, attr.ino, invalid_name)
                .expect_err("invalid btrfs getxattr name must be rejected");
            assert_eq!(
                err.to_errno(),
                libc::EINVAL,
                "invalid name {invalid_name:?}"
            );

            let err = ops
                .removexattr(&cx, &mut RequestScope::empty(), attr.ino, invalid_name)
                .expect_err("invalid btrfs removexattr name must be rejected");
            assert_eq!(
                err.to_errno(),
                libc::EINVAL,
                "invalid name {invalid_name:?}"
            );

            assert_eq!(
                ops.getxattr(&cx, attr.ino, "user.good").unwrap(),
                Some(b"kept".to_vec()),
                "invalid-name operation must not damage existing xattr payload"
            );
            assert_eq!(
                ops.listxattr(&cx, attr.ino).unwrap(),
                vec!["user.good"],
                "invalid-name operation must leave btrfs xattr list parseable"
            );
        }

        let after_invalid = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap()
            .ctime;
        assert_eq!(
            after_invalid, before_invalid,
            "invalid-name xattr operations must not mutate inode ctime"
        );
    }

    #[test]
    fn btrfs_write_xattr_hash_collision_preserves_neighbors() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let collision_a = "user.qQHUkgl8f";
        let collision_b = "user.dua3yAXVkTW";

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("xattr_collision.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            collision_a,
            b"alpha",
            XattrSetMode::Set,
        )
        .unwrap();
        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            collision_b,
            b"beta",
            XattrSetMode::Set,
        )
        .unwrap();

        assert_eq!(
            ops.getxattr(&cx, attr.ino, collision_a).unwrap(),
            Some(b"alpha".to_vec())
        );
        assert_eq!(
            ops.getxattr(&cx, attr.ino, collision_b).unwrap(),
            Some(b"beta".to_vec())
        );

        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            collision_a,
            b"alpha-2",
            XattrSetMode::Replace,
        )
        .unwrap();
        assert_eq!(
            ops.getxattr(&cx, attr.ino, collision_a).unwrap(),
            Some(b"alpha-2".to_vec())
        );
        assert_eq!(
            ops.getxattr(&cx, attr.ino, collision_b).unwrap(),
            Some(b"beta".to_vec()),
            "updating one colliding xattr must preserve its neighbor"
        );

        let removed = ops
            .removexattr(&cx, &mut RequestScope::empty(), attr.ino, collision_a)
            .unwrap();
        assert!(removed);
        assert_eq!(ops.getxattr(&cx, attr.ino, collision_a).unwrap(), None);
        assert_eq!(
            ops.getxattr(&cx, attr.ino, collision_b).unwrap(),
            Some(b"beta".to_vec()),
            "removing one colliding xattr must preserve the other"
        );

        let mut names = ops.listxattr(&cx, attr.ino).unwrap();
        names.sort();
        assert_eq!(names, vec![collision_b]);
    }

    #[test]
    fn btrfs_write_xattr_updates_ctime() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("xattr_ctime.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        let before_set = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap()
            .ctime;
        wait_until_wall_clock_after(before_set);

        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            "user.key",
            b"value",
            XattrSetMode::Set,
        )
        .unwrap();

        let after_set = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap()
            .ctime;
        assert!(
            after_set > before_set,
            "setxattr should advance ctime: before={before_set:?} after={after_set:?}"
        );

        wait_until_wall_clock_after(after_set);
        assert!(
            ops.removexattr(&cx, &mut RequestScope::empty(), attr.ino, "user.key")
                .unwrap()
        );

        let after_remove = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap()
            .ctime;
        assert!(
            after_remove > after_set,
            "removexattr should advance ctime: after_set={after_set:?} after_remove={after_remove:?}"
        );
    }

    #[test]
    fn btrfs_write_fallocate_basic() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("prealloc.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        assert_eq!(attr.size, 0);

        // Preallocate 8192 bytes.
        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 8192, 0)
            .unwrap();

        let attr2 = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(attr2.size, 8192);

        // Reading preallocated region should return zeros (hole or prealloc).
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096)
            .unwrap();
        assert_eq!(data.len(), 4096);

        // Write into the preallocated region.
        let written = ops
            .write(&cx, &mut RequestScope::empty(), attr.ino, 0, b"hello")
            .unwrap();
        assert_eq!(written, 5);

        // Size should still be 8192 (not shrunk).
        let attr3 = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(attr3.size, 8192);
    }

    #[test]
    fn btrfs_validate_fallocate_mode_rejects_invalid_combinations() {
        let v = |mode| OpenFs::btrfs_validate_fallocate_mode(mode, "op", "scenario");

        // Plain allocation and KEEP_SIZE alone are accepted.
        assert!(v(0).is_ok());
        assert!(v(libc::FALLOC_FL_KEEP_SIZE).is_ok());

        // PUNCH_HOLE and ZERO_RANGE are mutually exclusive -> EINVAL.
        let punch_zero =
            libc::FALLOC_FL_PUNCH_HOLE | libc::FALLOC_FL_ZERO_RANGE | libc::FALLOC_FL_KEEP_SIZE;
        assert_eq!(v(punch_zero).unwrap_err().to_errno(), libc::EINVAL);

        // PUNCH_HOLE requires KEEP_SIZE -> EINVAL without it.
        assert_eq!(
            v(libc::FALLOC_FL_PUNCH_HOLE).unwrap_err().to_errno(),
            libc::EINVAL
        );

        // An unknown / unsupported mode bit is rejected.
        assert!(v(0x4000).is_err());
    }

    #[test]
    fn btrfs_fallocate_collapse_insert_reject_misaligned_and_out_of_bounds() {
        let (fs, cx) = open_writable_btrfs();
        let attr = fs
            .create(
                &cx,
                InodeNumber(1),
                OsStr::new("falloc-shift.bin"),
                0o644,
                0,
                0,
            )
            .expect("create");
        // 4 sectors of 4096 bytes.
        fs.write(&cx, attr.ino, 0, &[0xAB_u8; 16384])
            .expect("write");

        let collapse = libc::FALLOC_FL_COLLAPSE_RANGE;
        let insert = libc::FALLOC_FL_INSERT_RANGE;

        // Misaligned offset is rejected for both shift operations.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 100, 4096, collapse)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 100, 4096, insert)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
        // A collapse that reaches EOF is rejected.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 0, 16384, collapse)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
        // An insert offset at/past EOF is rejected.
        assert_eq!(
            fs.fallocate(&cx, attr.ino, 16384, 4096, insert)
                .unwrap_err()
                .to_errno(),
            libc::EINVAL
        );
    }

    #[test]
    fn btrfs_write_fallocate_extends_file() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("extend.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // Write some data first.
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, b"existing")
            .unwrap();
        let attr2 = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(attr2.size, 8);

        // Fallocate past current file end.
        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096, 0)
            .unwrap();
        let attr3 = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(attr3.size, 4096);
    }

    #[test]
    fn btrfs_write_fallocate_keep_size_does_not_extend_file() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let stat_before = ops
            .statfs(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("keep.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, b"existing")
            .unwrap();
        let before = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(before.size, 8);
        assert_eq!(
            before.blocks, 1,
            "an 8-byte inline payload counts its inline length toward nbytes \
             (8 bytes -> 1 512B sector); see bd-5svhs"
        );

        ops.fallocate(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            4096,
            4096,
            libc::FALLOC_FL_KEEP_SIZE,
        )
        .unwrap();

        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(after.size, 8);
        assert!(
            after.blocks > before.blocks,
            "KEEP_SIZE preallocation should reserve backing extent blocks"
        );
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096)
            .unwrap();
        assert_eq!(&data[..8], b"existing");
        let stat_after = ops
            .statfs(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();
        assert!(
            stat_after.blocks_free < stat_before.blocks_free,
            "KEEP_SIZE preallocation should reduce free space: before={}, after={}",
            stat_before.blocks_free,
            stat_after.blocks_free
        );
    }

    #[test]
    fn btrfs_write_into_keep_size_prealloc_splits_unwritten_tail_bd_xmh5g_183() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let block = 4096_u64;
        let block_usize = usize::try_from(block).unwrap();

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("keep-size-write-tail.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.fallocate(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            0,
            2 * block,
            libc::FALLOC_FL_KEEP_SIZE,
        )
        .expect("keep-size preallocate two blocks");
        let before = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr after keep-size prealloc");
        assert_eq!(before.size, 0);
        assert!(
            before.blocks > 0,
            "KEEP_SIZE preallocation must reserve blocks before the write"
        );

        let payload = vec![b'W'; block_usize];
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, &payload)
            .expect("write into first preallocated block");

        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr after write");
        assert_eq!(after.size, block);
        let readback = ops
            .read(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                0,
                u32::try_from(block).unwrap(),
            )
            .expect("read written block");
        assert_eq!(readback, payload);

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, attr.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            extents.len(),
            2,
            "write must split KEEP_SIZE prealloc into written data plus unwritten tail: {extents:?}"
        );
        assert_eq!(extents[0].logical, 0);
        assert_eq!(extents[0].length, block);
        assert_eq!(
            extents[0].flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "written block must not stay unwritten"
        );
        assert_eq!(extents[1].logical, block);
        assert_eq!(extents[1].length, block);
        assert_ne!(
            extents[1].flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "tail beyond i_size must remain an unwritten preallocation"
        );
    }

    #[test]
    fn btrfs_write_fallocate_materializes_compressed_inline_extent() {
        use flate2::Compression;
        use flate2::write::ZlibEncoder;
        use std::io::Write as _;

        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let original = b"compressed inline fallocate payload ".repeat(12);

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("compressed-inline.bin"),
                0o644,
                0,
                0,
            )
            .expect("create compressed inline file");
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, &original)
            .expect("seed inline payload");

        let mut encoder = ZlibEncoder::new(Vec::new(), Compression::default());
        encoder
            .write_all(&original)
            .expect("write zlib fixture payload");
        let compressed = encoder.finish().expect("finish zlib fixture");
        assert!(
            compressed.len() < original.len(),
            "fixture must be meaningfully compressed"
        );

        let canonical = fs.btrfs_canonical_inode(attr.ino).unwrap();
        let extent_key = BtrfsKey {
            objectid: canonical,
            item_type: BTRFS_ITEM_EXTENT_DATA,
            offset: 0,
        };
        let alloc_mutex = fs.require_btrfs_alloc_state().unwrap();
        {
            let mut alloc = alloc_mutex.write();
            let compressed_extent = BtrfsExtentData::Inline {
                generation: alloc.generation,
                ram_bytes: u64::try_from(original.len()).unwrap(),
                compression: 1,
                data: compressed,
            };
            alloc
                .fs_tree
                .update(&extent_key, &compressed_extent.to_bytes())
                .expect("replace inline extent with compressed fixture");
        }

        ops.fallocate(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            4096,
            4096,
            libc::FALLOC_FL_KEEP_SIZE,
        )
        .expect("preallocate beyond compressed inline data");

        let preserved = ops
            .read(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                0,
                u32::try_from(original.len()).unwrap(),
            )
            .expect("read materialized inline data");
        assert_eq!(preserved, original);

        let entries = alloc_mutex
            .read()
            .fs_tree
            .range(&extent_key, &extent_key)
            .expect("lookup converted extent");
        let converted = parse_extent_data(&entries[0].1).expect("parse converted extent");
        assert!(
            matches!(
                converted,
                BtrfsExtentData::Regular {
                    compression: 0,
                    num_bytes,
                    ..
                } if num_bytes == u64::try_from(original.len()).unwrap()
            ),
            "fallocate should convert inline data to an uncompressed regular extent: {converted:?}"
        );
    }

    #[test]
    fn btrfs_write_fallocate_punch_hole_zeroes_data() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("hole.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        let mut original = vec![b'A'; 4096];
        original.extend(vec![b'B'; 4096]);
        original.extend(vec![b'C'; 4096]);
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, &original)
            .expect("seed file before punch hole");
        let before_attr = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr before punch hole");
        ops.fallocate(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            4096,
            4096,
            libc::FALLOC_FL_KEEP_SIZE | libc::FALLOC_FL_PUNCH_HOLE,
        )
        .expect("punch-hole mode should succeed for btrfs");
        let after_attr = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr after punch hole");
        let after_data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 12288)
            .expect("read after punch hole");
        assert_eq!(
            after_attr.size, before_attr.size,
            "punch-hole mode must preserve file size under KEEP_SIZE"
        );
        assert_eq!(&after_data[..4096], &original[..4096]);
        assert!(after_data[4096..8192].iter().all(|byte| *byte == 0));
        assert_eq!(
            &after_data[8192..],
            &original[8192..],
            "punch hole must preserve data outside the requested range"
        );
    }

