    // ── WritebackEpochBarrier tests ──────────────────────────────────────

    #[test]
    fn epoch_barrier_disabled_is_noop() {
        let mut barrier = WritebackEpochBarrier::new();
        assert!(!barrier.is_enabled());
        // All operations are no-ops when disabled.
        barrier.stage_write(InodeNumber(1));
        barrier.commit_inode(InodeNumber(1));
        assert!(barrier.mark_durable(InodeNumber(1)).is_ok());
        assert!(barrier.is_epoch_visible(InodeNumber(1), 999));
        assert_eq!(barrier.tracked_inode_count(), 0);
    }

    #[test]
    fn epoch_barrier_untracked_inode_is_visible() {
        let barrier = WritebackEpochBarrier::enabled();
        // An inode that was never staged (predates writeback-cache) should
        // be visible at any epoch — its data was committed via the direct path.
        let untracked = InodeNumber(999);
        assert!(barrier.is_epoch_visible(untracked, 0));
        assert!(barrier.is_epoch_visible(untracked, 1));
        assert!(barrier.is_epoch_visible(untracked, 100));
    }

    #[test]
    fn epoch_barrier_stage_and_commit_cycle() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(42);

        // Stage a write.
        barrier.stage_write(inode);
        let state = barrier.inode_state(inode).expect("inode tracked");
        assert_eq!(state.staged_epoch, 1);
        assert_eq!(state.visible_epoch, 0);
        assert!(state.has_pending_visibility());
        assert!(!barrier.is_epoch_visible(inode, 1));

        // Commit makes it visible.
        barrier.commit_inode(inode);
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.visible_epoch, 1);
        assert!(barrier.is_epoch_visible(inode, 1));
        assert!(state.has_pending_durability());

        // Mark durable.
        barrier.mark_durable(inode).expect("durable");
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.durable_epoch, 1);
        assert!(!state.has_pending_durability());
    }

    #[test]
    fn epoch_barrier_fsync_commits_and_durables() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(10);
        barrier.stage_write(inode);
        barrier.fsync_barrier(inode).expect("fsync");
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.visible_epoch, 1);
        assert_eq!(state.durable_epoch, 1);
        assert!(state.is_valid());
    }

    #[test]
    fn epoch_barrier_commit_at_higher_epoch_advances_to_staged() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(5);

        // Stage at epoch 1, then advance to epoch 2.
        barrier.stage_write(inode); // staged at epoch 1
        let _epoch2 = barrier.advance_epoch(); // now epoch 2

        // Commit at epoch 2 should succeed — the inode has no epoch-2 writes,
        // so visibility advances to staged_epoch (1), not current_epoch (2).
        barrier.commit_inode(inode);
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.staged_epoch, 1);
        assert_eq!(state.visible_epoch, 1);
        assert!(state.is_valid());
    }

    #[test]
    fn epoch_barrier_mark_durable_before_visible_fails() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(5);

        // Stage at epoch 1 but don't commit.
        barrier.stage_write(inode);
        // mark_durable should fail because visible_epoch is still 0.
        let result = barrier.mark_durable(inode);
        // mark_durable uses visible_epoch (0), so epoch=0 > durable(0) is false → Ok (no-op).
        // Actually, let's verify: mark_durable reads state.visible_epoch=0,
        // then checks epoch(0) > visible(0) → false → no error, no advance. ✓
        assert!(result.is_ok());
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.durable_epoch, 0);
    }

    #[test]
    fn epoch_barrier_multi_epoch_advances() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(7);

        // Epoch 1: stage and commit.
        barrier.stage_write(inode);
        barrier.fsync_barrier(inode).unwrap();

        // Advance to epoch 2.
        barrier.advance_epoch();
        assert_eq!(barrier.current_epoch(), 2);

        // Epoch 2: stage and commit.
        barrier.stage_write(inode);
        barrier.fsync_barrier(inode).unwrap();
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.staged_epoch, 2);
        assert_eq!(state.visible_epoch, 2);
        assert_eq!(state.durable_epoch, 2);
    }

    #[test]
    fn epoch_barrier_invariant_always_holds() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(99);
        barrier.stage_write(inode);
        let state = barrier.inode_state(inode).unwrap();
        assert!(state.is_valid());
        barrier.commit_inode(inode);
        assert!(barrier.inode_state(inode).unwrap().is_valid());
        barrier.mark_durable(inode).expect("durable");
        assert!(barrier.inode_state(inode).unwrap().is_valid());
    }

    // ── Writeback benchmark tests ────────────────────────────────────────

    #[test]
    fn writeback_benchmark_all_workloads_complete() {
        for workload in WritebackWorkload::ALL {
            let disabled = run_writeback_barrier_benchmark(workload, false);
            let enabled = run_writeback_barrier_benchmark(workload, true);

            assert_eq!(disabled.operations, workload.operation_count());
            assert_eq!(enabled.operations, workload.operation_count());
            assert!(!disabled.writeback_enabled);
            assert!(enabled.writeback_enabled);
            assert_eq!(disabled.epoch_transitions, 0); // Disabled → no epochs.
            // Enabled should have some epoch transitions.
            if workload.write_count() > 0 {
                assert!(
                    enabled.epoch_transitions > 0 || enabled.fsync_barriers > 0,
                    "{workload:?}: expected epoch transitions when enabled"
                );
            }
        }
    }

    #[test]
    fn writeback_benchmark_comparison_produces_valid_ratios() {
        for workload in WritebackWorkload::ALL {
            let baseline = run_writeback_barrier_benchmark(workload, false);
            let writeback = run_writeback_barrier_benchmark(workload, true);
            let cmp = WritebackComparison::compare(baseline, writeback);

            assert!(cmp.throughput_ratio > 0.0);
            assert!(cmp.throughput_ratio.is_finite());
            assert!(cmp.latency_p50_ratio.is_finite());
            assert!(cmp.latency_p95_ratio.is_finite());
            assert_eq!(cmp.workload, workload);

            eprintln!(
                "  {:20} throughput_ratio={:.3} p50_ratio={:.3} p95_ratio={:.3} \
                 epoch_transitions={}",
                workload.name(),
                cmp.throughput_ratio,
                cmp.latency_p50_ratio,
                cmp.latency_p95_ratio,
                cmp.writeback.epoch_transitions,
            );
        }
    }

