    #[test]
    fn btrfs_write_unlink_zero_nlink_reports_corruption() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("bad_nlink.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, attr.ino.0)
                .expect("read child inode");
            inode.nlink = 0;
            let key = BtrfsKey {
                objectid: attr.ino.0,
                item_type: BTRFS_ITEM_INODE_ITEM,
                offset: 0,
            };
            alloc
                .fs_tree
                .update(&key, &inode.to_bytes())
                .expect("corrupt inode nlink");
        }

        let err = ops
            .unlink(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("bad_nlink.txt"),
            )
            .expect_err("unlink should fail on zero nlink corruption");
        assert!(matches!(err, FfsError::Corruption { .. }));

        let looked_up = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("bad_nlink.txt"),
            )
            .expect("failed unlink must leave directory entry intact");
        assert_eq!(looked_up.ino, attr.ino);
    }

    #[test]
    fn btrfs_link_at_max_links_returns_emlink_without_mutation() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("maxlink.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // Drive the inode's nlink up to the btrfs cap (BTRFS_LINK_MAX = 65535)
        // so the next link would exceed it. Injecting the count directly avoids
        // 65k real link() calls.
        {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, attr.ino.0)
                .expect("read target inode");
            inode.nlink = 65_535;
            let key = BtrfsKey {
                objectid: attr.ino.0,
                item_type: BTRFS_ITEM_INODE_ITEM,
                offset: 0,
            };
            alloc
                .fs_tree
                .update(&key, &inode.to_bytes())
                .expect("pin nlink at the link cap");
        }

        let err = ops
            .link(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                InodeNumber(1),
                OsStr::new("maxlink_overflow.bin"),
            )
            .expect_err("link at BTRFS_LINK_MAX must be rejected with EMLINK");
        assert_eq!(err.to_errno(), libc::EMLINK);

        // No partial mutation: the rejected link created no new directory entry
        // and left the link count unchanged.
        assert!(
            ops.lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("maxlink_overflow.bin"),
            )
            .is_err(),
            "rejected link must not create the new name"
        );
        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr after rejected link");
        assert_eq!(after.nlink, 65_535, "rejected link must not bump nlink");
    }

    #[test]
    fn btrfs_link_to_immutable_or_append_is_eperm_bd_69ich() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let parent = InodeNumber(1);

        // vfs_link forbids a hard link to an immutable OR append-only file
        // (EPERM). btrfs_link previously checked neither (bd-69ich).
        for (name, flag) in [
            ("imm.bin", BTRFS_INODE_IMMUTABLE),
            ("app.bin", BTRFS_INODE_APPEND),
        ] {
            let attr = ops
                .create(
                    &cx,
                    &mut RequestScope::empty(),
                    parent,
                    OsStr::new(name),
                    0o644,
                    0,
                    0,
                )
                .unwrap();
            {
                let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
                let mut alloc = alloc_mutex.write();
                let mut inode = fs
                    .btrfs_read_inode_from_tree(&alloc, attr.ino.0)
                    .expect("read target inode");
                inode.flags |= flag;
                let key = BtrfsKey {
                    objectid: attr.ino.0,
                    item_type: BTRFS_ITEM_INODE_ITEM,
                    offset: 0,
                };
                alloc
                    .fs_tree
                    .update(&key, &inode.to_bytes())
                    .expect("pin attribute flag");
            }
            let link_name = format!("{name}.link");
            let err = ops
                .link(
                    &cx,
                    &mut RequestScope::empty(),
                    attr.ino,
                    parent,
                    OsStr::new(&link_name),
                )
                .expect_err("link to an immutable/append-only file must be rejected");
            assert_eq!(
                err.to_errno(),
                libc::EPERM,
                "{name} hard link must be EPERM"
            );
            // No partial mutation: the rejected link created no new name.
            assert!(
                ops.lookup(
                    &cx,
                    &mut RequestScope::empty(),
                    parent,
                    OsStr::new(&link_name)
                )
                .is_err(),
                "rejected link must not create the new name for {name}"
            );
        }
    }

