    #[test]
    fn btrfs_rename_immutable_source_or_target_is_eperm_bd_85rav() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);

        let set_flag = |ino_raw: u64, flag: u64| {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, ino_raw)
                .expect("read inode");
            inode.flags |= flag;
            let key = BtrfsKey {
                objectid: ino_raw,
                item_type: BTRFS_ITEM_INODE_ITEM,
                offset: 0,
            };
            alloc
                .fs_tree
                .update(&key, &inode.to_bytes())
                .expect("pin flag");
        };

        // Case 1: an immutable SOURCE cannot be renamed (vfs_rename may_delete).
        let s1 = fs
            .create(&cx, parent, OsStr::new("s1"), 0o644, 0, 0)
            .unwrap()
            .ino;
        set_flag(s1.0, BTRFS_INODE_IMMUTABLE);
        assert_eq!(
            fs.rename(&cx, parent, OsStr::new("s1"), parent, OsStr::new("s1moved"))
                .unwrap_err()
                .to_errno(),
            libc::EPERM,
            "renaming an immutable source must be EPERM"
        );
        assert!(
            fs.lookup(&cx, parent, OsStr::new("s1")).is_ok(),
            "immutable source must not be moved"
        );

        // Case 2: an append-only VICTIM cannot be clobbered by a rename.
        fs.create(&cx, parent, OsStr::new("s2"), 0o644, 0, 0)
            .unwrap();
        let v2 = fs
            .create(&cx, parent, OsStr::new("v2"), 0o644, 0, 0)
            .unwrap()
            .ino;
        set_flag(v2.0, BTRFS_INODE_APPEND);
        assert_eq!(
            fs.rename(&cx, parent, OsStr::new("s2"), parent, OsStr::new("v2"))
                .unwrap_err()
                .to_errno(),
            libc::EPERM,
            "renaming onto an append-only victim must be EPERM"
        );
        assert!(
            fs.lookup(&cx, parent, OsStr::new("s2")).is_ok(),
            "source must survive a rejected rename"
        );
        assert!(
            fs.lookup(&cx, parent, OsStr::new("v2")).is_ok(),
            "append-only victim must survive a rejected rename"
        );
    }

    #[test]
    fn btrfs_delete_reclaims_data_blocks() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let free_before = fs.statfs(&cx, parent).expect("statfs before").blocks_free;

        let attr = fs
            .create(&cx, parent, OsStr::new("big.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, &[0xAB_u8; 128 * 1024])
            .expect("write");
        let free_after_write = fs
            .statfs(&cx, parent)
            .expect("statfs after write")
            .blocks_free;
        assert!(
            free_after_write < free_before,
            "write must consume data blocks ({free_after_write} < {free_before})"
        );

        // Removing the file's only name must return its data blocks to the pool.
        fs.unlink(&cx, parent, OsStr::new("big.bin"))
            .expect("remove");
        let free_after_delete = fs
            .statfs(&cx, parent)
            .expect("statfs after delete")
            .blocks_free;
        assert!(
            free_after_delete > free_after_write,
            "delete must reclaim data blocks ({free_after_delete} > {free_after_write})"
        );
    }

    #[test]
    fn btrfs_removing_one_hardlink_keeps_data_for_other() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let a = fs
            .create(&cx, parent, OsStr::new("a.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, a.ino, 0, b"PERSIST").expect("write");
        fs.link(&cx, a.ino, parent, OsStr::new("b.bin"))
            .expect("link");

        // Remove the first name; the second hardlink must keep the inode + data.
        fs.unlink(&cx, parent, OsStr::new("a.bin"))
            .expect("remove first name");

        assert!(fs.lookup(&cx, parent, OsStr::new("a.bin")).is_err());
        let b = fs
            .lookup(&cx, parent, OsStr::new("b.bin"))
            .expect("lookup surviving name");
        assert_eq!(b.ino, a.ino, "surviving link keeps the same inode");
        let data = fs.read(&cx, b.ino, 0, 7).expect("read via surviving link");
        assert_eq!(&data, b"PERSIST");
    }

    #[test]
    fn btrfs_unlink_dir_and_rmdir_file_reject_by_type() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(1);
        fs.mkdir(&cx, root, OsStr::new("d"), 0o755, 0, 0)
            .expect("mkdir");
        fs.create(&cx, root, OsStr::new("f.txt"), 0o644, 0, 0)
            .expect("create");

        // Removing a directory through the file-removal path must fail (EISDIR).
        let e1 = fs.unlink(&cx, root, OsStr::new("d")).unwrap_err();
        assert_eq!(e1.to_errno(), libc::EISDIR);
        // rmdir on a regular file must fail with ENOTDIR.
        let e2 = fs.rmdir(&cx, root, OsStr::new("f.txt")).unwrap_err();
        assert_eq!(e2.to_errno(), libc::ENOTDIR);

        // Both entries remain intact after the rejected operations.
        assert!(fs.lookup(&cx, root, OsStr::new("d")).is_ok());
        assert!(fs.lookup(&cx, root, OsStr::new("f.txt")).is_ok());
    }

    #[test]
    fn btrfs_rmdir_non_empty_returns_enotempty() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(1);
        let dir = fs
            .mkdir(&cx, root, OsStr::new("nonempty_dir"), 0o755, 0, 0)
            .expect("mkdir");
        fs.create(&cx, dir.ino, OsStr::new("child.txt"), 0o644, 0, 0)
            .expect("create child");

        // rmdir of a non-empty directory must fail with ENOTEMPTY.
        let err = fs.rmdir(&cx, root, OsStr::new("nonempty_dir")).unwrap_err();
        assert_eq!(err.to_errno(), libc::ENOTEMPTY);

        // The directory and its child remain intact (not orphaned).
        assert!(fs.lookup(&cx, root, OsStr::new("nonempty_dir")).is_ok());
        assert!(fs.lookup(&cx, dir.ino, OsStr::new("child.txt")).is_ok());
    }

    #[test]
    fn btrfs_rename_type_mismatch_target_rejected() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(1);
        fs.mkdir(&cx, root, OsStr::new("dir"), 0o755, 0, 0)
            .expect("mkdir");
        fs.create(&cx, root, OsStr::new("file.txt"), 0o644, 0, 0)
            .expect("create file");

        // Renaming a file onto an existing directory must fail with EISDIR.
        let e1 = fs
            .rename(&cx, root, OsStr::new("file.txt"), root, OsStr::new("dir"))
            .unwrap_err();
        assert_eq!(e1.to_errno(), libc::EISDIR);

        // Renaming a directory onto an existing file must fail with ENOTDIR.
        let e2 = fs
            .rename(&cx, root, OsStr::new("dir"), root, OsStr::new("file.txt"))
            .unwrap_err();
        assert_eq!(e2.to_errno(), libc::ENOTDIR);

        // Both entries remain intact after the rejected renames.
        assert!(fs.lookup(&cx, root, OsStr::new("dir")).is_ok());
        assert!(fs.lookup(&cx, root, OsStr::new("file.txt")).is_ok());
    }

    #[test]
    fn btrfs_rename_overwrites_existing_target() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let a = fs
            .create(&cx, parent, OsStr::new("src.bin"), 0o644, 0, 0)
            .expect("create src");
        fs.write(&cx, a.ino, 0, b"SOURCE").expect("write src");
        let b = fs
            .create(&cx, parent, OsStr::new("dst.bin"), 0o644, 0, 0)
            .expect("create dst");
        fs.write(&cx, b.ino, 0, b"TARGET").expect("write dst");
        assert_ne!(a.ino, b.ino);

        // Rename src onto the existing dst (POSIX overwrite).
        fs.rename(
            &cx,
            parent,
            OsStr::new("src.bin"),
            parent,
            OsStr::new("dst.bin"),
        )
        .expect("rename overwrite");

        // src is gone; dst now resolves to the source inode with the source data.
        assert!(fs.lookup(&cx, parent, OsStr::new("src.bin")).is_err());
        let dst = fs
            .lookup(&cx, parent, OsStr::new("dst.bin"))
            .expect("lookup dst");
        assert_eq!(dst.ino, a.ino, "dst must now point to the source inode");
        let data = fs.read(&cx, dst.ino, 0, 6).expect("read dst");
        assert_eq!(&data, b"SOURCE");
    }

    #[test]
    fn btrfs_link_directory_and_existing_name_rejected() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(1);
        let dir = fs
            .mkdir(&cx, root, OsStr::new("dir"), 0o755, 0, 0)
            .expect("mkdir");
        let file = fs
            .create(&cx, root, OsStr::new("file.txt"), 0o644, 0, 0)
            .expect("create");

        // Hard-linking a directory is forbidden (it would allow cycles) -> EPERM.
        let e1 = fs
            .link(&cx, dir.ino, root, OsStr::new("dirlink"))
            .unwrap_err();
        assert_eq!(e1.to_errno(), libc::EPERM);
        assert!(fs.lookup(&cx, root, OsStr::new("dirlink")).is_err());

        // Linking onto an already-existing name -> EEXIST.
        let e2 = fs.link(&cx, file.ino, root, OsStr::new("dir")).unwrap_err();
        assert_eq!(e2.to_errno(), libc::EEXIST);
    }

    #[test]
    fn btrfs_hardlink_shares_inode_data() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let attr = fs
            .create(&cx, parent, OsStr::new("orig.bin"), 0o644, 0, 0)
            .expect("create");
        fs.write(&cx, attr.ino, 0, b"shared_data").expect("write");

        // A hardlink is a second name for the same inode.
        fs.link(&cx, attr.ino, parent, OsStr::new("link.bin"))
            .expect("link");

        // A write through the original is visible through the hardlinked name.
        fs.write(&cx, attr.ino, 0, b"UPDATED_DAT").expect("update");
        let linked = fs
            .lookup(&cx, parent, OsStr::new("link.bin"))
            .expect("lookup link");
        assert_eq!(
            linked.ino, attr.ino,
            "hardlink must resolve to the same inode"
        );
        let data = fs.read(&cx, linked.ino, 0, 11).expect("read via link");
        assert_eq!(&data, b"UPDATED_DAT");
    }

    #[test]
    fn btrfs_truncate_then_sparse_extend_zero_fills_gap() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let attr = fs
            .create(&cx, parent, OsStr::new("trunc_extend.bin"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        fs.write(&cx, ino, 0, b"hello world!")
            .expect("initial write");

        // Truncate to 5 bytes ("hello"), dropping " world!".
        let trunc = SetAttrRequest {
            mode: None,
            uid: None,
            gid: None,
            size: Some(5),
            atime: None,
            mtime: None,
        };
        fs.setattr(&cx, ino, &trunc).expect("truncate to five");

        // Re-extend by writing past a gap; the gap [5,10) must read zeros, not the
        // old truncated bytes " worl".
        fs.write(&cx, ino, 10, b"Z").expect("sparse extend write");

        let data = fs.read(&cx, ino, 0, 11).expect("read after sparse extend");
        assert_eq!(&data[..5], b"hello");
        assert!(
            data[5..10].iter().all(|&b| b == 0),
            "gap after truncate must be zero-filled, not stale data: {:?}",
            &data[5..10]
        );
        assert_eq!(data[10], b'Z');
    }

    #[test]
    fn btrfs_setattr_extend_sparse_reads_zeros() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let attr = fs
            .create(&cx, parent, OsStr::new("extend.bin"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        fs.write(&cx, ino, 0, b"HEAD").expect("write head");

        // Extend to 8192 via a size-only setattr (a sparse region beyond "HEAD").
        let req = SetAttrRequest {
            mode: None,
            uid: None,
            gid: None,
            size: Some(8192),
            atime: None,
            mtime: None,
        };
        fs.setattr(&cx, ino, &req).expect("extend");
        assert_eq!(fs.getattr(&cx, ino).expect("getattr").size, 8192);

        // Original data intact; the sparse extension reads as zeros (no stale data).
        let head = fs.read(&cx, ino, 0, 4).expect("read head");
        assert_eq!(&head, b"HEAD");
        let tail = fs.read(&cx, ino, 4, 100).expect("read tail");
        assert_eq!(tail.len(), 100);
        assert!(
            tail.iter().all(|&b| b == 0),
            "btrfs sparse extension must be zero-filled"
        );
    }

    #[test]
    fn btrfs_write_sparse_hole_reads_as_zeros() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let attr = fs
            .create(&cx, parent, OsStr::new("sparse.bin"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        // Write past a hole: data at offset 8192, leaving [0, 8192) unwritten.
        fs.write(&cx, ino, 8192, b"DATA").expect("write past hole");

        // The hole reads back as the full requested span of zeros.
        let hole = fs.read(&cx, ino, 0, 8192).expect("read hole");
        assert_eq!(
            hole.len(),
            8192,
            "hole read returns the full requested span"
        );
        assert!(
            hole.iter().all(|&b| b == 0),
            "btrfs hole must be zero-filled"
        );
        // The written data reads back intact.
        let tail = fs.read(&cx, ino, 8192, 4).expect("read data");
        assert_eq!(&tail[..], b"DATA");
    }

    #[test]
    fn btrfs_inode_to_attr_preserves_special_perm_bits_and_rounds_blocks() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let created = fs
            .create(&cx, parent, OsStr::new("f.bin"), 0o644, 0, 0)
            .unwrap();

        // Read the inode, set a setuid mode and a non-512-aligned nbytes.
        let inode = {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let alloc = alloc_mutex.read();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, created.ino.0)
                .expect("read inode");
            inode.mode = 0o104_755; // S_IFREG | setuid 0o4755
            inode.nbytes = 513; // not a multiple of 512
            inode
        };

        let attr = fs.btrfs_inode_to_attr(created.ino.0, &inode);
        // setuid/setgid/sticky bits survive into attr.perm.
        assert_eq!(attr.perm, 0o4755);
        // nbytes 513 rounds up to ceil(513/512) = 2 512-byte blocks.
        assert_eq!(attr.blocks, 2);
    }

    #[test]
    fn btrfs_inode_to_attr_maps_each_timestamp_field_distinctly() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let created = fs
            .create(&cx, parent, OsStr::new("t.bin"), 0o644, 0, 0)
            .unwrap();
        let inode = {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let alloc = alloc_mutex.read();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, created.ino.0)
                .expect("read inode");
            // Distinct per-field seconds so a swap (incl. otime->crtime) fails.
            inode.atime_sec = 1_000;
            inode.atime_nsec = 0;
            inode.mtime_sec = 2_000;
            inode.mtime_nsec = 0;
            inode.ctime_sec = 3_000;
            inode.ctime_nsec = 0;
            inode.otime_sec = 4_000;
            inode.otime_nsec = 0;
            inode
        };
        let attr = fs.btrfs_inode_to_attr(created.ino.0, &inode);
        let secs =
            |t: std::time::SystemTime| t.duration_since(std::time::UNIX_EPOCH).unwrap().as_secs();
        assert_eq!(secs(attr.atime), 1_000, "atime <- atime_sec");
        assert_eq!(secs(attr.mtime), 2_000, "mtime <- mtime_sec");
        assert_eq!(secs(attr.ctime), 3_000, "ctime <- ctime_sec");
        assert_eq!(secs(attr.crtime), 4_000, "crtime <- otime_sec");
    }

    #[test]
    fn btrfs_inode_to_attr_saturates_out_of_range_timestamp_without_panic() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);
        let created = fs
            .create(&cx, parent, OsStr::new("t.bin"), 0o644, 0, 0)
            .unwrap();
        let inode = {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let alloc = alloc_mutex.read();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, created.ino.0)
                .expect("read inode");
            // Out-of-range timestamp the parser accepts but that would overflow
            // UNIX_EPOCH + Duration::new and panic before the fix (bd-xmh5g.281).
            inode.atime_sec = u64::MAX;
            inode.atime_nsec = 999_999_999;
            inode
        };
        // Must not panic; the out-of-range atime saturates to UNIX_EPOCH.
        let attr = fs.btrfs_inode_to_attr(created.ino.0, &inode);
        assert_eq!(attr.atime, std::time::UNIX_EPOCH);
    }

    #[test]
    fn btrfs_inode_timestamp_converts_valid_and_saturates_overflow() {
        use std::time::{Duration, UNIX_EPOCH};
        // A valid timestamp converts exactly.
        assert_eq!(
            OpenFs::btrfs_inode_timestamp(1_700_000_000, 123),
            UNIX_EPOCH + Duration::new(1_700_000_000, 123)
        );
        // nsec >= 1e9 is clamped so Duration::new's second carry cannot overflow.
        assert_eq!(
            OpenFs::btrfs_inode_timestamp(0, u32::MAX),
            UNIX_EPOCH + Duration::new(0, 999_999_999)
        );
        // Out-of-range seconds saturate to UNIX_EPOCH instead of panicking.
        assert_eq!(OpenFs::btrfs_inode_timestamp(u64::MAX, 0), UNIX_EPOCH);
        assert_eq!(
            OpenFs::btrfs_inode_timestamp(u64::MAX, u32::MAX),
            UNIX_EPOCH
        );
    }

    #[test]
    fn btrfs_immutable_and_append_enforced_on_content_ops_bd_xpsq4() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);

        let set_flag = |ino_raw: u64, flag: u64| {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, ino_raw)
                .expect("read inode");
            inode.flags |= flag;
            let key = BtrfsKey {
                objectid: ino_raw,
                item_type: BTRFS_ITEM_INODE_ITEM,
                offset: 0,
            };
            alloc
                .fs_tree
                .update(&key, &inode.to_bytes())
                .expect("pin flag");
        };

        // ── Immutable: every content mutation is rejected (EPERM). ──
        let imm = fs
            .create(&cx, parent, OsStr::new("imm.bin"), 0o644, 0, 0)
            .unwrap()
            .ino;
        fs.write(&cx, imm, 0, b"hello")
            .expect("seed write before immutable");
        set_flag(imm.0, BTRFS_INODE_IMMUTABLE);
        assert_eq!(
            fs.write(&cx, imm, 0, b"nope").unwrap_err().to_errno(),
            libc::EPERM,
            "write to an immutable file must be EPERM"
        );
        assert_eq!(
            fs.setattr(
                &cx,
                imm,
                &SetAttrRequest {
                    size: Some(0),
                    ..SetAttrRequest::default()
                },
            )
            .unwrap_err()
            .to_errno(),
            libc::EPERM,
            "truncating an immutable file must be EPERM"
        );
        assert_eq!(
            fs.fallocate(&cx, imm, 0, 4096, 0).unwrap_err().to_errno(),
            libc::EPERM,
            "fallocate on an immutable file must be EPERM"
        );

        // ── Append-only: EOF append allowed; non-append write + shrink rejected. ──
        let app = fs
            .create(&cx, parent, OsStr::new("app.bin"), 0o644, 0, 0)
            .unwrap()
            .ino;
        fs.write(&cx, app, 0, b"0123456789").expect("seed write");
        let size = fs.getattr(&cx, app).unwrap().size;
        set_flag(app.0, BTRFS_INODE_APPEND);
        assert_eq!(
            fs.write(&cx, app, 0, b"x").unwrap_err().to_errno(),
            libc::EPERM,
            "a non-append (offset < EOF) write to an append-only file must be EPERM"
        );
        fs.write(&cx, app, size, b"appended")
            .expect("appending at EOF on an append-only file must succeed");
        assert_eq!(
            fs.setattr(
                &cx,
                app,
                &SetAttrRequest {
                    size: Some(1),
                    ..SetAttrRequest::default()
                },
            )
            .unwrap_err()
            .to_errno(),
            libc::EPERM,
            "shrinking an append-only file must be EPERM"
        );
    }

    #[test]
    fn btrfs_delete_of_immutable_or_append_is_eperm_bd_rmgwc() {
        let (fs, cx) = open_writable_btrfs();
        let parent = InodeNumber(1);

        let set_flag = |ino_raw: u64, flag: u64| {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let mut inode = fs
                .btrfs_read_inode_from_tree(&alloc, ino_raw)
                .expect("read inode");
            inode.flags |= flag;
            let key = BtrfsKey {
                objectid: ino_raw,
                item_type: BTRFS_ITEM_INODE_ITEM,
                offset: 0,
            };
            alloc
                .fs_tree
                .update(&key, &inode.to_bytes())
                .expect("pin flag");
        };

        // may_delete forbids removing an immutable or append-only file (EPERM).
        for (name, flag) in [
            ("imm.bin", BTRFS_INODE_IMMUTABLE),
            ("app.bin", BTRFS_INODE_APPEND),
        ] {
            let f = fs
                .create(&cx, parent, OsStr::new(name), 0o644, 0, 0)
                .unwrap()
                .ino;
            set_flag(f.0, flag);
            assert_eq!(
                fs.unlink(&cx, parent, OsStr::new(name))
                    .unwrap_err()
                    .to_errno(),
                libc::EPERM,
                "deleting {name} must be EPERM"
            );
            assert!(
                fs.lookup(&cx, parent, OsStr::new(name)).is_ok(),
                "{name} must survive a rejected delete"
            );
        }
    }

    #[test]
    fn btrfs_remove_inode_ref_missing_name_reports_corruption() {
        let (fs, _cx) = open_writable_btrfs();
        let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
        let mut alloc = alloc_mutex.write();
        let ref_key = BtrfsKey {
            objectid: 9001,
            item_type: BTRFS_ITEM_INODE_REF,
            offset: 256,
        };
        let payload =
            OpenFs::btrfs_serialize_inode_ref_payload(&[(42, b"present.txt".to_vec())]).unwrap();
        alloc.fs_tree.insert(ref_key, &payload).unwrap();

        let err = OpenFs::btrfs_remove_inode_ref(&mut alloc, 9001, 256, b"missing.txt")
            .expect_err("missing backref name should be treated as corruption");
        drop(alloc);

        assert!(matches!(err, FfsError::Corruption { .. }));
    }

    /// Reference O(N) implementation of btrfs_lookup_dir_entry: scan EVERY
    /// DIR_ITEM in the directory (the pre-bd-a9wot behavior). Used only to prove
    /// the hash-keyed point lookup is isomorphic to a full scan.
    #[cfg(test)]
    fn btrfs_lookup_dir_entry_full_scan_reference(
        alloc: &BtrfsAllocState,
        parent_oid: u64,
        name: &[u8],
    ) -> Option<BtrfsDirItem> {
        let start = BtrfsKey {
            objectid: parent_oid,
            item_type: BTRFS_ITEM_DIR_ITEM,
            offset: 0,
        };
        let end = BtrfsKey {
            objectid: parent_oid,
            item_type: BTRFS_ITEM_DIR_ITEM,
            offset: u64::MAX,
        };
        for (_, data) in alloc.fs_tree.range(&start, &end).ok()? {
            let entries = parse_dir_items(&data).ok()?;
            if let Some(e) = entries.into_iter().find(|e| e.name == name) {
                return Some(e);
            }
        }
        None
    }

    /// Isomorphism guard for bd-a9wot: the hash-keyed btrfs_lookup_dir_entry must
    /// return exactly what an O(N) full DIR_ITEM scan returns — for every present
    /// name and for absent names — across a large directory.
    #[test]
    fn btrfs_lookup_dir_entry_hash_keyed_matches_full_scan_bd_a9wot() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(u64::from(BTRFS_FIRST_FREE_OBJECTID));
        let mut names = Vec::new();
        for i in 0..200u32 {
            let name = format!("entry_{i:04}.dat");
            fs.create(&cx, root, OsStr::new(&name), 0o644, 0, 0)
                .expect("create entry");
            names.push(name);
        }

        let parent = fs.btrfs_canonical_inode(root).expect("canonical");
        let alloc_mutex = fs.btrfs_alloc_state.as_ref().expect("writable");
        let alloc = alloc_mutex.read();
        for name in &names {
            let via_hash = fs
                .btrfs_lookup_dir_entry(&alloc, parent, name.as_bytes())
                .expect("present name must be found");
            let via_scan =
                btrfs_lookup_dir_entry_full_scan_reference(&alloc, parent, name.as_bytes())
                    .expect("full scan must find it too");
            assert_eq!(
                via_hash.child_objectid, via_scan.child_objectid,
                "hash lookup must return the same entry as a full scan for {name}"
            );
            assert_eq!(via_hash.name, via_scan.name);
        }
        for absent in ["zzz_absent.dat", "nope", "entry_9999.dat"] {
            assert!(
                fs.btrfs_lookup_dir_entry(&alloc, parent, absent.as_bytes())
                    .is_err(),
                "absent name {absent} must be NotFound under the hash-keyed lookup"
            );
            assert!(
                btrfs_lookup_dir_entry_full_scan_reference(&alloc, parent, absent.as_bytes())
                    .is_none(),
                "absent name {absent} must also be missing under a full scan"
            );
        }
    }

    /// Diagnostic A/B for bd-a9wot: time the hash-keyed point lookup vs the O(N)
    /// full-scan reference over a large directory. Prints the Score (full / hash)
    /// so the complexity-class win is measurable. Run with --ignored --nocapture.
    #[test]
    #[ignore = "perf A/B: btrfs dir lookup hash-keyed vs O(N) full scan (bd-a9wot)"]
    fn btrfs_lookup_dir_entry_hash_vs_full_scan_ab_bd_a9wot() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(u64::from(BTRFS_FIRST_FREE_OBJECTID));
        let n = 2000u32;
        let mut names = Vec::new();
        for i in 0..n {
            let name = format!("f_{i:05}.dat");
            fs.create(&cx, root, OsStr::new(&name), 0o644, 0, 0)
                .expect("create");
            names.push(name);
        }
        let parent = fs.btrfs_canonical_inode(root).unwrap();
        let alloc = fs.btrfs_alloc_state.as_ref().unwrap().read();

        let iters = 5usize;
        let t_hash = std::time::Instant::now();
        let mut acc = 0u64;
        for _ in 0..iters {
            for name in &names {
                acc = acc.wrapping_add(
                    fs.btrfs_lookup_dir_entry(&alloc, parent, name.as_bytes())
                        .unwrap()
                        .child_objectid,
                );
            }
        }
        let hash_ns = t_hash.elapsed().as_nanos();

        let t_scan = std::time::Instant::now();
        for _ in 0..iters {
            for name in &names {
                acc = acc.wrapping_add(
                    btrfs_lookup_dir_entry_full_scan_reference(&alloc, parent, name.as_bytes())
                        .unwrap()
                        .child_objectid,
                );
            }
        }
        let scan_ns = t_scan.elapsed().as_nanos();
        eprintln!(
            "BD_A9WOT N={n} iters={iters} hash_ns={hash_ns} scan_ns={scan_ns} score={:.2} (acc={acc})",
            scan_ns as f64 / hash_ns.max(1) as f64
        );
    }

    /// Read-only full-scan reference for bd-k115m: the prior
    /// O(directory size) btrfs_lookup_child — walk every item of the parent and
    /// scan DIR_ITEM then DIR_INDEX for the name.
    fn btrfs_lookup_child_full_scan_reference(
        fs: &OpenFs,
        cx: &Cx,
        canonical_parent: u64,
        name: &[u8],
    ) -> Option<u64> {
        let items = fs.walk_btrfs_fs_tree_object(cx, canonical_parent).ok()?;
        for preferred in [BTRFS_ITEM_DIR_ITEM, BTRFS_ITEM_DIR_INDEX] {
            for item in &items {
                if item.key.objectid != canonical_parent || item.key.item_type != preferred {
                    continue;
                }
                let dir_items = parse_dir_items(&item.data).ok()?;
                for di in dir_items {
                    if di.name == name {
                        return Some(di.child_objectid);
                    }
                }
            }
        }
        None
    }

    /// mkfs a real btrfs image, create `n` files writable, persist, and reopen
    /// READ-ONLY so `btrfs_lookup_child` takes the keyed on-disk path. Returns
    /// `None` when btrfs-progs is unavailable (test skips).
    fn btrfs_readonly_lookup_fixture(n: u32) -> Option<(OpenFs, Cx, InodeNumber, Vec<String>)> {
        let (fs, dev, _tmp, _img) = open_writable_btrfs_mkfs(64)?;
        let cx = Cx::for_testing();
        let root = InodeNumber(u64::from(BTRFS_FIRST_FREE_OBJECTID));
        let mut names = Vec::new();
        for i in 0..n {
            let name = format!("rofile_{i:05}.dat");
            fs.create(&cx, root, OsStr::new(&name), 0o644, 0, 0)
                .expect("create");
            names.push(name);
        }
        fs.flush_mvcc_to_device(&cx)
            .expect("flush writes to device");
        let bytes = dev.snapshot_bytes();
        let ro = OpenFs::from_device(
            &cx,
            Box::new(TestDevice::from_vec(bytes)),
            &OpenOptions::default(),
        )
        .expect("reopen read-only");
        assert!(!ro.is_writable());
        Some((ro, cx, root, names))
    }

    /// Isomorphism guard for bd-k115m: the read-only keyed DIR_ITEM lookup must
    /// resolve every present name to the same child as a full DIR_ITEM/DIR_INDEX
    /// scan, and report absent names as NotFound.
    #[test]
    fn btrfs_readonly_lookup_keyed_matches_full_scan_bd_k115m() {
        let Some((ro, cx, root, names)) = btrfs_readonly_lookup_fixture(150) else {
            return;
        };
        let canonical = ro.btrfs_canonical_inode(root).expect("canonical");
        for name in &names {
            let via_keyed = <OpenFs as FsOps>::lookup(
                &ro,
                &cx,
                &mut RequestScope::empty(),
                root,
                OsStr::new(name),
            )
            .expect("present name must be found by the keyed lookup");
            let via_scan =
                btrfs_lookup_child_full_scan_reference(&ro, &cx, canonical, name.as_bytes())
                    .expect("full scan must find it too");
            assert_eq!(
                via_keyed.ino,
                InodeNumber(via_scan),
                "keyed lookup must return the same child as a full scan for {name}"
            );
        }
        for absent in ["absent.dat", "nope", "rofile_99999.dat"] {
            assert!(
                <OpenFs as FsOps>::lookup(
                    &ro,
                    &cx,
                    &mut RequestScope::empty(),
                    root,
                    OsStr::new(absent)
                )
                .is_err(),
                "absent name {absent} must be NotFound under the keyed lookup"
            );
            assert!(
                btrfs_lookup_child_full_scan_reference(&ro, &cx, canonical, absent.as_bytes())
                    .is_none()
            );
        }
    }

    /// Diagnostic A/B for bd-k115m: time the read-only keyed point lookup vs the
    /// O(directory) full-scan reference. Run with --ignored --nocapture.
    #[test]
    #[ignore = "perf A/B: read-only btrfs lookup keyed vs O(N) full scan (bd-k115m)"]
    fn btrfs_readonly_lookup_keyed_vs_full_scan_ab_bd_k115m() {
        let n = 1000u32;
        let Some((ro, cx, root, names)) = btrfs_readonly_lookup_fixture(n) else {
            return;
        };
        let canonical = ro.btrfs_canonical_inode(root).unwrap();
        let iters = 3usize;
        let mut acc = 0u64;
        let t_keyed = std::time::Instant::now();
        for _ in 0..iters {
            for name in &names {
                acc = acc.wrapping_add(
                    <OpenFs as FsOps>::lookup(
                        &ro,
                        &cx,
                        &mut RequestScope::empty(),
                        root,
                        OsStr::new(name),
                    )
                    .unwrap()
                    .ino
                    .0,
                );
            }
        }
        let keyed_ns = t_keyed.elapsed().as_nanos();
        let t_scan = std::time::Instant::now();
        for _ in 0..iters {
            for name in &names {
                acc = acc.wrapping_add(
                    btrfs_lookup_child_full_scan_reference(&ro, &cx, canonical, name.as_bytes())
                        .unwrap(),
                );
            }
        }
        let scan_ns = t_scan.elapsed().as_nanos();
        eprintln!(
            "BD_K115M N={n} iters={iters} keyed_ns={keyed_ns} scan_ns={scan_ns} score={:.2} (acc={acc})",
            scan_ns as f64 / keyed_ns.max(1) as f64
        );
    }

    #[test]
    fn btrfs_remove_dir_entry_missing_name_reports_corruption() {
        let (fs, _cx) = open_writable_btrfs();
        let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
        let mut alloc = alloc_mutex.write();
        let parent_oid = 256;
        let dir_item = BtrfsDirItem {
            child_objectid: 9001,
            child_key_type: BTRFS_ITEM_INODE_ITEM,
            child_key_offset: 0,
            file_type: BTRFS_FT_REG_FILE,
            name: b"present.txt".to_vec(),
        };
        let dir_index = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &dir_item)
            .unwrap();

        let err = fs
            .btrfs_remove_dir_entry(&mut alloc, parent_oid, b"missing.txt", dir_index)
            .expect_err("missing dir entry should be treated as corruption");
        drop(alloc);

        assert!(matches!(err, FfsError::Corruption { .. }));
    }

    #[test]
    fn btrfs_dir_index_uses_monotonic_sequence_not_child_objectid() {
        // bd-yqoni: DIR_INDEX must be keyed by a monotonic per-directory
        // sequence number (the kernel's index_cnt), not the child objectid.
        // This gives readdir creation-order iteration and a unique item per
        // link — including multiple hard links of one inode in one directory.
        let (fs, _cx) = open_writable_btrfs();
        let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
        let mut alloc = alloc_mutex.write();
        let parent_oid = 256;
        let mk = |child: u64, name: &str| BtrfsDirItem {
            child_objectid: child,
            child_key_type: BTRFS_ITEM_INODE_ITEM,
            child_key_offset: 0,
            file_type: BTRFS_FT_REG_FILE,
            name: name.as_bytes().to_vec(),
        };

        let base = OpenFs::btrfs_next_dir_index_seq(&alloc, parent_oid).unwrap();
        assert!(base >= BTRFS_DIR_START_INDEX);

        let seq_a = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &mk(9001, "a.txt"))
            .unwrap();
        let seq_b = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &mk(9002, "b.txt"))
            .unwrap();
        // Hard link: SAME child_objectid as a.txt, distinct name. Under the old
        // child-objectid keying this collided onto a.txt's DIR_INDEX item.
        let seq_link = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &mk(9001, "a-hardlink"))
            .unwrap();

        assert_eq!(seq_a, base);
        assert_eq!(seq_b, base + 1);
        assert_eq!(seq_link, base + 2);

        let start = BtrfsKey {
            objectid: parent_oid,
            item_type: BTRFS_ITEM_DIR_INDEX,
            offset: 0,
        };
        let end = BtrfsKey {
            objectid: parent_oid,
            item_type: BTRFS_ITEM_DIR_INDEX,
            offset: u64::MAX,
        };
        let indices = alloc.fs_tree.range(&start, &end).unwrap();
        let new_offsets: Vec<u64> = indices
            .iter()
            .map(|(k, _)| k.offset)
            .filter(|off| *off >= base)
            .collect();
        // Three distinct items — the hard link did NOT merge onto a.txt.
        assert_eq!(new_offsets, vec![base, base + 1, base + 2]);
        // The offset is the sequence, never the child objectid.
        assert!(!new_offsets.contains(&9001));
        assert!(!new_offsets.contains(&9002));
        // Each DIR_INDEX item carries exactly one entry (no merged payloads).
        for (key, data) in &indices {
            if key.offset < base {
                continue;
            }
            assert_eq!(parse_dir_items(data).unwrap().len(), 1);
        }
        drop(alloc);
    }

    /// bd-rfi5j: the DIR_INDEX sequence must be monotonic within a mount —
    /// deleting the highest-indexed entry must NOT free its index for reuse (the
    /// kernel's in-memory index_cnt never goes backward). The pre-fix max+1
    /// derivation reused a deleted tail index.
    #[test]
    fn btrfs_dir_index_does_not_reuse_deleted_tail_bd_rfi5j() {
        let (fs, _cx) = open_writable_btrfs();
        let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
        let mut alloc = alloc_mutex.write();
        let parent_oid = 256;
        let mk = |child: u64, name: &str| BtrfsDirItem {
            child_objectid: child,
            child_key_type: BTRFS_ITEM_INODE_ITEM,
            child_key_offset: 0,
            file_type: BTRFS_FT_REG_FILE,
            name: name.as_bytes().to_vec(),
        };

        let a = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &mk(9001, "a"))
            .unwrap();
        let b = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &mk(9002, "b"))
            .unwrap();
        let c = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &mk(9003, "c"))
            .unwrap();
        assert_eq!(b, a + 1);
        assert_eq!(c, b + 1);

        // Delete the highest-indexed entry's DIR_INDEX item (the on-disk max now
        // drops back to `b`).
        alloc
            .fs_tree
            .delete(&BtrfsKey {
                objectid: parent_oid,
                item_type: BTRFS_ITEM_DIR_INDEX,
                offset: c,
            })
            .unwrap();

        // The next entry must get c + 1, NOT reuse c (which max+1 would now yield).
        let d = fs
            .btrfs_insert_dir_entry(&mut alloc, parent_oid, &mk(9004, "d"))
            .unwrap();
        assert_eq!(
            d,
            c + 1,
            "a deleted tail DIR_INDEX must not be reused within a mount session"
        );
        drop(alloc);
    }

    #[test]
    fn btrfs_hard_link_inode_ref_index_matches_dir_index_offset() {
        // bd-yqoni: each link's INODE_REF.index must equal its DIR_INDEX.offset
        // (the kernel assigns one sequence number per link at link time).
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let target = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("seq-a.txt"),
                0o644,
                0,
                0,
            )
            .expect("create file");
        ops.link(
            &cx,
            &mut RequestScope::empty(),
            target.ino,
            InodeNumber(1),
            OsStr::new("seq-a-link"),
        )
        .expect("hard link");

        let root_oid = fs.btrfs_superblock().unwrap().root_dir_objectid;
        let alloc = fs.btrfs_alloc_state.as_ref().unwrap().read();

        // Collect (offset -> name) for the two DIR_INDEX entries of `target`.
        let dir_start = BtrfsKey {
            objectid: root_oid,
            item_type: BTRFS_ITEM_DIR_INDEX,
            offset: 0,
        };
        let dir_end = BtrfsKey {
            objectid: root_oid,
            item_type: BTRFS_ITEM_DIR_INDEX,
            offset: u64::MAX,
        };
        let mut dir_index_by_name: BTreeMap<Vec<u8>, u64> = BTreeMap::new();
        for (key, data) in alloc.fs_tree.range(&dir_start, &dir_end).unwrap() {
            for entry in parse_dir_items(&data).unwrap() {
                if entry.child_objectid == target.ino.0 {
                    dir_index_by_name.insert(entry.name, key.offset);
                }
            }
        }
        assert_eq!(dir_index_by_name.len(), 2, "two distinct DIR_INDEX items");

        // The child's INODE_REF carries one (index, name) per link; each index
        // must equal the DIR_INDEX offset of the same-named entry.
        let ref_key = BtrfsKey {
            objectid: target.ino.0,
            item_type: BTRFS_ITEM_INODE_REF,
            offset: root_oid,
        };
        let payload = alloc
            .fs_tree
            .range(&ref_key, &ref_key)
            .unwrap()
            .first()
            .map(|(_, v)| v.clone())
            .expect("inode_ref present");
        let refs = OpenFs::btrfs_parse_inode_ref_payload(&payload).unwrap();
        assert_eq!(refs.len(), 2);
        for (index, name) in refs {
            assert_eq!(
                Some(&index),
                dir_index_by_name.get(&name),
                "INODE_REF.index must match DIR_INDEX.offset for {}",
                String::from_utf8_lossy(&name)
            );
        }
        drop(alloc);
    }

    #[test]
    fn btrfs_write_hard_link_preserves_symlink_type() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let sym_attr = ops
            .symlink(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original-link"),
                Path::new("/tmp/target"),
                0,
                0,
            )
            .expect("create symlink");
        assert_eq!(sym_attr.kind, FileType::Symlink);

        let linked = ops
            .link(
                &cx,
                &mut RequestScope::empty(),
                sym_attr.ino,
                InodeNumber(1),
                OsStr::new("linked-symlink"),
            )
            .expect("hard-link symlink");
        assert_eq!(linked.kind, FileType::Symlink);

        let looked_up = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("linked-symlink"),
            )
            .expect("lookup linked symlink");
        assert_eq!(looked_up.kind, FileType::Symlink);
        assert_eq!(looked_up.ino, sym_attr.ino);
    }

    #[test]
    fn btrfs_write_hard_link_existing_name_returns_exists() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let target = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("target.txt"),
                0o644,
                0,
                0,
            )
            .expect("create target");
        let occupied = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("occupied.txt"),
                0o644,
                0,
                0,
            )
            .expect("create occupied");

        let err = ops
            .link(
                &cx,
                &mut RequestScope::empty(),
                target.ino,
                InodeNumber(1),
                OsStr::new("occupied.txt"),
            )
            .expect_err("hard link should reject an existing destination name");
        assert!(matches!(err, FfsError::Exists));

        let target_after = ops
            .getattr(&cx, &mut RequestScope::empty(), target.ino)
            .expect("target inode survives");
        assert_eq!(target_after.nlink, 1);

        let occupied_lookup = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("occupied.txt"),
            )
            .expect("occupied entry remains intact");
        assert_eq!(occupied_lookup.ino, occupied.ino);
    }

    #[test]
    fn btrfs_write_rename_overwrite_decrements_nlink() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        // Create two files.
        let victim = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("victim.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            victim.ino,
            0,
            b"victim data",
        )
        .unwrap();

        let winner = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("winner.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            winner.ino,
            0,
            b"winner data",
        )
        .unwrap();

        // Rename winner → victim (overwrite).
        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("winner.txt"),
            InodeNumber(1),
            OsStr::new("victim.txt"),
        )
        .unwrap();

        // victim.txt should now be the winner's data.
        let result = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("victim.txt"),
            )
            .unwrap();
        assert_eq!(result.ino, winner.ino);
        let data = ops
            .read(&cx, &mut RequestScope::empty(), result.ino, 0, 4096)
            .unwrap();
        assert_eq!(data, b"winner data");

        // The old victim inode (nlink 0) should be purged.
        assert!(
            ops.getattr(&cx, &mut RequestScope::empty(), victim.ino)
                .is_err()
        );

        // winner.txt name should be gone.
        assert!(
            ops.lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("winner.txt")
            )
            .is_err()
        );
    }

