        let src = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("src-dir"),
                0o755,
                0,
                0,
            )
            .unwrap();
        let dst = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("dst-dir"),
                0o755,
                0,
                0,
            )
            .unwrap();
        ops.create(
            &cx,
            &mut RequestScope::empty(),
            dst.ino,
            OsStr::new("child.txt"),
            0o644,
            0,
            0,
        )
        .unwrap();

        let err = ops
            .rename(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("src-dir"),
                InodeNumber(1),
                OsStr::new("dst-dir"),
            )
            .unwrap_err();
