    /// POSIX: a size-changing truncate is a data modification and must update
    /// mtime (not just ctime). The kernel sends ATTR_SIZE/ATTR_CTIME (no
    /// ATTR_MTIME) on truncate, so the fs owns the mtime bump; btrfs_setattr
    /// updated only ctime, leaving mtime at the prior write time (bd-pssza).
    /// Deterministic: after the truncate, mtime and ctime are stamped from the
    /// same op timestamp, so they must be equal (before the fix mtime stayed at
    /// the distinct write time).
    #[test]
    fn btrfs_truncate_updates_mtime_bd_pssza() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("trunc.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(&cx, &mut RequestScope::empty(), file.ino, 0, b"0123456789")
            .unwrap();

        let attr = ops
            .setattr(
                &cx,
                &mut RequestScope::empty(),
                file.ino,
                &SetAttrRequest {
                    size: Some(4),
                    ..Default::default()
                },
            )
            .unwrap();
        assert_eq!(attr.size, 4);
        assert_eq!(
            attr.mtime, attr.ctime,
            "a size-changing truncate must update mtime, not leave it at the write time"
        );
    }

    /// btrfs fallocate(2) must bump mtime and ctime on success, matching ext4
    /// (ext4_fallocate touches both) and the kernel's file_modified semantics.
    /// Previously btrfs_fallocate updated only size/nbytes, leaving the
    /// timestamps frozen so mtime/ctime-based tooling missed the allocation.
    #[test]
    fn btrfs_fallocate_updates_mtime_and_ctime() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("falloc.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // Pin mtime to a known old value; setting it is a status change, so
        // ctime advances to "now" — leaving mtime != ctime before fallocate.
        let old = std::time::UNIX_EPOCH + std::time::Duration::from_secs(1_000_000_000);
        ops.setattr(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            &SetAttrRequest {
                mtime: Some(old),
                ..Default::default()
            },
        )
        .unwrap();
        let before = ops
            .getattr(&cx, &mut RequestScope::empty(), file.ino)
            .unwrap();
        assert_eq!(before.mtime, old, "setup: mtime should be the pinned value");

        // Default-mode (prealloc) allocation of one sector.
        ops.fallocate(&cx, &mut RequestScope::empty(), file.ino, 0, 4096, 0)
            .unwrap();

        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), file.ino)
            .unwrap();
        assert_ne!(
            after.mtime, old,
            "fallocate must bump mtime off the pinned value"
        );
        assert_eq!(
            after.mtime, after.ctime,
            "fallocate must stamp mtime and ctime to the same allocation time"
        );
    }

    /// btrfs SEEK_DATA/SEEK_HOLE must treat an explicit hole extent
    /// (disk_bytenr == 0, as kernel images without NO_HOLES carry) as a hole,
    /// matching btrfs_read_file. Previously the lseek paths counted every
    /// present EXTENT_DATA as data, so SEEK_DATA returned a hole offset and
    /// SEEK_HOLE skipped past the hole (bd-pb6bs).
    #[test]
    fn btrfs_lseek_data_hole_at_eof_returns_enxio() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("seek_eof.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            0,
            &[0xAB_u8; 4096],
        )
        .expect("write");

        // SEEK_DATA / SEEK_HOLE at or beyond EOF must return ENXIO (lseek(2)),
        // not EINVAL. file size is 4096, so offset 4096 is exactly EOF.
        let err = ops
            .lseek(
                &cx,
                &mut RequestScope::empty(),
                file.ino,
                4096,
                SeekWhence::Data,
            )
            .expect_err("SEEK_DATA at EOF must fail");
        assert_eq!(err.to_errno(), libc::ENXIO);
        let err = ops
            .lseek(
                &cx,
                &mut RequestScope::empty(),
                file.ino,
                8192,
                SeekWhence::Hole,
            )
            .expect_err("SEEK_HOLE beyond EOF must fail");
        assert_eq!(err.to_errno(), libc::ENXIO);
    }

    #[test]
    fn btrfs_lseek_treats_explicit_hole_extent_as_hole_bd_pb6bs() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let s: u64 = 4096; // fsops image sectorsize

        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("sparse.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        // Data extent A at [0, s) and data extent C at [2s, 3s); gap [s, 2s).
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            0,
            &vec![0xAB_u8; s as usize],
        )
        .unwrap();
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            2 * s,
            &vec![0xCD_u8; s as usize],
        )
        .unwrap();

        // Inject an EXPLICIT hole extent (disk_bytenr == 0) over [s, 2s).
        let canonical = fs.btrfs_canonical_inode(file.ino).unwrap();
        {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let hole = BtrfsExtentData::Regular {
                generation: alloc.generation,
                ram_bytes: s,
                extent_type: BTRFS_FILE_EXTENT_REG,
                compression: 0,
                disk_bytenr: 0,
                disk_num_bytes: 0,
                extent_offset: 0,
                num_bytes: s,
            };
            let key = BtrfsKey {
                objectid: canonical,
                item_type: BTRFS_ITEM_EXTENT_DATA,
                offset: s,
            };
            alloc.fs_tree.insert(key, &hole.to_bytes()).unwrap();
        }

        // SEEK_DATA from the start of the hole must skip to extent C at 2s.
        let data_pos = ops
            .lseek(
                &cx,
                &mut RequestScope::empty(),
                file.ino,
                s,
                SeekWhence::Data,
            )
            .unwrap();
        assert_eq!(
            data_pos,
            2 * s,
            "SEEK_DATA must skip an explicit hole extent to the next real data"
        );

        // SEEK_HOLE from 0 must land at the start of the hole (s), not skip it.
        let hole_pos = ops
            .lseek(
                &cx,
                &mut RequestScope::empty(),
                file.ino,
                0,
                SeekWhence::Hole,
            )
            .unwrap();
        assert_eq!(
            hole_pos, s,
            "SEEK_HOLE must report the explicit hole extent at offset s"
        );
    }

    /// btrfs fiemap must report an explicit hole extent (disk_bytenr == 0, as
    /// kernel images without NO_HOLES carry) as a GAP, not as a physical-0
    /// extent — otherwise filefrag / cp --sparse see the hole as data. Mirrors
    /// the SEEK_DATA/SEEK_HOLE fix; both consume the same EXTENT_DATA items
    /// (bd-cfjvh).
    #[test]
    fn btrfs_fiemap_skips_explicit_hole_extent_bd_cfjvh() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let s: u64 = 4096; // fsops image sectorsize

        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("fiemap-sparse.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        // Real data extents at [0, s) and [2s, 3s); implicit gap [s, 2s).
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            0,
            &vec![0xAB_u8; s as usize],
        )
        .unwrap();
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            2 * s,
            &vec![0xCD_u8; s as usize],
        )
        .unwrap();

        // Inject an EXPLICIT hole extent (disk_bytenr == 0) over [s, 2s).
        let canonical = fs.btrfs_canonical_inode(file.ino).unwrap();
        {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let hole = BtrfsExtentData::Regular {
                generation: alloc.generation,
                ram_bytes: s,
                extent_type: BTRFS_FILE_EXTENT_REG,
                compression: 0,
                disk_bytenr: 0,
                disk_num_bytes: 0,
                extent_offset: 0,
                num_bytes: s,
            };
            let key = BtrfsKey {
                objectid: canonical,
                item_type: BTRFS_ITEM_EXTENT_DATA,
                offset: s,
            };
            alloc.fs_tree.insert(key, &hole.to_bytes()).unwrap();
        }

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, file.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            extents.len(),
            2,
            "fiemap must report only the two real extents; the hole is a gap"
        );
        assert_eq!(extents[0].logical, 0);
        assert_eq!(
            extents[1].logical,
            2 * s,
            "no extent may be reported for the hole at offset s"
        );
        assert_ne!(
            extents[1].physical, 0,
            "the trailing real data extent must keep its physical address"
        );
        assert_ne!(
            extents[1].flags & FIEMAP_EXTENT_LAST,
            0,
            "FIEMAP_EXTENT_LAST must land on the last REAL extent, not a trailing hole"
        );
    }

    #[test]
    fn btrfs_write_rename_updates_dotdot() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let dir_a = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("a"),
                0o755,
                0,
                0,
            )
            .unwrap();
        let dir_b = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("b"),
                0o755,
                0,
                0,
            )
            .unwrap();
        let sub = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                dir_a.ino,
                OsStr::new("sub"),
                0o755,
                0,
                0,
            )
            .unwrap();

        // Before rename: sub's ".." should be dir_a.
        let entries = ops
            .readdir(&cx, &mut RequestScope::empty(), sub.ino, 0)
            .unwrap();
        let dotdot = entries.iter().find(|e| e.name == b"..").unwrap();
        assert_eq!(dotdot.ino, dir_a.ino);

        // Rename sub from a/ to b/.
        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            dir_a.ino,
            OsStr::new("sub"),
            dir_b.ino,
            OsStr::new("sub"),
        )
        .unwrap();

        // After rename: sub's ".." should now be dir_b.
        let entries = ops
            .readdir(&cx, &mut RequestScope::empty(), sub.ino, 0)
            .unwrap();
        let dotdot = entries.iter().find(|e| e.name == b"..").unwrap();
        assert_eq!(dotdot.ino, dir_b.ino);
    }

    #[test]
    fn btrfs_write_rename_dir_cross_parent_nlink() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let dir_a = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("a"),
                0o755,
                0,
                0,
            )
            .unwrap();
        let dir_b = ops
            .mkdir(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("b"),
                0o755,
                0,
                0,
            )
            .unwrap();

        // Create a subdirectory under a/.
        ops.mkdir(
            &cx,
            &mut RequestScope::empty(),
            dir_a.ino,
            OsStr::new("sub"),
            0o755,
            0,
            0,
        )
        .unwrap();

        // btrfs directories always have nlink == 1 — subdirectories do not bump
        // the parent's link count (bd-egyf6), unlike ext4's 2 + subdir-count.
        let a_before = ops
            .getattr(&cx, &mut RequestScope::empty(), dir_a.ino)
            .unwrap();
        let b_before = ops
            .getattr(&cx, &mut RequestScope::empty(), dir_b.ino)
            .unwrap();
        assert_eq!(a_before.nlink, 1, "a stays nlink=1 (btrfs dir)");
        assert_eq!(b_before.nlink, 1, "b stays nlink=1 (btrfs dir)");

        // Rename sub from a/ to b/.
        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            dir_a.ino,
            OsStr::new("sub"),
            dir_b.ino,
            OsStr::new("sub"),
        )
        .unwrap();

        // A cross-parent directory move leaves both parents at nlink=1.
        let a_after = ops
            .getattr(&cx, &mut RequestScope::empty(), dir_a.ino)
            .unwrap();
        let b_after = ops
            .getattr(&cx, &mut RequestScope::empty(), dir_b.ino)
            .unwrap();
        assert_eq!(a_after.nlink, 1, "a stays nlink=1 after rename");
        assert_eq!(b_after.nlink, 1, "b stays nlink=1 after rename");
        // The entry actually moved.
        assert!(
            ops.lookup(
                &cx,
                &mut RequestScope::empty(),
                dir_b.ino,
                OsStr::new("sub")
            )
            .is_ok()
        );
        assert!(
            ops.lookup(
                &cx,
                &mut RequestScope::empty(),
                dir_a.ino,
                OsStr::new("sub")
            )
            .is_err()
        );
    }

    #[test]
    fn btrfs_write_rename_file_same_parent_nlink_unchanged() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("old.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        let root_before = ops
            .getattr(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();

        // Rename file within the same directory.
        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("old.txt"),
            InodeNumber(1),
            OsStr::new("new.txt"),
        )
        .unwrap();

        // Root nlink should be unchanged (files don't affect parent nlink).
        let root_after = ops
            .getattr(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();
        assert_eq!(root_before.nlink, root_after.nlink);

        // File nlink should still be 1.
        let file_after = ops
            .getattr(&cx, &mut RequestScope::empty(), file.ino)
            .unwrap();
        assert_eq!(file_after.nlink, 1);
    }

    #[test]
    fn btrfs_write_rename_over_same_inode_hardlink_is_noop() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            0,
            b"same inode rename",
        )
        .unwrap();
        ops.link(
            &cx,
            &mut RequestScope::empty(),
            file.ino,
            InodeNumber(1),
            OsStr::new("alias.txt"),
        )
        .unwrap();

        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("original.txt"),
            InodeNumber(1),
            OsStr::new("alias.txt"),
        )
        .unwrap();

        // rename(2): "If oldpath and newpath are existing hard links referring
        // to the same file, then rename() does nothing, and returns a success
        // status." So BOTH names survive and the link count is unchanged — this
        // is a true no-op, not a source-removing rename (bd-f7q6k). The previous
        // assertions here encoded the buggy non-noop behavior (original.txt gone,
        // nlink dropped to 1), which destroyed one of the two hard links.
        let alias = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("alias.txt"),
            )
            .unwrap();
        assert_eq!(alias.ino, file.ino);

        let original = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original.txt"),
            )
            .expect("original.txt must survive a same-inode no-op rename");
        assert_eq!(original.ino, file.ino);

        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), file.ino)
            .unwrap();
        assert_eq!(after.nlink, 2, "both hard links must survive");

        let data = ops
            .read(&cx, &mut RequestScope::empty(), file.ino, 0, 4096)
            .unwrap();
        assert_eq!(data, b"same inode rename");
    }

    #[test]
    fn btrfs_write_fallocate_preserves_data() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("predata.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // Write data at offset 0.
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            0,
            b"ORIGINAL_DATA",
        )
        .unwrap();

        // Fallocate overlapping the same offset — should NOT destroy data.
        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096, 0)
            .unwrap();

        // Size should be 4096 (fallocate extends).
        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(after.size, 4096);

        // Original data should still be readable.
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 13)
            .unwrap();
        assert_eq!(
            &data[..13],
            b"ORIGINAL_DATA",
            "fallocate destroyed existing data"
        );
    }

    #[test]
    fn btrfs_write_fallocate_overlapping_existing_extent_preserves_data() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("overlap.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();

        let mut payload = vec![0u8; 8192];
        for (idx, byte) in payload.iter_mut().enumerate() {
            *byte = b'A' + u8::try_from(idx % 26).unwrap();
        }
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, &payload)
            .unwrap();

        // Preallocate the second half of the already-written extent. This must not insert a
        // competing prealloc extent over live data.
        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 4096, 4096, 0)
            .unwrap();

        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(after.size, 8192);

        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 8192)
            .unwrap();
        assert_eq!(data, payload);
    }

    #[test]
    fn btrfs_write_fallocate_overlapping_existing_extent_does_not_create_unwritten_overlap() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("overlap-fiemap.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        let payload = vec![0x5A_u8; 8192];
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, &payload)
            .unwrap();

        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 4096, 4096, 0)
            .unwrap();

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, attr.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            extents.len(),
            1,
            "prealloc over initialized data must not create an overlapping unwritten extent"
        );
        assert_eq!(extents[0].logical, 0);
        assert_eq!(extents[0].length, 8192);
        assert_eq!(
            extents[0].flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "initialized data extent must not be marked unwritten"
        );
    }

    #[test]
    fn btrfs_write_fallocate_preallocates_only_uncovered_hole_before_live_extent() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("partial-overlap-fiemap.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        let payload = vec![0x42_u8; 4096];
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 4096, &payload)
            .unwrap();

        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 8192, 0)
            .unwrap();

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, attr.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            extents.len(),
            2,
            "prealloc should fill only the uncovered leading hole"
        );
        assert_eq!(extents[0].logical, 0);
        assert_eq!(extents[0].length, 4096);
        assert_ne!(
            extents[0].flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "leading prealloc extent must be marked unwritten"
        );
        assert_eq!(extents[1].logical, 4096);
        assert_eq!(extents[1].length, 4096);
        assert_eq!(
            extents[1].flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "live data extent must not be marked unwritten"
        );
        assert!(
            extents[0].logical + extents[0].length <= extents[1].logical,
            "FIEMAP extents must not overlap: {extents:?}"
        );

        let readback = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 8192)
            .unwrap();
        assert!(readback[..4096].iter().all(|byte| *byte == 0));
        assert_eq!(&readback[4096..], payload.as_slice());
    }

    #[test]
    fn btrfs_write_fallocate_punch_hole_preserves_unpunched_prealloc_extents() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let block = 4096_u64;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("punch-prealloc.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 3 * block, 0)
            .expect("seed preallocated range");

        ops.fallocate(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            block,
            block,
            libc::FALLOC_FL_PUNCH_HOLE | libc::FALLOC_FL_KEEP_SIZE,
        )
        .expect("punch middle block out of prealloc extent");

        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr after punch");
        assert_eq!(after.size, 3 * block);

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, attr.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            extents.len(),
            2,
            "punching one block out of prealloc should preserve the two untouched unwritten runs"
        );
        assert_eq!(extents[0].logical, 0);
        assert_eq!(extents[0].length, block);
        assert_ne!(extents[0].flags & FIEMAP_EXTENT_UNWRITTEN, 0);
        assert_eq!(extents[1].logical, 2 * block);
        assert_eq!(extents[1].length, block);
        assert_ne!(extents[1].flags & FIEMAP_EXTENT_UNWRITTEN, 0);
    }

    #[test]
    fn btrfs_write_fallocate_zero_range_preserves_prealloc_extents() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let block = 4096_u64;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("zero-prealloc.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 3 * block, 0)
            .expect("seed preallocated range");

        ops.fallocate(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            block,
            block,
            libc::FALLOC_FL_ZERO_RANGE | libc::FALLOC_FL_KEEP_SIZE,
        )
        .expect("zero middle block of prealloc extent");

        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr after zero range");
        assert_eq!(after.size, 3 * block);

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, attr.ino, 0, u64::MAX).unwrap();
        assert!(
            !extents.is_empty(),
            "zeroing a preallocated range must not discard the allocation"
        );
        assert_eq!(extents.first().expect("first extent").logical, 0);
        let last = extents.last().expect("last extent");
        assert_eq!(last.logical + last.length, 3 * block);
        assert_eq!(
            extents.iter().map(|extent| extent.length).sum::<u64>(),
            3 * block,
            "all preallocated bytes should remain represented after zero range"
        );
        assert!(
            extents
                .iter()
                .all(|extent| extent.flags & FIEMAP_EXTENT_UNWRITTEN != 0),
            "preallocated zero-range extents should remain unwritten"
        );
    }

    #[test]
    fn btrfs_write_inline_to_regular_preserves_prefix() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("prefix.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // Write small data at offset 0 (inline).
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, b"PREFIX")
            .unwrap();
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 100)
            .unwrap();
        assert_eq!(&data, b"PREFIX");

        // Write large data at a non-zero offset (forces regular extent).
        let big = vec![0x42_u8; 4096];
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 4096, &big)
            .unwrap();

        // Prefix data at offset 0 should still be readable.
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 6)
            .unwrap();
        assert_eq!(
            &data[..6],
            b"PREFIX",
            "inline prefix data lost during inline-to-regular transition"
        );

        // Data at offset 4096 should also be correct.
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 4096, 4096)
            .unwrap();
        assert_eq!(data.len(), 4096);
        assert!(data.iter().all(|&b| b == 0x42));
    }

    #[test]
    fn btrfs_fiemap_reports_inline_extent_with_zero_physical() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let payload = b"inline-fiemap";

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("inline-fiemap.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, payload)
            .unwrap();

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, attr.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            extents.len(),
            1,
            "inline file should expose one FIEMAP extent"
        );

        let extent = &extents[0];
        assert_eq!(extent.logical, 0);
        assert_eq!(
            extent.physical, 0,
            "inline FIEMAP physical offset must be zero"
        );
        assert_eq!(extent.length, payload.len() as u64);
        // The kernel reports an inline extent DATA_INLINE | NOT_ALIGNED, plus
        // LAST (it is the sole extent). (bd-eordg)
        assert_eq!(
            extent.flags,
            FIEMAP_EXTENT_DATA_INLINE | FIEMAP_EXTENT_NOT_ALIGNED | FIEMAP_EXTENT_LAST,
            "inline FIEMAP extent must carry DATA_INLINE | NOT_ALIGNED | LAST"
        );
    }

    /// btrfs fiemap must flag a compressed extent FIEMAP_EXTENT_ENCODED (its
    /// data cannot be read raw while unmounted), matching the kernel. FrankenFS
    /// writes only uncompressed extents, so inject a compressed EXTENT_DATA
    /// (as a kernel image carries) and confirm the flag (bd-eordg).
    #[test]
    fn btrfs_fiemap_marks_compressed_extent_encoded_bd_eordg() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let s: u64 = 4096;

        let file = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("compressed.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        let canonical = fs.btrfs_canonical_inode(file.ino).unwrap();
        {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            let compressed = BtrfsExtentData::Regular {
                generation: alloc.generation,
                ram_bytes: s,
                extent_type: BTRFS_FILE_EXTENT_REG,
                compression: 1,        // zlib (any nonzero compression algorithm)
                disk_bytenr: 0x2_0000, // arbitrary; fiemap reports it, never reads it
                disk_num_bytes: s,
                extent_offset: 0,
                num_bytes: s,
            };
            let key = BtrfsKey {
                objectid: canonical,
                item_type: BTRFS_ITEM_EXTENT_DATA,
                offset: 0,
            };
            alloc.fs_tree.insert(key, &compressed.to_bytes()).unwrap();
        }

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, file.ino, 0, u64::MAX).unwrap();
        assert_eq!(extents.len(), 1);
        assert_ne!(
            extents[0].flags & FIEMAP_EXTENT_ENCODED,
            0,
            "a compressed extent must carry FIEMAP_EXTENT_ENCODED"
        );
        assert_eq!(
            extents[0].flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "a compressed regular extent is not UNWRITTEN"
        );
        assert_ne!(
            extents[0].flags & FIEMAP_EXTENT_LAST,
            0,
            "the sole extent must carry LAST"
        );
    }

    /// btrfs fiemap must flag a reflinked (shared) extent FIEMAP_EXTENT_SHARED
    /// on every inode that references it, and leave an unshared extent
    /// unflagged. FrankenFS reflink (FICLONE) bumps the extent refcount, which
    /// fiemap now reads via extent_item_refs (bd-g704k).
    #[test]
    fn btrfs_fiemap_marks_reflinked_extent_shared_bd_g704k() {
        let (fs, cx) = open_writable_btrfs();
        let root = InodeNumber(u64::from(BTRFS_FIRST_FREE_OBJECTID));
        let src = fs
            .create(&cx, root, OsStr::new("share-src.dat"), 0o644, 0, 0)
            .expect("create src");
        let dst = fs
            .create(&cx, root, OsStr::new("share-dst.dat"), 0o644, 0, 0)
            .expect("create dst");
        let lone = fs
            .create(&cx, root, OsStr::new("share-lone.dat"), 0o644, 0, 0)
            .expect("create lone");

        let fs_ops: &dyn FsOps = &fs;
        let payload = vec![0x5A_u8; 16384];
        fs_ops
            .write(&cx, &mut RequestScope::empty(), src.ino, 0, &payload)
            .expect("write src");
        fs_ops
            .write(&cx, &mut RequestScope::empty(), lone.ino, 0, &payload)
            .expect("write lone");

        let mut scope = RequestScope::empty();
        let src_before = fs.fiemap(&cx, &mut scope, src.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            src_before[0].flags & FIEMAP_EXTENT_SHARED,
            0,
            "an unshared extent must not be SHARED before the reflink"
        );

        // Reflink src -> dst (shares the disk extent, refs 1 -> 2).
        let src_canon = fs.btrfs_canonical_inode(src.ino).unwrap();
        let dst_canon = fs.btrfs_canonical_inode(dst.ino).unwrap();
        {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            fs.btrfs_clone_file_data(&mut alloc, src_canon, dst_canon)
                .expect("reflink src into dst");
        }

        // BOTH src and dst now report SHARED on the shared extent.
        let src_after = fs.fiemap(&cx, &mut scope, src.ino, 0, u64::MAX).unwrap();
        assert_ne!(
            src_after[0].flags & FIEMAP_EXTENT_SHARED,
            0,
            "src's now-shared extent must be SHARED"
        );
        let dst_after = fs.fiemap(&cx, &mut scope, dst.ino, 0, u64::MAX).unwrap();
        assert_ne!(
            dst_after[0].flags & FIEMAP_EXTENT_SHARED,
            0,
            "dst's shared extent must be SHARED"
        );

        // The unrelated file's extent stays unshared.
        let lone_fm = fs.fiemap(&cx, &mut scope, lone.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            lone_fm[0].flags & FIEMAP_EXTENT_SHARED,
            0,
            "an unrelated file's extent must not be SHARED"
        );
    }

    /// FIEMAP_EXTENT_SHARED must also be reported on a READ-ONLY mount, where the
    /// in-memory extent allocator is not loaded and the refcount is read straight
    /// from the on-disk extent tree. Write + reflink + commit, reopen read-only,
    /// and confirm fiemap still flags the shared extent (bd-0j8ev).
    #[test]
    fn btrfs_fiemap_reports_shared_on_readonly_mount_bd_0j8ev() {
        // A full COW commit does not fit the tiny in-memory fsops image, so this
        // uses a real mkfs image (256 MiB) like the other commit+remount tests.
        // It skips when btrfs-progs/mkfs is unavailable (the sandbox blocks
        // mkfs) and runs end-to-end on a privileged runner.
        let Some((fs, dev, _tmp, _image)) = open_writable_btrfs_mkfs(256) else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(u64::from(BTRFS_FIRST_FREE_OBJECTID));
        let src = fs
            .create(&cx, root, OsStr::new("ro-src.dat"), 0o644, 0, 0)
            .expect("create src");
        let dst = fs
            .create(&cx, root, OsStr::new("ro-dst.dat"), 0o644, 0, 0)
            .expect("create dst");

        let fs_ops: &dyn FsOps = &fs;
        let payload = vec![0x5A_u8; 16384];
        fs_ops
            .write(&cx, &mut RequestScope::empty(), src.ino, 0, &payload)
            .expect("write src");

        let src_canon = fs.btrfs_canonical_inode(src.ino).unwrap();
        let dst_canon = fs.btrfs_canonical_inode(dst.ino).unwrap();
        {
            let alloc_mutex = fs.btrfs_alloc_state.as_ref().unwrap();
            let mut alloc = alloc_mutex.write();
            fs.btrfs_clone_file_data(&mut alloc, src_canon, dst_canon)
                .expect("reflink src into dst");
        }

        // Persist data + metadata, then snapshot the on-disk image.
        let _ = fs.flush_mvcc_to_device(&cx);
        fs.btrfs_full_transaction_commit(&cx, "ro-shared-fiemap-test")
            .expect("commit");
        let committed = dev.snapshot_bytes();

        // Reopen READ-ONLY (no enable_writes => btrfs_alloc_state is None).
        let ro = OpenFs::from_device(
            &cx,
            Box::new(TestDevice::from_vec(committed)),
            &OpenOptions::default(),
        )
        .expect("reopen committed image read-only");
        assert!(!ro.is_writable(), "the remount must be read-only");

        let src_ro = ro
            .lookup(&cx, root, OsStr::new("ro-src.dat"))
            .expect("lookup src on the read-only mount");
        let mut scope = RequestScope::empty();
        let extents = ro.fiemap(&cx, &mut scope, src_ro.ino, 0, u64::MAX).unwrap();
        assert_ne!(
            extents[0].flags & FIEMAP_EXTENT_SHARED,
            0,
            "a read-only mount must report SHARED for a reflinked extent"
        );
    }

    #[test]
    fn btrfs_fiemap_marks_keep_size_prealloc_extent_unwritten() {
        let _guard = log_contract_guard();
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;
        let payload = b"existing";

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("prealloc-fiemap.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, payload)
            .unwrap();
        ops.fallocate(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            4096,
            4096,
            libc::FALLOC_FL_KEEP_SIZE,
        )
        .unwrap();

        let mut scope = RequestScope::empty();
        let extents = fs.fiemap(&cx, &mut scope, attr.ino, 0, u64::MAX).unwrap();
        assert_eq!(
            extents.len(),
            2,
            "inline-to-regular keep-size preallocation should expose data plus unwritten extent"
        );

        let data_extent = &extents[0];
        assert_eq!(data_extent.logical, 0);
        assert!(data_extent.physical > 0);
        assert_eq!(data_extent.length, payload.len() as u64);
        assert_eq!(
            data_extent.flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "materialized prefix extent must not be marked unwritten"
        );

        let prealloc_extent = &extents[1];
        assert_eq!(prealloc_extent.logical, 4096);
        assert!(prealloc_extent.physical > 0);
        assert_eq!(prealloc_extent.length, 4096);
        assert_ne!(
            prealloc_extent.flags & FIEMAP_EXTENT_UNWRITTEN,
            0,
            "keep-size preallocation must surface FIEMAP_EXTENT_UNWRITTEN"
        );
        assert_ne!(
            prealloc_extent.flags & FIEMAP_EXTENT_LAST,
            0,
            "trailing preallocation extent must surface FIEMAP_EXTENT_LAST"
        );

        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 64)
            .unwrap();
        assert_eq!(&data[..payload.len()], payload);
    }

    #[test]
    fn btrfs_write_statfs_reflects_allocations() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let stat_before = ops
            .statfs(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();
        let free_before = stat_before.blocks_free;

        // Create a file and write enough data to trigger a regular extent allocation.
        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("big.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        let big = vec![0xAA_u8; 8192];
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, &big)
            .unwrap();

        let stat_after = ops
            .statfs(&cx, &mut RequestScope::empty(), InodeNumber(1))
            .unwrap();
        let free_after = stat_after.blocks_free;

        // Free space should have decreased after the allocation.
        assert!(
            free_after < free_before,
            "statfs should reflect decreased free space: before={free_before}, after={free_after}"
        );
    }

    // ── verify_ext4_integrity direct tests (GreenSnow) ────────────────

    /// Helper: resolve the ext4_small.img fixture path, returning None in CI
    /// where fixtures may be absent.
    fn ext4_small_fixture_path() -> Option<std::path::PathBuf> {
        let p = std::path::Path::new("tests/fixtures/images/ext4_small.img");
        if p.exists() {
            return Some(p.to_path_buf());
        }
        let ws = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .parent()
            .unwrap()
            .parent()
            .unwrap()
            .join("tests/fixtures/images/ext4_small.img");
        if ws.exists() { Some(ws) } else { None }
    }

    /// Helper: load the ext4_small fixture image bytes, or skip test.
    fn load_ext4_small_image() -> Option<Vec<u8>> {
        ext4_small_fixture_path().map(|p| std::fs::read(p).expect("read ext4_small.img"))
    }

    #[test]
    fn verify_ext4_integrity_clean_image_has_zero_failures() {
        let Some(image) = load_ext4_small_image() else {
            return;
        };
        let report = verify_ext4_integrity(&image, 64).expect("integrity check should succeed");
        assert_eq!(
            report.failed, 0,
            "clean ext4_small.img should have zero failures, got: passed={}, failed={}",
            report.passed, report.failed
        );
        assert!(report.passed > 0, "should have at least one passing check");
        // Should have verdicts for superblock, group descs, and inodes.
        assert!(
            !report.verdicts.is_empty(),
            "should have at least one verdict"
        );
        // All individual verdicts should have passed.
        for v in &report.verdicts {
            assert!(
                v.passed,
                "verdict for '{}' should pass on clean image: {}",
                v.component, v.detail
            );
        }
        // Superblock checksum should pass on a clean mkfs'd image.
        let sb_verdict = report.verdicts.iter().find(|v| v.component == "superblock");
        assert!(sb_verdict.is_some(), "should have a superblock verdict");
        // Bayesian posterior should reflect zero failures.
        assert!(
            (report.posterior_alpha - 1.0).abs() < 1e-6,
            "alpha should be 1.0 (no failures), got {}",
            report.posterior_alpha
        );
    }

    #[test]
    fn verify_ext4_integrity_corrupt_superblock_checksum() {
        let Some(mut image) = load_ext4_small_image() else {
            return;
        };
        // Tamper with a byte in the superblock region (after the magic, before checksum).
        // Offset 1024 is superblock start; byte at offset 1024+0x60 is in the middle.
        let tamper_off = ffs_types::EXT4_SUPERBLOCK_OFFSET + 0x60;
        image[tamper_off] ^= 0xFF;

        let report = verify_ext4_integrity(&image, 8).expect("should still return a report");
        // The superblock checksum should have failed.
        let sb_verdict = report.verdicts.iter().find(|v| v.component == "superblock");
        assert!(
            sb_verdict.is_some(),
            "should have a superblock verdict after tampering"
        );
        let sb = sb_verdict.unwrap();
        assert!(
            !sb.passed,
            "superblock checksum should fail after tampering"
        );
        assert!(report.failed > 0, "should have at least one failure");
    }

    #[test]
    fn verify_ext4_integrity_corrupt_group_desc_checksum() {
        let Some(mut image) = load_ext4_small_image() else {
            return;
        };
        // Parse the superblock to find group descriptor location.
        let sb = ffs_ondisk::Ext4Superblock::parse_from_image(&image)
            .expect("parse superblock for fixture");
        // Group 0 descriptor is at the block after the superblock.
        // For 4K block size: block 0 = boot+sb, block 1 = group desc table.
        if let Some(gd_off) = sb.group_desc_offset(ffs_types::GroupNumber(0)) {
            let off = usize::try_from(gd_off).unwrap();
            // Tamper with byte at offset+4 (inode_bitmap field), avoiding the
            // checksum field itself (offset 0x1E).
            if off + 4 < image.len() {
                image[off + 4] ^= 0xFF;
            }
        }

        let report = verify_ext4_integrity(&image, 8).expect("should still return a report");
        // Should have at least one group_desc failure.
        assert!(
            report
                .verdicts
                .iter()
                .any(|v| v.component.starts_with("group_desc[") && !v.passed),
            "should have at least one group_desc checksum failure, verdicts: {:?}",
            report
                .verdicts
                .iter()
                .map(|v| format!("{}:{}", v.component, v.passed))
                .collect::<Vec<_>>()
        );
    }

    #[test]
    fn verify_ext4_integrity_garbage_image_returns_error() {
        // An image full of zeros should fail to parse as ext4.
        let image = vec![0u8; 8192];
        let result = verify_ext4_integrity(&image, 0);
        assert!(result.is_err(), "garbage image should fail: got {result:?}");
    }

