    #[test]
    fn verify_ext4_integrity_max_inodes_zero_checks_all() {
        let Some(image) = load_ext4_small_image() else {
            return;
        };
        // max_inodes=0 means "check all inodes"
        let report_all = verify_ext4_integrity(&image, 0).expect("integrity check should succeed");
        assert_eq!(
            report_all.failed, 0,
            "clean image with all inodes should have zero failures"
        );
        let report_limited =
            verify_ext4_integrity(&image, 8).expect("limited integrity check should succeed");
        // Checking all inodes should examine at least as many checks total.
        assert!(
            report_all.passed >= report_limited.passed,
            "checking all inodes should have >= passing checks: all={}, limited={}",
            report_all.passed,
            report_limited.passed
        );
    }

    #[test]
    fn verify_ext4_integrity_bayesian_posterior_is_consistent() {
        let Some(image) = load_ext4_small_image() else {
            return;
        };
        let report = verify_ext4_integrity(&image, 16).expect("integrity check should succeed");
        // For a clean image with bitmap filtering: posterior_alpha = 1 + 0 = 1
        assert!(
            (report.posterior_alpha - 1.0).abs() < 1e-6,
            "alpha: expected 1.0 (no failures), got {}",
            report.posterior_alpha
        );
        let expected_beta = 1.0 + report.passed as f64;
        assert!(
            (report.posterior_beta - expected_beta).abs() < 1e-6,
            "beta: expected {expected_beta}, got {}",
            report.posterior_beta
        );
        // Expected corruption rate should be very small for a clean image.
        assert!(
            report.expected_corruption_rate < 0.1,
            "expected low corruption rate for clean image, got {}",
            report.expected_corruption_rate
        );
        // Upper bound should be >= expected rate
        assert!(
            report.upper_bound_corruption_rate >= report.expected_corruption_rate,
            "upper bound {} should be >= expected rate {}",
            report.upper_bound_corruption_rate,
            report.expected_corruption_rate
        );
    }

    /// Regression: a corrupted superblock advertising inodes_per_group == 0
    /// previously caused verify_ext4_integrity to divide by zero and panic
    /// in the per-inode bitmap-cache loop. The fix emits an "inodes_per_group"
    /// failure verdict and skips the inode-checksum scan; the function must
    /// still return Ok with a well-formed report.
    #[test]
    fn verify_ext4_integrity_zero_inodes_per_group_returns_failure_verdict() {
        let Some(mut image) = load_ext4_small_image() else {
            return;
        };
        // Zero out inodes_per_group at superblock offset 0x28..0x2C.
        let off = ffs_types::EXT4_SUPERBLOCK_OFFSET + 0x28;
        image[off..off + 4].copy_from_slice(&0_u32.to_le_bytes());

        let report = verify_ext4_integrity(&image, 16)
            .expect("zero inodes_per_group must not panic the verifier");
        let ipg_verdict = report
            .verdicts
            .iter()
            .find(|v| v.component == "inodes_per_group");
        assert!(
            ipg_verdict.is_some_and(|v| !v.passed),
            "expected an inodes_per_group failure verdict, got: {:?}",
            report
                .verdicts
                .iter()
                .map(|v| format!("{}:{}", v.component, v.passed))
                .collect::<Vec<_>>()
        );
        assert!(
            report.failed >= 1,
            "report.failed must cover the inodes_per_group verdict, got {}",
            report.failed
        );
    }

    /// Profiling probe: run verify_ext4_integrity on the exact image
    /// the fuzz_verify_ext4_integrity timeout artifact reproduces, with
    /// a 5-second wall-time budget. Without ASAN (unit tests) this
    /// should complete in well under a second; if it ever exceeds 5s
    /// we have a real per-iteration regression, not a fuzz-instrumentation
    /// artifact.
    #[test]
    fn verify_ext4_integrity_per_inode_cost_under_5s() {
        let mut image = build_ext4_image(2);
        let sb = ffs_types::EXT4_SUPERBLOCK_OFFSET;
        // Replicate the timeout-artifact mutations:
        //   log_block_size → 0   (block_size = 1024)
        //   blocks_count_lo → 46
        // (Full sequence in the timeout artifact applies several rounds;
        // these are the net effects on the superblock fields.)
        image[sb + 0x18..sb + 0x1C].copy_from_slice(&0_u32.to_le_bytes());
        image[sb + 0x04..sb + 0x08].copy_from_slice(&46_u32.to_le_bytes());

        let start = std::time::Instant::now();
        let report = verify_ext4_integrity(&image, 0).expect("verify must complete");
        let elapsed = start.elapsed();
        assert!(
            elapsed < std::time::Duration::from_secs(5),
            "verify_ext4_integrity took {:?} on the timeout-artifact shape; \
             investigate per-iteration cost. report.failed={} verdicts={}",
            elapsed,
            report.failed,
            report.verdicts.len(),
        );
    }

    /// Regression: a corrupted superblock advertising u32::MAX blocks_count
    /// previously made `for g in 0..groups_count` push billions of failure
    /// verdicts, OOM-ing the verifier itself. The fix caps the scan at
    /// MAX_GROUPS_VERIFIED and emits a single "groups_count" verdict on
    /// truncation. This pins the cap so a future un-bounding regression
    /// fails fast rather than allocating gigabytes again.
    #[test]
    fn verify_ext4_integrity_excessive_groups_count_is_bounded() {
        let Some(mut image) = load_ext4_small_image() else {
            return;
        };
        // Set blocks_count to u32::MAX. With default 4 KiB blocks and a
        // small blocks_per_group (e.g. 8192), groups_count would compute
        // to ~524288 — well above any sane cap. We rely on the fact that
        // the cap is far below this value.
        let off = ffs_types::EXT4_SUPERBLOCK_OFFSET + 0x04;
        image[off..off + 4].copy_from_slice(&u32::MAX.to_le_bytes());

        let report = verify_ext4_integrity(&image, 16)
            .expect("u32::MAX blocks_count must not OOM the verifier");
        // Either we emitted the explicit "groups_count" cap verdict, or
        // the underlying parser rejected the corrupted superblock outright.
        let cap_verdict = report
            .verdicts
            .iter()
            .find(|v| v.component == "groups_count");
        let group_desc_failures = report
            .verdicts
            .iter()
            .filter(|v| v.component.starts_with("group_desc[") && !v.passed)
            .count();
        assert!(
            cap_verdict.is_some_and(|v| !v.passed) || group_desc_failures > 0,
            "expected groups_count cap verdict or group_desc failures, got: {:?}",
            report
                .verdicts
                .iter()
                .map(|v| format!("{}:{}", v.component, v.passed))
                .collect::<Vec<_>>()
        );
        // Bound the verdict count so the cap is actually working: a
        // pre-fix run produced billions of verdicts.
        assert!(
            report.verdicts.len() <= 200_000,
            "verdict count must be capped, got {}",
            report.verdicts.len()
        );
    }

